// ═════════════════════════════════════════════════════════════════════════════
// EMAIL QUEUE SYSTEM (Prevents blocking)
// ═════════════════════════════════════════════════════════════════════════════

const emailQueue = [];
let isProcessingQueue = false;

async function processEmailQueue() {
  if (isProcessingQueue || emailQueue.length === 0) return;

  isProcessingQueue = true;

  while (emailQueue.length > 0) {
    const emailTask = emailQueue.shift();
    let attempts = 0;
    let success  = false;

    while (attempts < 3 && !success) {
      try {
        await emailTask();
        success = true;
      } catch (error) {
        attempts++;
        console.error(`❌ Queue email error (attempt ${attempts}/3):`, error.message);
        if (attempts < 3) {
          // Exponential back-off: 2s, 4s
          await new Promise(r => setTimeout(r, 2000 * attempts));
        }
      }
    }

    if (!success) {
      console.error('❌ Email permanently failed after 3 attempts — dropped.');
    }
  }

  isProcessingQueue = false;
}

// Process queue — self-schedules only when there is work to do
async function scheduleEmailQueue() {
  await processEmailQueue();
  const delay = emailQueue.length > 0 ? 100 : 2000; // fast when busy, idle otherwise
  setTimeout(scheduleEmailQueue, delay);
}
setTimeout(scheduleEmailQueue, 100);

global.queueEmail = (emailFunction) => {
  emailQueue.push(emailFunction);
  console.log(`📬 Email queued (${emailQueue.length} in queue)`);
};

