// ═════════════════════════════════════════════════════════════════════════════
// WEBSOCKET SETUP FOR REAL-TIME CHAT
// ═════════════════════════════════════════════════════════════════════════════

const wss = new WebSocket.Server({ 
  server,
  path: '/wss',  // ✅ FIXED: Changed from /ws to /wss to match frontend
  verifyClient: (info) => {
    // Allow all connections - authentication handled in message handler
    console.log('🔌 WebSocket connection attempt from:', info.origin);
    return true;
  }
});
global.wss = wss;

// Store active WebSocket connections
const activeConnections = new Map(); // chatId -> Set of WebSocket connections
const agentConnections = new Map();  // agentId -> WebSocket connection
const customerConnections = new Map(); // customerId -> WebSocket connection

// WebSocket connection handler
// WebSocket connection handler
wss.on('connection', async (ws, req) => {
  const url        = new URL(req.url, `http://${req.headers.host}`);
  const chatId     = url.searchParams.get('chatId');
  const agentId    = url.searchParams.get('agentId');
  const customerId = url.searchParams.get('customerId');
  const token      = url.searchParams.get('token');

  console.log(`\n🔌 WebSocket Connection Attempt:`);
  console.log(`   Chat ID: ${chatId || 'N/A'} | Agent ID: ${agentId || 'N/A'} | Customer ID: ${customerId || 'N/A'}`);
  console.log(`   Token: ${token ? 'Provided' : 'None'} | Total before add: ${wss.clients.size}`);

  // ── Maintenance mode guard ──────────────────────────────────────────────
  // Admins and agents are always allowed to connect (support cannot go dark).
  // Regular users are disconnected immediately when maintenance is ON.
  try {
    const settings = await getSettings();

    if (settings.maintenanceMode) {
      let isPrivileged = false;

      if (token) {
        try {
          const decoded = jwt.verify(token, JWT_SECRET);
          if (decoded && decoded.userId) {
            const user = await User.findById(decoded.userId)
                                   .select('isAdmin isAgent')
                                   .lean();
            if (user && (user.isAdmin || user.isAgent)) {
              isPrivileged = true;
            }
          }
        } catch (_) {
          // Invalid token — treat as unprivileged
        }
      }

      // Also allow connections that supply the bypass token as a query param
      if (!isPrivileged) {
        const bypass = url.searchParams.get('bypass');
        if (bypass && settings.maintenanceBypassToken && bypass === settings.maintenanceBypassToken) {
          isPrivileged = true;
        }
      }

      if (!isPrivileged) {
        console.log(`🔧 WebSocket blocked (maintenance): ${customerId || agentId || 'unknown'}`);
        ws.send(JSON.stringify({
          type:        'maintenance',
          maintenance: true,
          title:       settings.maintenanceTitle   || 'Under Maintenance',
          message:     settings.maintenanceMessage || "We'll be back shortly!",
          eta:         settings.maintenanceETA     || '',
        }));
        ws.close(1001, 'Server under maintenance');
        return; // do not register this connection
      }
    }
  } catch (err) {
    // If we cannot check maintenance (DB error) we let the connection through
    console.error('⚠️  WS maintenance check failed (allowing connection):', err.message);
  }

  // ── Decode and tag the socket with identity ───────────────────────────
  let wsUserRole = 'customer'; // default
  if (token) {
    try {
      const decoded = jwt.verify(token, JWT_SECRET);
      if (decoded && decoded.userId) {
        const user = await User.findById(decoded.userId)
                               .select('isAdmin isAgent')
                               .lean();
        if (user) {
          wsUserRole = user.isAdmin ? 'admin' : user.isAgent ? 'agent' : 'customer';
        }
      }
    } catch (_) {}
  }

  // Store connection metadata
  ws.isAlive     = true;
  ws.chatId      = chatId;
  ws.agentId     = agentId;
  ws.customerId  = customerId;
  ws.userRole    = wsUserRole;   // 'admin' | 'agent' | 'customer'
  ws.connectedAt = new Date();

  // Register in maps
  if (chatId) {
    if (!activeConnections.has(chatId)) activeConnections.set(chatId, new Set());
    activeConnections.get(chatId).add(ws);
    console.log(`   ✅ Added to chat: ${chatId}`);
  }
  if (agentId) {
    agentConnections.set(agentId, ws);
    console.log(`   ✅ Registered agent: ${agentId}`);
  }
  if (customerId) {
    customerConnections.set(customerId, ws);
    console.log(`   ✅ Registered customer: ${customerId}`);
  }

  console.log(`   ✅ Connected as: ${wsUserRole} | Total: ${wss.clients.size}`);

  // Pong handler
  ws.on('pong', () => { ws.isAlive = true; });

  // Confirm connection
  ws.send(JSON.stringify({
    type:      'connected',
    message:   'WebSocket connection established',
    role:      wsUserRole,
    timestamp: new Date(),
  }));

  // ── Message handler ───────────────────────────────────────────────────
  ws.on('message', async (message) => {
    // Guard: reject oversized messages (max 64KB — more than enough for chat)
    if (message.length > 65536) {
      console.warn(`⚠️  WS message too large (${message.length} bytes) from ${ws.userRole} — rejected`);
      return ws.send(JSON.stringify({ type: 'error', message: 'Message too large (max 64KB)' }));
    }
    try {
      const data = JSON.parse(message);
      console.log(`📨 WebSocket message received: ${data.type} (role: ${ws.userRole})`);

      switch (data.type) {
        case 'join_agent':    await handleAgentJoin(ws, data);    break;
        case 'join_customer': await handleCustomerJoin(ws, data); break;
        case 'join_chat':     await handleJoinChat(ws, data);     break;
        case 'new_message':   await handleNewMessage(ws, data);   break;
        case 'typing':        await handleTyping(ws, data);       break;
        case 'stop_typing':   await handleStopTyping(ws, data);   break;
        case 'ping':
          ws.send(JSON.stringify({ type: 'pong', timestamp: new Date() }));
          break;
        default:
          console.log(`❓ Unknown WS message type: ${data.type}`);
      }
    } catch (err) {
      console.error('❌ WS message error:', err);
      ws.send(JSON.stringify({ type: 'error', message: 'Failed to process message' }));
    }
  });

  // ── Disconnect handler ────────────────────────────────────────────────
  ws.on('close', () => {
    console.log(`🔌 WebSocket closed (role: ${ws.userRole}, chatId: ${ws.chatId || 'N/A'})`);

    if (ws.chatId && activeConnections.has(ws.chatId)) {
      const set = activeConnections.get(ws.chatId);
      set.delete(ws);
      if (set.size === 0) activeConnections.delete(ws.chatId);
    }
    if (ws.agentId    && agentConnections.get(ws.agentId)       === ws) agentConnections.delete(ws.agentId);
    if (ws.customerId && customerConnections.get(ws.customerId) === ws) customerConnections.delete(ws.customerId);

    delete ws.userId; delete ws.chatId;
    delete ws.agentId; delete ws.customerId; delete ws.userRole;
  });

  // ── Error handler ─────────────────────────────────────────────────────
  ws.on('error', (err) => {
    console.error('❌ WebSocket error:', err.message);
  });
});


/**
 * Handle agent joining the WebSocket
 */
async function handleAgentJoin(ws, data) {
  const { userId, agentId } = data;
  
  ws.userId = userId;
  ws.agentId = agentId;
  ws.userType = 'agent';
  
  console.log(`✅ Agent joined: ${agentId}`);
  
  ws.send(JSON.stringify({
    type: 'joined',
    message: 'Successfully joined as agent',
    userId,
    agentId
  }));
}

/**
 * Handle customer joining the WebSocket
 */
async function handleCustomerJoin(ws, data) {
  const { userId, chatId } = data;
  
  ws.userId = userId;
  ws.chatId = chatId;
  ws.userType = 'customer';
  
  console.log(`✅ Customer joined chat: ${chatId}`);
  
  ws.send(JSON.stringify({
    type: 'joined',
    message: 'Successfully joined chat',
    userId,
    chatId
  }));
}

/**
 * Handle agent joining a specific chat room
 */
async function handleJoinChat(ws, data) {
  const { chatId, userId } = data;
  
  ws.chatId = chatId;
  ws.userId = userId;
  
  console.log(`✅ User ${userId} joined chat room: ${chatId}`);
  
  ws.send(JSON.stringify({
    type: 'chat_joined',
    message: 'Successfully joined chat room',
    chatId
  }));
}

/**
 * ✅ CRITICAL: Handle new message with INSTANT broadcasting
 */
async function handleNewMessage(ws, data) {
  try {
    const { chatId, message, sender, senderId, senderName } = data;
    
    console.log(`💬 New message in chat ${chatId} from ${sender}`);

    // Validate message
    if (!chatId || !message || !sender) {
      ws.send(JSON.stringify({
        type: 'error',
        message: 'Missing required fields'
      }));
      return;
    }

    // Create message object
    const messageObj = {
      messageId: `MSG-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      sender,
      senderId: senderId || ws.userId,
      senderName: senderName || (sender === 'agent' ? 'Agent' : 'Customer'),
      message: message.trim(),
      timestamp: new Date(),
      read: false
    };

    // Save to database
    const chat = await Chat.findOne({ chatId });
    if (!chat) {
      ws.send(JSON.stringify({
        type: 'error',
        message: 'Chat not found'
      }));
      return;
    }

    // Add message to chat
    chat.messages.push(messageObj);
    chat.updatedAt = new Date();
    await chat.save();

    console.log(`✅ Message saved to database: ${messageObj.messageId}`);

    // ✅ INSTANT BROADCAST to ALL participants in this chat
    const broadcastData = {
      type: 'chat_message',
      chatId,
      message: messageObj
    };

    let broadcastCount = 0;

wss.clients.forEach((client) => {
  if (client.readyState === 1 &&
      (client.chatId === chatId || 
       (client.agentId && client.chatId === chatId))) { // In chat room OR is an agent
        try {
          client.send(JSON.stringify(broadcastData));
          broadcastCount++;
        } catch (error) {
          console.error('Error broadcasting message:', error);
        }
      }
    });

    console.log(`📢 Message broadcasted to ${broadcastCount} clients`);

    // Send confirmation to sender
    ws.send(JSON.stringify({
      type: 'message_sent',
      message: messageObj,
      success: true
    }));

  } catch (error) {
    console.error('❌ Error handling new message:', error);
    ws.send(JSON.stringify({
      type: 'error',
      message: 'Failed to send message',
      error: error.message
    }));
  }
}

/**
 * Handle typing indicator
 */
async function handleTyping(ws, data) {
  const { chatId, sender, senderName } = data;
  
  console.log(`⌨️  ${senderName} is typing in chat ${chatId}`);

  // Broadcast to all participants EXCEPT sender
  const typingData = {
    type: 'typing',
    chatId,
    sender,
    senderName
  };

  wss.clients.forEach((client) => {
    if (client.readyState === 1 && 
        client.chatId === chatId && 
        client !== ws) { // Don't send back to sender
      try {
        client.send(JSON.stringify(typingData));
      } catch (error) {
        console.error('Error broadcasting typing:', error);
      }
    }
  });
}

/**
 * Handle stop typing
 */
async function handleStopTyping(ws, data) {
  const { chatId, sender } = data;
  
  // Broadcast to all participants EXCEPT sender
  const stopTypingData = {
    type: 'stop_typing',
    chatId,
    sender
  };

  wss.clients.forEach((client) => {
    if (client.readyState === 1 && 
        client.chatId === chatId && 
        client !== ws) {
      try {
        client.send(JSON.stringify(stopTypingData));
      } catch (error) {
        console.error('Error broadcasting stop typing:', error);
      }
    }
  });
}


// ✅ Performance monitoring middleware
app.use((req, res, next) => {
  const start = Date.now();
  
  res.on('finish', () => {
    const duration = Date.now() - start;
    
    // Log slow requests (> 1 second)
    if (duration > 1000) {
      console.warn(`⚠️  SLOW REQUEST: ${req.method} ${req.path} - ${duration}ms`);
    }
  });
  
  next();
});

// ═════════════════════════════════════════════════════════════════════════════
// MAINTENANCE MODE MIDDLEWARE
// ─────────────────────────────────────────────────────────────────────────────
app.use(async (req, res, next) => {
  try {
    const settings = await getSettings();
    if (!settings.maintenanceMode) return next(); // maintenance is OFF — pass through

    const path = req.path;

    // ── 1. Always-allowed paths (no auth needed) ──────────────────────────
    const alwaysAllow = [
      '/api/settings/public',
      '/api/health',
      '/api/status/current',
    ];
    if (alwaysAllow.some(p => path === p || path.startsWith(p + '/'))) {
      return next();
    }

    // ── 2. Admin route prefix — pass through ─────────────────────────────
    if (
      path.startsWith('/api/admin/')   ||
      path.startsWith('/api/auth/admin') ||
      path.startsWith('/api/auth/agent') ||
      path.startsWith('/api/agent/')
    ) {
      return next();
    }

    // ── 3. Bypass token (header or query param) ───────────────────────────
    const bypassToken = req.headers['x-bypass-token'] || req.query.bypass;
    if (
      bypassToken &&
      settings.maintenanceBypassToken &&
      bypassToken === settings.maintenanceBypassToken
    ) {
      return next();
    }

    // ── 4. JWT-authenticated admin or agent ───────────────────────────────
    // We decode the token without throwing — invalid tokens just get blocked.
    const authHeader = req.headers['authorization'];
    if (authHeader && authHeader.startsWith('Bearer ')) {
      const token = authHeader.slice(7);
      try {
        const decoded = jwt.verify(token, JWT_SECRET);
        if (decoded && decoded.userId) {
          // Lightweight DB check — only fetch the two fields we need
          const user = await User.findById(decoded.userId)
                                 .select('isAdmin isAgent')
                                 .lean();
          if (user && (user.isAdmin || user.isAgent)) {
            return next();   // admin or agent — let them through
          }
        }
      } catch (_) {
        // Invalid / expired token — fall through to 503
      }
    }

    // ── 5. Everything else is blocked ────────────────────────────────────
    console.log(`🔧 Maintenance blocked: ${req.method} ${path}`);
    return res.status(503).json({
      success: false,
      maintenance: true,
      title:   settings.maintenanceTitle   || 'Under Maintenance',
      message: settings.maintenanceMessage || "We'll be back shortly!",
      eta:     settings.maintenanceETA     || '',
    });

  } catch (err) {
    // If the DB is down we cannot check maintenance — let the request through
    // so the server doesn't become completely unresponsive.
    console.error('⚠️  Maintenance middleware DB error (passing through):', err.message);
    next();
  }
});

/**
 * Strip sensitive fields from a request body before logging.
 * Returns a shallow copy — never mutates the original.
 */
function sanitiseBody(body) {
  if (!body || typeof body !== 'object') return null;
  const safe = { ...body };
  SENSITIVE_FIELDS.forEach(f => {
    if (safe[f] !== undefined) safe[f] = '[REDACTED]';
  });
  return safe;
}
 
/**
 * Parse a minimal device string from the User-Agent header.
 * Keeps it short: "Chrome / Windows", "Safari / iOS", etc.
 */
function parseDevice(ua) {
  if (!ua) return 'Unknown';
  if (/mobile/i.test(ua)) return 'Mobile';
  if (/tablet|ipad/i.test(ua)) return 'Tablet';
  if (/windows/i.test(ua)) return 'Desktop / Windows';
  if (/macintosh|mac os/i.test(ua)) return 'Desktop / Mac';
  if (/linux/i.test(ua)) return 'Desktop / Linux';
  return 'Unknown';
}
 
/**
 * Resolve actor fields from an Express request.
 * Works whether the request is authenticated or anonymous.
 */
function resolveActor(req) {
  const ip = (
    req.headers['x-forwarded-for']?.split(',')[0]?.trim() ||
    req.socket?.remoteAddress ||
    null
  );
  const device = parseDevice(req.headers['user-agent']);
 
  // Unauthenticated baseline
  const actor = {
    id:     null,
    email:  'anonymous',
    name:   'Anonymous',
    role:   'guest',
    ip,
    device,
  };
 
  // Authenticated via authenticateToken / authenticateAdmin / authenticateAgent
  if (req.user) {
    actor.id    = req.user.userId  || req.user._id  || null;
    actor.email = req.user.email   || actor.email;
    actor.name  = req.user.name    || req.user.fullName || actor.name;
    actor.role  = req.user.isAdmin ? 'admin'
                : req.user.isAgent ? 'agent'
                : 'user';
  }
  if (req.adminUser) {
    actor.id    = req.adminUser._id;
    actor.email = req.adminUser.email;
    actor.name  = req.adminUser.fullName || actor.name;
    actor.role  = 'admin';
  }
  if (req.agentUser) {
    actor.id    = req.agentUser._id;
    actor.email = req.agentUser.email;
    actor.name  = req.agentUser.fullName || actor.name;
    actor.role  = 'agent';
  }
 
  return actor;
}
 
// The middleware itself — attach AFTER auth middleware so req.user is populated
app.use((req, res, next) => {
  // Skip noisy paths
  if (LOG_SKIP_PATHS.some(p => req.path === p || req.path.startsWith(p + '/'))) {
    return next();
  }
 
  const start = Date.now();
 
  // Hook into res.json() so we can capture the status code after the handler runs
  const originalJson = res.json.bind(res);
  res.json = function (body) {
    const duration   = Date.now() - start;
    const actor      = resolveActor(req);
    const success    = res.statusCode >= 200 && res.statusCode < 400;
 
    // Decide category from the path
    const path = req.path;
    let category = 'server';
    if (path.startsWith('/api/auth'))        category = 'auth';
    else if (path.startsWith('/api/admin'))  category = 'admin';
    else if (path.startsWith('/api/agent'))  category = 'agent';
    else if (path.startsWith('/api/upload')) category = 'upload';
    else if (path.startsWith('/api/orders')) category = 'order';
    else if (path.startsWith('/api/products') || path.startsWith('/api/creator/products')) category = 'product';
    else if (path.startsWith('/api/creator')) category = 'creator';
    else if (path.startsWith('/api/affiliate')) category = 'affiliate';
    else if (path.startsWith('/api/chat'))   category = 'chat';
    else if (path.startsWith('/api/tickets')) category = 'ticket';
    else if (path.startsWith('/api/coupons')) category = 'coupon';
    else if (path.startsWith('/api/blog'))   category = 'blog';
    else if (path.startsWith('/api/access')) category = 'access';
    else if (path.startsWith('/api/profile') || path.startsWith('/api/user')) category = 'user';
    else if (path.startsWith('/api/settings')) category = 'settings';
    else if (path.startsWith('/api/status')) category = 'health';
 
    const severity = res.statusCode >= 500 ? 'error'
                   : res.statusCode === 401 || res.statusCode === 403 ? 'warning'
                   : 'info';
 
    adminLog({
      actor,
      category,
      action:   `${req.method.toLowerCase()}_${path.replace(/\//g, '_').replace(/^_/, '')}`,
      severity,
      http: {
        method:     req.method,
        path,
        statusCode: res.statusCode,
        duration,
        bodySize:   req.headers['content-length'] ? parseInt(req.headers['content-length']) : null,
      },
      detail: {
        query:  Object.keys(req.query).length ? req.query : null,
        body:   req.method !== 'GET' ? sanitiseBody(req.body) : null,
        response: !success && body ? { message: body.message || null } : null,
      },
      success,
      errorMessage: !success ? (body?.message || null) : null,
    });
 
    return originalJson(body);
  };
 
  next();
});
 
