// FEATURE FLAG MIDDLEWARE FACTORY
// ─────────────────────────────────────────────────────────────────────────────
// Usage:  app.post('/api/chat/start', requireFeature('chatEnabled'), ...)
// Returns 503 with a clear message when the feature is disabled in settings.
// Admin and agent tokens always bypass feature flags (they need access for ops).
// ═════════════════════════════════════════════════════════════════════════════

function requireFeature(flagName) {
  const friendlyNames = {
    storeEnabled:      'The store',
    blogEnabled:       'The blog',
    chatEnabled:       'Live chat',
    creatorEnabled:    'The creator program',
    affiliatesEnabled: 'The affiliate program',
  };

  return async function featureFlagGuard(req, res, next) {
    try {
      const settings = await getSettings();

      // Feature is ON — pass through immediately
      if (settings[flagName] !== false) return next();

      // Feature is OFF — but admins and agents can still pass
      const authHeader = req.headers['authorization'];
      if (authHeader && authHeader.startsWith('Bearer ')) {
        const token = authHeader.slice(7);
        try {
          const decoded = jwt.verify(token, JWT_SECRET);
          if (decoded && decoded.userId) {
            const user = await User.findById(decoded.userId)
                                   .select('isAdmin isAgent')
                                   .lean();
            if (user && (user.isAdmin || user.isAgent)) return next();
          }
        } catch (_) {}
      }

      const label = friendlyNames[flagName] || 'This feature';
      return res.status(503).json({
        success:  false,
        disabled: true,
        message:  `${label} is currently disabled. Please check back later.`,
      });

    } catch (err) {
      console.error(`⚠️  requireFeature('${flagName}') error:`, err.message);
      next(); // DB error — pass through rather than block users
    }
  };
}

global.requireFeature = requireFeature;

// Helper: build visitor hash for unique-click deduplication (no PII stored)
function visitorHash(req) {
  const ip = req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.ip || '';
  const ua = req.headers['user-agent'] || '';
  return crypto.createHash('sha256').update(ip + ua).digest('hex').slice(0, 16);
}
 

// Heartbeat to keep connections alive - Every 30 seconds
const heartbeatInterval = setInterval(() => {
  console.log(`\n💓 WebSocket Heartbeat - Active connections: ${wss.clients.size}`);
  
  wss.clients.forEach((ws) => {
    if (ws.isAlive === false) {
      console.log('   ❌ Terminating dead connection');
      return ws.terminate();
    }
    
    ws.isAlive = false;
    ws.ping();
  });
}, 30000);




// Handle WebSocket messages
function handleWebSocketMessage(ws, data) {
  switch (data.type) {
    case 'ping':
      ws.send(JSON.stringify({ 
        type: 'pong', 
        timestamp: new Date().toISOString() 
      }));
      break;
      
    case 'typing':
      if (ws.chatId) {
        broadcastToChat(ws.chatId, {
          type: 'typing',
          userId: data.userId || ws.customerId || ws.agentId,
          isTyping: data.isTyping
        }, ws);
      }
      break;
      
    case 'join_chat':
      console.log(`👤 User joining chat: ${data.chatId}`);
      ws.chatId = data.chatId;
      if (!activeConnections.has(data.chatId)) {
        activeConnections.set(data.chatId, new Set());
      }
      activeConnections.get(data.chatId).add(ws);
      ws.send(JSON.stringify({
        type: 'joined_chat',
        chatId: data.chatId,
        message: 'Successfully joined chat'
      }));
      break;
      
    case 'leave_chat':
      if (ws.chatId && activeConnections.has(ws.chatId)) {
        activeConnections.get(ws.chatId).delete(ws);
        if (activeConnections.get(ws.chatId).size === 0) {
          activeConnections.delete(ws.chatId);
        }
      }
      ws.send(JSON.stringify({
        type: 'left_chat',
        chatId: ws.chatId
      }));
      ws.chatId = null;
      break;
      
    default:
      console.log(`⚠️  Unhandled message type: ${data.type}`);
      ws.send(JSON.stringify({
        type: 'unknown_type',
        message: `Message type '${data.type}' not recognized`
      }));
  }
}

// Helper function to broadcast to chat
function broadcastToChat(chatId, message, excludeWs = null) {
  console.log(`📡 Broadcasting to chat ${chatId}:`, message.type);

  if (activeConnections.has(chatId)) {
    const connections = activeConnections.get(chatId);
    let sentCount = 0;

    connections.forEach((clientWs) => {
      if (clientWs !== excludeWs && clientWs.readyState === WebSocket.OPEN) {
        try {
          clientWs.send(JSON.stringify(message));
          sentCount++;
        } catch (error) {
          console.error('❌ Broadcast error:', error);
        }
      }
    });

    console.log(`✅ Broadcast sent to ${sentCount} connections`);
  } else {
    console.log(`⚠️  No active connections for chat ${chatId}`);
  }
}
// Helper function to send to specific agent
function sendToAgent(agentId, message) {
  const agentWs = agentConnections.get(agentId);
  if (agentWs && agentWs.readyState === WebSocket.OPEN) {
    agentWs.send(JSON.stringify(message));
  }
}

// Helper function to send to specific customer
function sendToCustomer(customerId, message) {
  const customerWs = customerConnections.get(customerId);
  if (customerWs && customerWs.readyState === WebSocket.OPEN) {
    customerWs.send(JSON.stringify(message));
  }
}

