// Helper: derive Cloudinary resource_type from mimetype
function getCloudinaryResourceType(mimetype) {
  if (mimetype.startsWith('image/')) return 'image';
  if (mimetype.startsWith('video/')) return 'video';
  if (mimetype.startsWith('audio/')) return 'video'; // Cloudinary handles audio under 'video'
  return 'raw'; // ZIPs, PDFs, executables, docs
}

// Helper: upload buffer to Cloudinary, returns { secureUrl, publicId, resourceType, bytes }
function uploadToCloudinary(buffer, mimetype, folder, options = {}) {
  return new Promise((resolve, reject) => {
    const resourceType = getCloudinaryResourceType(mimetype);
    const uploadStream = cloudinary.uploader.upload_stream(
      {
        folder,
        resource_type: resourceType,
        use_filename: true,
        unique_filename: true,
        ...options
      },
      (error, result) => {
        if (error) return reject(error);
        resolve({
          secureUrl: result.secure_url,
          publicId:  result.public_id,
          resourceType,
          bytes:     result.bytes,
          format:    result.format,
          duration:  result.duration || null,  // for video/audio
        });
      }
    );
    uploadStream.end(buffer);
  });
}

function parseExternalMediaUrl(rawUrl) {
  if (!rawUrl || typeof rawUrl !== 'string') {
    return { embedType: 'unknown', embedUrl: '', mediaType: 'unknown', mediaCategory: 'unknown' };
  }

  const url = rawUrl.trim();

  // ─────────────────────────────────────────────────────────────────────────
  // VIDEO PLATFORMS
  // ─────────────────────────────────────────────────────────────────────────

  // ── YouTube (video) ──────────────────────────────────────────────────────
  const ytMatch =
    url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/shorts\/)([A-Za-z0-9_-]{11})/) ||
    url.match(/youtube\.com\/embed\/([A-Za-z0-9_-]{11})/);
  if (ytMatch) {
    return {
      embedType:     'youtube',
      embedUrl:      `https://www.youtube.com/embed/${ytMatch[1]}?rel=0&modestbranding=1`,
      mediaType:     'video',
      mediaCategory: 'video',
      videoId:        ytMatch[1],
    };
  }

  // ── Vimeo (video) ────────────────────────────────────────────────────────
  const vimeoMatch = url.match(/vimeo\.com\/(?:video\/)?(\d+)/);
  if (vimeoMatch) {
    return {
      embedType:     'vimeo',
      embedUrl:      `https://player.vimeo.com/video/${vimeoMatch[1]}?byline=0&portrait=0`,
      mediaType:     'video',
      mediaCategory: 'video',
      videoId:        vimeoMatch[1],
    };
  }

  // ── Dailymotion (video) ──────────────────────────────────────────────────
  const dmMatch = url.match(/dailymotion\.com\/video\/([a-zA-Z0-9]+)/);
  if (dmMatch) {
    return {
      embedType:     'dailymotion',
      embedUrl:      `https://www.dailymotion.com/embed/video/${dmMatch[1]}`,
      mediaType:     'video',
      mediaCategory: 'video',
      videoId:        dmMatch[1],
    };
  }

  // ── Google Drive (video) ─────────────────────────────────────────────────
  const driveMatch = url.match(/drive\.google\.com\/file\/d\/([^/]+)/);
  if (driveMatch) {
    return {
      embedType:     'gdrive',
      embedUrl:      `https://drive.google.com/file/d/${driveMatch[1]}/preview`,
      mediaType:     'video',
      mediaCategory: 'video',
      videoId:        driveMatch[1],
    };
  }

  // ─────────────────────────────────────────────────────────────────────────
  // AUDIO PLATFORMS
  // ─────────────────────────────────────────────────────────────────────────

  // ── SoundCloud (audio) ───────────────────────────────────────────────────
  if (url.includes('soundcloud.com/')) {
    return {
      embedType:     'soundcloud',
      embedUrl:      `https://w.soundcloud.com/player/?url=${encodeURIComponent(url)}&color=%2300b359&auto_play=false&hide_related=true&show_comments=false&show_user=true&show_reposts=false&show_teaser=false`,
      mediaType:     'audio',
      mediaCategory: 'audio',
    };
  }

  // ── Spotify (audio) ──────────────────────────────────────────────────────
  // Handles: open.spotify.com/track/ID, /album/ID, /episode/ID, /show/ID
  const spotifyMatch = url.match(/open\.spotify\.com\/(track|album|playlist|episode|show)\/([A-Za-z0-9]+)/);
  if (spotifyMatch) {
    return {
      embedType:     'spotify',
      embedUrl:      `https://open.spotify.com/embed/${spotifyMatch[1]}/${spotifyMatch[2]}?utm_source=generator&theme=0`,
      mediaType:     'audio',
      mediaCategory: 'audio',
    };
  }

  // ── Audiomack (audio) ────────────────────────────────────────────────────
  // Handles: audiomack.com/artist/song/slug, audiomack.com/album/slug
  if (url.includes('audiomack.com/')) {
    // Audiomack embeds use: https://audiomack.com/embed/song/{slug} or /album/{slug}
    const amMatch = url.match(/audiomack\.com\/([^/]+)\/(song|album|playlist)\/([^/?]+)/) ||
                    url.match(/audiomack\.com\/([^/]+)\/([^/?]+)/);
    const embedSrc = amMatch
      ? `https://audiomack.com/embed/${amMatch[1]}/${amMatch[2]}/${amMatch[3] || ''}`.replace(/\/$/, '')
      : `https://audiomack.com/embed/song${url.replace('https://audiomack.com', '')}`;
    return {
      embedType:     'audiomack',
      embedUrl:      embedSrc,
      mediaType:     'audio',
      mediaCategory: 'audio',
    };
  }

  // ── YouTube Music (audio) ────────────────────────────────────────────────
  // music.youtube.com/watch?v=ID
  const ytMusicMatch = url.match(/music\.youtube\.com\/watch\?v=([A-Za-z0-9_-]{11})/);
  if (ytMusicMatch) {
    return {
      embedType:     'youtube_music',
      embedUrl:      `https://www.youtube.com/embed/${ytMusicMatch[1]}?rel=0&modestbranding=1`,
      mediaType:     'audio',
      mediaCategory: 'audio',
      videoId:        ytMusicMatch[1],
    };
  }

  // ── Mixcloud (audio) ─────────────────────────────────────────────────────
  if (url.includes('mixcloud.com/')) {
    const mcPath = url.replace(/^https?:\/\/(?:www\.)?mixcloud\.com/, '').replace(/\/$/, '');
    return {
      embedType:     'mixcloud',
      embedUrl:      `https://www.mixcloud.com/widget/iframe/?hide_cover=1&feed=${encodeURIComponent(`https://www.mixcloud.com${mcPath}/`)}`,
      mediaType:     'audio',
      mediaCategory: 'audio',
    };
  }

  // ── Bandcamp (audio) ─────────────────────────────────────────────────────
  // Bandcamp embed requires track/album ID which is hard to extract from URL alone.
  // Fall back to iframe with the URL as src — works for Bandcamp embed pages.
  if (url.includes('bandcamp.com/')) {
    return {
      embedType:     'bandcamp',
      embedUrl:      url,  // Bandcamp pages can be iframe'd directly
      mediaType:     'audio',
      mediaCategory: 'audio',
    };
  }

  // ── Apple Music (audio) ──────────────────────────────────────────────────
  if (url.includes('music.apple.com/')) {
    const embedUrl = url.replace('music.apple.com/', 'embed.music.apple.com/');
    return {
      embedType:     'apple_music',
      embedUrl,
      mediaType:     'audio',
      mediaCategory: 'audio',
    };
  }

  // ── Deezer (audio) ───────────────────────────────────────────────────────
  const deezerMatch = url.match(/deezer\.com\/(?:[a-z]{2}\/)?(track|album|playlist)\/(\d+)/);
  if (deezerMatch) {
    return {
      embedType:     'deezer',
      embedUrl:      `https://widget.deezer.com/widget/dark/${deezerMatch[1]}/${deezerMatch[2]}`,
      mediaType:     'audio',
      mediaCategory: 'audio',
    };
  }

  // ─────────────────────────────────────────────────────────────────────────
  // DIRECT FILE LINKS
  // ─────────────────────────────────────────────────────────────────────────

  const audioExts = ['.mp3', '.wav', '.ogg', '.flac', '.aac', '.m4a', '.opus'];
  const videoExts = ['.mp4', '.webm', '.mov', '.avi', '.mkv'];
  const lowerUrl  = url.toLowerCase().split('?')[0];

  if (audioExts.some(ext => lowerUrl.endsWith(ext))) {
    return { embedType: 'direct', embedUrl: url, mediaType: 'audio', mediaCategory: 'audio' };
  }
  if (videoExts.some(ext => lowerUrl.endsWith(ext))) {
    return { embedType: 'direct', embedUrl: url, mediaType: 'video', mediaCategory: 'video' };
  }

  // ── Fallback ─────────────────────────────────────────────────────────────
  return { embedType: 'unknown', embedUrl: url, mediaType: 'unknown', mediaCategory: 'unknown' };
}

global.parseExternalMediaUrl = parseExternalMediaUrl;
console.log('✅ External Media URL Parser Loaded');

function generateSecureDeliveryUrl(publicId, resourceType, expiresInSeconds = 3600, forDownload = false, originalName = null) {
  const rt = resourceType || 'raw';

  if (forDownload) {
    if (rt === 'raw') {
      // For raw files (ZIPs, PDFs, executables, docs) — do NOT use fl_attachment.
      // Cloudinary re-wraps raw files when fl_attachment is applied, which adds
      // metadata bytes and causes the file size mismatch seen on download.
      // Instead return the plain secure_url; the /api/download/file proxy route
      // fetches it and sets Content-Disposition: attachment with the real filename.
      return cloudinary.url(publicId, {
        resource_type: 'raw',
        type:          'upload',
        secure:        true,
      });
    }

    // For image/video — fl_attachment is safe, no re-encoding happens
    const rawName  = originalName || publicId.split('/').pop();
    const safeName = rawName.replace(/[^\w.\-]/g, '_'); // URL-safe
    return cloudinary.url(publicId, {
      resource_type: rt,
      type:          'upload',
      flags:         `attachment:${safeName}`,
      secure:        true,
    });
  }

  // Direct streamable URL
  return cloudinary.url(publicId, {
    resource_type: rt,
    type:          'upload',
    secure:        true,
  });
}

