userSchema.pre('save', function(next) {
  this.updatedAt = Date.now();
  if (this.email.toLowerCase() === ADMIN_EMAIL.toLowerCase()) {
    this.isAdmin = true;
  }
  // Auto-clear lockout once the lock window has passed
  if (this.lockUntil && this.lockUntil < Date.now()) {
    this.lockUntil     = undefined;
    this.loginAttempts = 0;
  }
  next();
});

userSchema.index({ isAdmin: 1 });
userSchema.index({ isAgent: 1 });
userSchema.index({ createdAt: -1 });
userSchema.index({ lockUntil: 1 }, { sparse: true });  // fast lockout check

const User = mongoose.model('User', userSchema);


// ✅ Create compound indexes for better query performance
async function createDatabaseIndexes() {
  try {
    // ── Chat ──────────────────────────────────────────────────────────
    await Chat.collection.createIndex({ chatId: 1, status: 1 });
    await Chat.collection.createIndex({ assignedAgent: 1, status: 1 });
    await Chat.collection.createIndex({ customerId: 1, createdAt: -1 });

    // ── User ──────────────────────────────────────────────────────────
    await User.collection.createIndex({ email: 1, isAgent: 1 });

    // ── Order ─────────────────────────────────────────────────────────
    await Order.collection.createIndex({ userId: 1, status: 1, createdAt: -1 });
    await Order.collection.createIndex({ userId: 1, 'paymentInfo.status': 1 });
    await Order.collection.createIndex({ orderReference: 1 }, { unique: true, sparse: true });
    await Order.collection.createIndex({ 'items.id': 1 });
    await Order.collection.createIndex({ 'items.productId': 1 });
    await Order.collection.createIndex({ 'paymentInfo.transactionId': 1 }, { sparse: true });
    await Order.collection.createIndex({ 'paymentInfo.transactionRef': 1 }, { sparse: true });
    await Order.collection.createIndex({ status: 1, createdAt: -1 });          // admin order list
    await Order.collection.createIndex({ createdAt: -1 });                     // recent orders
    await Order.collection.createIndex({ affiliateId: 1 }, { sparse: true }); // affiliate lookups
    await Affiliate.collection.createIndex({ registrationIp: 1 }, { sparse: true }); // fraud: IP multi-account check
    await User.collection.createIndex({ referredByAffiliateCode: 1 }, { sparse: true }); // affiliate referral lookup

    // ── Product ───────────────────────────────────────────────────────
    await Product.collection.createIndex({ creatorProductId: 1 }, { sparse: true });
    await Product.collection.createIndex({ slug: 1 }, { unique: true, sparse: true });
    await Product.collection.createIndex({ title: 1, isActive: 1 });
    await Product.collection.createIndex({ productType: 1, isActive: 1, status: 1 });
    await Product.collection.createIndex({ category: 1, isActive: 1, status: 1 });
    await Product.collection.createIndex({ tags: 1, isActive: 1 });
    await Product.collection.createIndex({ isFeatured: 1, isActive: 1 });
    await Product.collection.createIndex({ rating: -1, isActive: 1 });
    await Product.collection.createIndex({ soldCount: -1, isActive: 1 });
    await Product.collection.createIndex({ viewCount: -1 });
    await Product.collection.createIndex({ publishedAt: -1, status: 1 });
    await Product.collection.createIndex({ creatorId: 1, status: 1 }, { sparse: true });
    // ── Review ────────────────────────────────────────────────────────
    await Review.collection.createIndex({ productId: 1, status: 1 });
    await Review.collection.createIndex({ userId: 1, productId: 1 }, { unique: true });
    await Review.collection.createIndex({ productId: 1, rating: -1 });
    await Review.collection.createIndex({ orderId: 1 }, { sparse: true });
    await Review.collection.createIndex({ createdAt: -1 });

    // ── CreatorProduct ────────────────────────────────────────────────
    await CreatorProduct.collection.createIndex({ productId: 1 }, { sparse: true });
    await CreatorProduct.collection.createIndex({ title: 1, status: 1 });
    await CreatorProduct.collection.createIndex({ creatorId: 1, status: 1 });

    // ── CourseProgress ────────────────────────────────────────────────
    if (typeof CourseProgress !== 'undefined') {
      await CourseProgress.collection.createIndex({ userId: 1, productId: 1 }, { unique: true });
      await CourseProgress.collection.createIndex({ productId: 1 });
    }

    // ── Download ──────────────────────────────────────────────────────
    await Download.collection.createIndex({ userId: 1, downloadedAt: -1 });
    await Download.collection.createIndex({ productId: 1 });

    console.log('✅ Database indexes created successfully');
  } catch (error) {
    console.error('❌ Index creation error:', error);
  }
}


