// ═════════════════════════════════════════════════════════════════════════════
// SETTINGS CACHE  — avoids a DB hit on every request
// ─────────────────────────────────────────────────────────────────────────────
// All code that needs settings calls getSettings() instead of
// SystemSettings.findOne() directly.  The cache is invalidated every time
// settings are saved so the TTL is just a safety net for edge cases.
// ═════════════════════════════════════════════════════════════════════════════

let _settingsCache     = null;   // cached document (plain object)
let _settingsCacheTime = 0;      // epoch ms of last successful load
const SETTINGS_TTL_MS  = 60_000; // 60 seconds safety-net TTL
let _dashboardCache     = null;
let _dashboardCacheTime = 0;
const DASHBOARD_CACHE_TTL = 30 * 1000; // 30 seconds

/**
 * Returns a plain-object snapshot of SystemSettings.
 * First call (or after invalidation) hits MongoDB; subsequent calls within
 * the TTL window return the in-memory copy instantly.
 */
async function getSettings() {
  const now = Date.now();
  if (_settingsCache && (now - _settingsCacheTime) < SETTINGS_TTL_MS) {
    return _settingsCache;
  }

  let doc = await SystemSettings.findOne().lean();
  if (!doc) {
    doc = await ensureSettings();
  }

  _settingsCache     = doc;
  _settingsCacheTime = now;
  return doc;
}

/**
 * Clears the in-memory cache so the next getSettings() call re-reads from DB.
 * Must be called after every settings save — already wired into the PUT route
 * and all toggle/partial-update routes below.
 */
function invalidateSettings() {
  _settingsCache     = null;
  _settingsCacheTime = 0;
  console.log('🔄 Settings cache invalidated');
}

/**
 * Canonical first-boot seed.
 * Creates ONE complete settings document with all fields populated to
 * sensible defaults.  Safe to call multiple times — uses findOneAndUpdate
 * with upsert so it never duplicates.
 */
async function ensureSettings() {
  const defaults = {
    siteName:                 'UYEH TECH',
    siteDescription:          'Your one-stop digital marketplace',
    siteUrl:                  process.env.FRONTEND_URL || 'https://uyehtech.netlify.app',
    contactEmail:             'contact@uyehtech.com',
    supportEmail:             'support@uyehtech.com',
    phone:                    '',
    address:                  '',
    logo:                     '',
    favicon:                  '',
    socialMedia:              { facebook:'', twitter:'', instagram:'', linkedin:'', youtube:'' },
    maintenanceMode:          false,
    maintenanceMessage:       "We're performing scheduled maintenance. We'll be back shortly!",
    maintenanceTitle:         'Under Maintenance',
    maintenanceETA:           '',
    maintenanceBypassToken:   '',
    maintenancePages:         'all',
    allowRegistration:        true,
    requireEmailVerification: true,
    allowGuestCheckout:       true,
    storeEnabled:             true,
    blogEnabled:              true,
    chatEnabled:              true,
    creatorEnabled:           true,
    affiliatesEnabled:        true,
    bannerEnabled:            false,
    bannerText:               '',
    bannerType:               'info',
    bannerLink:               '',
    bannerLinkText:           '',
    bannerDismissible:        true,
    paymentSettings: {
      flutterwaveEnabled: true,
      paystackEnabled:    false,
      stripeEnabled:      false,
    },
    customCSS:         '',
    customJS:          '',
    customHead:        '',
    seoTitle:          'UYEH TECH',
    seoDescription:    '',
    seoKeywords:       '',
    googleAnalyticsId: '',
    facebookPixelId:   '',
    updatedAt:         new Date(),
    updatedBy:         'system',
  };

  const doc = await SystemSettings.findOneAndUpdate(
    {},                              // match the single settings doc
    { $setOnInsert: defaults },      // only write on INSERT — never overwrites existing
    { upsert: true, new: true, lean: true }
  );

  console.log('✅ Settings document ensured');
  return doc;
}


// Export helpers for use in routes and middleware
global.getSettings      = getSettings;
global.invalidateSettings = invalidateSettings;
