// ANALYTICS SCHEMA
// ──────────────────────────────────────────────────────────────────────────────
const analyticsSchema = new mongoose.Schema({
  // One document per calendar day — keyed by UTC midnight
  date:     { type: Date, required: true, unique: true, index: true },
  dateStr:  { type: String, required: true, index: true }, // 'YYYY-MM-DD' for fast string lookups
 
  // ── Traffic ──────────────────────────────────────────────────────────
  pageViews:       { type: Number, default: 0 },
  uniqueVisitors:  { type: Number, default: 0 }, // distinct visitor fingerprints seen today
  sessions:        { type: Number, default: 0 }, // browser sessions started
 
  // ── User growth ───────────────────────────────────────────────────────
  newUsers:        { type: Number, default: 0 },
  verifiedUsers:   { type: Number, default: 0 }, // completed email verification
  deletedUsers:    { type: Number, default: 0 },
 
  // ── Commerce ──────────────────────────────────────────────────────────
  orders:          { type: Number, default: 0 }, // all orders created
  completedOrders: { type: Number, default: 0 }, // status = completed
  failedOrders:    { type: Number, default: 0 },
  refundedOrders:  { type: Number, default: 0 },
  revenue:         { type: Number, default: 0 }, // sum of completed order totals
  avgOrderValue:   { type: Number, default: 0 }, // revenue / completedOrders
  downloads:       { type: Number, default: 0 },
 
  // ── Creator & Affiliate ───────────────────────────────────────────────
  newCreators:     { type: Number, default: 0 }, // applications submitted
  creatorSales:    { type: Number, default: 0 },
  creatorRevenue:  { type: Number, default: 0 },
  affiliateClicks: { type: Number, default: 0 },
  affiliateSales:  { type: Number, default: 0 },
  affiliateRevenue:{ type: Number, default: 0 },
 
  // ── Support ───────────────────────────────────────────────────────────
  chatsStarted:    { type: Number, default: 0 },
  chatsResolved:   { type: Number, default: 0 },
  ticketsCreated:  { type: Number, default: 0 },
  ticketsResolved: { type: Number, default: 0 },
  avgChatResponseTime: { type: Number, default: 0 }, // minutes
 
  // ── Top performers (pre-computed to avoid per-request aggregations) ───
  topProducts: [{
    productId:   { type: mongoose.Schema.Types.ObjectId, ref: 'Product' },
    productName: String,
    productType: String,
    sales:       Number,
    revenue:     Number,
  }],
  topCreatorProducts: [{
    productId:   mongoose.Schema.Types.ObjectId,
    productName: String,
    creatorName: String,
    sales:       Number,
    revenue:     Number,
  }],
  topPages: [{
    page:  String,
    views: Number,
  }],
 
  // ── Breakdowns ────────────────────────────────────────────────────────
  revenueByCategory: [{
    category: String,
    revenue:  Number,
    sales:    Number,
  }],
  trafficSources: [{
    source: { type: String, enum: ['organic','direct','affiliate','social','email','referral','paid','other'] },
    visits: { type: Number, default: 0 },
  }],
  deviceTypes: {
    mobile:  { type: Number, default: 0 },
    desktop: { type: Number, default: 0 },
    tablet:  { type: Number, default: 0 },
    unknown: { type: Number, default: 0 },
  },
 
  // ── Metadata ─────────────────────────────────────────────────────────
  aggregatedAt: Date,   // when the background job last ran for this day
  isComplete:   { type: Boolean, default: false }, // false = today (still accumulating)
 
  createdAt: { type: Date, default: Date.now },
});
 
analyticsSchema.index({ date: -1 });
analyticsSchema.index({ dateStr: 1 });
analyticsSchema.index({ isComplete: 1, date: -1 });
 
const Analytics = mongoose.model('Analytics', analyticsSchema);
global.Analytics = Analytics;
 
// ── In-memory analytics cache — prevents hammering the DB on every tab open ─
const _analyticsCache = new Map();
const ANALYTICS_CACHE_TTL = 5 * 60 * 1000; // 5 minutes
 
function _getCachedAnalytics(key) {
  const entry = _analyticsCache.get(key);
  if (entry && Date.now() - entry.ts < ANALYTICS_CACHE_TTL) return entry.data;
  _analyticsCache.delete(key);
  return null;
}
function _setCachedAnalytics(key, data) {
  _analyticsCache.set(key, { ts: Date.now(), data });
}
// ✅ FIX: Creator list cache — 60s TTL, invalidated on approve/reject/suspend
const _creatorsCache = new Map();
const CREATORS_CACHE_TTL = 60 * 1000;
function _getCachedCreators(key) {
  const entry = _creatorsCache.get(key);
  if (entry && Date.now() - entry.ts < CREATORS_CACHE_TTL) return entry.data;
  _creatorsCache.delete(key);
  return null;
}
function _setCachedCreators(key, data) { _creatorsCache.set(key, { ts: Date.now(), data }); }
function invalidateCreatorsCache()     { _creatorsCache.clear(); }
global.invalidateCreatorsCache = invalidateCreatorsCache;
 
 
// ╔═══════════════════════════════════════════════════════════════════════╗
// ║  PASTE LOCATION 2                                                     ║
// ║  WHERE: After the Analytics model (just after PASTE LOCATION 1)      ║
// ║  This is the analytics engine — the aggregation job and all helpers  ║
// ╚═══════════════════════════════════════════════════════════════════════╝
 
// ── Helper: get today's UTC midnight date ─────────────────────────────────
function _todayUTC() {
  const d = new Date();
  d.setUTCHours(0, 0, 0, 0);
  return d;
}
function _dateToStr(date) {
  return date.toISOString().slice(0, 10); // 'YYYY-MM-DD'
}
 
// ── Real-time event counters — call these throughout the server ───────────
// These use $inc which is atomic — no race conditions, no data loss.
 
/**
 * Increment a real-time counter on today's analytics document.
 * Safe to call from anywhere — creates the document if it doesn't exist.
 * Fire-and-forget: wrapped in setImmediate so it never blocks a response.
 *
 * Usage: trackEvent('orders', 1)  OR  trackEvent({ revenue: 49.99, completedOrders: 1 })
 */
function trackEvent(fieldOrObject, amount = 1) {
  setImmediate(async () => {
    try {
      const today  = _todayUTC();
      const incObj = typeof fieldOrObject === 'string'
        ? { [fieldOrObject]: amount }
        : fieldOrObject;
 
      await Analytics.findOneAndUpdate(
        { date: today },
        {
          $inc:         incObj,
          $setOnInsert: { dateStr: _dateToStr(today), isComplete: false },
        },
        { upsert: true }
      );
    } catch (err) {
      // Never crash a route because analytics failed
      console.warn('⚠️  trackEvent failed (non-fatal):', err.message);
    }
  });
}
global.trackEvent = trackEvent;
 
// Specific helpers used throughout the server
function trackNewUser()         { trackEvent('newUsers'); }
function trackOrderCompleted(revenue) { trackEvent({ completedOrders: 1, orders: 1, revenue }); }
function trackOrderFailed()     { trackEvent({ orders: 1, failedOrders: 1 }); }
function trackOrderRefunded()   { trackEvent('refundedOrders'); }
function trackDownload()        { trackEvent('downloads'); }
function trackChatStarted()     { trackEvent('chatsStarted'); }
function trackChatResolved()    { trackEvent('chatsResolved'); }
function trackTicketCreated()   { trackEvent('ticketsCreated'); }
function trackTicketResolved()  { trackEvent('ticketsResolved'); }
function trackAffiliateClick()  { trackEvent('affiliateClicks'); }
function trackAffiliateSale(revenue) { trackEvent({ affiliateSales: 1, affiliateRevenue: revenue || 0 }); }
function trackCreatorSale(revenue)   { trackEvent({ creatorSales: 1, creatorRevenue: revenue || 0 }); }
function trackNewCreator()      { trackEvent('newCreators'); }
 
global.trackNewUser        = trackNewUser;
global.trackOrderCompleted = trackOrderCompleted;
global.trackOrderFailed    = trackOrderFailed;
global.trackOrderRefunded  = trackOrderRefunded;
global.trackDownload       = trackDownload;
global.trackChatStarted    = trackChatStarted;
global.trackChatResolved   = trackChatResolved;
global.trackTicketCreated  = trackTicketCreated;
global.trackTicketResolved = trackTicketResolved;
global.trackAffiliateClick = trackAffiliateClick;
global.trackAffiliateSale  = trackAffiliateSale;
global.trackCreatorSale    = trackCreatorSale;
global.trackNewCreator     = trackNewCreator;
 
 
// ── Page view middleware — records every frontend page hit ────────────────
// Mounted as app.use() below. Fires only for frontend HTML page GETs,
// never for API routes or static assets.
function analyticsPageViewMiddleware(req, res, next) {
  // Only track GET requests to HTML pages
  if (
    req.method !== 'GET'                    ||
    req.path.startsWith('/api/')            ||
    req.path.startsWith('/ws')              ||
    req.path.includes('.')                  // static assets (.js, .css, .png etc.)
  ) {
    return next();
  }
 
  setImmediate(async () => {
    try {
      const today      = _todayUTC();
      const ua         = req.headers['user-agent'] || '';
      const deviceType = _detectDevice(ua);
 
      // Visitor fingerprint: hash of IP + UA (no cookies, no PII stored)
      const visitorHash = require('crypto')
        .createHash('sha256')
        .update(`${req.ip}:${ua}:${_dateToStr(today)}`)
        .digest('hex')
        .slice(0, 16);
 
      // Check if this fingerprint has been seen today
      const cacheKey = `visitor:${visitorHash}`;
      const seenToday = _analyticsCache.get(cacheKey);
      const isNewVisitor = !seenToday;
      if (isNewVisitor) {
        _analyticsCache.set(cacheKey, { ts: Date.now(), data: true });
      }
 
      const incFields = {
        pageViews: 1,
        [`deviceTypes.${deviceType}`]: 1,
      };
      if (isNewVisitor) incFields.uniqueVisitors = 1;
 
      await Analytics.findOneAndUpdate(
        { date: today },
        {
          $inc:         incFields,
          $setOnInsert: { dateStr: _dateToStr(today), isComplete: false },
        },
        { upsert: true }
      );
    } catch (_) {}
  });
 
  next();
}
 
app.use(analyticsPageViewMiddleware);

function _detectDevice(ua) {
  const u = ua.toLowerCase();
  if (/tablet|ipad/.test(u))               return 'tablet';
  if (/mobile|android|iphone|ipod/.test(u)) return 'mobile';
  if (/mozilla|chrome|safari|edge/.test(u)) return 'desktop';
  return 'unknown';
}
 

// ── Daily analytics aggregation job ──────────────────────────────────────
// Runs at midnight and also on demand. Takes yesterday's raw data and
// enriches it with computed fields (topProducts, AOV, breakdown arrays).
// This is the job that makes the Analytics collection genuinely useful.
 
async function runDailyAnalyticsAggregation(targetDate) {
  const d = targetDate || new Date(Date.now() - 86400000); // default: yesterday
  d.setUTCHours(0, 0, 0, 0);
  const nextDay = new Date(d.getTime() + 86400000);
  const dateStr = _dateToStr(d);
 
  console.log(`📊 Running daily analytics aggregation for ${dateStr}…`);
 
  try {
    // ── Revenue & orders ────────────────────────────────────────────────
    const [orderAgg, failedAgg, refundAgg] = await Promise.all([
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: d, $lt: nextDay } } },
        { $group: { _id: null, count: { $sum: 1 }, revenue: { $sum: '$total' } } },
      ]),
      Order.countDocuments({ status: 'failed',   createdAt: { $gte: d, $lt: nextDay } }),
      Order.countDocuments({ status: 'refunded', createdAt: { $gte: d, $lt: nextDay } }),
    ]);
 
    const completedOrders = orderAgg[0]?.count   || 0;
    const revenue         = orderAgg[0]?.revenue || 0;
    const avgOrderValue   = completedOrders > 0 ? revenue / completedOrders : 0;
    const totalOrders     = await Order.countDocuments({ createdAt: { $gte: d, $lt: nextDay } });
 
    // ── Users ────────────────────────────────────────────────────────────
    const [newUsers, verifiedUsers, deletedUsers] = await Promise.all([
      User.countDocuments({ createdAt: { $gte: d, $lt: nextDay } }),
      User.countDocuments({ emailVerifiedAt: { $gte: d, $lt: nextDay } }),
      User.countDocuments({ deletedAt: { $gte: d, $lt: nextDay } }),
    ]);
 
    // ── Downloads ────────────────────────────────────────────────────────
    const downloads = await Download.countDocuments({ downloadedAt: { $gte: d, $lt: nextDay } });
 
    // ── Creator & affiliate ──────────────────────────────────────────────
    const [creatorLedger, affiliateLedger, newCreators, affiliateClicks] = await Promise.all([
      EarningsLedger.aggregate([
        { $match: { recipientType: 'creator', createdAt: { $gte: d, $lt: nextDay } } },
        { $group: { _id: null, count: { $sum: 1 }, total: { $sum: '$earningAmount' } } },
      ]),
      EarningsLedger.aggregate([
        { $match: { recipientType: 'affiliate', createdAt: { $gte: d, $lt: nextDay } } },
        { $group: { _id: null, count: { $sum: 1 }, total: { $sum: '$earningAmount' } } },
      ]),
      Creator.countDocuments({ createdAt: { $gte: d, $lt: nextDay } }),
      AffiliateClick.countDocuments({ clickedAt: { $gte: d, $lt: nextDay } }),
    ]);
 
    const creatorSales    = creatorLedger[0]?.count   || 0;
    const creatorRevenue  = creatorLedger[0]?.total   || 0;
    const affiliateSales  = affiliateLedger[0]?.count || 0;
    const affiliateRevenue= affiliateLedger[0]?.total || 0;
 
    // ── Support ──────────────────────────────────────────────────────────
    const [chatsStarted, chatsResolved, ticketsCreated, ticketsResolved, chatTimingAgg] = await Promise.all([
      Chat.countDocuments({ createdAt: { $gte: d, $lt: nextDay } }),
      Chat.countDocuments({ status: 'resolved', updatedAt: { $gte: d, $lt: nextDay } }),
      SupportTicket.countDocuments({ createdAt: { $gte: d, $lt: nextDay } }),
      SupportTicket.countDocuments({ status: 'closed', closedAt: { $gte: d, $lt: nextDay } }),
      Chat.aggregate([
        { $match: { firstResponseTime: { $exists: true, $ne: null }, createdAt: { $gte: d, $lt: nextDay } } },
        { $group: { _id: null, avg: { $avg: '$firstResponseTime' } } },
      ]),
    ]);
    const avgChatResponseTime = chatTimingAgg[0]?.avg || 0;
 
    // ── Top products ─────────────────────────────────────────────────────
    const [topProducts, topCreatorProducts] = await Promise.all([
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: d, $lt: nextDay } } },
        { $unwind: '$items' },
        { $group: {
          _id: '$items.productId',
          productName: { $first: '$items.title' },
          productType: { $first: '$items.productType' },
          sales:   { $sum: 1 },
          revenue: { $sum: '$items.price' },
        }},
        { $sort: { revenue: -1 } },
        { $limit: 10 },
      ]),
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: d, $lt: nextDay }, 'items.isCreatorProduct': true } },
        { $unwind: '$items' },
        { $match: { 'items.isCreatorProduct': true } },
        { $group: {
          _id: '$items.productId',
          productName: { $first: '$items.title' },
          sales:   { $sum: 1 },
          revenue: { $sum: '$items.price' },
        }},
        { $sort: { revenue: -1 } },
        { $limit: 10 },
      ]),
    ]);
 
    // ── Revenue by category ───────────────────────────────────────────────
    const revenueByCategory = await Order.aggregate([
      { $match: { status: 'completed', createdAt: { $gte: d, $lt: nextDay } } },
      { $unwind: '$items' },
      { $group: {
        _id: '$items.category',
        revenue: { $sum: '$items.price' },
        sales:   { $sum: 1 },
      }},
      { $sort: { revenue: -1 } },
    ]);
 
    // ── Write or update today's analytics document ────────────────────────
    await Analytics.findOneAndUpdate(
      { date: d },
      {
        $set: {
          dateStr,
          completedOrders,
          totalOrders,
          revenue,
          avgOrderValue:   parseFloat(avgOrderValue.toFixed(2)),
          failedOrders:    failedAgg,
          refundedOrders:  refundAgg,
          newUsers,
          verifiedUsers,
          deletedUsers,
          downloads,
          newCreators,
          creatorSales,
          creatorRevenue,
          affiliateClicks,
          affiliateSales,
          affiliateRevenue,
          chatsStarted,
          chatsResolved,
          ticketsCreated,
          ticketsResolved,
          avgChatResponseTime: parseFloat(avgChatResponseTime.toFixed(1)),
          topProducts,
          topCreatorProducts,
          revenueByCategory,
          aggregatedAt: new Date(),
          isComplete:   targetDate ? false : true, // only mark complete for past days
        },
      },
      { upsert: true, new: true }
    );
 
    invalidateAnalyticsCache();
    console.log(`✅ Analytics aggregation complete for ${dateStr} — revenue: $${revenue.toFixed(2)}, orders: ${completedOrders}`);
    return true;
 
  } catch (err) {
    console.error(`❌ Analytics aggregation failed for ${dateStr}:`, err.message);
    return false;
  }
}
 
global.runDailyAnalyticsAggregation = runDailyAnalyticsAggregation;
 

// ── Notification Schema ────────────────────────────────────────────────────
const notificationSchema = new mongoose.Schema({
  // Who receives this notification
  recipientId:   { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true, index: true },
  recipientRole: { type: String, enum: ['user', 'agent', 'admin', 'creator', 'affiliate'], default: 'user' },
 
  // What it says
  type: {
    type: String,
    required: true,
    enum: [
      'order_completed',     // user bought something
      'order_failed',        // payment failed
      'order_refunded',      // order was refunded
      'sale',                // creator/affiliate made a sale
      'payout_requested',    // payout request submitted
      'payout_approved',     // payout approved by admin
      'payout_rejected',     // payout rejected
      'product_approved',    // creator product approved
      'product_rejected',    // creator product rejected
      'creator_approved',    // creator application approved
      'creator_rejected',    // creator application rejected
      'chat_assigned',       // agent was assigned a chat
      'ticket_assigned',     // agent was assigned a ticket
      'ticket_reply',        // someone replied to a ticket
      'download_ready',      // file is ready to download
      'certificate_ready',   // course certificate generated
      '2fa_enabled',
      '2fa_disabled',
      '2fa_backup_used',
      'system',              // admin broadcast message
      'review_received',     // product received a new review
      'follower_new',        // someone followed a creator
      'badge',               // achievement unlocked
    ],
    index: true,
  },
 
  title:   { type: String, required: true },
  message: { type: String, required: true },
 
  // Optional structured data — link, icon, amounts, IDs for deep linking
  data: {
    url:        String,   // where to navigate on click
    icon:       String,   // emoji or icon class
    orderId:    mongoose.Schema.Types.ObjectId,
    productId:  mongoose.Schema.Types.ObjectId,
    chatId:     String,
    ticketId:   String,
    amount:     Number,
    currency:   { type: String, default: 'USD' },
    extra:      mongoose.Schema.Types.Mixed,
  },
 
  read:      { type: Boolean, default: false, index: true },
  readAt:    Date,
 
  // Soft-delete — user can dismiss without DB delete
  dismissed: { type: Boolean, default: false },
 
  createdAt: { type: Date, default: Date.now, index: true },
});
 
// Compound indexes for fast unread counts and paginated fetches
notificationSchema.index({ recipientId: 1, read: 1, createdAt: -1 });
notificationSchema.index({ recipientId: 1, createdAt: -1 });
// Auto-expire notifications after 90 days (optional — remove TTL if you want to keep all)
notificationSchema.index({ createdAt: 1 }, { expireAfterSeconds: 90 * 24 * 60 * 60 });
 
const Notification = mongoose.model('Notification', notificationSchema);
global.Notification = Notification;

// ========== COUPON SCHEMA ==========
const couponSchema = new mongoose.Schema({
  code:              { type: String, required: true, unique: true, uppercase: true, trim: true },
  discount:          { type: Number, required: true, min: 0 },
  type:              { type: String, enum: ['percentage', 'fixed'], required: true },
  isActive:          { type: Boolean, default: false },     // only true after admin approval
  usageLimit:        { type: Number, default: null },
  usageCount:        { type: Number, default: 0 },
  usedBy:            [{ type: mongoose.Schema.Types.ObjectId, ref: 'User' }],
  expiresAt:         { type: Date, default: null },
  minPurchaseAmount: { type: Number, default: 0 },
  maxDiscountAmount: { type: Number, default: null },
  description:       { type: String, default: '' },
  createdBy:         { type: mongoose.Schema.Types.ObjectId, ref: 'User' },

  // ── Creator-scoping ───────────────────────────────────────────────────────
  // ownerCreatorId: set for all creator-generated coupons.
  // null = platform-level coupon (admin only, works on all products).
  ownerCreatorId:       { type: mongoose.Schema.Types.ObjectId, ref: 'Creator', default: null },

  // applicableCreators kept for backward compat but ownerCreatorId is the authority
  applicableCreators:   [{ type: mongoose.Schema.Types.ObjectId, ref: 'Creator' }],
  applicableCategories: [String],

  // Specific product IDs within the creator's catalogue that this coupon applies to.
  // Empty array = all of the creator's products (default behaviour).
  applicableProducts:   [{ type: mongoose.Schema.Types.ObjectId, ref: 'Product' }],

  // Creator-controlled opt-in list — product IDs that the creator has explicitly
  // opted IN or OUT. Managed via PATCH /api/creator/coupons/:id/products
  allowedProductIds: [{ type: mongoose.Schema.Types.ObjectId, ref: 'Product' }],

  singleUsePerUser: { type: Boolean, default: false },

  // ── Monetisation workflow ─────────────────────────────────────────────────
  // paymentStatus flow:
  //   'unpaid'  → coupon just created, waiting for creator to pay the 20% fee
  //   'paid'    → Flutterwave tx verified; now waiting for admin approval
  //   'refunded'→ admin rejected after payment (admin should refund manually)
  paymentStatus:  {
    type:    String,
    enum:    ['unpaid', 'paid', 'refunded'],
    default: 'unpaid',
  },
  paymentFee:     { type: Number, default: 0 },   // 20% of (discountValue × quantity) in NGN
  paymentTxRef:   { type: String, default: null }, // Flutterwave tx_ref after payment
  paymentTxId:    { type: String, default: null }, // Flutterwave transaction ID

  // adminApprovalStatus:
  //   'pending'  → paid, awaiting admin review
  //   'approved' → admin activated it (isActive becomes true)
  //   'rejected' → admin rejected (isActive stays false)
  adminApprovalStatus: {
    type:    String,
    enum:    ['none', 'pending', 'approved', 'rejected'],
    default: 'none',
  },
  adminNote:      { type: String, default: null },
  approvedBy:     { type: mongoose.Schema.Types.ObjectId, ref: 'User', default: null },
  approvedAt:     { type: Date, default: null },

  createdAt: { type: Date, default: Date.now }
});

couponSchema.index({ code: 1 });
couponSchema.index({ isActive: 1, expiresAt: 1 });
couponSchema.index({ ownerCreatorId: 1 });
couponSchema.index({ paymentStatus: 1, adminApprovalStatus: 1 });

const Coupon = mongoose.model('Coupon', couponSchema);
// ─────────────────────────────────────────────────────────────────────────────
// COUPON USAGE TRACKING — replaces the usedBy array for scale
// ─────────────────────────────────────────────────────────────────────────────
const couponUsageSchema = new mongoose.Schema({
  couponCode: { type: String, required: true, uppercase: true, trim: true },
  userId:     { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
  orderId:    { type: mongoose.Schema.Types.ObjectId, ref: 'Order', default: null },
  usedAt:     { type: Date, default: Date.now },
});

// Compound unique index — one record per user per coupon, looked up in O(log n)
couponUsageSchema.index({ couponCode: 1, userId: 1 }, { unique: true });
couponUsageSchema.index({ userId: 1 });
couponUsageSchema.index({ couponCode: 1 });

const CouponUsage = mongoose.model('CouponUsage', couponUsageSchema);

