// CREATOR/SELLER SCHEMA
// ═══════════════════════════════════════════════

const creatorSchema = new mongoose.Schema({
  userId: { 
    type: mongoose.Schema.Types.ObjectId, 
    ref: 'User', 
    required: true, 
    unique: true 
  },
  
  // Store Identity
  storeName: { type: String, required: true, unique: true, trim: true },
  storeSlug: { type: String, required: true, unique: true, lowercase: true },
  storeDescription: { type: String, maxlength: 500 },
  storeLogo: String,
  storeBanner: String,
  
  // Personal/Business Info
  businessName: String,
  businessType: { 
    type: String, 
    enum: ['individual', 'company', 'freelancer'], 
    default: 'individual' 
  },
  country: String,
  phone: String,
  website: String,
  socialLinks: {
    twitter:   String,
    instagram: String,
    linkedin:  String,
    youtube:   String,
    tiktok:    String,
  },
  categories: [{ type: String }],

  // Creator identity — used in public profile and marketplace search
  bio:             { type: String, maxlength: 1000, default: null },  // personal bio, different from storeDescription
  skills:          [{ type: String, trim: true }],                    // e.g. ['React', 'UI Design', 'Branding']
  portfolioLinks:  [{
    label: { type: String, trim: true },  // e.g. "Dribbble", "GitHub", "My Work"
    url:   { type: String, trim: true },
  }],
  yearsExperience: { type: Number, default: null, min: 0, max: 60 },
  languages:       [{ type: String, trim: true }],                    // e.g. ['English', 'Yoruba']

  // Creator notification preferences (creator-specific, extends User.notificationPreferences)
  creatorNotifPrefs: {
    newSale:        { type: Boolean, default: true },
    newReview:      { type: Boolean, default: true },
    newFollower:    { type: Boolean, default: true },
    payoutUpdate:   { type: Boolean, default: true },
    productUpdate:  { type: Boolean, default: true },
    weeklySummary:  { type: Boolean, default: false },
  },

  // Application / Approval
  applicationStatus: { 
    type: String, 
    enum: ['pending', 'approved', 'rejected', 'suspended'], 
    default: 'pending' 
  },
  applicationMessage: String,   // Creator's reason for joining
  rejectionReason: String,       // Admin's reason for rejection
  reviewedBy: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  reviewedAt: Date,
  approvedAt: Date,

  // Commission Settings (set by admin per creator or globally)
  platformCommissionRate: { type: Number, default: 20, min: 0, max: 100 }, // % platform takes
  affiliateCommissionRate: { type: Number, default: 10, min: 0, max: 100 }, // % affiliates earn

  // Payout Info
  payoutMethod: { 
    type: String, 
    enum: ['bank_transfer', 'paypal', 'flutterwave', 'crypto'], 
    default: 'bank_transfer' 
  },
 payoutDetails: {
  // Common
  country:       String,
  // Bank transfer
  bankName:      String,
  accountNumber: String,
  accountName:   String,
  sortCode:      String,   // UK sort code / branch code
  swift:         String,   // SWIFT/BIC for international
  iban:          String,   // Europe/UK
  routingNumber: String,   // USA ACH routing
  otherDetails:  String,   // Free text for other countries
  // PayPal
  paypalEmail:   String,
  paypalName:    String,
  // Flutterwave
  flwEmail:      String,
  flwAccount:    String,
  flwBank:       String,
  flwCountry:    String,
  // Crypto
  cryptoType:    String,   // e.g. USDT_TRC20
  cryptoAddress: String,
  cryptoName:    String,
},
  payoutThreshold: { type: Number, default: 50 }, // Minimum to request payout
  
  // Analytics
  totalProducts: { type: Number, default: 0 },
  totalSales: { type: Number, default: 0 },
  totalRevenue: { type: Number, default: 0 },      // Raw revenue before commission
  totalEarnings: { type: Number, default: 0 },     // After platform commission
  pendingPayout: { type: Number, default: 0 },     // Awaiting withdrawal
  totalPaidOut: { type: Number, default: 0 },
  
  // Status
  isVerified: { type: Boolean, default: false },    // Verified badge
  isFeatured: { type: Boolean, default: false },
  isSuspended: { type: Boolean, default: false },
  suspensionReason: String,
  
  rating: { type: Number, default: 0, min: 0, max: 5 },
  totalRatings: { type: Number, default: 0 },
  
  createdAt: { type: Date, default: Date.now },
  updatedAt: { type: Date, default: Date.now }
});

creatorSchema.pre('save', function(next) {
  this.updatedAt = Date.now();
  if (!this.storeSlug && this.storeName) {
    this.storeSlug = this.storeName.toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '');
  }
  next();
});

creatorSchema.index({ storeSlug: 1 });
creatorSchema.index({ applicationStatus: 1, createdAt: -1 });  // compound: faster admin list queries
creatorSchema.index({ userId: 1 });                             // speeds up .populate('userId') join
creatorSchema.index(
  { storeName: 'text', bio: 'text', skills: 'text' },
  { weights: { storeName: 10, skills: 5, bio: 1 }, name: 'creator_text_search' }
);
creatorSchema.index({ userId: 1 });
creatorSchema.index({ applicationStatus: 1, createdAt: -1 });
const Creator = mongoose.model('Creator', creatorSchema);


