// ══════════════════════════════════════════════════════════════════════════════
// CORRECTED productSchema
// Replace your ENTIRE existing productSchema block with this one.
// The creator-related fields now appear exactly ONCE, at the bottom.
// ══════════════════════════════════════════════════════════════════════════════

const productSchema = new mongoose.Schema({

  // ── Core product fields ───────────────────────────────────────────────────
  title:          { type: String, required: true, trim: true },
  description:    { type: String, required: true },
  category:       { type: String, required: true },
  price:          { type: Number, required: true, min: 0 },
  comparePrice:   { type: Number, default: 0 },
  icon:           String,
  image:          String,
  images:         [String],
  features:       [String],

  // Download / file info
  downloadLink:   { type: String, default: '' },
  fileSize:       String,
  version:        String,
  requirements:   [String],

  // ── Product Type & Delivery Mode ─────────────────────────────────────────
  // productType drives how the product is delivered and displayed
  productType: {
    type: String,
    enum: ['download', 'course', 'software', 'music', 'video', 'template', 'script', 'component', 'ebook', 'other'],
    default: 'download'
  },

  // ── Hosted File (replaces / extends downloadLink) ────────────────────────
  // When a file is uploaded directly to Cloudinary instead of using an external link
  hostedFile: {
    publicId:     String,           // Cloudinary public_id
    secureUrl:    String,           // full Cloudinary URL (not exposed to buyers directly)
    resourceType: String,           // 'raw' | 'video' | 'image'
    bytes:        Number,
    format:       String,
    uploadedAt:   { type: Date, default: Date.now }
  },

    externalVideoUrl: { type: String, default: null },
  externalAudioUrl: { type: String, default: null },
  embedType: {
    type: String,
    enum: ['youtube','vimeo','soundcloud','dailymotion','gdrive','direct','unknown',
      'spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer', null],
    default: null
  },
  embedUrl:  { type: String, default: null },
 
  mediaType: {
    type:    String,
    enum:    ['video', 'audio', 'file', 'course', null],
    default: null
  },
  
  // ── Preview / Demo ────────────────────────────────────────────────────────
  previewUrl:   String,             // hosted preview/demo URL (public, no auth needed)
  previewType:  {                   // how to display the preview
    type: String,
    enum: ['video', 'audio', 'image', 'iframe', 'none'],
    default: 'none'
  },

  // ── Course Structure ──────────────────────────────────────────────────────
  // Only populated when productType === 'course'
  courseData: {
    totalDuration:  Number,         // total seconds
    totalChapters:  Number,
    totalSections:  Number,
    level:          { type: String, enum: ['beginner', 'intermediate', 'advanced', 'all'], default: 'all' },
    language:       { type: String, default: 'English' },
    certificate:    { type: Boolean, default: false },
    whatYouLearn:   [String],       // bullet points: "By the end you will..."
    targetAudience: [String],       // bullet points: "This course is for..."
    welcomeMessage:    String,      // shown when student first opens the course
    completionMessage: String,      // shown when student finishes all chapters
    sections: [
      {
        sectionTitle:       String,
        sectionDescription: String,
        sectionOrder:       Number,
        chapters: [
          {
            chapterTitle:   String,
            chapterOrder:   Number,
            duration:       Number,      // seconds
            isFree:         { type: Boolean, default: false },  // free preview chapter
            hostedFile: {
              publicId:     String,
              secureUrl:    String,
              resourceType: String,
              bytes:        Number,
              format:       String,
            },
            chapterType:    { type: String, enum: ['video','audio','text','pdf'], default: 'video' },
            mediaType:      { type: String, enum: ['video','audio','document',null], default: null },
            // Separate video and audio embed URLs — set automatically by server on save
            embedVideoUrl:  String,   // resolved embed URL for video platforms (YouTube, Vimeo, etc.)
            embedAudioUrl:  String,   // resolved embed URL for audio platforms (SoundCloud, Spotify, etc.)
            embedVideoType: { type: String, enum: ['youtube','vimeo','dailymotion','gdrive','direct',null], default: null },
            embedAudioType: { type: String, enum: ['soundcloud','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer','direct',null], default: null },
            // Legacy single-field — kept for backwards compat, populated from video/audio fields
            externalUrl:    String,
            embedUrl:       String,
            embedType:      { type: String, enum: ['youtube','vimeo','soundcloud','dailymotion','gdrive','direct','unknown','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer', null], default: null },
             playerType:     { type: String, enum: ['iframe','html5_video','html5_audio','cloudinary','cloudinary_audio','soundcloud_widget','pdf_viewer','audio_embed', null], default: null },
            transcript:     String,
            notes:          String,  // creator's written notes shown to student
            // Resource links — creator adds these for students to click
            resources: [{
              label:   String,   // e.g. "Download slides", "GitHub repo", "Article link"
              url:     String,
              type:    { type: String, enum: ['link','file','github','article','video','audio','other'], default: 'link' },
            }],
          }
        ]
      }
    ]
  },

  /// ── Music / Audio metadata ─────────────────────────────────────────────────
  audioData: {
    bpm:            Number,
    key:            String,           // e.g. "C minor"
    genre:          String,
    mood:           String,
    duration:       Number,           // seconds
    stems:          { type: Boolean, default: false },
    hasVocals:      { type: Boolean, default: false },
    loopable:       { type: Boolean, default: false },
    license:        { type: String, enum: ['personal', 'commercial', 'exclusive'], default: 'personal' },
    trackTitle:     String,           // display title separate from product title
    artist:         String,
    album:          String,
    releaseYear:    Number,
    instruments:    [String],         // e.g. ['piano', 'drums', 'guitar']
    allowedUses:    [String],         // e.g. ['YouTube', 'Podcasts', 'Ads']
    isrc:           String,           // International Standard Recording Code
    waveformUrl:    String,           // URL to waveform image for player UI
    previewStartTime: { type: Number, default: 0 }, // seconds into track where preview starts
  },

  // ── Software metadata ─────────────────────────────────────────────────────
  softwareData: {
    platform:      [String],
    licenseType:   { type: String, enum: ['single', 'multi', 'lifetime', 'subscription'], default: 'single' },
    maxDevices:    { type: Number, default: 1 },
    licenseKeys:   [String],         // available (unissued) key pool
    issuedKeys: [{                   // audit trail of issued keys
      key:      String,
      orderId:  { type: mongoose.Schema.Types.ObjectId, ref: 'Order' },
      userId:   { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
      issuedAt: { type: Date, default: Date.now },
      revoked:  { type: Boolean, default: false },
      revokedAt: Date,
      revokedReason: String,
    }],
    activationUrl:  String,
    supportPeriod:  String,
    updatePeriod:   String,
    trialDays:      { type: Number, default: 0 },
    demoUrl:        String,
    repoUrl:        String,
    minOsVersion:   String,
    architecture:   [String],
    changelog:      String,
  },
// ── Video product metadata ────────────────────────────────────────────────
  // Only populated when productType === 'video'
  videoData: {
    duration:       Number,         // total seconds
    resolution:     { type: String, enum: ['360p','480p','720p','1080p','4K', null], default: null },
    genre:          String,         // e.g. 'Documentary', 'Tutorial', 'Short Film'
    language:       { type: String, default: 'English' },
    subtitles:      [String],       // available subtitle languages
    hasCaption:     { type: Boolean, default: false },
    director:       String,
    cast:           [String],
    releaseYear:    Number,
    license:        { type: String, enum: ['personal','commercial','exclusive'], default: 'personal' },
    allowDownload:  { type: Boolean, default: false }, // whether buyer can download or stream-only
    waveformUrl:    String,         // optional visual thumbnail / poster frame
  },

  // ── eBook metadata ────────────────────────────────────────────────────────
  ebookData: {
    pageCount:       Number,
    language:        { type: String, default: 'English' },
    isbn:            String,
    author:          String,
    publisher:       String,
    edition:         String,
    publicationYear: Number,
    format:          [String],        // ['PDF', 'EPUB', 'MOBI']
    readingTimeMin:  Number,          // estimated reading time in minutes
  },

  // ── Template / Script / Component metadata ────────────────────────────────
  designData: {
    framework:   [String],            // ['React', 'Vue', 'HTML', 'Next.js', 'Angular']
    stack:       [String],            // ['Tailwind', 'Bootstrap', 'SCSS']
    compatible:  [String],            // ['WordPress', 'Shopify', 'Webflow']
    responsive:  { type: Boolean, default: true },
    darkMode:    { type: Boolean, default: false },
    livePreviewUrl: String,
    repoUrl:     String,
    figmaUrl:    String,
    browserSupport: [String],         // ['Chrome', 'Firefox', 'Safari', 'Edge']
  },

  // ── Universal product fields ──────────────────────────────────────────────
  slug:           { type: String, unique: true, sparse: true, lowercase: true, trim: true },
  viewCount:      { type: Number, default: 0 },
  publishedAt:    { type: Date, default: null },
  status:         { type: String, enum: ['draft', 'published', 'archived'], default: 'published' },
  refundPolicy:   { type: String, enum: ['no_refund', '7_day', '14_day', '30_day', 'custom'], default: 'no_refund' },
  refundDays:     { type: Number, default: 0 },        // used when refundPolicy = 'custom'
  licenseText:    String,                               // full license body shown on product page
  usageRights:    String,                               // short plain-English summary of usage
  notes:          String,                               // creator's notes for buyers (social links, instructions, etc.)
  faqs: [{
    question: { type: String, required: true },
    answer:   { type: String, required: true },
    order:    { type: Number, default: 0 },
  }],

  // Visibility & merchandising
  isActive:       { type: Boolean, default: true },
  isFeatured:     { type: Boolean, default: false },
  stock:          { type: Number, default: 999 },
  soldCount:      { type: Number, default: 0 },

  // Reviews
  rating:         { type: Number, default: 0, min: 0, max: 5 },
  reviewCount:    { type: Number, default: 0 },

  // Discovery
  tags:           [String],

  // SEO
  seoTitle:       String,
  seoDescription: String,
  seoKeywords:    [String],

  // ── Creator marketplace fields
  isCreatorProduct: { type: Boolean, default: false },
  isAdminProduct:   { type: Boolean, default: true  },
  creatorId:        { type: mongoose.Schema.Types.ObjectId, ref: 'Creator'        },
  creatorProductId: { type: mongoose.Schema.Types.ObjectId, ref: 'CreatorProduct' },

  // Timestamps
  createdAt:                 { type: Date, default: Date.now },
  updatedAt:                 { type: Date, default: Date.now },
  lastStatsRecalculatedAt:   Date,   // set by nightly reconciliation job
  publishedAt:               Date,
});

productSchema.pre('save', function (next) {
  this.updatedAt = Date.now();
  const t = this.productType;

  // ── Auto-generate slug from title if not set ──────────────────────────
  if (!this.slug && this.title) {
    this.slug = this.title
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '')
      .substring(0, 80);
  }

  // ── Stamp publishedAt when status first set to published ─────────────
  if (this.status === 'published' && !this.publishedAt) {
    this.publishedAt = new Date();
  }

  // ── Type-specific guards ──────────────────────────────────────────────
  if (t === 'course') {
    if (!this.courseData) {
      this.courseData = { sections: [], totalSections: 0, totalChapters: 0, totalDuration: 0 };
    }
    if (!Array.isArray(this.courseData.sections)) this.courseData.sections = [];
    this.downloadLink = '';
  }
  if (['download','template','script','component','ebook'].includes(t)) {
    if (this.courseData && this.isModified('productType')) this.courseData = undefined;
  }
  if (t === 'music') {
    if (!this.audioData) this.audioData = {};
    if (this.isModified('productType')) this.courseData = undefined;
  }
  if (t === 'software') {
    if (!this.softwareData) this.softwareData = {};
    if (this.isModified('productType')) this.courseData = undefined;
  }
  if (t === 'ebook') {
    if (!this.ebookData) this.ebookData = {};
  }
  if (['template','script','component'].includes(t)) {
    if (!this.designData) this.designData = {};
  }
  next();
});

const Product = mongoose.model('Product', productSchema);
 productSchema.index({ title: 'text', description: 'text', category: 'text', tags: 'text' }, 
  { weights: { title: 10, tags: 5, category: 3, description: 1 }, name: 'product_text_search' });

