// CREATOR PRODUCT SCHEMA  ← THIS WAS MISSING — ADD THIS BLOCK
// ═══════════════════════════════════════════════════════════════

const creatorProductSchema = new mongoose.Schema({
  creatorId:    { type: mongoose.Schema.Types.ObjectId, ref: 'Creator', required: true },
  productId:    { type: mongoose.Schema.Types.ObjectId, ref: 'Product' }, // set after approval
 
  // ── Core fields submitted by creator ─────────────────────────────────────
  title:          { type: String, required: true, trim: true },
  description:    { type: String, required: true },
  category:       { type: String, default: 'General' },
  suggestedPrice: { type: Number, required: true, min: 0 },
  tags:           [String],
  images:         [String],
  fileSize:       String,
  version:        String,
  features:       [String],
  requirements:   [String],
 
  // ── Product type ──────────────────────────────────────────────────────────
  productType: {
    type:    String,
    enum:    ['download', 'course', 'software', 'music', 'video', 'template', 'script', 'component', 'ebook', 'other'],
    default: 'download'
  },
 
  // ── DELIVERY: Option A — Uploaded file (Cloudinary) ──────────────────────
  // Used for: scripts, templates, PDFs, ZIPs, small files
  // NOT used for: video or audio (those use Option B below)
  downloadLink:   String,    // kept for backwards compatibility / admin products
  hostedFile: {
    publicId:     String,
    secureUrl:    String,
    resourceType: String,   // 'raw' | 'image'
    bytes:        Number,
    format:       String,
    uploadedAt:   { type: Date, default: Date.now }
  },
 
  // ── DELIVERY: Option B — External media links (Video / Audio) ─────────────
  // Used for: YouTube, Vimeo, SoundCloud, Google Drive, direct .mp4/.mp3 links
  // These are GATED — only revealed after payment is verified.
  externalVideoUrl: {
    type:    String,
    default: null
    // Example: 'https://www.youtube.com/watch?v=abc123'
  },
  externalAudioUrl: {
    type:    String,
    default: null
    // Example: 'https://soundcloud.com/artist/trackname'
  },
 
  // ── Parsed/computed embed info (auto-filled by server on save) ────────────
  embedType: {
    type: String,
    enum: ['youtube','vimeo','soundcloud','dailymotion','gdrive','direct','unknown',
      'spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer', null],
    default: null
  },
  embedUrl: {
    // The ready-to-use embed URL (e.g. youtube.com/embed/ID)
    // Generated by parseExternalMediaUrl() — never set manually by creator
    type:    String,
    default: null
  },
  mediaType: {
    // 'video' | 'audio' | 'file' | 'course' — drives how the product player renders
    type:    String,
    enum:    ['video', 'audio', 'file', 'course', null],
    default: null
  },
 
  // ── Preview (public, visible before purchase) ─────────────────────────────
  previewUrl:  { type: String, default: null }, // short clip or thumbnail
  previewType: {
    type:    String,
    enum:    ['video', 'audio', 'image', 'iframe', 'none'],
    default: 'none'
  },
 
  // ── Course / Audio / Software structured metadata ─────────────────────────
  courseData: {
    totalDuration:  Number,
    totalChapters:  Number,
    totalSections:  Number,
    level:          { type: String, enum: ['beginner', 'intermediate', 'advanced', 'all'], default: 'all' },
    language:       { type: String, default: 'English' },
    certificate:    { type: Boolean, default: false },
    whatYouLearn:   [String],
    targetAudience: [String],
    welcomeMessage:    String,
    completionMessage: String,
    sections: [
      {
        sectionTitle:       String,
        sectionDescription: String,
        sectionOrder:       Number,
        chapters: [
          {
            chapterTitle:   String,
            chapterOrder:   Number,
            duration:       Number,
            isFree:         { type: Boolean, default: false },
            hostedFile: {
              publicId:     String,
              secureUrl:    String,
              resourceType: String,
              bytes:        Number,
              format:       String,
            },
          chapterType:    { type: String, enum: ['video','audio','text','pdf'], default: 'video' },
            mediaType:      { type: String, enum: ['video','audio','document',null], default: null },
            // Separate video and audio embed URLs
            embedVideoUrl:  String,
            embedAudioUrl:  String,
            embedVideoType: { type: String, enum: ['youtube','vimeo','dailymotion','gdrive','direct',null], default: null },
            embedAudioType: { type: String, enum: ['soundcloud','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer','direct',null], default: null },
            // Legacy fields — kept for backwards compat
            externalUrl:    String,
            embedUrl:       String,
            embedType:      { type: String, enum: ['youtube','vimeo','soundcloud','dailymotion','gdrive','direct','unknown','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer',null], default: null },
           playerType:     { type: String, enum: ['iframe','html5_video','html5_audio','cloudinary','cloudinary_audio','soundcloud_widget','pdf_viewer','audio_embed', null], default: null },
             transcript:     String,
            notes:          String,  // creator's written notes shown to student
            // Resource links — creator adds these for students to click
            resources: [{
              label:   String,   // e.g. "Download slides", "GitHub repo", "Article link"
              url:     String,
              type:    { type: String, enum: ['link','file','github','article','video','audio','other'], default: 'link' },
            }],
          }
        ]
      }
    ]
  },
  notes:        { type: String, default: null },        // creator's notes for buyers
  audioData:    { type: mongoose.Schema.Types.Mixed, default: null },
  softwareData: { type: mongoose.Schema.Types.Mixed, default: null },
  videoData:    { type: mongoose.Schema.Types.Mixed, default: null },
 
  // ── Admin review fields ───────────────────────────────────────────────────
  status: {
    type:    String,
    enum:    ['draft', 'pending_review', 'approved', 'rejected', 'suspended'],
    default: 'pending_review'
  },
  // For draft products: isDraft flag (used to separate locally-initiated drafts from submitted ones)
  isDraft:    { type: Boolean, default: false },
  // Price change tracking — lets creator see if admin changed their suggested price
  priceChangeNote: { type: String, default: null }, // set by admin on approval if price differs
  approvedPrice:          Number,
  platformCommission:     { type: Number, default: 20 },
  affiliateCommission:    { type: Number, default: 10 },
  creatorEarningPerSale:  Number,
  adminNotes:             String,
  rejectionReason:        String,
  approvedBy:             { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  approvedAt:             Date,
 
  // ── Sales tracking ────────────────────────────────────────────────────────
  totalSales:   { type: Number, default: 0 },
  totalRevenue: { type: Number, default: 0 },
 
  submittedAt:  { type: Date, default: Date.now },
  createdAt:    { type: Date, default: Date.now },
  updatedAt:    { type: Date, default: Date.now }
});
 
creatorProductSchema.pre('save', function (next) {
  this.updatedAt = Date.now();
  const t = this.productType;

  // ── Auto-generate slug from title if not set ──────────────────────────
  if (!this.slug && this.title) {
    this.slug = this.title
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '')
      .substring(0, 80);
  }

  // ── Stamp publishedAt when status first set to published ─────────────
  if (this.status === 'published' && !this.publishedAt) {
    this.publishedAt = new Date();
  }

  // ── Type-specific guards ──────────────────────────────────────────────
  if (t === 'course') {
    if (!this.courseData) {
      this.courseData = { sections: [], totalSections: 0, totalChapters: 0, totalDuration: 0 };
    }
    if (!Array.isArray(this.courseData.sections)) this.courseData.sections = [];
    this.downloadLink = '';
  }
  if (['download','template','script','component','ebook'].includes(t)) {
    if (this.courseData && this.isModified('productType')) this.courseData = undefined;
  }
  if (t === 'music') {
    if (!this.audioData) this.audioData = {};
    if (this.isModified('productType')) this.courseData = undefined;
  }
  if (t === 'software') {
    if (!this.softwareData) this.softwareData = {};
    if (this.isModified('productType')) this.courseData = undefined;
  }
   if (t === 'video') {
    if (!this.videoData) this.videoData = {};
    // video products are delivered via embed or hosted file — no courseData
    if (this.isModified('productType')) this.courseData = undefined;
  }
  if (t === 'ebook') {
    if (!this.ebookData) this.ebookData = {};
  }
  if (['template','script','component'].includes(t)) {
    if (!this.designData) this.designData = {};
  }
  next();
});


creatorProductSchema.index({ creatorId: 1 });
creatorProductSchema.index({ status: 1 });
creatorProductSchema.index({ submittedAt: -1 });

const CreatorProduct = mongoose.model('CreatorProduct', creatorProductSchema);
creatorProductSchema.index({ title: 'text', description: 'text', tags: 'text', category: 'text' },
{ weights: { title: 10, tags: 5, category: 3, description: 1 }, name: 'creator_product_text_search' });

global.CreatorProduct = CreatorProduct;
console.log('✅ CreatorProduct Model Defined');

