// COURSE PROGRESS SCHEMA
// Tracks per-user, per-course completion state for resume + certificate issuance
// ══════════════════════════════════════════════════════════════════════════════
const courseProgressSchema = new mongoose.Schema({
  userId:    { type: mongoose.Schema.Types.ObjectId, ref: 'User',    required: true },
  productId: { type: mongoose.Schema.Types.ObjectId, ref: 'Product', required: true },
  orderId:   { type: mongoose.Schema.Types.ObjectId, ref: 'Order' },

  // Array of chapterOrder values the user has marked complete
  completedChapters: [String],  // stored as "sectionOrder:chapterOrder" e.g. "1:3"

  // Resume position
  lastSectionOrder: { type: Number, default: 0 },
  lastChapterOrder: { type: Number, default: 0 },

  // Computed on save
  completionPct: { type: Number, default: 0 },

  // Time tracking
  startedAt:      { type: Date, default: Date.now }, // when student first opened the course
  lastAccessedAt: { type: Date, default: Date.now }, // updated on every progress save
  timeSpent:      { type: Number, default: 0 },      // total seconds spent (incremented by client)

  // Certificate
  certificateIssued:   { type: Boolean, default: false },
  certificateIssuedAt: Date,
  certificateId:       { type: String, default: null }, // unique verifiable ID
  completedAt:         Date,
}, { timestamps: true });

// Primary lookup — one progress record per user per course (intended behaviour).
// orderId is stored on the document for auditing but is NOT part of the unique key
// so that a re-purchase doesn't create a duplicate or throw a conflict error.
// If you ever want separate progress per purchase, change this to { userId, productId, orderId }.
courseProgressSchema.index({ userId: 1, productId: 1 }, { unique: true });
courseProgressSchema.index({ orderId: 1 });          // fast lookup by order
courseProgressSchema.index({ productId: 1 });        // admin analytics by product
courseProgressSchema.index({ lastAccessedAt: -1 });  // sort active learners
const CourseProgress = mongoose.model('CourseProgress', courseProgressSchema);
global.CourseProgress = CourseProgress;
console.log('✅ CourseProgress Model Defined');

// ══════════════════════════════════════════════════════════════════════════════
// REVIEW SCHEMA
// Verified-purchase reviews — one per user per product
// ══════════════════════════════════════════════════════════════════════════════
const reviewSchema = new mongoose.Schema({
  productId:  { type: mongoose.Schema.Types.ObjectId, ref: 'Product',  required: true },
  userId:     { type: mongoose.Schema.Types.ObjectId, ref: 'User',     required: true },
  orderId:    { type: mongoose.Schema.Types.ObjectId, ref: 'Order',    required: true },

  rating:     { type: Number, required: true, min: 1, max: 5 },
  title:      { type: String, trim: true, maxlength: 120 },
  body:       { type: String, trim: true, maxlength: 2000 },

  // Moderation
  status:     { type: String, enum: ['pending', 'approved', 'rejected'], default: 'pending' },
  adminNote:  String,

  // Helpfulness voting
  helpfulCount:    { type: Number, default: 0 },
  notHelpfulCount: { type: Number, default: 0 },

  // Creator/admin reply
  reply: {
    body:       String,
    repliedAt:  Date,
    repliedBy:  { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  },

  // Verified purchase flag — set to true automatically by the server
  verifiedPurchase: { type: Boolean, default: true },

  createdAt: { type: Date, default: Date.now },
  updatedAt: { type: Date, default: Date.now },
});

reviewSchema.pre('save', function (next) { this.updatedAt = Date.now(); next(); });

// One review per user per product (enforced at DB level)
reviewSchema.index({ userId: 1, productId: 1 }, { unique: true });
reviewSchema.index({ productId: 1, status: 1 });
reviewSchema.index({ productId: 1, rating: -1 });
reviewSchema.index({ orderId: 1 }, { sparse: true });
reviewSchema.index({ createdAt: -1 });

const Review = mongoose.model('Review', reviewSchema);
global.Review = Review;
console.log('✅ Review Model Defined');

