// STUDENT NOTES
// Students can write personal notes per chapter and click resource links
// ══════════════════════════════════════════════════════════════════════════════
const studentNoteSchema = new mongoose.Schema({
  userId:      { type: mongoose.Schema.Types.ObjectId, ref: 'User',    required: true },
  productId:   { type: mongoose.Schema.Types.ObjectId, ref: 'Product', required: true },
  orderId:     { type: mongoose.Schema.Types.ObjectId, ref: 'Order',   required: true },
  // Which chapter this note belongs to
  sectionOrder: { type: Number, required: true },
  chapterOrder: { type: Number, required: true },
  // The note content
  content:     { type: String, default: '' },
  updatedAt:   { type: Date, default: Date.now },
  createdAt:   { type: Date, default: Date.now },
});
studentNoteSchema.pre('save', function(next) { this.updatedAt = Date.now(); next(); });
studentNoteSchema.index({ userId: 1, productId: 1 });
studentNoteSchema.index({ userId: 1, productId: 1, sectionOrder: 1, chapterOrder: 1 }, { unique: true });

const StudentNote = mongoose.model('StudentNote', studentNoteSchema);
global.StudentNote = StudentNote;
console.log('✅ StudentNote Model Defined');


// ═══════════════════════════════════════════════
// AFFILIATE SCHEMA
// ═══════════════════════════════════════════════

const affiliateSchema = new mongoose.Schema({
  userId: { 
    type: mongoose.Schema.Types.ObjectId, 
    ref: 'User', 
    required: true, 
    unique: true 
  },
  affiliateCode: { type: String, required: true, unique: true, uppercase: true },
  
  // Status
  status: { 
    type: String, 
    enum: ['active', 'suspended', 'pending'], 
    default: 'active' 
  },
  
  // Earnings
  totalClicks: { type: Number, default: 0 },
  totalConversions: { type: Number, default: 0 },
  totalEarnings: { type: Number, default: 0 },
  pendingEarnings: { type: Number, default: 0 },
  paidEarnings: { type: Number, default: 0 },
  
  // Payout Info
  payoutMethod: {
    type:    String,
    enum:    ['bank_transfer', 'paypal', 'flutterwave', 'crypto'],
    default: 'bank_transfer'
  },
  payoutDetails: {
    country:       String,
    // Bank transfer
    bankName:      String,
    accountNumber: String,
    accountName:   String,
    sortCode:      String,
    swift:         String,
    iban:          String,
    routingNumber: String,
    otherDetails:  String,
    // PayPal
    paypalEmail:   String,
    paypalName:    String,
    // Flutterwave
    flwEmail:      String,
    flwAccount:    String,
    flwBank:       String,
    flwCountry:    String,
    // Crypto
    cryptoType:    String,
    cryptoAddress: String,
    cryptoName:    String,
  },
  payoutThreshold: { type: Number, default: 20 },
// ── Tier system (4-tier) ───────────────────────────────────────────────────
  // starter  → 0-9 referrals    → 2% commission but LOCKED (earns $0 until 10 refs)
  // regular  → 10-49 referrals  → 5% commission
  // pro      → 50-149 referrals → 7% commission
  // elite    → 150+ referrals   → 10% commission (capped here)
  tier: {
    type: String,
    enum: ['starter', 'regular', 'pro', 'elite'],
    default: 'starter'
  },

  tierEligibleAt: Date,

  // IP recorded at affiliate registration — used for multi-account fraud checks
  registrationIp: { type: String, default: null },
 
  // Custom slug for vanity links  (/ref/john instead of ?ref=JOHN1234)
  customSlug: { type: String, default: null, lowercase: true, trim: true },
 
  // Referral tracking — used for tier promotion
  // referredBy: who referred this affiliate when they joined
  // referrals:  list of affiliates this person has referred (used for tier count)
  // totalReferrals: count of people this affiliate has successfully brought onboard
  referredBy:       { type: mongoose.Schema.Types.ObjectId, ref: 'Affiliate', default: null },
  referrals:        [{ type: mongoose.Schema.Types.ObjectId, ref: 'Affiliate' }],
  totalReferrals:   { type: Number, default: 0 },
  // subEarnings removed — no 2-tier commission system
 
  // Cookie duration override (days) — admin can set per affiliate
  cookieDays: { type: Number, default: 30 },
 
  // Per-affiliate commission override (null = use product default)
  commissionOverride: { type: Number, default: null },
 
  // Fraud / quality flags
  fraudFlags:    { type: Number, default: 0 },
  lastFraudCheck: Date,
 
  // Performance tracking
  bestProductId:    { type: mongoose.Schema.Types.ObjectId, ref: 'Product', default: null },
  bestProductTitle: { type: String, default: null },
  bestProductRevenue: { type: Number, default: 0 },

  // Unique-visitor click counter (de-duped by 24h visitorHash window)
  uniqueClicks: { type: Number, default: 0 },

  updatedAt: { type: Date, default: Date.now },
  createdAt: { type: Date, default: Date.now }
});

affiliateSchema.pre('save', function(next) {
  this.updatedAt = Date.now();
  next();
});

affiliateSchema.index({ status: 1 });
affiliateSchema.index({ userId: 1 });

