const adminLogSchema = new mongoose.Schema({
 
  // ── Who did it ────────────────────────────────────────────────────────────
  actor: {
    id:       { type: mongoose.Schema.Types.ObjectId, ref: 'User', default: null },
    email:    { type: String, default: 'anonymous' },
    name:     { type: String, default: 'Anonymous' },
    role:     { type: String, enum: ['admin', 'agent', 'user', 'creator', 'affiliate', 'guest', 'system'], default: 'guest' },
    ip:       { type: String, default: null },
    device:   { type: String, default: null },   // parsed from User-Agent
    location: { type: String, default: null },   // country/city from IP (optional)
  },
 
  // ── What happened ─────────────────────────────────────────────────────────
  category: {
    type: String,
    enum: [
      'auth',           // login, logout, signup, password change, 2FA
      'user',           // profile update, account delete, suspension
      'order',          // purchase, refund, download
      'product',        // create, edit, delete, approve, reject
      'creator',        // apply, approve, suspend, payout
      'affiliate',      // register, payout, suspend
      'admin',          // admin action on any resource
      'agent',          // agent action (chat, ticket)
      'chat',           // chat start, message, resolve
      'ticket',         // ticket create, assign, close
      'coupon',         // create, use, delete
      'blog',           // post create, publish, delete
      'access',         // secret code attempt, session
      'upload',         // file upload
      'settings',       // settings changed
      'security',       // failed logins, rate limit hits, blocked requests
      'server',         // startup, shutdown, DB connect/disconnect, memory
      'error',          // uncaught exceptions, unhandled rejections
      'websocket',      // WS connect, disconnect
      'health',         // health check queries
    ],
    required: true,
  },
 
  action: {
    type: String,
    required: true,
    // e.g. 'login_success', 'product_created', 'payout_approved', 'db_disconnected'
  },
 
  severity: {
    type: String,
    enum: ['info', 'warning', 'error', 'critical'],
    default: 'info',
  },
 
  // ── What was affected ─────────────────────────────────────────────────────
  target: {
    type:  { type: String, default: null },   // 'user', 'product', 'order', etc.
    id:    { type: String, default: null },   // ObjectId or string ID of the target
    label: { type: String, default: null },   // human-readable (email, product title, etc.)
  },
 
  // ── HTTP context (null for server-side events) ────────────────────────────
  http: {
    method:     { type: String, default: null },
    path:       { type: String, default: null },
    statusCode: { type: Number, default: null },
    duration:   { type: Number, default: null },   // milliseconds
    bodySize:   { type: Number, default: null },   // bytes
  },
 
  // ── Free-form detail payload ──────────────────────────────────────────────
  // Store only safe, non-sensitive data. Never passwords, tokens, card numbers.
  detail: { type: mongoose.Schema.Types.Mixed, default: null },
 
  // ── Outcome ───────────────────────────────────────────────────────────────
  success: { type: Boolean, default: true },
  errorMessage: { type: String, default: null },
 
  // ── Timestamps ────────────────────────────────────────────────────────────
  timestamp: { type: Date, default: Date.now, index: true },
 
}, { collection: 'adminlogs', versionKey: false });
 
// Indexes for every query pattern the admin panel will use
adminLogSchema.index({ 'actor.id': 1,    timestamp: -1 });
adminLogSchema.index({ 'actor.role': 1,  timestamp: -1 });
adminLogSchema.index({ 'actor.ip': 1,    timestamp: -1 });
adminLogSchema.index({ category: 1,      timestamp: -1 });
adminLogSchema.index({ action: 1,        timestamp: -1 });
adminLogSchema.index({ severity: 1,      timestamp: -1 });
adminLogSchema.index({ success: 1,       timestamp: -1 });
adminLogSchema.index({ 'target.id': 1,   timestamp: -1 });
adminLogSchema.index({ 'target.type': 1, timestamp: -1 });
// TTL: auto-delete logs older than 180 days to keep the collection lean.
// Change 180 to any number of days you prefer.
adminLogSchema.index({ timestamp: 1 }, { expireAfterSeconds: 100 * 24 * 60 * 60 });
 
const AdminLog = mongoose.model('AdminLog', adminLogSchema);
 
