async function _enrichCart(cart) {
  if (!cart || !cart.items.length) return { items: [], subtotal: 0, count: 0 };
  const items = await Promise.all(cart.items.map(async item => {
    let product = null;
    if (item.productCollection === 'CreatorProduct') {
      product = await CreatorProduct.findById(item.productId).select('title coverImage suggestedPrice productType status').lean();
    } else {
      product = await Product.findById(item.productId).select('title coverImage price productType isPublished').lean();
    }
    const currentPrice = product?.price || product?.suggestedPrice || item.price || 0;
    return { ...item.toObject(), product: product || null, currentPrice, available: !!product };
  }));
  const subtotal = items.reduce((s, i) => s + (i.currentPrice * (i.quantity || 1)), 0);
  return { items, subtotal: parseFloat(subtotal.toFixed(2)), count: items.length };
}
/**
 * adminLog(entry) — write one log entry to MongoDB.
 *
 * This is intentionally fire-and-forget: it never throws or blocks a request.
 * If MongoDB is down, the entry is dropped silently rather than crashing the
 * route that triggered it.
 *
 * @param {Object} entry — see AdminLog schema above for all fields
 */
async function adminLog(entry) {
  try {
    await AdminLog.create(entry);
  } catch (err) {
    // Never let a log write break a live request
    console.error('[AdminLog write error]', err.message);
  }
}
 
// Make it available everywhere in the server without importing
global.adminLog = adminLog;

