// HEALTH CHECK FUNCTIONS
// ═════════════════════════════════════════════════════════════════════════════

// Check API endpoint
async function checkAPIService() {
  try {
    const startTime = Date.now();
    
    // Check if server is running and can connect to DB
    const mongoState = mongoose.connection.readyState;
    const responseTime = Date.now() - startTime;

    if (mongoState === 1) {
      return {
        status: 'operational',
        responseTime,
        statusCode: 200,
        metadata: {
          uptime: process.uptime(),
          memory: {
            used: Math.round(process.memoryUsage().heapUsed / 1024 / 1024),
            total: Math.round(process.memoryUsage().heapTotal / 1024 / 1024)
          }
        }
      };
    } else {
      return {
        status: 'degraded',
        responseTime,
        statusCode: 503,
        errorMessage: 'Database connection unstable'
      };
    }
  } catch (error) {
    return {
      status: 'outage',
      responseTime: 0,
      statusCode: 0,
      errorMessage: error.message
    };
  }
}

// Check MongoDB database
async function checkDatabase() {
  try {
    const startTime = Date.now();
    
    // Test actual database operation
    await mongoose.connection.db.admin().ping();
    
    // Try a simple query
    await ServiceStatus.findOne().lean();
    
    const responseTime = Date.now() - startTime;

    return {
      status: 'operational',
      responseTime,
      statusCode: 200,
      metadata: {
        readyState: mongoose.connection.readyState,
        name: mongoose.connection.name,
      }
    };
  } catch (error) {
    return {
      status: 'outage',
      responseTime: 0,
      statusCode: 0,
      errorMessage: error.message
    };
  }
}

// Check WebSocket service
function checkWebSocket() {
  try {
    // Access global wss from your server
    const wss = global.wss || (typeof wss !== 'undefined' ? wss : null);
    
    if (!wss) {
      return {
        status: 'outage',
        responseTime: 0,
        statusCode: 0,
        errorMessage: 'WebSocket server not initialized'
      };
    }

    const activeConnections = wss.clients ? wss.clients.size : 0;
    const activeChats = global.activeConnections ? global.activeConnections.size : 0;
    const agentCount = global.agentConnections ? global.agentConnections.size : 0;
    const customerCount = global.customerConnections ? global.customerConnections.size : 0;

    return {
      status: 'operational',
      responseTime: 5,
      statusCode: 200,
      metadata: {
        activeConnections,
        activeChats,
        agentCount,
        customerCount
      }
    };
  } catch (error) {
    return {
      status: 'outage',
      responseTime: 0,
      statusCode: 0,
      errorMessage: error.message
    };
  }
}

