// ── deleteFromCloudinary() — safe single-asset delete helper ──────────────
// Returns { success, publicId, result } or { success: false, error }
async function deleteFromCloudinary(publicId, resourceType = 'raw') {
  if (!publicId) return { success: false, error: 'No publicId provided' };
  try {
    const result = await cloudinary.uploader.destroy(publicId, {
      resource_type: resourceType,
      invalidate:    true,  // also purge from CDN cache
    });
    const ok = result.result === 'ok' || result.result === 'not found';
    if (!ok) console.warn(`⚠️  Cloudinary delete unexpected result for ${publicId}:`, result);
    return { success: ok, publicId, result: result.result };
  } catch (err) {
    console.error(`❌ Cloudinary delete failed for ${publicId}:`, err.message);
    return { success: false, publicId, error: err.message };
  }
}
 
global.deleteFromCloudinary = deleteFromCloudinary;
 




// ========== EMAIL OTP STORAGE ==========
const otpStore = new Map();

// Sweep expired OTP entries every 15 minutes
// OTPs expire in 10 minutes — anything older than 15 is definitely dead
setInterval(() => {
  const now     = Date.now();
  const MAX_AGE = 15 * 60 * 1000; // 15 minutes
  let cleaned   = 0;
  for (const [key, entry] of otpStore.entries()) {
    const age = entry.expiresAt
      ? now - new Date(entry.expiresAt).getTime()
      : entry.createdAt ? now - entry.createdAt : MAX_AGE + 1;
    if (age > 0 || now - (entry.createdAt || 0) > MAX_AGE) {
      otpStore.delete(key);
      cleaned++;
    }
  }
  if (cleaned > 0) console.log(`🧹 otpStore: cleared ${cleaned} expired entries`);
}, 15 * 60 * 1000);

// ========== UTILITY FUNCTIONS ==========
function generateToken() {
  return crypto.randomBytes(32).toString('hex');
}

function generateOTP() {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

function generateSlug(text) {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

function generateChatId() {
  return 'CHAT-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9).toUpperCase();
}

function generateMessageId() {
  return 'MSG-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9).toUpperCase();
}


// ✅ ADD THIS — was missing, caused the crash in /api/creator/apply & /api/creator/upgrade
function escapeRegex(str) {
  return String(str).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

global.escapeRegex = escapeRegex;
