// ── AUTH EVENTS ──────────────────────────────────────────────────────────────
 
async function logLogin(req, user, success, reason = null) {
  await adminLog({
    actor: {
      id:     user?._id || null,
      email:  user?.email || req.body?.email || 'unknown',
      name:   user?.fullName || 'Unknown',
      role:   user?.isAdmin ? 'admin' : user?.isAgent ? 'agent' : 'user',
      ip:     req.headers['x-forwarded-for']?.split(',')[0] || req.socket?.remoteAddress,
      device: parseDevice(req.headers['user-agent']),
    },
    category: 'auth',
    action:   success ? 'login_success' : 'login_failed',
    severity: success ? 'info' : 'warning',
    target:   { type: 'user', id: user?._id?.toString(), label: user?.email },
    detail:   { reason },
    success,
    errorMessage: success ? null : (reason || 'Login failed'),
  });
}
 
async function logLogout(req, user) {
  await adminLog({
    actor: resolveActor(req),
    category: 'auth',
    action:   'logout',
    severity: 'info',
    target:   { type: 'user', id: user?._id?.toString(), label: user?.email },
    success:  true,
  });
}
 
