function processChaptersForDelivery(courseData) {
  if (!courseData || !Array.isArray(courseData.sections)) return courseData;

 const VALID_EMBED_TYPES  = ['youtube','vimeo','soundcloud','dailymotion','gdrive','direct','unknown',
    'spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer'];
  const VALID_PLAYER_TYPES = ['iframe','html5_video','html5_audio','cloudinary','cloudinary_audio','soundcloud_widget','pdf_viewer','audio_embed'];

  const processed = JSON.parse(JSON.stringify(courseData)); // deep clone

  processed.sections = processed.sections.map((section) => {
    section.chapters = (section.chapters || []).map((ch) => {
      // ── Sanitize embedType & playerType — coerce any invalid value to null ──
      if (ch.embedType  !== null && ch.embedType  !== undefined && !VALID_EMBED_TYPES.includes(ch.embedType))   ch.embedType  = null;
      if (ch.playerType !== null && ch.playerType !== undefined && !VALID_PLAYER_TYPES.includes(ch.playerType)) ch.playerType = null;

      const AUDIO_FORMATS = ['mp3','wav','ogg','aac','flac','m4a','wma','opus'];
      const VIDEO_EMBED_TYPES = ['youtube','vimeo','dailymotion','gdrive'];
      const AUDIO_EMBED_TYPES = ['soundcloud','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer'];

      // ── Parse and split video/audio URLs ─────────────────────────────────
      // Source candidates: embedVideoUrl/embedAudioUrl (new) or legacy externalUrl/embedUrl
      const rawVideoUrl = ch.embedVideoUrl || (ch.chapterType !== 'audio' ? (ch.externalUrl || ch.embedUrl) : null) || null;
      const rawAudioUrl = ch.embedAudioUrl || (ch.chapterType === 'audio'  ? (ch.externalUrl || ch.embedUrl) : null) || null;

      // Parse video URL
      if (rawVideoUrl && (!ch.embedVideoUrl || !ch.embedVideoType)) {
        const parsed = parseExternalMediaUrl(rawVideoUrl);
        if (parsed.mediaCategory === 'video' && parsed.embedType !== 'unknown') {
          ch.embedVideoUrl  = parsed.embedUrl;
          ch.embedVideoType = parsed.embedType;
        } else if (parsed.mediaCategory === 'audio') {
          // Creator accidentally pasted audio URL into video field — move it to audio
          ch.embedAudioUrl  = ch.embedAudioUrl || parsed.embedUrl;
          ch.embedAudioType = ch.embedAudioType || parsed.embedType;
          ch.embedVideoUrl  = null;
          ch.embedVideoType = null;
        }
      }

      // Parse audio URL
      if (rawAudioUrl && (!ch.embedAudioUrl || !ch.embedAudioType)) {
        const parsed = parseExternalMediaUrl(rawAudioUrl);
        if (parsed.mediaCategory === 'audio' && parsed.embedType !== 'unknown') {
          ch.embedAudioUrl  = parsed.embedUrl;
          ch.embedAudioType = parsed.embedType;
        } else if (parsed.mediaCategory === 'video') {
          // Creator accidentally pasted video URL into audio field — move it to video
          ch.embedVideoUrl  = ch.embedVideoUrl || parsed.embedUrl;
          ch.embedVideoType = ch.embedVideoType || parsed.embedType;
          ch.embedAudioUrl  = null;
          ch.embedAudioType = null;
        }
      }

      // ── Auto-detect chapterType from what was parsed ──────────────────────
      if (!ch.chapterType || ch.chapterType === 'video') {
        if (ch.embedAudioUrl && !ch.embedVideoUrl) ch.chapterType = 'audio';
        else if (ch.embedVideoUrl) ch.chapterType = 'video';
      }

      // ── Populate legacy fields for backwards compat ───────────────────────
      // Legacy embedUrl/embedType: prefer video, fallback to audio
      if (ch.embedVideoUrl) {
        ch.embedUrl  = ch.embedVideoUrl;
        ch.embedType = ch.embedVideoType || null;
      } else if (ch.embedAudioUrl) {
        ch.embedUrl  = ch.embedAudioUrl;
        ch.embedType = ch.embedAudioType || null;
      }
      // externalUrl: keep raw source for re-parsing
      ch.externalUrl = ch.externalUrl || rawVideoUrl || rawAudioUrl || null;

      // ── Derive playerType ─────────────────────────────────────────────────
      if (!ch.playerType) {
        if (ch.embedVideoUrl) {
          const et = ch.embedVideoType || '';
          if (VIDEO_EMBED_TYPES.includes(et)) {
            ch.playerType = 'iframe';
          } else if (et === 'direct') {
            ch.playerType = 'html5_video';
          } else {
            ch.playerType = 'iframe';
          }
        } else if (ch.embedAudioUrl) {
          const et = ch.embedAudioType || '';
          if (AUDIO_EMBED_TYPES.includes(et)) {
            ch.playerType = 'soundcloud_widget'; // frontend uses this for all audio iframes
          } else if (et === 'direct') {
            ch.playerType = 'html5_audio';
          } else {
            ch.playerType = 'soundcloud_widget';
          }
       } else if (ch.hostedFile?.publicId) {
          const hfFmt  = (ch.hostedFile.format || '').toLowerCase();
          const hfUrl  = (ch.hostedFile.secureUrl   || '').toLowerCase().split('?')[0];
          const hfName = (ch.hostedFile.originalName || ch.hostedFile.publicId || '').toLowerCase();
          const isPdf  = hfFmt === 'pdf' || hfUrl.endsWith('.pdf') || hfName.endsWith('.pdf');
          if (isPdf) {
            ch.chapterType = 'pdf';
            ch.playerType  = 'pdf_viewer';
          } else {
            const isAudio = ch.chapterType === 'audio'
              || ch.mediaType === 'audio'
              || AUDIO_FORMATS.includes(hfFmt)
              || AUDIO_FORMATS.some(ext => (ch.hostedFile.publicId || '').toLowerCase().endsWith('.' + ext));
            ch.playerType = isAudio ? 'cloudinary_audio' : 'cloudinary';
          }
        }
      }

      // ── Cloudinary-hosted chapter: derive chapterType from format ─────────
      if (ch.hostedFile?.publicId && !ch.embedUrl) {
        const hfFmt  = (ch.hostedFile.format || '').toLowerCase();
        const hfUrl  = (ch.hostedFile.secureUrl   || '').toLowerCase().split('?')[0];
        const hfName = (ch.hostedFile.originalName || ch.hostedFile.publicId || '').toLowerCase();
        const isPdfFile = hfFmt === 'pdf' || hfUrl.endsWith('.pdf') || hfName.endsWith('.pdf');
        const isAudio = ch.chapterType === 'audio'
          || ch.mediaType === 'audio'
          || AUDIO_FORMATS.includes(hfFmt)
          || AUDIO_FORMATS.some(ext => (ch.hostedFile.publicId || '').toLowerCase().endsWith('.' + ext));
        if (isPdfFile) {
          ch.chapterType = 'pdf';
          ch.playerType  = 'pdf_viewer';
        } else if (isAudio) {
          ch.chapterType = 'audio';
          ch.mediaType   = 'audio';
          ch.playerType  = ch.playerType || 'cloudinary_audio';
        } else {
          ch.playerType  = ch.playerType || 'cloudinary';
        }
      }
      return ch;
    });
    return section;
  });
 
  return processed;
}
global.processChaptersForDelivery = processChaptersForDelivery;
 
 
/**
 * inferProductMediaType
 * Given a product-like object, determine the correct mediaType string.
 * Used both at approval time and in media-access delivery.
 */
function inferProductMediaType(p) {
  const pt = p.productType || 'download';

  // Explicit course types
  if (pt === 'course' || p.courseData?.sections?.length)       return 'course';

  // Explicit audio product types
  if (pt === 'music')                                          return 'audio';

  // Explicit video product type
  if (pt === 'video')                                          return 'video';

  // External URL signals
  if (p.externalAudioUrl && !p.externalVideoUrl)               return 'audio';
  if (p.externalVideoUrl)                                      return 'video';

  // Embed type signals
  const AUDIO_EMBED_T = ['soundcloud','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer'];
  if (AUDIO_EMBED_T.includes(p.embedType))                     return 'audio';
  if (p.embedAudioUrl || p.embedAudioType)                     return 'audio';
  if (p.embedUrl || p.embedType)                               return 'video';

  // Stored mediaType field (set at approval time)
  if (p.mediaType === 'audio')                                 return 'audio';
  if (p.mediaType === 'video')                                 return 'video';

  // Hosted Cloudinary file — detect audio by format since resourceType is 'video' for audio too
  if (p.hostedFile?.publicId) {
    const AUDIO_FMTS = ['mp3','wav','ogg','aac','flac','m4a','wma','opus','aiff'];
    const hfFmt      = (p.hostedFile.format   || '').toLowerCase();
    const hfId       = (p.hostedFile.publicId || '').toLowerCase();
    if (
      AUDIO_FMTS.includes(hfFmt) ||
      AUDIO_FMTS.some(ext => hfId.endsWith('.' + ext))
    ) return 'audio';
    return 'file';  // non-audio hosted file (ZIP, PDF, etc.)
  }

  if (p.downloadLink)                                          return 'file';
  return 'file';
}
global.inferProductMediaType = inferProductMediaType;
 
 

