function getEmailHeader(title) {
  return `
    <div style="
      background: linear-gradient(135deg, #00b359 0%, #00ff88 100%); 
      color: white; 
      padding: 30px 20px; 
      text-align: center; 
      border-radius: 10px 10px 0 0;
    ">
      <div style="margin-bottom: 15px;">
        <img src="${LOGO_URL}" alt="UYEH TECH" style="
          width: 80px; 
          height: 80px; 
          border-radius: 50%; 
          border: 3px solid white;
          background: #1a1a1a;
          padding: 10px;
          box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
        ">
      </div>
      <h1 style="
        font-size: 24px; 
        margin: 15px 0 5px 0;
        font-weight: bold;
      ">${title}</h1>
      <div style="
        font-size: 14px; 
        opacity: 0.9;
        letter-spacing: 1px;
      ">UYEH TECH</div>
    </div>
  `;
}

