// ✅ FUNCTION 2: SEND ORDER CONFIRMATION EMAIL
// ═════════════════════════════════════════════════════════════════════════════
async function sendOrderConfirmationEmail(to, orderData) {
  try {
    const order    = orderData || {};
    const items    = order.items || [];
    const info     = order.customerInfo || {};
    const payment  = order.paymentInfo  || {};
    const ref      = order.orderReference || order._id || 'N/A';
    const total    = Number(order.total || 0).toFixed(2);
    const paidAt   = payment.paidAt
      ? new Date(payment.paidAt).toLocaleDateString('en-GB', { day:'2-digit', month:'long', year:'numeric' })
      : new Date().toLocaleDateString('en-GB', { day:'2-digit', month:'long', year:'numeric' });

    const itemRows = items.map(item => `
      <div style="display:flex;justify-content:space-between;align-items:flex-start;
                  padding:12px 0;border-bottom:1px solid #2a2a2a;gap:10px;">
        <div style="flex:1;min-width:0;">
          <div style="font-size:14px;color:#e5e7eb;font-weight:600;
                      white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">
            ${item.title || item.name || 'Product'}
          </div>
          ${item.productType ? `<div style="font-size:12px;color:#6b7280;margin-top:2px;
                                            text-transform:capitalize;">${item.productType}</div>` : ''}
        </div>
        <div style="font-size:14px;color:#00ff88;font-weight:700;white-space:nowrap;">
          $${Number(item.price || 0).toFixed(2)}
        </div>
      </div>`).join('');

    const subject = `🎉 Order Confirmed — ${ref}`;
    const html = _shell('🎉 Order Confirmed!', `
      <h2 class="title">Your purchase is complete!</h2>
      <p>Hi <strong style="color:#00ff88;">${info.name || info.fullName || 'there'}</strong>,</p>
      <p>Thank you for your purchase! Your payment has been confirmed and your products are ready to access.</p>

      <div class="info-card">
        ${_row('Order Reference', ref)}
        ${_row('Date',            paidAt)}
        ${_row('Payment Method',  payment.method || 'Card')}
        ${_row('Status',          '✅ Payment Confirmed')}
      </div>

      <p style="font-size:13px;font-weight:700;color:#a0a0a0;text-transform:uppercase;
                letter-spacing:1.5px;margin:22px 0 8px;">Items Purchased</p>
      <div style="background:#1a1a1a;border-radius:10px;padding:4px 16px;
                  border:1px solid #2a2a2a;">
        ${itemRows || `<div style="padding:12px 0;font-size:14px;color:#6b7280;">No items listed.</div>`}
        <div style="display:flex;justify-content:space-between;padding:14px 0;
                    margin-top:4px;border-top:2px solid #00ff88;">
          <strong style="font-size:15px;color:#e5e7eb;">Total Paid</strong>
          <strong style="font-size:18px;color:#00ff88;">$${total}</strong>
        </div>
      </div>

      ${_btn(`${FRONTEND_URL}/marketplace/my-products`, '📦 Access My Products')}

      <p>If you have any questions about your order, reply to this email or visit our support page.</p>
      <p>Thank you for shopping with us,<br>
         <strong style="color:#00ff88;">The UYEH TECH Team</strong></p>
    `);

    return _sendEmail(to, subject, html, 'order-confirmation');
  } catch (err) {
    console.error('❌ sendOrderConfirmationEmail error:', err.message);
    return { success: false, error: err.message };
  }
}

