// ─────────────────────────────────────────────────────────────────────────────
// SHARED EMAIL HELPERS
// ─────────────────────────────────────────────────────────────────────────────

// Single branded send wrapper — handles Resend guard, error, console fallback
async function _sendEmail(to, subject, htmlBody, tag = '') {
  if (!resend || !RESEND_API_KEY) {
    console.log(`📧 [${tag||subject}] Email disabled — logged for: ${to}`);
    return { success: true, method: 'console_log' };
  }
  try {
    const { data, error } = await resend.emails.send({
      from: `${RESEND_SENDER_NAME} <${RESEND_SENDER_EMAIL}>`,
      to:   [to],
      subject,
      html: htmlBody,
    });
    if (error) {
      console.error(`❌ Resend [${tag}]:`, error);
      return { success: true, method: 'console_log' };
    }
    console.log(`✅ Email sent [${tag}] → ${to} | ID: ${data.id}`);
    return { success: true, method: 'resend', data };
  } catch (err) {
    console.error(`❌ Resend [${tag}] threw:`, err.message);
    return { success: true, method: 'console_log' };
  }
}

// Reusable email footer HTML
function _emailFooter(ref = '') {
  return `
  <div style="background:#1a1a1a;padding:28px 30px;text-align:center;border-top:1px solid #2a2a2a;">
    <img src="${LOGO_URL}" alt="UYEH TECH"
         style="width:38px;height:38px;border-radius:50%;border:2px solid #00ff88;
                padding:4px;background:#0a0a0a;margin-bottom:10px;opacity:.85;">
    <p style="margin:4px 0;font-size:12px;color:#6b7280;">
      © ${new Date().getFullYear()} UYEH TECH. All rights reserved.
    </p>
    ${ref ? `<p style="margin:4px 0;font-size:11px;color:#4b5563;">Ref: ${ref}</p>` : ''}
    <p style="margin:6px 0;font-size:12px;color:#6b7280;">
      Questions? <a href="mailto:${ADMIN_EMAIL}" style="color:#00ff88;text-decoration:none;">${ADMIN_EMAIL}</a>
    </p>
    <p style="margin:4px 0;font-size:11px;color:#374151;">This is an automated message — please do not reply.</p>
  </div>`;
}

// Info card row helper (label : value)
function _row(label, value) {
  return `
  <div style="display:flex;justify-content:space-between;padding:11px 0;
              border-bottom:1px solid #2a2a2a;font-size:14px;">
    <span style="color:#a0a0a0;">${label}</span>
    <span style="color:#00ff88;font-weight:700;">${value}</span>
  </div>`;
}

// CTA button
function _btn(href, label) {
  return `
  <div style="text-align:center;margin:28px 0;">
    <a href="${href}"
       style="display:inline-block;background:linear-gradient(135deg,#00ff88 0%,#00b359 100%);
              color:#0a0a0a;padding:15px 38px;text-decoration:none;border-radius:8px;
              font-weight:700;font-size:15px;text-transform:uppercase;letter-spacing:1px;
              box-shadow:0 8px 24px rgba(0,255,136,.3);">
      ${label}
    </a>
  </div>`;
}

// Alert box (green by default, pass color for warning/danger)
function _alert(msg, color = '#00ff88') {
  return `
  <div style="background:#1a1a1a;border-left:4px solid ${color};
              padding:18px 20px;margin:22px 0;border-radius:0 8px 8px 0;">
    <p style="margin:0;color:#ffffff;font-size:14px;line-height:1.6;">${msg}</p>
  </div>`;
}

// Shared email shell (dark branded container)
function _shell(headerTitle, bodyContent) {
  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1.0">
<style>
  *{margin:0;padding:0;box-sizing:border-box;}
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Arial,sans-serif;
       background:linear-gradient(135deg,#0a0a0a 0%,#1a1a1a 100%);
       padding:40px 20px;line-height:1.6;}
  .wrap{max-width:600px;margin:0 auto;background:#1a1a1a;border-radius:16px;
        overflow:hidden;box-shadow:0 20px 60px rgba(0,255,136,.15);border:1px solid #2a2a2a;}
  .body{padding:38px 30px;background:#0a0a0a;color:#ffffff;}
  h2.title{font-size:26px;font-weight:700;color:#00ff88;margin-bottom:18px;text-align:center;}
  p{margin-bottom:14px;font-size:15px;color:#e5e7eb;line-height:1.7;}
  .info-card{background:#1a1a1a;border-radius:10px;padding:18px 20px;
             margin:20px 0;border:1px solid #2a2a2a;}
  @media(max-width:600px){.body{padding:24px 18px;}}
</style>
</head>
<body>
<div class="wrap">
  ${getEmailHeader(headerTitle)}
  <div class="body">
    ${bodyContent}
  </div>
  ${_emailFooter()}
</div>
</body>
</html>`;
}

