// ═════════════════════════════════════════════════════════════════════════════
// FUNCTION: SEND REFUND EMAIL (to customer when admin refunds their order)
// ═════════════════════════════════════════════════════════════════════════════
async function sendRefundEmail(to, data) {
  try {
    const ref      = data.orderReference || data.orderId || 'N/A';
    const amount   = Number(data.refundAmount || data.total || 0).toFixed(2);
    const fullName = data.fullName || data.name || 'there';
    const items    = data.items || [];
    const reason   = data.refundReason || 'Requested by support';
    const date     = new Date().toLocaleDateString('en-GB', {
      day: '2-digit', month: 'long', year: 'numeric'
    });

    const itemRows = items.map(item => `
      <div style="display:flex;justify-content:space-between;align-items:center;
                  padding:10px 0;border-bottom:1px solid #2a2a2a;">
        <span style="font-size:14px;color:#e5e7eb;">${item.title || item.name || 'Product'}</span>
        <span style="font-size:14px;color:#e5e7eb;font-weight:600;">
          $${Number(item.price || 0).toFixed(2)}
        </span>
      </div>`).join('');

    const subject = `💸 Refund Processed — Order ${ref}`;
    const html = _shell('💸 Refund Processed', `
      <h2 class="title">Your refund is on the way</h2>
      <p>Hi <strong style="color:#00ff88;">${fullName}</strong>,</p>
      <p>
        Your refund for order <strong style="color:#00ff88;">${ref}</strong> has been
        approved and is being processed. Please allow 5–10 business days for the funds
        to appear in your account depending on your payment provider.
      </p>

      <div class="info-card">
        ${_row('Order Reference', ref)}
        ${_row('Refund Amount',   '$' + amount)}
        ${_row('Refund Date',     date)}
        ${_row('Reason',          reason)}
        ${_row('Status',          '✅ Approved — Processing')}
      </div>

      ${items.length ? `
        <p style="font-size:13px;font-weight:700;color:#a0a0a0;text-transform:uppercase;
                  letter-spacing:1.5px;margin:22px 0 8px;">Refunded Items</p>
        <div style="background:#1a1a1a;border-radius:10px;padding:4px 16px;border:1px solid #2a2a2a;">
          ${itemRows}
          <div style="display:flex;justify-content:space-between;padding:14px 0;
                      margin-top:4px;border-top:2px solid #ff4d4d;">
            <strong style="font-size:15px;color:#e5e7eb;">Total Refunded</strong>
            <strong style="font-size:18px;color:#ff4d4d;">$${amount}</strong>
          </div>
        </div>` : ''}

      ${_alert('⏱️ Refunds typically take <strong>5–10 business days</strong> to appear. ' +
        'If you paid by card, the refund goes back to your original payment method. ' +
        'If you have questions, reply to this email.', '#ff4d4d')}

      ${_btn(`${FRONTEND_URL}/marketplace/orders`, '📋 View My Orders')}

      <p>We are sorry for any inconvenience. If you would like to make a new purchase,
         we would love to have you back.<br>
         <strong style="color:#00ff88;">The UYEH TECH Team</strong></p>
    `);

    return _sendEmail(to, subject, html, 'refund-processed');
  } catch (err) {
    console.error('❌ sendRefundEmail error:', err.message);
    return { success: false, error: err.message };
  }
}

