async function sendTicketResolvedEmail(to, data) {
  try {
    const ticketId  = data.ticketId  || 'N/A';
    const subject_  = data.subject   || 'Your support issue';
    const agentName = data.agentName || 'Our support team';
    const fullName  = data.fullName  || data.name || 'there';
    const summary   = data.summary   || data.lastReply || null;

    const emailSubject = `✅ Ticket ${ticketId} Resolved — UYEH TECH`;
    const html = _shell('✅ Ticket Resolved', `
      <h2 class="title">Your issue has been resolved</h2>
      <p>Hi <strong style="color:#00ff88;">${fullName}</strong>,</p>
      <p>
        Your support ticket <strong style="color:#00ff88;">${ticketId}</strong> regarding
        "<strong>${subject_}</strong>" has been marked as resolved by ${agentName}.
      </p>

      <div class="info-card">
        ${_row('Ticket ID',   ticketId)}
        ${_row('Subject',     subject_)}
        ${_row('Handled by',  agentName)}
        ${_row('Status',      '✅ Resolved')}
        ${_row('Resolved on', new Date().toLocaleDateString('en-GB', {
          day: '2-digit', month: 'long', year: 'numeric'
        }))}
      </div>

      ${summary ? `
        <div style="background:#1a1a1a;border-left:4px solid #00ff88;
                    padding:16px 20px;margin:20px 0;border-radius:0 8px 8px 0;">
          <p style="margin:0 0 6px;font-size:12px;color:#6b7280;
                    text-transform:uppercase;letter-spacing:1px;">Final response</p>
          <p style="margin:0;color:#e5e7eb;font-size:14px;line-height:1.7;">${summary}</p>
        </div>` : ''}

      ${_alert('🔄 Was your issue <strong>not fully resolved</strong>? Reply to this email within ' +
        '7 days and we will reopen your ticket immediately. After 7 days, please open a new ticket.')}

      ${_btn(`${FRONTEND_URL}/marketplace/support`, '💬 Need More Help?')}

      <p>Thank you for contacting UYEH TECH support. We are always happy to help.<br>
         <strong style="color:#00ff88;">The UYEH TECH Support Team</strong></p>
    `);

    return _sendEmail(to, emailSubject, html, 'ticket-resolved');
  } catch (err) {
    console.error('❌ sendTicketResolvedEmail error:', err.message);
    return { success: false, error: err.message };
  }
}

