// ========== MIDDLEWARE: AUTHENTICATE TOKEN ==========
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ success: false, message: 'Access token required' });
  }

  jwt.verify(token, JWT_SECRET, (err, user) => {
    if (err) {
      if (err.name === 'TokenExpiredError') {
        return res.status(401).json({
          success: false,
          message: 'Session expired. Please log in again.',
          expired: true,   // frontend can check this flag to auto-redirect to login
        });
      }
      return res.status(403).json({ success: false, message: 'Invalid token' });
    }
    req.user = user;
    next();
  });
}
 

// ========== MIDDLEWARE: AUTHENTICATE ADMIN ==========
async function authenticateAdmin(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ success: false, message: 'Token required' });
  }

  jwt.verify(token, JWT_SECRET, async (err, decoded) => {
    if (err) {
      return res.status(403).json({ success: false, message: 'Invalid token' });
    }

    try {
      const user = await User.findById(decoded.userId);
      
      if (!user || !user.isAdmin) {
        return res.status(403).json({ 
          success: false, 
          message: 'Admin access required',
          isAdmin: false 
        });
      }

      req.user = decoded;
      req.adminUser = user;
      next();
    } catch (error) {
      return res.status(500).json({ success: false, message: 'Auth failed' });
    }
  });
}
// Authenticate Agent
async function authenticateAgent(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ success: false, message: 'Agent token required' });
  }

  jwt.verify(token, JWT_SECRET, async (err, decoded) => {
    if (err) {
      return res.status(403).json({ success: false, message: 'Invalid or expired token' });
    }

    try {
      const user = await User.findById(decoded.userId);
      
      if (!user || (!user.isAgent && !user.isAdmin)) {
        return res.status(403).json({ 
          success: false, 
          message: 'Agent access required',
          isAgent: false 
        });
      }

      // Update agent status
      if (user.isAgent) {
        user.lastActivity = new Date();
        await user.save();
      }

      req.user = decoded;
      req.agentUser = user;
      next();
    } catch (error) {
      console.error('❌ Agent auth error:', error);
      return res.status(500).json({ success: false, message: 'Authentication failed' });
    }
  });
}
function userWantsEmail(user, type) {
  const prefs = user?.notificationPreferences;
  if (!prefs) return true; // default: send
  if (prefs.email === false) return false; // master off switch
  if (type === 'orders')    return prefs.orders    !== false;
  if (type === 'marketing') return prefs.marketing !== false;
  return true;
}
 
