// ─────────────────────────────────────────────────────────────────────────────
// HELPER: safely cast a string to ObjectId, returns null on invalid input
// ─────────────────────────────────────────────────────────────────────────────
async function sendPushToUser(userId, { title, body, url = '/', tag = 'uyeh-push', icon = '/icons/icon-192.png' }) {
  if (!global.webpush) return;
  try {
    const user = await User.findById(userId).select('pushSubscriptions').lean();
    if (!user?.pushSubscriptions?.length) return;
    const payload = JSON.stringify({ title, body, url, icon, tag, badge: '/icons/icon-96.png', timestamp: Date.now() });
    for (const sub of user.pushSubscriptions) {
      try {
        await global.webpush.sendNotification(
          { endpoint: sub.endpoint, expirationTime: sub.expirationTime, keys: { p256dh: sub.keys.p256dh, auth: sub.keys.auth } },
          payload,
          { TTL: 86400, urgency: 'normal' }
        );
      } catch (err) {
        if (err.statusCode === 410 || err.statusCode === 404) {
          await User.findByIdAndUpdate(userId, { $pull: { pushSubscriptions: { endpoint: sub.endpoint } } });
        }
      }
    }
  } catch (_) {}
}
global.sendPushToUser = sendPushToUser;
 
function toObjectId(id) {
  try {
    return new mongoose.Types.ObjectId(String(id));
  } catch {
    return null;
  }
}

// postLikeIPs: Map<postId, { ips: Set<string>, createdAt: number }>
// Entries expire after 24 hours — prevents unbounded growth
const postLikeIPs = new Map();
const POST_LIKE_TTL = 24 * 60 * 60 * 1000; // 24 hours

function hasLiked(postId, ip) {
  const entry = postLikeIPs.get(postId);
  if (!entry) return false;
  // Auto-expire stale entries on read
  if (Date.now() - entry.createdAt > POST_LIKE_TTL) {
    postLikeIPs.delete(postId);
    return false;
  }
  return entry.ips.has(ip);
}

function recordLike(postId, ip) {
  const existing = postLikeIPs.get(postId);
  if (existing && Date.now() - existing.createdAt <= POST_LIKE_TTL) {
    existing.ips.add(ip);
  } else {
    postLikeIPs.set(postId, { ips: new Set([ip]), createdAt: Date.now() });
  }
}

// Sweep stale postLikeIPs entries every hour
setInterval(() => {
  const now = Date.now();
  let cleaned = 0;
  for (const [postId, entry] of postLikeIPs.entries()) {
    if (now - entry.createdAt > POST_LIKE_TTL) {
      postLikeIPs.delete(postId);
      cleaned++;
    }
  }
  if (cleaned > 0) console.log(`🧹 postLikeIPs: cleared ${cleaned} expired entries`);
}, 60 * 60 * 1000);

// ─── helper: resolve real client IP ───
function getClientIp(req) {
  return (
    req.headers['x-forwarded-for']?.split(',')[0]?.trim() ||
    req.headers['x-real-ip'] ||
    req.socket.remoteAddress ||
    'unknown'
  );
}
 
