// Multer instance for creator product files — allows all file types including audio/video
// (music tracks and software installers route through here from the dashboard)
const uploadCreatorProductFile = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: 250 * 1024 * 1024 }, // 250MB — ebooks/PDFs/audio rarely exceed this
  fileFilter: (req, file, cb) => {
    const ALLOWED = [
      // Images
      'image/jpeg', 'image/jpg', 'image/png', 'image/gif', 'image/webp', 'image/svg+xml',
      // Documents
      'application/pdf',
      'application/msword',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      'text/plain', 'text/html', 'text/css', 'text/javascript', 'application/javascript',
      'application/json',
      // Archives / installers
      'application/zip', 'application/x-zip-compressed',
      'application/x-rar-compressed', 'application/x-tar',
      'application/gzip', 'application/x-7z-compressed', 'application/x-bzip2',
      'application/octet-stream',
      'application/x-msdownload',
      'application/vnd.android.package-archive',
      'application/x-apple-diskimage',
      // Spreadsheets / Presentations
      'application/vnd.ms-excel',
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      'application/vnd.ms-powerpoint',
      'application/vnd.openxmlformats-officedocument.presentationml.presentation',
      // Audio — for music product type
      'audio/mpeg', 'audio/mp3', 'audio/wav', 'audio/x-wav',
      'audio/ogg', 'audio/flac', 'audio/x-flac', 'audio/aac',
      'audio/x-m4a', 'audio/mp4', 'audio/opus', 'audio/webm',
      // Video — for video product type
      'video/mp4', 'video/webm', 'video/ogg', 'video/quicktime', 'video/x-msvideo',
    ];
    if (ALLOWED.includes(file.mimetype)) return cb(null, true);
    cb(new Error(`File type not supported: ${file.mimetype}`), false);
  }
});

// Upload a product's main deliverable file (creator — all product types)
app.post('/api/upload/creator-product-file', authenticateToken, uploadCreatorProductFile.single('file'), async (req, res) => {
  try {
    if (!req.file) return res.status(400).json({ success: false, message: 'No file uploaded' });

    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator) return res.status(403).json({ success: false, message: 'Creator account required' });
    if (creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Creator account must be approved' });
    }

    const folder = `uyehtech/creator-products/${creator._id}`;
    const result = await uploadToCloudinary(req.file.buffer, req.file.mimetype, folder);

    res.json({
      success:  true,
      message:  'File uploaded successfully',
      file: {
        publicId:      result.publicId,
        secureUrl:     result.secureUrl,
        resourceType:  result.resourceType,
        bytes:         result.bytes,
        format:        result.format,
        duration:      result.duration || null,
        originalName:  req.file.originalname,   // ← FIX: store real filename
        fileSizeLabel: formatBytes(result.bytes),
      }
    });
  } catch (error) {
    console.error('❌ Creator product file upload error:', error);
    res.status(500).json({ success: false, message: error.message || 'File upload failed' });
  }
});
 
