// SOFTWARE PRODUCT UPLOADS
// POST /api/upload/software-file     — the app/installer (exe, dmg, apk, zip)
// POST /api/upload/software-data     — supplementary data files (docs, datasets)
// ══════════════════════════════════════════════════════════════════════════════

const uploadSoftwareFile = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: 500 * 1024 * 1024 }, // 500MB — larger files must be chunked or use direct Cloudinary upload from frontend
  fileFilter: (req, file, cb) => {
    const ALLOWED_SW = [
      // Executables & installers
      'application/octet-stream',       // .exe, .dmg, .bin, .apk, .ipa
      'application/x-msdownload',       // .exe (alternate mime)
      'application/vnd.android.package-archive', // .apk
      'application/x-apple-diskimage',  // .dmg
      // Archives (zipped source/app)
      'application/zip', 'application/x-zip-compressed',
      'application/x-rar-compressed', 'application/x-tar',
      'application/gzip', 'application/x-7z-compressed',
      'application/x-bzip2',
      // Scripts & source
      'text/plain', 'text/javascript', 'application/javascript',
      'application/json',
      // Documents (readme, license)
      'application/pdf',
      'application/msword',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    ];
    if (ALLOWED_SW.includes(file.mimetype)) return cb(null, true);
    cb(new Error(`File type not allowed for software: ${file.mimetype}`), false);
  }
});

const uploadSoftwareData = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: 500 * 1024 * 1024 }, // 500MB
  fileFilter: (req, file, cb) => {
    const ALLOWED_DATA = [
      'application/json', 'text/csv', 'text/plain',
      'application/vnd.ms-excel',
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      'application/zip', 'application/x-zip-compressed',
      'application/pdf',
      'application/octet-stream', // generic binary data
    ];
    if (ALLOWED_DATA.includes(file.mimetype)) return cb(null, true);
    cb(new Error(`Data file type not allowed: ${file.mimetype}`), false);
  }
});

