app.post('/api/auth/send-email-otp', otpLimiter, async (req, res) => {
  try {
    const { email } = req.body;
    if (!email) {
      return res.status(400).json({ success: false, message: 'Email required' });
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({ success: false, message: 'Invalid email' });
    }

    const cleanEmail = email.toLowerCase().trim();
    const otp = generateOTP();
   
    otpStore.set(cleanEmail, {
      code: otp,
      expires: Date.now() + 10 * 60 * 1000,
      attempts: 0
    });

    await sendEmailOTP(cleanEmail, otp, 'verification');

    res.json({
      success: true,
      message: 'Verification code sent',
      email: cleanEmail,
      ...(process.env.NODE_ENV === 'development' && { debug_otp: otp })
    });
  } catch (error) {
    console.error('❌ Send OTP error:', error);
    res.status(500).json({ success: false, message: 'Failed to send code' });
  }
});

app.post('/api/auth/verify-email-otp', async (req, res) => {
  try {
    const { email, code } = req.body;
    if (!email || !code) {
      return res.status(400).json({ success: false, message: 'Email and code required' });
    }

    const cleanEmail = email.toLowerCase().trim();
    const storedOTP = otpStore.get(cleanEmail);

    if (!storedOTP) {
      return res.status(400).json({ success: false, message: 'No code found' });
    }

    if (Date.now() > storedOTP.expires) {
      otpStore.delete(cleanEmail);
      return res.status(400).json({ success: false, message: 'Code expired' });
    }

    if (storedOTP.attempts >= 5) {
      otpStore.delete(cleanEmail);
      return res.status(400).json({ success: false, message: 'Too many attempts' });
    }

    if (storedOTP.code !== String(code).trim()) {
      storedOTP.attempts += 1;
      otpStore.set(cleanEmail, storedOTP);
      return res.status(400).json({ success: false, message: 'Invalid code' });
    }

    otpStore.delete(cleanEmail);
    res.json({ success: true, message: 'Email verified' });
  } catch (error) {
    console.error('❌ Verify OTP error:', error);
    res.status(500).json({ success: false, message: 'Verification failed' });
  }
});

app.post('/api/auth/signup', authLimiter, async (req, res) => {
  try {

    // ── Check if registration is allowed ──────────────────────────────────
    const siteSettings = await getSettings();
    if (siteSettings && siteSettings.allowRegistration === false) {
      return res.status(403).json({ success: false, message: 'New registrations are currently closed.' });
    }

    const { fullName, email, password, emailVerified, ref } = req.body;

    if (!fullName || !email || !password) {
      return res.status(400).json({ success: false, message: 'All fields required' });
    }

    if (!emailVerified) {
      return res.status(400).json({ success: false, message: 'Verify email first' });
    }

    const existingUser = await User.findOne({ email: email.toLowerCase() });
    if (existingUser) {
      return res.status(400).json({ success: false, message: 'Email already registered' });
    }

    if (password.length < 8) {
      return res.status(400).json({ success: false, message: 'Password must be 8+ characters' });
    }

    // Check email verification requirement from settings
    const requireVerif = !siteSettings || siteSettings.requireEmailVerification !== false;
    if (requireVerif && !emailVerified) {
      return res.status(400).json({ success: false, message: 'Verify email first' });
    }

    // ── Resolve affiliate referral code ────────────────────────────────────
    // Priority: body `ref` field → `req.affiliateCode` (set by middleware from ?ref= query)
    // Sanitize: strip everything except A-Z 0-9 and hyphen/underscore (blocks NoSQL injection)
    let referrerAffiliate = null;
    const rawRef = (typeof ref === 'string' ? ref : null) ||
                   (typeof req.affiliateCode === 'string' ? req.affiliateCode : null);

    if (rawRef) {
      const safeRef = rawRef.replace(/[^a-zA-Z0-9_-]/g, '').toUpperCase().slice(0, 20);
      if (safeRef) {
        referrerAffiliate = await Affiliate.findOne({
          $or: [
            { affiliateCode: safeRef },
            { customSlug: safeRef.toLowerCase() }
          ],
          status: 'active'
        }).lean();
        if (!referrerAffiliate) {
          console.log(`ℹ️  Signup ref "${safeRef}" not matched to any active affiliate — proceeding without referral`);
        }
      }
    }

    const hashedPassword = await bcrypt.hash(password, 10);

    const user = new User({
      fullName,
      email:           email.toLowerCase(),
      password:        hashedPassword,
      emailVerified:   true,
      emailVerifiedAt: new Date(),
      // Record affiliate referral if present
      referredByAffiliateId:   referrerAffiliate?._id   || null,
      referredByAffiliateCode: referrerAffiliate?.affiliateCode || null,
    });

    await user.save();
    trackNewUser();

    // ── Increment referrer's totalReferrals and run tier promotion ─────────
    // Fire-and-forget — never delays the signup response
    if (referrerAffiliate) {
      setImmediate(async () => {
        try {
          await Affiliate.findByIdAndUpdate(referrerAffiliate._id, {
            $addToSet: { referrals: user._id }, // store user._id (not affiliate._id — these are real users)
            $inc:      { totalReferrals: 1 }
          });

          // Re-read and run 4-tier promotion check
          const freshReferrer = await Affiliate.findById(referrerAffiliate._id);
          if (freshReferrer) {
            const promoted = _checkAndPromoteAffiliateTier(freshReferrer);
            if (promoted) {
              await freshReferrer.save();
              console.log(`🏆 Affiliate ${freshReferrer.affiliateCode} promoted to ${freshReferrer.tier} via signup referral (${freshReferrer.totalReferrals} refs)`);
              // TODO: send tier-upgrade notification email here if desired
            }
          }
          console.log(`🔗 Signup referral recorded: ${referrerAffiliate.affiliateCode} referred ${user.email}`);
        } catch (refErr) {
          console.error('❌ Referral count update failed (non-blocking):', refErr.message);
        }
      });
    }

    // Welcome email — fire and forget
    setImmediate(() => {
      sendWelcomeEmail(user.email, user.fullName).catch(e =>
        console.error('⚠️ Welcome email failed:', e.message)
      );
    });

    const token = jwt.sign({ userId: user._id, email: user.email }, JWT_SECRET, { expiresIn: '7d' });
    await logSignup(req, user, true);

    res.status(201).json({
      success: true,
      message: 'Account created successfully!',
      token,
      user: {
        id:        user._id,
        name:      user.fullName,
        email:     user.email,
        isAdmin:   user.isAdmin,
        isCreator: user.isCreator || false
      }
    });
  } catch (error) {
    console.error('❌ Signup error:', error);
    res.status(500).json({ success: false, message: 'Signup failed' });
  }
});

// ════════════════════════════════════════════════════════════════════════════
// 🔑 USER LOGIN (🔧 FIXED - Returns fullName + emailVerified)
// ════════════════════════════════════════════════════════════════════════════
// ── Internal helpers ───────────────────────────────────────────────────────
 
/**
 * Verify a TOTP code OR a backup code for a user.
 * Returns { valid: true } or { valid: false, reason: '...' }
 * Also handles per-user rate limiting (5 wrong codes → 15 min lock).
 */
async function _verify2FACode(user, code) {
  const clean = String(code || '').trim().replace(/\s/g, '');
  if (!clean) return { valid: false, reason: 'No code provided' };
 
  // ── Per-user brute-force lock (DB-level, survives server restart) ───────
  if (user.twoFactorLockedUntil && user.twoFactorLockedUntil > new Date()) {
    const waitMin = Math.ceil((user.twoFactorLockedUntil - Date.now()) / 60000);
    return {
      valid: false,
      reason: `Account 2FA is temporarily locked. Try again in ${waitMin} minute(s).`
    };
  }
 
  // ── Try TOTP first ────────────────────────────────────────────────────
  const totpValid = speakeasy.totp.verify({
    secret:   user.twoFactorSecret,
    encoding: 'base32',
    token:    clean,
    window:   1,   // accept 1 step before/after (±30 sec tolerance)
  });
 
  if (totpValid) {
    // Reset brute-force counter on success
    if (user.twoFactorAttempts > 0) {
      user.twoFactorAttempts    = 0;
      user.twoFactorLockedUntil = undefined;
      await user.save();
    }
    return { valid: true, method: 'totp' };
  }
 
  // ── Try backup codes ──────────────────────────────────────────────────
  // Only try if the code looks like a backup code (longer than 6 chars)
  if (clean.length > 6 && Array.isArray(user.twoFactorBackupCodes)) {
    for (let i = 0; i < user.twoFactorBackupCodes.length; i++) {
      const entry = user.twoFactorBackupCodes[i];
      if (entry.usedAt) continue; // already redeemed
 
      const match = await bcrypt.compare(clean.toUpperCase(), entry.codeHash);
      if (match) {
        // Mark this backup code as used
        user.twoFactorBackupCodes[i].usedAt = new Date();
        user.twoFactorAttempts    = 0;
        user.twoFactorLockedUntil = undefined;
        await user.save();
 
        // Fire-and-forget email alert
        setImmediate(() => {
          _send2FABackupCodeUsedEmail(user.email, user.fullName).catch(() => {});
        });
 
        return { valid: true, method: 'backup_code' };
      }
    }
  }
 
  // ── Wrong code — increment attempt counter ────────────────────────────
  user.twoFactorAttempts = (user.twoFactorAttempts || 0) + 1;
  if (user.twoFactorAttempts >= 5) {
    user.twoFactorLockedUntil = new Date(Date.now() + 15 * 60 * 1000);
    user.twoFactorAttempts    = 0;
    await user.save();
    return {
      valid: false,
      reason: 'Too many wrong codes. 2FA locked for 15 minutes.',
      locked: true,
    };
  }
  await user.save();
 
  return {
    valid: false,
    reason: 'Invalid code. Please check your authenticator app.',
    attemptsLeft: 5 - user.twoFactorAttempts,
  };
}
 
/**
 * Generate 8 random backup codes, return plaintext array and hash array.
 * Format: XXXX-XXXX (easy to read, hard to guess)
 */
async function _generateBackupCodes() {
  const chars     = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'; // no ambiguous chars
  const plaintext = [];
  const hashed    = [];
 
  for (let i = 0; i < 8; i++) {
    const part1 = Array.from({ length: 4 }, () => chars[Math.floor(Math.random() * chars.length)]).join('');
    const part2 = Array.from({ length: 4 }, () => chars[Math.floor(Math.random() * chars.length)]).join('');
    const code  = `${part1}-${part2}`;
    plaintext.push(code);
    hashed.push({ codeHash: await bcrypt.hash(code, 10), usedAt: null });
  }
 
  return { plaintext, hashed };
}
 
// ─────────────────────────────────────────────────────────────────────────
// LOGIN — updated to handle 2FA challenge
// ─────────────────────────────────────────────────────────────────────────
app.post('/api/auth/login', authLimiter,  authEmailLimiter, async (req, res) => {
  try {
    const { email, password } = req.body;
 
    if (!email || !password) {
      return res.status(400).json({ success: false, message: 'Email and password are required' });
    }
 
    const user = await User.findOne({ email: email.toLowerCase() });
    if (!user) {
      await logLogin(req, null, false, 'invalid_credentials');
      return res.status(401).json({ success: false, message: 'Invalid email or password' });
    }

    // ── Re-activate if user previously deactivated their own account ───────
    if (user.isDeactivated) {
      user.isDeactivated = false;
      user.deactivatedAt = null;
      // do not save yet — the save at the end of the route will persist this
    }

    // ── Account lockout check ──────────────────────────────────────────────
    if (user.lockUntil && user.lockUntil > Date.now()) {
      const minutesLeft = Math.ceil((user.lockUntil - Date.now()) / 60000);
      await logLogin(req, user, false, 'account_locked');
      return res.status(429).json({
        success: false,
        message: `Account temporarily locked due to too many failed attempts. Try again in ${minutesLeft} minute${minutesLeft === 1 ? '' : 's'}.`,
        lockedUntil: user.lockUntil,
      });
    }
    if (user.isBanned) {
      await logLogin(req, user, false, 'account_banned');
      return res.status(403).json({
        success: false,
        message: `Account is banned. Reason: ${user.banReason || 'Please contact support'}`
      });
    }
 
    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      // Increment login attempt counter (from schema audit fix)
      user.loginAttempts = (user.loginAttempts || 0) + 1;
      if (user.loginAttempts >= 10) {
        user.lockUntil = new Date(Date.now() + 30 * 60 * 1000); // 30 min
        user.loginAttempts = 0;
      }
      await user.save();
      return res.status(401).json({ success: false, message: 'Invalid email or password' });
    }
 
    // ── 2FA CHECK ─────────────────────────────────────────────────────────
    if (user.twoFactorEnabled && user.twoFactorSecret) {
      // Issue a short-lived pre-auth token (5 min) that ONLY allows the
      // 2FA verification call — it carries no real session privileges.
      const preAuthToken = jwt.sign(
        { userId: user._id, email: user.email, preAuth: true },
        JWT_SECRET,
        { expiresIn: '5m' }
      );
 
      return res.json({
        success:       true,
        twoFactorRequired: true,
        preAuthToken,
        message: 'Enter your 2FA code to complete login',
      });
    }
 
    // ── No 2FA — issue full session token ─────────────────────────────────
    user.loginAttempts = 0;
    user.lockUntil     = undefined;
    user.lastLogin     = new Date();
    user.lastActivity  = new Date();

    // Issue refresh token and store hashed
    const rawRefresh  = crypto.randomBytes(64).toString('hex');
    user.refreshToken = hashToken(rawRefresh);
    await user.save();

    const token = jwt.sign(
      { userId: user._id, email: user.email },
      JWT_SECRET,
      { expiresIn: '15m' }   // short-lived — client uses refresh to extend
    );

    console.log(`✅ User logged in: ${user.email}`);
    await logLogin(req, user, true);
    res.json({
      success: true,
      message: 'Login successful',
      token,
      refreshToken: rawRefresh,
      expiresIn: 900,         // 15 minutes in seconds
      user: {
        id:            user._id,
        fullName:      user.fullName,
        name:          user.fullName,
        email:         user.email,
        phone:         user.phone          || '',
        country:       user.country        || '',
        profileImage:  user.profileImage   || '',
        emailVerified: user.emailVerified,
        isAdmin:       user.isAdmin,
        isAgent:       user.isAgent,
        isCreator:     user.isCreator      || false,
        twoFactorEnabled: user.twoFactorEnabled,
        createdAt:     user.createdAt,
      }
    });
 
  } catch (error) {
    console.error('❌ Login error:', error);
    res.status(500).json({ success: false, message: 'Login failed' });
  }
});
 
 // ─────────────────────────────────────────────────────────────────────────
// 2FA COMPLETE LOGIN — verify TOTP/backup code, issue real session token
// Called after login returns twoFactorRequired: true
// ─────────────────────────────────────────────────────────────────────────
app.post('/api/auth/2fa/verify-login', twoFaLimiter, async (req, res) => {
  try {
    const { preAuthToken, code } = req.body;
 
    if (!preAuthToken || !code) {
      return res.status(400).json({ success: false, message: 'preAuthToken and code are required' });
    }
 
    // Decode and validate the pre-auth token
    let decoded;
    try {
      decoded = jwt.verify(preAuthToken, JWT_SECRET);
    } catch {
      return res.status(401).json({ success: false, message: 'Session expired — please log in again' });
    }
 
    if (!decoded.preAuth) {
      return res.status(401).json({ success: false, message: 'Invalid token type' });
    }
 
    const user = await User.findById(decoded.userId);
    if (!user || user.isBanned) {
      return res.status(401).json({ success: false, message: 'Account not found or banned' });
    }
 
    // Verify the code
    const result = await _verify2FACode(user, code);
    if (!result.valid) {
      return res.status(401).json({
        success:      false,
        message:      result.reason,
        attemptsLeft: result.attemptsLeft,
        locked:       result.locked || false,
      });
    }
 
    // Issue the real full-session token
    user.lastLogin    = new Date();
    user.lastActivity = new Date();

    // Issue and store refresh token
    const rawRefresh  = crypto.randomBytes(64).toString('hex');
    user.refreshToken = hashToken(rawRefresh);
    await user.save();

    const token = jwt.sign(
      { userId: user._id, email: user.email },
      JWT_SECRET,
      { expiresIn: '15m' }
    );

    console.log(`✅ 2FA login complete (${result.method}): ${user.email}`);

    res.json({
      success: true,
      message: 'Login successful',
      method:  result.method,
      token,
      refreshToken: rawRefresh,
      expiresIn: 900,
      user: {
        id:            user._id,
        fullName:      user.fullName,
        name:          user.fullName,
        email:         user.email,
        phone:         user.phone          || '',
        country:       user.country        || '',
        profileImage:  user.profileImage   || '',
        emailVerified: user.emailVerified,
        isAdmin:       user.isAdmin,
        isAgent:       user.isAgent,
        isCreator:     user.isCreator      || false,
        twoFactorEnabled: user.twoFactorEnabled,
        createdAt:     user.createdAt,
      }
    });
 
  } catch (error) {
    console.error('❌ 2FA verify-login error:', error);
    res.status(500).json({ success: false, message: '2FA verification failed' });
  }
});
 
 
// ─────────────────────────────────────────────────────────────────────────
// 2FA SETUP — Step 1: generate secret + QR code
// Returns qrCodeUrl (data URI) and manualEntryKey
// The secret is stored as twoFactorPending — NOT yet active
// ─────────────────────────────────────────────────────────────────────────
app.post('/api/auth/2fa/setup', authenticateToken, async (req, res) => {
  try {
    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
 
    if (user.twoFactorEnabled) {
      return res.status(400).json({
        success: false,
        message: '2FA is already enabled. Disable it first before setting up a new authenticator.'
      });
    }
 
    // Generate a fresh TOTP secret
    const secret = speakeasy.generateSecret({
      name:   `UYEH TECH (${user.email})`,
      issuer: 'UYEH TECH',
      length: 32,
    });
 
    // Store it as PENDING — only becomes active after the user confirms a code
    user.twoFactorPending = secret.base32;
    await user.save();
 
    // Build the otpauth URI and render a QR code as a data URI
    const otpauthUrl = speakeasy.otpauthURL({
      secret:  secret.base32,
      label:   encodeURIComponent(`UYEH TECH:${user.email}`),
      issuer:  'UYEH TECH',
      encoding:'base32',
    });
 
    const qrCodeUrl = await QRCode.toDataURL(otpauthUrl, {
      width:           260,
      margin:          2,
      color: { dark: '#00ff88', light: '#0a0a0a' }
    });
 
    console.log(`🔐 2FA setup initiated: ${user.email}`);
 
    res.json({
      success:        true,
      message:        'Scan the QR code with your authenticator app, then call /api/auth/2fa/confirm to activate',
      qrCodeUrl,
      manualEntryKey: secret.base32,  // for users who can't scan QR
      issuer:         'UYEH TECH',
      accountName:    user.email,
    });
 
  } catch (error) {
    console.error('❌ 2FA setup error:', error);
    res.status(500).json({ success: false, message: '2FA setup failed' });
  }
});
 
 
// ─────────────────────────────────────────────────────────────────────────
// 2FA CONFIRM — Step 2: verify first code → activate 2FA + generate backups
// User scanned the QR and submits their first code to prove it works
// ─────────────────────────────────────────────────────────────────────────
app.post('/api/auth/2fa/confirm', authenticateToken, twoFaLimiter, async (req, res) => {
  try {
    const { code } = req.body;
    if (!code) {
      return res.status(400).json({ success: false, message: 'Verification code is required' });
    }
 
    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
 
    if (!user.twoFactorPending) {
      return res.status(400).json({
        success: false,
        message: 'No pending 2FA setup found. Call /api/auth/2fa/setup first.'
      });
    }
 
    // Verify the code against the PENDING secret
    const totpValid = speakeasy.totp.verify({
      secret:   user.twoFactorPending,
      encoding: 'base32',
      token:    String(code).trim(),
      window:   1,
    });
 
    if (!totpValid) {
      return res.status(401).json({
        success: false,
        message: 'Invalid code. Make sure your authenticator app is showing the current code and try again.'
      });
    }
 
    // Code is correct — activate 2FA
    const { plaintext, hashed } = await _generateBackupCodes();
 
    user.twoFactorSecret      = user.twoFactorPending;  // promote pending → active
    user.twoFactorPending     = undefined;               // clear pending
    user.twoFactorEnabled     = true;
    user.twoFactorBackupCodes = hashed;
    user.twoFactorEnabledAt   = new Date();
    user.twoFactorAttempts    = 0;
    user.twoFactorLockedUntil = undefined;
    await user.save();
 
    console.log(`✅ 2FA ENABLED: ${user.email}`);
 
    // Email alert
    setImmediate(() => {
      _send2FAEnabledEmail(user.email, user.fullName).catch(() => {});
    });
 
    res.json({
      success:      true,
      message:      '✅ Two-factor authentication is now active on your account',
      backupCodes:  plaintext,  // shown ONCE — user must save these
      backupCodeWarning: 'Save these backup codes somewhere safe. Each can only be used once. You cannot view them again.',
    });
 
  } catch (error) {
    console.error('❌ 2FA confirm error:', error);
    res.status(500).json({ success: false, message: '2FA confirmation failed' });
  }
});
 
 
// ─────────────────────────────────────────────────────────────────────────
// 2FA DISABLE — requires a live TOTP code (cannot just toggle off)
// ─────────────────────────────────────────────────────────────────────────
app.post('/api/auth/2fa/disable', authenticateToken, twoFaLimiter, async (req, res) => {
  try {
    const { code, password } = req.body;
 
    if (!code || !password) {
      return res.status(400).json({
        success: false,
        message: 'Both your current password and a 2FA code are required to disable 2FA'
      });
    }
 
    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
 
    if (!user.twoFactorEnabled) {
      return res.status(400).json({ success: false, message: '2FA is not currently enabled' });
    }
 
    // Require password confirmation first
    const passwordValid = await bcrypt.compare(password, user.password);
    if (!passwordValid) {
      return res.status(401).json({ success: false, message: 'Incorrect password' });
    }
 
    // Require a valid TOTP or backup code
    const result = await _verify2FACode(user, code);
    if (!result.valid) {
      return res.status(401).json({
        success:      false,
        message:      result.reason,
        attemptsLeft: result.attemptsLeft,
        locked:       result.locked || false,
      });
    }
 
    // Wipe all 2FA data
    user.twoFactorEnabled     = false;
    user.twoFactorSecret      = undefined;
    user.twoFactorPending     = undefined;
    user.twoFactorBackupCodes = [];
    user.twoFactorEnabledAt   = undefined;
    user.twoFactorAttempts    = 0;
    user.twoFactorLockedUntil = undefined;
    await user.save();
 
    console.log(`⚠️  2FA DISABLED: ${user.email}`);
 
    setImmediate(() => {
      _send2FADisabledEmail(user.email, user.fullName).catch(() => {});
    });
 
    res.json({ success: true, message: '2FA has been disabled. Your account is now protected by password only.' });
 
  } catch (error) {
    console.error('❌ 2FA disable error:', error);
    res.status(500).json({ success: false, message: '2FA disable failed' });
  }
});
 
 
// ─────────────────────────────────────────────────────────────────────────
// 2FA STATUS — get current 2FA state for the settings page
// ─────────────────────────────────────────────────────────────────────────
app.get('/api/auth/2fa/status', authenticateToken, async (req, res) => {
  try {
    const user = await User.findById(req.user.userId)
                           .select('twoFactorEnabled twoFactorEnabledAt twoFactorBackupCodes twoFactorLockedUntil')
                           .lean();
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
 
    const backupCodesRemaining = (user.twoFactorBackupCodes || [])
      .filter(c => !c.usedAt).length;
 
    res.json({
      success: true,
      twoFactorEnabled:       user.twoFactorEnabled || false,
      enabledAt:              user.twoFactorEnabledAt || null,
      backupCodesRemaining,
      backupCodesTotal:       8,
      locked:                 !!(user.twoFactorLockedUntil && user.twoFactorLockedUntil > new Date()),
      lockedUntil:            user.twoFactorLockedUntil || null,
    });
 
  } catch (error) {
    console.error('❌ 2FA status error:', error);
    res.status(500).json({ success: false, message: 'Could not fetch 2FA status' });
  }
});
 
 
// ─────────────────────────────────────────────────────────────────────────
// 2FA REGENERATE BACKUP CODES
// Requires a live TOTP code — old codes are immediately invalidated
// ─────────────────────────────────────────────────────────────────────────
app.post('/api/auth/2fa/backup-codes/regenerate', authenticateToken, twoFaLimiter, async (req, res) => {
  try {
    const { code } = req.body;
    if (!code) {
      return res.status(400).json({ success: false, message: 'A current 2FA code is required to regenerate backup codes' });
    }
 
    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
 
    if (!user.twoFactorEnabled) {
      return res.status(400).json({ success: false, message: '2FA is not enabled on this account' });
    }
 
    // Verify live TOTP only — no backup codes for this action
    const totpValid = speakeasy.totp.verify({
      secret:   user.twoFactorSecret,
      encoding: 'base32',
      token:    String(code).trim(),
      window:   1,
    });
 
    if (!totpValid) {
      return res.status(401).json({
        success: false,
        message: 'Invalid code. Use your authenticator app (not a backup code) to regenerate backup codes.'
      });
    }
 
    // Generate fresh set — old ones are discarded
    const { plaintext, hashed } = await _generateBackupCodes();
    user.twoFactorBackupCodes   = hashed;
    await user.save();
 
    console.log(`🔑 2FA backup codes regenerated: ${user.email}`);
 
    res.json({
      success:      true,
      message:      'New backup codes generated. Your old codes are now invalid.',
      backupCodes:  plaintext,
      backupCodeWarning: 'Save these now — they will not be shown again.',
    });
 
  } catch (error) {
    console.error('❌ 2FA backup code regeneration error:', error);
    res.status(500).json({ success: false, message: 'Backup code regeneration failed' });
  }
});
 

// Change Password (Authenticated)
app.post('/api/auth/change-password', authenticateToken, async (req, res) => {
  try {
    const { currentPassword, newPassword } = req.body;

    if (!currentPassword || !newPassword) {
      return res.status(400).json({ success: false, message: 'Current and new password are required' });
    }

    if (newPassword.length < 8) {
      return res.status(400).json({ success: false, message: 'New password must be at least 8 characters long' });
    }

    const user = await User.findById(req.user.userId);
    if (!user) {
      return res.status(404).json({ success: false, message: 'User not found' });
    }

    // Verify current password
    const isPasswordValid = await bcrypt.compare(currentPassword, user.password);
    if (!isPasswordValid) {
      return res.status(401).json({ success: false, message: 'Current password is incorrect' });
    }

    // Update to new password
    user.password = await bcrypt.hash(newPassword, 10);
    await user.save();

    console.log(`✅ Password changed: ${user.email}`);
    await logPasswordChange(req, req.user.userId, true);
    res.json({ success: true, message: 'Password changed successfully' });

    setImmediate(() => {
      sendPasswordChangedEmail(user.email, user.fullName).catch(e =>
        console.error('⚠️ Password changed email failed:', e.message)
      );
    });
    
  } catch (error) {
    console.error('❌ Change password error:', error);
    res.status(500).json({ success: false, message: 'Password change failed' });
  }
});

// ── POST /api/auth/deactivate — soft self-service account deactivation ──────
// Sets isDeactivated = true and wipes the refresh token (ends all sessions).
// The account is automatically restored the next time the user logs in successfully.
app.post('/api/auth/deactivate', authenticateToken, async (req, res) => {
  try {
    const user = await User.findById(req.user.userId);
    if (!user)       return res.status(404).json({ success: false, message: 'User not found' });
    if (user.isBanned) return res.status(403).json({ success: false, message: 'Account is banned' });

    user.isDeactivated = true;
    user.deactivatedAt = new Date();
    user.refreshToken  = null;   // invalidates all active sessions immediately
    await user.save();

    console.log(`⏸️  Account self-deactivated: ${user.email}`);
    res.json({
      success: true,
      message: 'Account deactivated. Log back in any time to restore full access.',
    });
  } catch (err) {
    console.error('❌ Deactivate account error:', err.message);
    res.status(500).json({ success: false, message: 'Deactivation failed. Please try again.' });
  }
});

