// ── SAVE push subscription ────────────────────────────────────────────────
// Called by the frontend after the user grants notification permission.
// Stores the subscription object (endpoint + keys) on the User document.
app.post('/api/push/subscribe', authenticateToken, requireWebPush, async (req, res) => {
  try {
    const { subscription, userAgent } = req.body;
 
    // Validate the subscription object shape
    if (
      !subscription                  ||
      !subscription.endpoint         ||
      !subscription.keys             ||
      !subscription.keys.p256dh      ||
      !subscription.keys.auth
    ) {
      return res.status(400).json({
        success: false,
        message: 'Invalid subscription object. Must contain endpoint, keys.p256dh, and keys.auth.'
      });
    }
 
    const user = await User.findById(req.user.userId);
    if (!user) {
      return res.status(404).json({ success: false, message: 'User not found' });
    }
 
    // Prevent duplicates — check by endpoint URL
    const alreadyExists = user.pushSubscriptions.some(
      s => s.endpoint === subscription.endpoint
    );
 
    if (!alreadyExists) {
      user.pushSubscriptions.push({
        endpoint:       subscription.endpoint,
        expirationTime: subscription.expirationTime
          ? new Date(subscription.expirationTime)
          : null,
        keys: {
          p256dh: subscription.keys.p256dh,
          auth:   subscription.keys.auth,
        },
        userAgent: (userAgent || req.headers['user-agent'] || '').substring(0, 300),
      });
      await user.save();
      console.log(`📲 Push subscription saved for user: ${user.email}`);
    } else {
      console.log(`📲 Push subscription already exists for: ${user.email} — skipped duplicate`);
    }
 
    res.json({ success: true, message: 'Push subscription saved successfully' });
 
  } catch (err) {
    console.error('❌ Push subscribe error:', err);
    res.status(500).json({ success: false, message: 'Failed to save push subscription' });
  }
});
 
 
// ── DELETE push subscription ──────────────────────────────────────────────
// Called when a user disables notifications or logs out.
app.delete('/api/push/subscribe', authenticateToken, async (req, res) => {
  try {
    const { endpoint } = req.body;
    if (!endpoint) {
      return res.status(400).json({ success: false, message: 'endpoint is required' });
    }
 
    await User.findByIdAndUpdate(
      req.user.userId,
      { $pull: { pushSubscriptions: { endpoint } } },
      { new: true }
    );
 
    console.log(`🗑️  Push subscription removed for user: ${req.user.userId}`);
    res.json({ success: true, message: 'Push subscription removed' });
 
  } catch (err) {
    console.error('❌ Push unsubscribe error:', err);
    res.status(500).json({ success: false, message: 'Failed to remove subscription' });
  }
});
 
 
// ── SEND push notification (admin only) ───────────────────────────────────
// Supports:
//   - Send to a single user:   { userId: '...', title, body, url }
//   - Broadcast to all users:  { sendAll: true, title, body, url }
//   - Send to a user group:    { role: 'agent', title, body, url }
//     (role can be: 'agent', 'admin', 'creator', 'affiliate', 'all')
app.post('/api/admin/push/send', authenticateAdmin, requireWebPush, async (req, res) => {
  try {
    const {
      userId,             // string  — send to one specific user
      sendAll,            // boolean — send to every subscribed user
      role,               // string  — 'agent'|'admin'|'creator'|'affiliate'|'all'
      title,
      body,
      url,
      icon,
      image,
      tag,
      requireInteraction,
      actions,            // array of { action, title } for actionable notifications
    } = req.body;
 
    // ── Validate required fields ────────────────────────────────────────
    if (!title || !title.trim()) {
      return res.status(400).json({ success: false, message: 'title is required' });
    }
    if (!body || !body.trim()) {
      return res.status(400).json({ success: false, message: 'body is required' });
    }
    if (!userId && !sendAll && !role) {
      return res.status(400).json({
        success: false,
        message: 'Provide one of: userId, sendAll:true, or role (agent/admin/creator/affiliate/all)'
      });
    }
 
    // ── Build the notification payload ─────────────────────────────────
    const payload = JSON.stringify({
      title:              title.trim(),
      body:               body.trim(),
      url:                url   || '/',
      icon:               icon  || '/icons/icon-192.png',
      badge:              '/icons/icon-96.png',
      image:              image || undefined,
      tag:                tag   || 'uyeh-admin-push',
      requireInteraction: requireInteraction === true,
      actions:            Array.isArray(actions) ? actions : [],
      timestamp:          Date.now(),
    });
 
    // ── Find target users ───────────────────────────────────────────────
    let query = { 'pushSubscriptions.0': { $exists: true } }; // must have at least 1 sub
 
    if (userId) {
      // Single user
      query._id = userId;
    } else if (role && role !== 'all') {
      // Filter by role
      if (role === 'agent')     query.isAgent     = true;
      if (role === 'admin')     query.isAdmin     = true;
      // creator and affiliate are on separate collections —
      // look up their userIds first then filter
      if (role === 'creator') {
        const creatorUserIds = await Creator.find({ status: 'approved' })
                                            .select('userId').lean();
        query._id = { $in: creatorUserIds.map(c => c.userId) };
      }
      if (role === 'affiliate') {
        const affiliateUserIds = await Affiliate.find({ status: 'approved' })
                                               .select('userId').lean();
        query._id = { $in: affiliateUserIds.map(a => a.userId) };
      }
    }
    // sendAll = true → query is just { pushSubscriptions.0: exists }
 
    const users = await User.find(query)
                            .select('pushSubscriptions email')
                            .lean();
 
    if (users.length === 0) {
      return res.json({
        success: true,
        sent: 0, failed: 0, cleaned: 0,
        message: 'No subscribed users found matching your criteria'
      });
    }
 
    // ── Send to every subscription of every matched user ───────────────
    let sent    = 0;
    let failed  = 0;
    let cleaned = 0; // expired/invalid subscriptions removed
 
    for (const user of users) {
      for (const sub of (user.pushSubscriptions || [])) {
        try {
          await webpush.sendNotification(
            {
              endpoint:       sub.endpoint,
              expirationTime: sub.expirationTime,
              keys: {
                p256dh: sub.keys.p256dh,
                auth:   sub.keys.auth,
              },
            },
            payload,
            {
              TTL: 86400, // deliver within 24 hours if device is offline
              urgency: 'normal', // 'very-low' | 'low' | 'normal' | 'high'
            }
          );
          sent++;
        } catch (err) {
          // 410 Gone / 404 = this subscription is expired or was revoked by the browser.
          // Remove it immediately so we don't keep trying.
          if (err.statusCode === 410 || err.statusCode === 404) {
            await User.findByIdAndUpdate(user._id, {
              $pull: { pushSubscriptions: { endpoint: sub.endpoint } }
            });
            cleaned++;
            console.log(`🗑️  Removed expired push sub for ${user.email}`);
          } else {
            // Any other error (network, malformed sub, etc.) — log and move on
            console.warn(`⚠️  Push delivery failed for ${user.email}:`, err.message);
            failed++;
          }
        }
      }
    }
 
    console.log(
      `📲 Push campaign by ${req.adminUser.email}: ` +
      `${sent} sent, ${failed} failed, ${cleaned} stale removed`
    );
 
    res.json({
      success: true,
      sent,
      failed,
      cleaned,
      total:   users.length,
      message: `Notification delivered to ${sent} device(s)`,
    });
 
  } catch (err) {
    console.error('❌ Push send error:', err);
    res.status(500).json({ success: false, message: 'Push notification failed to send' });
  }
});
 

// ========== ADMIN AUTH ==========
app.post('/api/auth/admin/login', authLimiter, async (req, res) => {
  try {
    const { email, password } = req.body;

    const user = await User.findOne({ email: email.toLowerCase() });
    if (!user || !user.isAdmin) {
      return res.status(403).json({ success: false, message: 'Admin access required', isAdmin: false });
    }

    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      return res.status(401).json({ success: false, message: 'Invalid credentials' });
    }

    user.lastLogin = new Date();
    await user.save();

    const token = jwt.sign({ userId: user._id, email: user.email }, JWT_SECRET, { expiresIn: '24h' });

    res.json({
      success: true,
      message: 'Admin login successful',
      token,
      isAdmin: true,
      user: {
        id: user._id,
        name: user.fullName,
        email: user.email
      }
    });
  } catch (error) {
    console.error('❌ Admin login error:', error);
    res.status(500).json({ success: false, message: 'Login failed' });
  }
});

app.get('/api/auth/admin/verify', authenticateAdmin, async (req, res) => {
  // Decode token to get expiry without re-verifying (already verified by middleware)
  let tokenExpiresAt = null;
  try {
    const raw = (req.headers.authorization || '').replace('Bearer ', '');
    const decoded = jwt.decode(raw);
    if (decoded?.exp) tokenExpiresAt = new Date(decoded.exp * 1000).toISOString();
  } catch (_) {}

  res.json({
    success:        true,
    isAdmin:        true,
    tokenExpiresAt,
    user: {
      id:    req.adminUser._id,
      name:  req.adminUser.fullName,
      email: req.adminUser.email
    }
  });
});

// ── Admin token refresh ───────────────────────────────────────────────────
// Called by dashboard when token is within 24h of expiry.
// Requires a valid (not yet expired) token — issues a fresh 7d token.
app.post('/api/auth/admin/refresh', authenticateAdmin, async (req, res) => {
  try {
    const newToken = jwt.sign(
      { userId: req.adminUser._id, email: req.adminUser.email, role: 'admin' },
      JWT_SECRET,
      { expiresIn: '7d' }
    );
    res.json({
      success:  true,
      token:    newToken,
      expiresIn: 7 * 24 * 60 * 60, // seconds
    });
  } catch (err) {
    console.error('❌ Admin token refresh error:', err.message);
    res.status(500).json({ success: false, message: 'Token refresh failed' });
  }
});

// GET /api/email/unsubscribe/:token  — one-click unsubscribe (no login needed)
app.get('/api/email/unsubscribe/:token', async (req, res) => {
  try {
    const { token } = req.params;
    const user = await User.findOne({ unsubscribeToken: token });
    if (!user) {
      return res.status(400).send(`
        <html><body style="font-family:sans-serif;text-align:center;padding:60px;background:#0d1117;color:#fff;">
          <h2>Invalid unsubscribe link</h2>
          <p style="color:#9ca3af;">This link is invalid or has already been used.</p>
        </body></html>`);
    }
    user.notificationPreferences.email     = false;
    user.notificationPreferences.orders    = false;
    user.notificationPreferences.marketing = false;
    await user.save();
    res.send(`
      <html><body style="font-family:sans-serif;text-align:center;padding:60px;background:#0d1117;color:#fff;">
        <h2 style="color:#00ff88;">✅ Unsubscribed</h2>
        <p>You have been unsubscribed from all UYEH TECH emails.</p>
        <p style="color:#9ca3af;font-size:.9rem;">You will still receive critical account security emails.</p>
        <a href="${process.env.FRONTEND_URL || ''}/auth/login.html"
          style="display:inline-block;margin-top:20px;padding:12px 28px;background:#00ff88;color:#000;border-radius:8px;text-decoration:none;font-weight:700;">
          Go to UYEH TECH
        </a>
      </body></html>`);
  } catch (err) {
    console.error('❌ Unsubscribe error:', err.message);
    res.status(500).send('<h2>Something went wrong. Try again later.</h2>');
  }
});
 
