// ─────────────────────────────────────────────────────────────────────────────
// BLOCK 18 — AUTH REFRESH TOKENS (C6)
// ─────────────────────────────────────────────────────────────────────────────
// Utility — hash a refresh token before storing (never store raw)
function hashToken(raw) {
  return crypto.createHash('sha256').update(raw).digest('hex');
}
 
// POST /api/auth/refresh  — exchange refresh token for new access token
app.post('/api/auth/refresh', async (req, res) => {
  try {
    const { refreshToken } = req.body;
    if (!refreshToken) return res.status(401).json({ success: false, message: 'Refresh token required' });
 
    const hashed = hashToken(refreshToken);
    const user   = await User.findOne({ refreshToken: hashed }).select('_id email isAdmin isAgent isCreator isBanned refreshToken');
    if (!user) return res.status(401).json({ success: false, message: 'Invalid or expired refresh token' });
    if (user.isBanned) return res.status(403).json({ success: false, message: 'Account suspended' });
 
    const accessToken = jwt.sign(
      { userId: user._id, email: user.email, isAdmin: user.isAdmin, isAgent: user.isAgent, isCreator: user.isCreator },
      process.env.JWT_SECRET || JWT_SECRET,
      { expiresIn: '15m' }
    );
 
    // Rotate the refresh token on every use (prevents token reuse attacks)
    const newRaw    = crypto.randomBytes(64).toString('hex');
    user.refreshToken = hashToken(newRaw);
    await user.save();
 
    res.json({ success: true, accessToken, refreshToken: newRaw, expiresIn: 900 }); // 15min
  } catch (err) {
    console.error('❌ Token refresh error:', err.message);
    res.status(500).json({ success: false, message: 'Token refresh failed' });
  }
});
 
// POST /api/auth/logout  — invalidate refresh token
