// ─────────────────────────────────────────────────────────────────────────────
// BLOCK 19 — CREATOR ANALYTICS ROUTE (C7, B9)
// ─────────────────────────────────────────────────────────────────────────────
 
app.get('/api/creator/analytics', authenticateToken, async (req, res) => {
  try {
    const { period = '30' } = req.query;
    const days  = Math.min(365, Math.max(7, parseInt(period) || 30));
    const since = new Date(Date.now() - days * 24 * 60 * 60 * 1000);
 
    const creator = await Creator.findOne({ userId: req.user.userId })
      .select('_id storeName totalSales totalRevenue totalEarnings pendingPayout applicationStatus platformCommissionRate affiliateCommissionRate')
      .lean();
    if (!creator) return res.status(403).json({ success: false, message: 'Creator profile not found' });
    if (creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Creator account not yet approved' });
    }
 
    const [
      earningsSeries,
      productPerformance,
      topBuyerCountries,
      affiliateDrivenSales,
      directSales,
      recentPayouts,
    ] = await Promise.all([
      // Daily earnings over the period
      EarningsLedger.aggregate([
        { $match: { recipientId: creator.userId, recipientType: 'creator', createdAt: { $gte: since } } },
        { $group: { _id: { $dateToString: { format: '%Y-%m-%d', date: '$createdAt' } }, earned: { $sum: '$earningAmount' }, sales: { $sum: 1 } } },
        { $sort: { _id: 1 } }
      ]),
      // Per-product: sales count + revenue, sorted by revenue
      EarningsLedger.aggregate([
        { $match: { recipientId: creator.userId, recipientType: 'creator', createdAt: { $gte: since } } },
        { $group: { _id: '$productId', sales: { $sum: 1 }, revenue: { $sum: '$saleAmount' }, earned: { $sum: '$earningAmount' } } },
        { $sort: { revenue: -1 } },
        { $limit: 20 },
        { $lookup: { from: 'creatorproducts', localField: '_id', foreignField: 'productId', as: 'product' } },
        { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } }
      ]),
      // Buyer geography from orders
      Order.aggregate([
        { $match: { creatorProductIds: { $in: (await CreatorProduct.find({ creatorId: creator._id }).select('_id').lean()).map(p => p._id) }, status: 'completed', createdAt: { $gte: since } } },
        { $group: { _id: '$customerInfo.country', buyers: { $sum: 1 } } },
        { $sort: { buyers: -1 } },
        { $limit: 10 }
      ]),
      // Affiliate-driven sales
      EarningsLedger.aggregate([
        { $match: { recipientId: creator.userId, recipientType: 'creator', createdAt: { $gte: since } } },
        { $lookup: { from: 'orders', localField: 'orderId', foreignField: '_id', as: 'order' } },
        { $unwind: { path: '$order', preserveNullAndEmptyArrays: true } },
        {
          $group: {
            _id:    { hasAffiliate: { $cond: [{ $ifNull: ['$order.affiliateCode', false] }, true, false] } },
            count:  { $sum: 1 },
            earned: { $sum: '$earningAmount' }
          }
        }
      ]),
      // Direct sales count
      EarningsLedger.countDocuments({ recipientId: creator.userId, recipientType: 'creator', createdAt: { $gte: since } }),
      // Recent payouts
      PayoutRequest.find({ requesterId: creator.userId, requesterType: 'creator' })
        .sort({ createdAt: -1 }).limit(5).lean()
    ]);
 
    // Build affiliate vs direct split
    let affiliateCount = 0, affiliateEarned = 0;
    for (const row of affiliateDrivenSales) {
      if (row._id?.hasAffiliate === true) { affiliateCount = row.count; affiliateEarned = row.earned; }
    }
 
    res.json({
      success: true,
      period:  days,
      overview: {
        totalSales:    creator.totalSales,
        totalRevenue:  creator.totalRevenue,
        totalEarnings: creator.totalEarnings,
        pendingPayout: creator.pendingPayout,
        commissionRate: creator.platformCommissionRate,
      },
      earningsSeries: earningsSeries.map(d => ({ date: d._id, earned: d.earned, sales: d.sales })),
      productPerformance: productPerformance.map(p => ({
        productId:    p._id,
        title:        p.product?.title || '—',
        productType:  p.product?.productType || '—',
        sales:        p.sales,
        revenue:      p.revenue,
        earned:       p.earned,
        conversionRate: null, // views data would need a separate PageView model
      })),
      topBuyerCountries: topBuyerCountries.map(c => ({ country: c._id || 'Unknown', buyers: c.buyers })),
      salesSplit: {
        total:             directSales,
        affiliateDriven:   affiliateCount,
        direct:            directSales - affiliateCount,
        affiliateEarned,
      },
      recentPayouts: recentPayouts.map(p => ({
        id:          p._id,
        amount:      p.amount,
        status:      p.status,
        requestedAt: p.createdAt,
        processedAt: p.processedAt,
      })),
    });
  } catch (err) {
    console.error('❌ Creator analytics error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch analytics' });
  }
});
 
