// Agent Login
app.post('/api/auth/agent/login', authLimiter, async (req, res) => {
  try {
    const { email, password } = req.body;

    if (!email || !password) {
      return res.status(400).json({ success: false, message: 'Email and password are required' });
    }

    const user = await User.findOne({ email: email.toLowerCase() });
    
    if (!user || (!user.isAgent && !user.isAdmin)) {
      return res.status(403).json({ 
        success: false, 
        message: 'Agent access required', 
        isAgent: false 
      });
    }

    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      return res.status(401).json({ success: false, message: 'Invalid credentials' });
    }

    user.lastLogin = new Date();
    user.lastActivity = new Date();
    if (user.isAgent && user.agentInfo) {
      user.agentInfo.status = 'online';
    }
    await user.save();

    const token = jwt.sign(
      { userId: user._id, email: user.email }, 
      JWT_SECRET, 
      { expiresIn: '12h' }
    );

    console.log(`✅ Agent logged in: ${user.email}`);

    res.json({
      success: true,
      message: 'Agent login successful',
      token,
      isAgent: true,
      isAdmin: user.isAdmin,
      user: {
        id: user._id,
        name: user.fullName,
        email: user.email,
        agentInfo: user.agentInfo
      }
    });
    
  } catch (error) {
    console.error('❌ Agent login error:', error);
    res.status(500).json({ success: false, message: 'Login failed' });
  }
});

