// 👤 USER PROFILE ROUTES
// ════════════════════════════════════════════════════════════════════════════
// GET /api/profile  — everything the frontend ever needs about the current user
app.get('/api/profile', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.userId;

    // ── 1. Core user record ──────────────────────────────────────────────
    const user = await User.findById(userId)
      .select('-password -twoFactorSecret -emailVerificationToken -passwordResetToken')
      .lean();

    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    // ── 2. Creator profile (if applicable) ──────────────────────────────
    const creator = user.isCreator
      ? await Creator.findOne({ userId })
          .select('-payoutDetails.accountNumber -payoutDetails.iban -payoutDetails.routingNumber -payoutDetails.sortCode')
          .lean()
      : null;

    // ── 3. Affiliate profile (if applicable) ────────────────────────────
    const affiliate = await Affiliate.findOne({ userId }).lean();

    // ── 4. Purchase/order stats ──────────────────────────────────────────
    const [
      totalOrders,
      completedOrders,
      totalSpent,
      totalDownloads,
      activeCourses,
      completedCourses,
    ] = await Promise.all([
      Order.countDocuments({ userId }),
      Order.countDocuments({ userId, status: 'completed' }),
      Order.aggregate([
        { $match: { userId: user._id, status: 'completed' } },
        { $group: { _id: null, total: { $sum: '$total' } } },
      ]),
      Download.countDocuments({ userId }),
      CourseProgress.countDocuments({ userId, completionPct: { $gt: 0, $lt: 100 } }),
      CourseProgress.countDocuments({ userId, completionPct: 100 }),
    ]);

    // ── 5. Recent orders (last 5) ────────────────────────────────────────
    const recentOrders = await Order.find({ userId, status: 'completed' })
      .sort({ createdAt: -1 })
      .limit(5)
      .select('orderReference total items createdAt status paymentInfo.paidAt')
      .lean();

    // ── 6. Build response ────────────────────────────────────────────────
    const profile = {
      // Identity
      id:                user._id,
      fullName:          user.fullName,
      name:              user.fullName,       // legacy compat
      email:             user.email,
      phone:             user.phone  || null,
      country:           user.country || null,
      bio:               user.bio    || null,
      profileImage:      user.profileImage || null,

      // Social links (stored on user schema — add socialLinks to userSchema if not present)
      socialLinks: user.socialLinks || {
        twitter:   null,
        instagram: null,
        linkedin:  null,
        youtube:   null,
        website:   null,
      },

      // Status flags
      emailVerified:        user.emailVerified,
      twoFactorEnabled:     user.twoFactorEnabled,
      isAdmin:              user.isAdmin,
      isAgent:              user.isAgent,
      isCreator:            user.isCreator,
      isBanned:             user.isBanned,
      banReason:            user.banReason || null,

      // Notification preferences
      notificationPreferences: user.notificationPreferences || {
        email: true, orders: true, marketing: false,
      },

      // Timestamps
      createdAt:  user.createdAt,
      lastLogin:  user.lastLogin  || null,
      updatedAt:  user.updatedAt  || null,

      // ── Purchase stats ───────────────────────────────────────────────
      stats: {
        totalOrders,
        completedOrders,
        totalSpent:       totalSpent[0]?.total || 0,
        totalDownloads,
        activeCourses,
        completedCourses,
      },

      // ── Recent activity ──────────────────────────────────────────────
      recentOrders: recentOrders.map(o => ({
        id:             o._id,
        reference:      o.orderReference,
        total:          o.total,
        itemCount:      o.items?.length || 0,
        firstItem:      o.items?.[0]?.title || null,
        status:         o.status,
        paidAt:         o.paymentInfo?.paidAt || o.createdAt,
        createdAt:      o.createdAt,
      })),

      // ── Creator info ─────────────────────────────────────────────────
      creator: creator ? {
        id:                     creator._id,
        storeName:              creator.storeName,
        storeSlug:              creator.storeSlug,
        storeDescription:       creator.storeDescription || null,
        storeLogo:              creator.storeLogo || null,
        storeBanner:            creator.storeBanner || null,
        applicationStatus:      creator.applicationStatus,
        isVerified:             creator.isVerified,
        isFeatured:             creator.isFeatured,
        isSuspended:            creator.isSuspended,
        totalProducts:          creator.totalProducts,
        totalSales:             creator.totalSales,
        totalRevenue:           creator.totalRevenue,
        totalEarnings:          creator.totalEarnings,
        pendingPayout:          creator.pendingPayout,
        totalPaidOut:           creator.totalPaidOut,
        platformCommissionRate: creator.platformCommissionRate,
        affiliateCommissionRate:creator.affiliateCommissionRate,
        payoutThreshold:        creator.payoutThreshold,
        payoutMethod:           creator.payoutMethod,
        rating:                 creator.rating,
        totalRatings:           creator.totalRatings,
        categories:             creator.categories || [],
        socialLinks:            creator.socialLinks || {},
        website:                creator.website || null,
        businessType:           creator.businessType,
        country:                creator.country || null,
        joinedAt:               creator.createdAt,
      } : null,

      // ── Affiliate info ───────────────────────────────────────────────
      affiliate: affiliate ? {
        id:                affiliate._id,
        affiliateCode:     affiliate.affiliateCode,
        status:            affiliate.status,
        totalClicks:       affiliate.totalClicks,
        uniqueClicks:      affiliate.uniqueClicks || 0,
        totalConversions:  affiliate.totalConversions,
        totalEarnings:     affiliate.totalEarnings,
        pendingEarnings:   affiliate.pendingEarnings,
        paidEarnings:      affiliate.paidEarnings,
        payoutThreshold:   affiliate.payoutThreshold,
        affiliateLink:     `${FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`,
        joinedAt:          affiliate.createdAt,
      } : null,
    };

    res.json({ success: true, user: profile, profile }); // both keys for compat

  } catch (err) {
    console.error('❌ GET /api/profile error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch profile' });
  }
});


// ─────────────────────────────────────────────────────────────────────────────
// PUT /api/profile  — update editable fields
// ─────────────────────────────────────────────────────────────────────────────
app.put('/api/profile', authenticateToken, async (req, res) => {
  try {
    const {
      fullName, name, bio, phone, country,
      socialLinks,                          // { twitter, instagram, linkedin, youtube, website }
    } = req.body;

    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    // Apply updates — only fields that were actually sent
    const resolvedName = (fullName || name || '').trim();
    if (resolvedName) user.fullName = resolvedName;
    if (bio       !== undefined) user.bio     = bio.trim().substring(0, 300);
    if (phone     !== undefined) user.phone   = phone.trim().substring(0, 20);
    if (country   !== undefined) user.country = country.trim().substring(0, 60);

    // Social links — merge rather than replace
    if (socialLinks && typeof socialLinks === 'object') {
      user.socialLinks = {
        ...(user.socialLinks || {}),
        ...Object.fromEntries(
          Object.entries(socialLinks).map(([k, v]) => [k, typeof v === 'string' ? v.trim() : null])
        ),
      };
    }

    await user.save();

    // Sync storeName on creator record if fullName changed
    if (resolvedName && user.isCreator) {
      await Creator.updateOne({ userId: user._id }, { $set: { updatedAt: new Date() } });
    }

    res.json({
      success: true,
      message: 'Profile updated',
      user: {
        id: user._id, fullName: user.fullName, name: user.fullName,
        email: user.email, phone: user.phone, country: user.country,
        bio: user.bio, profileImage: user.profileImage, socialLinks: user.socialLinks,
      },
    });

  } catch (err) {
    console.error('❌ PUT /api/profile error:', err.message);
    res.status(500).json({ success: false, message: 'Profile update failed' });
  }
});

// ─────────────────────────────────────────────────────────────────────────────
// POST /api/profile/avatar  — upload profile picture to Cloudinary
// Replaces both the old /api/profile/upload-picture and the base64 approach
// ─────────────────────────────────────────────────────────────────────────────
app.post('/api/profile/avatar',
  authenticateToken,
  upload.single('avatar'),      // field name: 'avatar'
  async (req, res) => {
    try {
      const user = await User.findById(req.user.userId);
      if (!user) return res.status(404).json({ success: false, message: 'User not found' });

      let imageUrl = null;

      // Option A — file upload via multipart
      if (req.file) {
        const result = await uploadToCloudinary(
          req.file.buffer,
          req.file.mimetype,
          'uyehtech/avatars',
          { transformation: [{ width: 400, height: 400, crop: 'fill', gravity: 'face' }] }
        );
        imageUrl = result.secureUrl;
      }

      // Option B — base64 data URL (legacy support)
      else if (req.body?.image) {
        const base64Data = req.body.image.replace(/^data:image\/\w+;base64,/, '');
        const buffer     = Buffer.from(base64Data, 'base64');
        const result     = await uploadToCloudinary(buffer, 'image/jpeg', 'uyehtech/avatars',
          { transformation: [{ width: 400, height: 400, crop: 'fill', gravity: 'face' }] }
        );
        imageUrl = result.secureUrl;
      }

      else {
        return res.status(400).json({ success: false, message: 'No image provided' });
      }

      user.profileImage = imageUrl;
      await user.save();

      res.json({
        success: true,
        message: 'Profile picture updated',
        profileImage: imageUrl,
        user: {
          id: user._id, fullName: user.fullName, name: user.fullName,
          email: user.email, profileImage: imageUrl,
        },
      });

    } catch (err) {
      console.error('❌ POST /api/profile/avatar error:', err.message);
      res.status(500).json({ success: false, message: 'Avatar upload failed' });
    }
  }
);

