// ─────────────────────────────────────────────────────────────────────────────
// GET /api/profile/stats  — lightweight stats-only endpoint for dashboard widgets
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/profile/stats', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.userId;
    const user   = await User.findById(userId).select('_id isCreator').lean();
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    const [
      totalOrders,
      completedOrders,
      totalSpentAgg,
      totalDownloads,
      activeCourses,
      completedCourses,
      pendingOrders,
    ] = await Promise.all([
      Order.countDocuments({ userId }),
      Order.countDocuments({ userId, status: 'completed' }),
      Order.aggregate([
        { $match: { userId: user._id, status: 'completed' } },
        { $group: { _id: null, total: { $sum: '$total' } } },
      ]),
      Download.countDocuments({ userId }),
      CourseProgress.countDocuments({ userId, completionPct: { $gt: 0, $lt: 100 } }),
      CourseProgress.countDocuments({ userId, completionPct: 100 }),
      Order.countDocuments({ userId, status: 'pending' }),
    ]);

    // Creator-specific stats
    let creatorStats = null;
    if (user.isCreator) {
      const creator = await Creator.findOne({ userId })
        .select('totalProducts totalSales totalRevenue totalEarnings pendingPayout applicationStatus')
        .lean();
      if (creator) {
        creatorStats = {
          totalProducts:     creator.totalProducts,
          totalSales:        creator.totalSales,
          totalRevenue:      creator.totalRevenue,
          totalEarnings:     creator.totalEarnings,
          pendingPayout:     creator.pendingPayout,
          applicationStatus: creator.applicationStatus,
        };
      }
    }

    // Affiliate-specific stats
    const affiliate = await Affiliate.findOne({ userId })
      .select('totalClicks totalConversions totalEarnings pendingEarnings status')
      .lean();

    res.json({
      success: true,
      stats: {
        orders: {
          total:     totalOrders,
          completed: completedOrders,
          pending:   pendingOrders,
          totalSpent: totalSpentAgg[0]?.total || 0,
        },
        downloads:       totalDownloads,
        courses: {
          active:    activeCourses,
          completed: completedCourses,
        },
        creator:   creatorStats,
        affiliate: affiliate ? {
          clicks:      affiliate.totalClicks,
          conversions: affiliate.totalConversions,
          earned:      affiliate.totalEarnings,
          pending:     affiliate.pendingEarnings,
          status:      affiliate.status,
        } : null,
      },
    });

  } catch (err) {
    console.error('❌ GET /api/profile/stats error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch stats' });
  }
});


