// ─────────────────────────────────────────────────────────────────────────────
// POST /api/profile/request-email-change  — initiate email address change
// Sends OTP to the NEW email address. Completion via /api/auth/verify-email-otp.
// ─────────────────────────────────────────────────────────────────────────────
app.post('/api/profile/request-email-change', authenticateToken, otpLimiter, async (req, res) => {
  try {
    const { newEmail, password } = req.body;
    if (!newEmail || !password)
      return res.status(400).json({ success: false, message: 'New email and current password are required' });

    const cleanEmail = newEmail.toLowerCase().trim();
    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    // Verify current password
    const valid = await bcrypt.compare(password, user.password);
    if (!valid)
      return res.status(401).json({ success: false, message: 'Incorrect password' });

    // Check new email not already taken
    const existing = await User.findOne({ email: cleanEmail });
    if (existing && existing._id.toString() !== user._id.toString())
      return res.status(409).json({ success: false, message: 'That email is already in use' });

    // Generate OTP and store pending change
    const otp = String(Math.floor(100000 + Math.random() * 900000));
    otpStore.set(`email_change_${user._id}`, {
      otp,
      newEmail: cleanEmail,
      expires: Date.now() + 15 * 60 * 1000, // 15 minutes
    });

    // Send OTP to the NEW address
    await sendEmailOTP(cleanEmail, otp, 'email-change');

    res.json({ success: true, message: `Verification code sent to ${cleanEmail}` });

  } catch (err) {
    console.error('❌ POST /api/profile/request-email-change error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to initiate email change' });
  }
});

// ─────────────────────────────────────────────────────────────────────────────
// POST /api/profile/confirm-email-change  — verify OTP and apply new email
// ─────────────────────────────────────────────────────────────────────────────
app.post('/api/profile/confirm-email-change', authenticateToken, async (req, res) => {
  try {
    const { otp } = req.body;
    if (!otp) return res.status(400).json({ success: false, message: 'OTP is required' });

    const key     = `email_change_${req.user.userId}`;
    const pending = otpStore.get(key);

    if (!pending) return res.status(400).json({ success: false, message: 'No pending email change. Request a new code.' });
    if (Date.now() > pending.expires) {
      otpStore.delete(key);
      return res.status(400).json({ success: false, message: 'Code expired. Request a new one.' });
    }
    if (pending.otp !== otp.toString().trim())
      return res.status(400).json({ success: false, message: 'Incorrect code' });

    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    user.email         = pending.newEmail;
    user.emailVerified = true;  // they just verified the new address
    await user.save();
    otpStore.delete(key);

    res.json({ success: true, message: 'Email address updated successfully', email: user.email });

  } catch (err) {
    console.error('❌ POST /api/profile/confirm-email-change error:', err.message);
    res.status(500).json({ success: false, message: 'Email change failed' });
  }
});



