// POST /api/cart/items  — add or update item
app.post('/api/cart/items', authenticateToken, async (req, res) => {
  try {
    const { productId, productCollection = 'Product', quantity = 1 } = req.body;
    if (!productId) return res.status(400).json({ success: false, message: 'productId required' });
 
    // Verify product exists and get snapshot
    let product = productCollection === 'CreatorProduct'
      ? await CreatorProduct.findById(productId).select('title coverImage suggestedPrice').lean()
      : await Product.findById(productId).select('title coverImage price').lean();
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });
 
    let cart = await Cart.findOne({ userId: req.user.userId });
    if (!cart) cart = new Cart({ userId: req.user.userId, items: [] });
 
    const idx = cart.items.findIndex(i => String(i.productId) === String(productId));
    if (idx >= 0) {
      cart.items[idx].quantity = Math.max(1, (cart.items[idx].quantity || 1) + parseInt(quantity));
    } else {
      cart.items.push({
        productId, productCollection,
        title:    product.title,
        price:    product.price || product.suggestedPrice || 0,
        image:    product.coverImage || '',
        quantity: Math.max(1, parseInt(quantity)),
      });
    }
    await cart.save();
    res.json({ success: true, message: 'Cart updated', count: cart.items.length });
  } catch (err) {
    console.error('❌ POST /api/cart/items:', err.message);
    res.status(500).json({ success: false, message: 'Failed to update cart' });
  }
});
 
