// POST /api/cart/sync  — sync localStorage cart on login
app.post('/api/cart/sync', authenticateToken, async (req, res) => {
  try {
    const { items } = req.body; // array of { productId, productCollection, quantity }
    if (!Array.isArray(items) || !items.length) return res.json({ success: true, message: 'Nothing to sync' });
 
    let cart = await Cart.findOne({ userId: req.user.userId });
    if (!cart) cart = new Cart({ userId: req.user.userId, items: [] });
 
    for (const incoming of items) {
      if (!incoming.productId) continue;
      const idx = cart.items.findIndex(i => String(i.productId) === String(incoming.productId));
      if (idx < 0) {
        let product = (incoming.productCollection === 'CreatorProduct')
          ? await CreatorProduct.findById(incoming.productId).select('title coverImage suggestedPrice').lean()
          : await Product.findById(incoming.productId).select('title coverImage price').lean();
        if (product) {
          cart.items.push({
            productId:         incoming.productId,
            productCollection: incoming.productCollection || 'Product',
            title:    product.title,
            price:    product.price || product.suggestedPrice || 0,
            image:    product.coverImage || '',
            quantity: Math.max(1, parseInt(incoming.quantity) || 1),
          });
        }
      }
    }
    await cart.save();
    res.json({ success: true, message: 'Cart synced', count: cart.items.length });
  } catch (err) {
    console.error('❌ POST /api/cart/sync:', err.message);
    res.status(500).json({ success: false, message: 'Cart sync failed' });
  }
});
 
