// ─────────────────────────────────────────────────────────────────────────────
// GET /api/dashboard  — full dashboard payload (single request)
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/dashboard', authenticateToken, async (req, res) => {
  try {
    const userId  = req.user.userId;
    const userOid = new mongoose.Types.ObjectId(userId);

    // ── 1. User record ────────────────────────────────────────────────────
    const user = await User.findById(userId)
      .select('-password -twoFactorSecret -emailVerificationToken -passwordResetToken')
      .lean();
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    // ── 2. Parallel heavy queries ─────────────────────────────────────────
    const [
      allOrders,
      courseProgressRecords,
      recentDownloads,
      affiliate,
    ] = await Promise.all([
      // All user orders — we'll slice/filter from this
      Order.find({ userId })
        .sort({ createdAt: -1 })
        .select('orderReference total items status paymentInfo createdAt affiliateCode hasCreatorProducts')
        .lean(),

      // Course progress for all enrolled courses
      CourseProgress.find({ userId })
        .sort({ lastAccessedAt: -1 })
        .lean(),

      // Recent downloads
      Download.find({ userId })
        .sort({ downloadedAt: -1 })
        .limit(10)
        .populate('productId', 'title icon image productType')
        .lean(),

      // Affiliate membership
      Affiliate.findOne({ userId })
        .select('affiliateCode status totalClicks totalConversions totalEarnings pendingEarnings paidEarnings payoutThreshold createdAt')
        .lean(),
    ]);

    const completedOrders = allOrders.filter(o => o.status === 'completed');
    const pendingOrders   = allOrders.filter(o => o.status === 'pending');
    const totalDownloads  = recentDownloads.length;    // ✅ FIX: was undefined, caused 500

    // ── 3. Stats ──────────────────────────────────────────────────────────
    const totalSpent = completedOrders.reduce((sum, o) => sum + (o.total || 0), 0);

    // Collect all purchased product IDs (for course lookup + recommendations)
    const purchasedProductIds = completedOrders.flatMap(o =>
      (o.items || []).map(i => i.productId || i.id).filter(Boolean)
    );

    const completedCourses = courseProgressRecords.filter(p => p.completionPct >= 100).length;
    const activeCourses    = courseProgressRecords.filter(p => p.completionPct > 0 && p.completionPct < 100).length;
    const enrolledCourses  = courseProgressRecords.length;

    // ── 4. Recent orders (last 8) ─────────────────────────────────────────
    const recentOrders = completedOrders.slice(0, 8).map(o => ({
      id:         o._id,
      reference:  o.orderReference,
      total:      o.total,
      status:     o.status,
      itemCount:  o.items?.length || 0,
      items:      (o.items || []).slice(0, 3).map(i => ({
        title:       i.title,
        productType: i.productType,
        price:       i.price,
        icon:        i.icon || null,
        image:       i.image || null,
      })),
      paidAt:    o.paymentInfo?.paidAt || o.createdAt,
      createdAt: o.createdAt,
    }));

    // ── 5. Active courses with progress ───────────────────────────────────
    let activeCourseData = [];
    if (courseProgressRecords.length > 0) {
      const activeProg = courseProgressRecords
        .filter(p => p.completionPct < 100)
        .slice(0, 6);

      if (activeProg.length > 0) {
        const productIds = activeProg.map(p => p.productId);

        // Primary: lookup by Product._id (canonical)
        const products = await Product.find({ _id: { $in: productIds } })
          .select('title image icon productType courseData.totalChapters courseData.level slug creatorProductId')
          .lean();

        const productMap = Object.fromEntries(products.map(p => [p._id.toString(), p]));

        // Fallback: for progress records whose productId is a CreatorProduct._id
        // (saved before checkout normalisation), resolve via CreatorProduct.
        const missedIds = productIds
          .map(id => id?.toString())
          .filter(id => id && !productMap[id]);

        if (missedIds.length) {
          const cps = await CreatorProduct.find({ _id: { $in: missedIds } })
            .select('title images productType courseData productId')
            .lean();

          // Build synthetic product-shaped objects from CreatorProduct data
          for (const cp of cps) {
            const synthetic = {
              _id:         cp._id,
              title:       cp.title,
              image:       cp.images?.[0] || null,
              icon:        null,
              productType: cp.productType || 'course',
              slug:        null,   // creator products have no public slug until mirrored
              courseData:  cp.courseData || {},
            };
            productMap[cp._id.toString()] = synthetic;

            // Also index by the mirrored Product._id if available, so any future
            // progress record saved against the canonical ID also resolves cleanly.
            if (cp.productId) {
              productMap[cp.productId.toString()] = synthetic;
            }
          }
        }

        activeCourseData = activeProg.map(prog => {
          const product = productMap[prog.productId?.toString()] || {};
          return {
            productId:         prog.productId,
            title:             product.title || 'Course',
            image:             product.image || null,
            icon:              product.icon  || null,
            productType:       product.productType || 'course',
            slug:              product.slug  || null,
            completionPct:     prog.completionPct,
            completedChapters: prog.completedChapters?.length || 0,
            totalChapters:     product.courseData?.totalChapters || 0,
            level:             product.courseData?.level || 'all',
            lastAccessedAt:    prog.lastAccessedAt,
            startedAt:         prog.startedAt,
            certificateIssued: prog.certificateIssued,
          };
        });
      }
    }

    // ── 6. Recently downloaded files ──────────────────────────────────────
    const recentDownloadData = recentDownloads.map(dl => ({
      downloadId:  dl._id,
      productId:   dl.productId?._id || dl.productId,
      title:       dl.productId?.title   || 'Product',
      productType: dl.productId?.productType || 'download',
      icon:        dl.productId?.icon    || null,
      image:       dl.productId?.image   || null,
      downloadedAt:dl.downloadedAt,
    }));

    // ── 7. Creator snapshot ───────────────────────────────────────────────
    let creatorSnapshot = null;
    if (user.isCreator) {
      const creator = await Creator.findOne({ userId })
        .select('storeName storeSlug storeLogo applicationStatus isVerified isFeatured isSuspended totalProducts totalSales totalRevenue totalEarnings pendingPayout payoutThreshold platformCommissionRate rating')
        .lean();

      if (creator) {
        // Pending products awaiting review
        const pendingProducts = await CreatorProduct.countDocuments({
          creatorId: creator._id,
          status:    'pending_review',
        });

        creatorSnapshot = {
          storeName:              creator.storeName,
          storeSlug:              creator.storeSlug,
          storeLogo:              creator.storeLogo || null,
          applicationStatus:      creator.applicationStatus,
          isVerified:             creator.isVerified,
          isFeatured:             creator.isFeatured,
          isSuspended:            creator.isSuspended,
          totalProducts:          creator.totalProducts,
          pendingProducts,
          totalSales:             creator.totalSales,
          totalRevenue:           creator.totalRevenue,
          totalEarnings:          creator.totalEarnings,
          pendingPayout:          creator.pendingPayout,
          payoutThreshold:        creator.payoutThreshold,
          platformCommissionRate: creator.platformCommissionRate,
          rating:                 creator.rating,
          canRequestPayout:       creator.pendingPayout >= creator.payoutThreshold,
        };
      }
    }

    // ── 8. Affiliate snapshot ─────────────────────────────────────────────
    const affiliateSnapshot = affiliate ? {
      affiliateCode:    affiliate.affiliateCode,
      status:           affiliate.status,
      affiliateLink:    `${FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`,
      totalClicks:      affiliate.totalClicks,
      totalConversions: affiliate.totalConversions,
      conversionRate:   affiliate.totalClicks > 0
                          ? ((affiliate.totalConversions / affiliate.totalClicks) * 100).toFixed(1)
                          : '0.0',
      totalEarnings:    affiliate.totalEarnings,
      pendingEarnings:  affiliate.pendingEarnings,
      paidEarnings:     affiliate.paidEarnings,
      payoutThreshold:  affiliate.payoutThreshold,
      canRequestPayout: affiliate.pendingEarnings >= affiliate.payoutThreshold,
      joinedAt:         affiliate.createdAt,
    } : null;

    // ── 9. Activity feed (last 15 events, mixed types) ────────────────────
    const activityFeed = [];

    // Orders → activity events
    completedOrders.slice(0, 8).forEach(o => {
      activityFeed.push({
        type:      'order',
        icon:      '🛒',
        title:     'Purchase completed',
        subtitle:  (o.items?.[0]?.title || 'Product') + (o.items?.length > 1 ? ` +${o.items.length - 1} more` : ''),
        amount:    o.total,
        reference: o.orderReference,
        timestamp: o.paymentInfo?.paidAt || o.createdAt,
        link:      `/marketplace/orders`,
      });
    });

    // Course completions → activity events
    courseProgressRecords
      .filter(p => p.completionPct >= 100 && p.completedAt)
      .slice(0, 4)
      .forEach(p => {
        activityFeed.push({
          type:          'course_complete',
          icon:          '🎓',
          title:         'Course completed',
          subtitle:      `Certificate ${p.certificateIssued ? 'issued' : 'pending'}`,
          productId:     p.productId,
          timestamp:     p.completedAt,
          completionPct: 100,             // ✅ ADD — dashboard badge reads this field
          link:          `/marketplace/my-products`,
        });
      });

    // Downloads → activity events
    recentDownloads.slice(0, 5).forEach(dl => {
      activityFeed.push({
        type:      'download',
        icon:      '⬇️',
        title:     'File downloaded',
        subtitle:  dl.productId?.title || 'Product',
        productId: dl.productId?._id,
        timestamp: dl.downloadedAt,
        link:      `/marketplace/my-products`,
      });
    });

    // Sort by timestamp desc
    activityFeed.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
    const recentActivity = activityFeed.slice(0, 15);

    // ── 10. Recommendations (based on purchase categories) ─────────────
    let recommendations = [];
    try {
      const purchasedCategories = [...new Set(
        completedOrders.flatMap(o => (o.items || []).map(i => i.category).filter(Boolean))
      )].slice(0, 3);

      if (purchasedCategories.length > 0) {
        recommendations = await Product.find({
          isActive:   true,
          status:     'published',
          category:   { $in: purchasedCategories },
          _id:        { $nin: purchasedProductIds.map(id => {
            try { return new mongoose.Types.ObjectId(id); } catch { return null; }
          }).filter(Boolean) },
        })
          .sort({ soldCount: -1, rating: -1 })
          .limit(6)
          .select('title price comparePrice icon image productType category rating reviewCount slug soldCount')
          .lean();
      }

      // Fill with popular products if not enough
      if (recommendations.length < 4) {
        const exclude = [
          ...purchasedProductIds,
          ...recommendations.map(p => p._id.toString()),
        ];
        const fillers = await Product.find({
          isActive: true,
          status:   'published',
          _id:      { $nin: exclude.map(id => {
            try { return new mongoose.Types.ObjectId(id); } catch { return null; }
          }).filter(Boolean) },
        })
          .sort({ soldCount: -1 })
          .limit(6 - recommendations.length)
          .select('title price comparePrice icon image productType category rating reviewCount slug soldCount')
          .lean();
        recommendations = [...recommendations, ...fillers];
      }
    } catch (recErr) {
      console.warn('⚠️ Recommendations failed (non-fatal):', recErr.message);
    }

    // ── 11. Spending chart data (last 6 months) ────────────────────────
    const sixMonthsAgo = new Date();
    sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);

    const spendingByMonth = await Order.aggregate([
      {
        $match: {
          userId:    userOid,
          status:    'completed',
          createdAt: { $gte: sixMonthsAgo },
        },
      },
      {
        $group: {
          _id: {
            year:  { $year:  '$createdAt' },
            month: { $month: '$createdAt' },
          },
          spent:  { $sum: '$total' },
          orders: { $sum: 1 },
        },
      },
      { $sort: { '_id.year': 1, '_id.month': 1 } },
    ]);

    const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const spendingChart = spendingByMonth.map(m => ({
      label:  `${monthNames[m._id.month - 1]} ${m._id.year}`,
      month:  m._id.month,
      year:   m._id.year,
      spent:  Number(m.spent.toFixed(2)),
      orders: m.orders,
    }));

    // ── 12. Assemble final response ────────────────────────────────────
    res.json({
      success: true,
      dashboard: {

        // ── User summary ─────────────────────────────────────────────
        user: {
          id:               user._id,
          fullName:         user.fullName,
          name:             user.fullName,
          email:            user.email,
          profileImage:     user.profileImage || null,
          emailVerified:    user.emailVerified,
          isCreator:        user.isCreator,
          isAgent:          user.isAgent,
          memberSince:      user.createdAt,
          lastLogin:        user.lastLogin || null,
        },

        // ── Purchase stats ───────────────────────────────────────────
        stats: {
          totalOrders:      allOrders.length,
          completedOrders:  completedOrders.length,
          pendingOrders:    pendingOrders.length,
          totalSpent:       Number(totalSpent.toFixed(2)),
          totalDownloads:   totalDownloads,
          productsOwned:    purchasedProductIds.length,
          enrolledCourses,
          activeCourseCount:  activeCourses,      // renamed: number
          completedCourses,
        },

        // ── Data sections ────────────────────────────────────────────
        recentOrders,
        activeCourseList:  activeCourseData,      // renamed: array
        recentDownloads: recentDownloadData,
        recentActivity,
        spendingChart,
        recommendations: recommendations.map(p => ({
          id:          p._id,
          title:       p.title,
          price:       p.price,
          comparePrice:p.comparePrice || null,
          icon:        p.icon   || null,
          image:       p.image  || null,
          productType: p.productType,
          category:    p.category,
          rating:      p.rating,
          reviewCount: p.reviewCount,
          slug:        p.slug,
          soldCount:   p.soldCount,
        })),

        // ── Creator & Affiliate ──────────────────────────────────────
        creator:   creatorSnapshot,
        affiliate: affiliateSnapshot,
      },
    });

  } catch (err) {
    console.error('❌ GET /api/dashboard error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to load dashboard' });
  }
});


// ─────────────────────────────────────────────────────────────────────────────
// GET /api/dashboard/activity  — paginated activity feed
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/dashboard/activity', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.userId;
    const page   = Math.max(1, parseInt(req.query.page)  || 1);
    const limit  = Math.min(50, parseInt(req.query.limit) || 20);
    const type   = req.query.type || 'all'; // 'all' | 'order' | 'download' | 'course'

    const feed = [];

    if (type === 'all' || type === 'order') {
      const orders = await Order.find({ userId, status: 'completed' })
        .sort({ createdAt: -1 })
        .select('orderReference total items paymentInfo createdAt')
        .lean();

      orders.forEach(o => feed.push({
        type:      'order',
        icon:      '🛒',
        title:     'Purchase completed',
        subtitle:  (o.items?.[0]?.title || 'Product') + (o.items?.length > 1 ? ` +${o.items.length - 1} more` : ''),
        amount:    o.total,
        reference: o.orderReference,
        timestamp: o.paymentInfo?.paidAt || o.createdAt,
        link:      '/marketplace/orders',
        meta: {
          itemCount: o.items?.length || 0,
          items: (o.items || []).slice(0, 2).map(i => ({ title: i.title, productType: i.productType })),
        },
      }));
    }

    if (type === 'all' || type === 'download') {
      const downloads = await Download.find({ userId })
        .sort({ downloadedAt: -1 })
        .populate('productId', 'title productType icon')
        .lean();

      downloads.forEach(dl => feed.push({
        type:      'download',
        icon:      '⬇️',
        title:     'File downloaded',
        subtitle:  dl.productId?.title || 'Product',
        productId: dl.productId?._id,
        timestamp: dl.downloadedAt,
        link:      '/marketplace/my-products',
        meta: { productType: dl.productId?.productType },
      }));
    }

    if (type === 'all' || type === 'course') {
      const progress = await CourseProgress.find({ userId, completionPct: { $gt: 0 } })
        .sort({ lastAccessedAt: -1 })
        .populate('productId', 'title icon')
        .lean();

      progress.forEach(p => {
        // Completion event
        if (p.completedAt) {
          feed.push({
            type:      'course_complete',
            icon:      '🎓',
            title:     'Course completed',
            subtitle:  p.productId?.title || 'Course',
            productId: p.productId?._id,
            timestamp: p.completedAt,
            link:      '/marketplace/my-products',
            meta: { certificateIssued: p.certificateIssued },
          });
        }
        // Started event
        if (p.startedAt && p.completionPct < 100) {
          feed.push({
            type:      'course_progress',
            icon:      '📚',
            title:     `${Math.round(p.completionPct)}% progress`,
            subtitle:  p.productId?.title || 'Course',
            productId: p.productId?._id,
            timestamp: p.lastAccessedAt,
            link:      '/marketplace/my-products',
            meta: { completionPct: p.completionPct },
          });
        }
      });
    }

    feed.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

    const total     = feed.length;
    const paginated = feed.slice((page - 1) * limit, page * limit);

    res.json({
      success: true,
      activity: paginated,
      pagination: {
        total,
        page,
        limit,
        pages: Math.ceil(total / limit),
        hasMore: page * limit < total,
      },
    });

  } catch (err) {
    console.error('❌ GET /api/dashboard/activity error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch activity' });
  }
});


// ─────────────────────────────────────────────────────────────────────────────
// GET /api/dashboard/courses  — all enrolled courses with full progress
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/dashboard/courses', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.userId;
    const filter = req.query.filter || 'all'; // 'all' | 'active' | 'completed' | 'not_started'

    let progressQuery = { userId };
    if (filter === 'active')      progressQuery.completionPct = { $gt: 0, $lt: 100 };
    if (filter === 'completed')   progressQuery.completionPct = 100;
    if (filter === 'not_started') progressQuery.completionPct = 0;

    const progressRecords = await CourseProgress.find(progressQuery)
      .sort({ lastAccessedAt: -1 })
      .lean();

    if (!progressRecords.length) return res.json({ success: true, courses: [], total: 0 });

    const productIds = progressRecords.map(p => p.productId);
    const products   = await Product.find({ _id: { $in: productIds } })
      .select('title description image icon productType courseData.totalChapters courseData.totalDuration courseData.level courseData.language courseData.certificate slug rating reviewCount price')
      .lean();

    const productMap = Object.fromEntries(products.map(p => [p._id.toString(), p]));

    const courses = progressRecords.map(prog => {
      const product = productMap[prog.productId?.toString()] || {};
      return {
        productId:          prog.productId,
        title:              product.title || 'Course',
        description:        product.description?.substring(0, 150) || null,
        image:              product.image  || null,
        icon:               product.icon   || null,
        productType:        product.productType || 'course',
        slug:               product.slug   || null,
        price:              product.price  || 0,
        rating:             product.rating || 0,
        reviewCount:        product.reviewCount || 0,
        level:              product.courseData?.level || 'all',
        language:           product.courseData?.language || 'English',
        hasCertificate:     product.courseData?.certificate || false,
        totalChapters:      product.courseData?.totalChapters || 0,
        totalDuration:      product.courseData?.totalDuration || 0,  // seconds
        completedChapters:  prog.completedChapters?.length || 0,
        completionPct:      prog.completionPct,
        lastSectionOrder:   prog.lastSectionOrder,
        lastChapterOrder:   prog.lastChapterOrder,
        timeSpent:          prog.timeSpent || 0,
        startedAt:          prog.startedAt,
        lastAccessedAt:     prog.lastAccessedAt,
        completedAt:        prog.completedAt   || null,
        certificateIssued:  prog.certificateIssued,
        certificateId:      prog.certificateId || null,
        status: prog.completionPct >= 100 ? 'completed'
               : prog.completionPct > 0   ? 'active'
               :                            'not_started',
      };
    });

    res.json({ success: true, courses, total: courses.length });

  } catch (err) {
    console.error('❌ GET /api/dashboard/courses error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch courses' });
  }
});


// ─────────────────────────────────────────────────────────────────────────────
// GET /api/dashboard/recommendations  — personalised product suggestions
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/dashboard/recommendations', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.userId;
    const limit  = Math.min(12, parseInt(req.query.limit) || 6);

    // What has the user already bought?
    const orders = await Order.find({ userId, status: 'completed' })
      .select('items')
      .lean();

    const purchasedIds = orders.flatMap(o =>
      (o.items || []).map(i => i.productId || i.id).filter(Boolean)
    );
    const purchasedCategories = [...new Set(
      orders.flatMap(o => (o.items || []).map(i => i.category).filter(Boolean))
    )];

    const excludeIds = purchasedIds.map(id => {
      try { return new mongoose.Types.ObjectId(id); } catch { return null; }
    }).filter(Boolean);

    let products = [];

    // Category-based suggestions first
    if (purchasedCategories.length > 0) {
      products = await Product.find({
        isActive:  true,
        status:    'published',
        category:  { $in: purchasedCategories },
        _id:       { $nin: excludeIds },
      })
        .sort({ soldCount: -1, rating: -1 })
        .limit(limit)
        .select('title price comparePrice icon image productType category tags rating reviewCount slug soldCount isFeatured')
        .lean();
    }

    // Top sellers as fallback
    if (products.length < limit) {
      const fillers = await Product.find({
        isActive: true,
        status:   'published',
        _id:      { $nin: [...excludeIds, ...products.map(p => p._id)] },
      })
        .sort({ soldCount: -1, isFeatured: -1 })
        .limit(limit - products.length)
        .select('title price comparePrice icon image productType category tags rating reviewCount slug soldCount isFeatured')
        .lean();
      products = [...products, ...fillers];
    }

    res.json({
      success: true,
      recommendations: products.map(p => ({
        id:          p._id,
        title:       p.title,
        price:       p.price,
        comparePrice:p.comparePrice || null,
        discount:    p.comparePrice > p.price
                       ? Math.round(((p.comparePrice - p.price) / p.comparePrice) * 100)
                       : null,
        icon:        p.icon   || null,
        image:       p.image  || null,
        productType: p.productType,
        category:    p.category,
        tags:        p.tags   || [],
        rating:      p.rating,
        reviewCount: p.reviewCount,
        slug:        p.slug,
        soldCount:   p.soldCount,
        isFeatured:  p.isFeatured,
      })),
      total: products.length,
    });

  } catch (err) {
    console.error('❌ GET /api/dashboard/recommendations error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch recommendations' });
  }
});


// ─────────────────────────────────────────────────────────────────────────────
// GET /api/dashboard/spending-chart  — monthly spending data for chart widgets
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/dashboard/spending-chart', authenticateToken, async (req, res) => {
  try {
    const userId  = req.user.userId;
    const months  = Math.min(12, parseInt(req.query.months) || 6);
    const cutoff  = new Date();
    cutoff.setMonth(cutoff.getMonth() - months);

    const data = await Order.aggregate([
      { $match: { userId: new mongoose.Types.ObjectId(userId), status: 'completed', createdAt: { $gte: cutoff } } },
      { $group: {
          _id:    { year: { $year: '$createdAt' }, month: { $month: '$createdAt' } },
          spent:  { $sum: '$total' },
          orders: { $sum: 1 },
          items:  { $sum: { $size: { $ifNull: ['$items', []] } } },
        },
      },
      { $sort: { '_id.year': 1, '_id.month': 1 } },
    ]);

    const monthNames = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    res.json({
      success: true,
      chart: data.map(m => ({
        label:  `${monthNames[m._id.month - 1]} ${m._id.year}`,
        month:  m._id.month,
        year:   m._id.year,
        spent:  Number(m.spent.toFixed(2)),
        orders: m.orders,
        items:  m.items,
      })),
    });

  } catch (err) {
    console.error('❌ GET /api/dashboard/spending-chart error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch chart data' });
  }
});


// ═══════════════════════════════════════════════════════════════
// CREATOR / SELLER ENDPOINTS
// ═══════════════════════════════════════════════════════════════

// ══════════════════════════════════════════════════════════════════════════════
// POST /api/creator/apply
// ══════════════════════════════════════════════════════════════════════════════
app.post('/api/creator/apply', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {

    // ── 1. PULL & VALIDATE REQUIRED FIELDS ──────────────────────────────────
    const {
      storeName,
      storeDescription,
      businessType,
      applicationMessage,
      country,
      phone,
      website,
      socialLinks,
      categories
    } = req.body;

    if (!storeName || typeof storeName !== 'string' || storeName.trim().length < 3) {
      return res.status(400).json({
        success: false,
        message: 'Store name is required and must be at least 3 characters.'
      });
    }

    if (!applicationMessage || typeof applicationMessage !== 'string' || applicationMessage.trim().length < 20) {
      return res.status(400).json({
        success: false,
        message: 'Please tell us about yourself (minimum 20 characters).'
      });
    }

    const cleanStoreName = storeName.trim();
    const cleanMessage   = applicationMessage.trim();

    // ── 2. CAST userId TO ObjectId CORRECTLY ────────────────────────────────
    const userObjectId = toObjectId(req.user.userId);
    if (!userObjectId) {
      return res.status(401).json({
        success: false,
        message: 'Invalid session. Please log out and log back in.'
      });
    }

    // ── 3. CHECK: user has not already applied ───────────────────────────────
    const existing = await Creator.findOne({ userId: userObjectId });
    if (existing) {
      return res.status(400).json({
        success: false,
        message: `You already have a creator account. Current status: "${existing.applicationStatus}".`,
        applicationStatus: existing.applicationStatus,
        storeName: existing.storeName
      });
    }

    // ── 4. CHECK: store name is unique (case-insensitive) ────────────────────
    // ✅ FIX: escapeRegex is now defined — this was the crash point
    const safeStoreName = escapeRegex(cleanStoreName);
    const nameExists = await Creator.findOne({
      storeName: { $regex: new RegExp(`^${safeStoreName}$`, 'i') }
    });
    if (nameExists) {
      return res.status(400).json({
        success: false,
        message: 'That store name is already taken. Please choose a different name.'
      });
    }

    // ── 5. VALIDATE businessType ─────────────────────────────────────────────
    const allowedTypes = ['individual', 'company', 'freelancer'];
    const cleanType    = allowedTypes.includes(businessType) ? businessType : 'individual';

    // ── 6. VALIDATE categories ───────────────────────────────────────────────
    let cleanCategories = [];
    if (Array.isArray(categories) && categories.length > 0) {
      cleanCategories = categories
        .filter(c => typeof c === 'string' && c.trim().length > 0)
        .map(c => c.trim())
        .slice(0, 10);
    }

   // ── 7. CREATE THE CREATO// ✅ Generate storeSlug explicitly — don't rely solely on pre-save hook
const storeSlug = cleanStoreName
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

// Check slug is also unique
const slugExists = await Creator.findOne({ storeSlug });
if (slugExists) {
  return res.status(400).json({
    success: false,
    message: 'That store name is already taken. Please choose a different name.'
  });
}

const creator = new Creator({
  userId:             userObjectId,
  storeName:          cleanStoreName,
  storeSlug:          storeSlug,          // ✅ explicitly set
  storeDescription:   storeDescription    ? String(storeDescription).trim()    : '',
  businessType:       cleanType,
  applicationMessage: cleanMessage,
  country:            country             ? String(country).trim()             : '',
  phone:              phone               ? String(phone).trim()               : '',
  website:            website             ? String(website).trim()             : '',
  socialLinks:        socialLinks && typeof socialLinks === 'object' ? socialLinks : {},
  categories:         cleanCategories,
  applicationStatus:  'pending'
});

await creator.save();
trackNewCreator();

    // ── 8. UPDATE USER RECORD ─────────────────────────────────────────────────
    await User.findByIdAndUpdate(userObjectId, {
      $set: {
        'creatorInfo.creatorId': creator._id,
        'creatorInfo.storeName': cleanStoreName,
        'creatorInfo.joinedAt':  new Date()
      }
    });

    // ── 9. NOTIFY ADMIN via WebSocket (non-fatal) ─────────────────────────────
    if (global.wss && global.wss.clients) {
      global.wss.clients.forEach(client => {
        if (client.isAdmin && client.readyState === 1) {
          try {
            client.send(JSON.stringify({
              type:      'new_creator_application',
              storeName: cleanStoreName,
              userId:    String(userObjectId),
              timestamp: new Date()
            }));
          } catch (_) { /* non-fatal */ }
        }
      });
    }

    console.log(`📋 New creator application: "${cleanStoreName}" — userId: ${userObjectId}`);
    await logCreatorAction(req, 'creator_applied', creator);
    // ── 10. SUCCESS ───────────────────────────────────────────────────────────
    return res.status(201).json({
      success: true,
      message: 'Application submitted! Our team will review it within 24–48 hours.',
      creator: {
        id:                creator._id,
        storeName:         creator.storeName,
        applicationStatus: creator.applicationStatus,
        submittedAt:       creator.createdAt
      }
    });

  } catch (error) {

    // Duplicate key (MongoDB unique index)
    if (error.code === 11000) {
      const field = Object.keys(error.keyPattern || {})[0] || 'field';
      return res.status(400).json({
        success: false,
        message: field === 'storeName'
          ? 'That store name is already taken. Please choose a different name.'
          : 'An account with that information already exists.'
      });
    }

    // Mongoose validation error
    if (error.name === 'ValidationError') {
      const firstMsg = Object.values(error.errors)[0]?.message || 'Validation failed.';
      return res.status(400).json({ success: false, message: firstMsg });
    }

    console.error('❌ /api/creator/apply error:', error);
    return res.status(500).json({
      success: false,
      message: 'Something went wrong on our end. Please try again in a moment.'
    });
  }
});



// ── GET MY CREATOR PROFILE ──────────────────────────────────────
app.get('/api/creator/me', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    // BUG FIX: Do NOT populate userId here — after populate, creator.userId becomes
    // a User object and breaks aggregate $match which expects an ObjectId.
    // We fetch the user separately to get name/email/profileImage safely.
    const creator = await Creator.findOne({ userId: req.user.userId });

    if (!creator) {
      return res.status(404).json({ success: false, message: 'Creator profile not found' });
    }

    // Fetch user info separately so creator.userId stays a clean ObjectId
    const user = await User.findById(creator.userId).select('fullName email profileImage');

    // Get product stats
    const products = await CreatorProduct.find({ creatorId: creator._id });

    // BUG FIX: creator.userId is now a plain ObjectId (no populate), safe for aggregate
    const pendingEarnings = await EarningsLedger.aggregate([
      { $match: { recipientId: creator.userId, status: 'confirmed', recipientType: 'creator' }},
      { $group: { _id: null, total: { $sum: '$earningAmount' }}}
    ]);

    // BUG FIX: creatorOut is a plain object, not a function — was `...creatorOut()` before
    const creatorOut = creator.toObject();
    if (creatorOut.storeLogo && !creatorOut.storeLogo.startsWith('http'))
      creatorOut.storeLogo = `${BASE_URL}${creatorOut.storeLogo}`;
    if (creatorOut.storeBanner && !creatorOut.storeBanner.startsWith('http'))
      creatorOut.storeBanner = `${BASE_URL}${creatorOut.storeBanner}`;

    res.json({
      success: true,
      creator: {
        ...creatorOut,
        fullName:       user?.fullName       || '',
        email:          user?.email          || '',
        profileImage:   user?.profileImage   || '',
        products: {
          total:    products.length,
          approved: products.filter(p => p.status === 'approved').length,
          pending:  products.filter(p => p.status === 'pending_review').length,
          rejected: products.filter(p => p.status === 'rejected').length,
          draft:    products.filter(p => p.status === 'draft').length,
        },
        pendingPayout:   pendingEarnings[0]?.total || 0,
        // Expose new fields explicitly so frontend can rely on them
        bio:             creatorOut.bio             || null,
        skills:          creatorOut.skills          || [],
        portfolioLinks:  creatorOut.portfolioLinks  || [],
        yearsExperience: creatorOut.yearsExperience || null,
        languages:       creatorOut.languages       || [],
        creatorNotifPrefs: creatorOut.creatorNotifPrefs || {
          newSale: true, newReview: true, newFollower: true,
          payoutUpdate: true, productUpdate: true, weeklySummary: false,
        },
        storeUrl: `${FRONTEND_URL}/marketplace/${creatorOut.storeSlug}/`,
      }
    });

  } catch (error) {
    console.error('❌ Get creator error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch profile' });
  }
});

// ── UPDATE CREATOR PROFILE ──────────────────────────────────────
app.put('/api/creator/profile', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator || creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Approved creator account required' });
    }

    const allowedFields = [
      'storeName', 'storeDescription', 'storeLogo',
      'businessName', 'businessType', 'country', 'phone',
      'website', 'socialLinks', 'payoutDetails', 'payoutMethod',
      // New fields
      'bio', 'skills', 'portfolioLinks', 'yearsExperience', 'languages',
      'creatorNotifPrefs',
    ];

    // Sanitise skills array — remove empty strings, trim, deduplicate, cap at 20
    if (req.body.skills && Array.isArray(req.body.skills)) {
      req.body.skills = [...new Set(req.body.skills.map(s => s.trim()).filter(Boolean))].slice(0, 20);
    }
    // Sanitise portfolioLinks — validate each has label and url
    if (req.body.portfolioLinks && Array.isArray(req.body.portfolioLinks)) {
      req.body.portfolioLinks = req.body.portfolioLinks
        .filter(p => p.label?.trim() && p.url?.trim())
        .slice(0, 10);
    }
    
    allowedFields.forEach(field => {
      if (req.body[field] !== undefined) {
        creator[field] = req.body[field];
      }
    });

    if (creator.storeLogo && !creator.storeLogo.startsWith('http'))
      creator.storeLogo = `${BASE_URL}${creator.storeLogo}`;
    if (creator.storeBanner && !creator.storeBanner.startsWith('http'))
      creator.storeBanner = `${BASE_URL}${creator.storeBanner}`;
    await creator.save();

    res.json({ success: true, message: 'Profile updated', creator });

  } catch (error) {
    console.error('❌ Update creator error:', error);
    res.status(500).json({ success: false, message: 'Update failed' });
  }
});

// ── POST /api/creator/products/draft — save work-in-progress without submitting for review ──
app.post('/api/creator/products/draft', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator || creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Approved creator account required' });
    }
    if (creator.isSuspended) {
      return res.status(403).json({ success: false, message: 'Creator account is suspended' });
    }

    const {
      title, description, category, suggestedPrice, tags,
      images, fileSize, version, features, requirements, productType,
      hostedFile, previewUrl, previewType, externalVideoUrl, externalAudioUrl,
      audioData, softwareData, videoData, courseData, ebookData, designData, notes,
      draftId, // if provided — update an existing draft instead of creating a new one
    } = req.body;

    // Validate only title is required for a draft
    if (!title?.trim()) {
      return res.status(400).json({ success: false, message: 'A title is required to save a draft' });
    }

    if (draftId) {
      // Update existing draft
      const existing = await CreatorProduct.findOne({
        _id: draftId, creatorId: creator._id, status: 'draft'
      });
      if (!existing) {
        return res.status(404).json({ success: false, message: 'Draft not found' });
      }

      const updatable = {
        title: title.trim(), description, category, suggestedPrice,
        tags, images, fileSize, version, features, requirements,
        productType, hostedFile, previewUrl, previewType,
        externalVideoUrl, externalAudioUrl, audioData, softwareData,
        videoData, courseData, ebookData, designData, notes, isDraft: true,
      };
      Object.keys(updatable).forEach(k => {
        if (updatable[k] !== undefined) existing[k] = updatable[k];
      });
      await existing.save();

      return res.json({ success: true, message: 'Draft saved', draft: existing, draftId: existing._id });
    }

    // Create new draft
    const draft = new CreatorProduct({
      creatorId:   creator._id,
      title:       title.trim(),
      description: description || '',
      category:    category    || 'General',
      suggestedPrice: parseFloat(suggestedPrice) || 0,
      tags:        tags        || [],
      images:      images      || [],
      productType: productType || 'download',
      status:      'draft',
      isDraft:     true,
      hostedFile, previewUrl, previewType,
      externalVideoUrl, externalAudioUrl,
      audioData, softwareData, videoData, courseData, ebookData, designData,
      fileSize, version, features, requirements, notes,
    });
    await draft.save();

    res.status(201).json({ success: true, message: 'Draft saved', draft, draftId: draft._id });

  } catch (error) {
    console.error('❌ Save draft error:', error);
    res.status(500).json({ success: false, message: 'Failed to save draft' });
  }
});

// ── CREATOR: SUBMIT A PRODUCT ───────────────────────────────────
app.post('/api/creator/products', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
 
    if (!creator) {
      return res.status(403).json({ success: false, message: 'Creator account required' });
    }
    if (creator.applicationStatus !== 'approved') {
      return res.status(403).json({
        success: false,
        message: 'Your creator account must be approved before listing products'
      });
    }
    if (creator.isSuspended) {
      return res.status(403).json({ success: false, message: 'Creator account is suspended' });
    }
 
    let {
      title, description, category, suggestedPrice, tags,
      images, downloadLink, fileSize, version, features, requirements,
      productType, hostedFile, previewUrl, previewType,
      audioData, softwareData, videoData, courseData, ebookData, designData,
      // ── external media fields ──
      externalVideoUrl,
      externalAudioUrl
    } = req.body;

    const parsedPrice = parseFloat(suggestedPrice);
    if (!title || !description) {
      return res.status(400).json({ success: false, message: 'Title and description are required' });
    }
    if (isNaN(parsedPrice) || parsedPrice < 0) {
      return res.status(400).json({ success: false, message: 'A valid price (0 or above) is required' });
    }

    // ── Parse external media URLs ────────────────────────────────────────────
    // Priority: video > audio. A product can have both but we embed one at a time.
    let parsedEmbed = { embedType: null, embedUrl: null, mediaType: null };

    if (externalVideoUrl && externalVideoUrl.trim()) {
      const parsed = parseExternalMediaUrl(externalVideoUrl.trim());
      parsedEmbed = {
        embedType: parsed.embedType,
        embedUrl:  parsed.embedUrl,
        // Don't stamp 'video' on a course — the trailer URL is supplementary
        mediaType: (productType === 'course') ? null : 'video'
      };
    } else if (externalAudioUrl && externalAudioUrl.trim()) {
      const parsed = parseExternalMediaUrl(externalAudioUrl.trim());
      parsedEmbed = {
        embedType: parsed.embedType,
        embedUrl:  parsed.embedUrl,
        mediaType: 'audio'
      };
    } else if (hostedFile && hostedFile.publicId) {
      parsedEmbed.mediaType = 'file';
    }

    const resolvedType = productType || 'download';

    // ── Normalise type-specific data blobs ───────────────────────────────────
    if (resolvedType === 'course') {
      // Treat null, undefined, or empty-object submissions as a blank structure
      if (!courseData || typeof courseData !== 'object' || Array.isArray(courseData)) {
        courseData = { sections: [], totalSections: 0, totalChapters: 0, totalDuration: 0 };
      }
      if (!Array.isArray(courseData.sections)) {
        courseData.sections = [];
      }
      audioData    = undefined;
      softwareData = undefined;
    } else if (resolvedType === 'music') {
      courseData   = undefined;
      softwareData = undefined;
      videoData    = undefined;
    } else if (resolvedType === 'video') {
      courseData   = undefined;
      audioData    = undefined;
      softwareData = undefined;
      // Video products MUST have either a hosted file or an external video URL
      if (!hostedFile?.publicId && !externalVideoUrl?.trim()) {
        return res.status(400).json({
          success: false,
          message: 'Video products require an uploaded video file or an external video URL (YouTube, Vimeo, etc.).'
        });
      }
      // Force mediaType to 'video'
      parsedEmbed.mediaType = 'video';
    } else if (resolvedType === 'software') {
      courseData = undefined;
      audioData  = undefined;
      videoData  = undefined;
    } else {
      // download, template, script, component, ebook, other
      courseData   = undefined;
      audioData    = undefined;
      softwareData = undefined;
      videoData    = undefined;
      // Strip type-specific blobs that don't belong to these types
      if (!['ebook'].includes(resolvedType))                          ebookData  = undefined;
      if (!['template','script','component'].includes(resolvedType))  designData = undefined;
      // Guard: non-course products must have at least one delivery method
      if (!parsedEmbed.mediaType && !downloadLink && !hostedFile?.publicId) {
        return res.status(400).json({
          success: false,
          message: 'Please provide a hosted file or an external media link for your product.'
        });
      }
    }
    const { notes } = req.body;

    const creatorProduct = new CreatorProduct({
      creatorId: creator._id,
      title,
      description,
      category,
      suggestedPrice,
      tags:         tags         || [],
      images:       images       || [],
      downloadLink: downloadLink || null,
      fileSize,
      version,
      features:     features     || [],
      requirements: requirements || [],
      notes:        notes        || null,
      status:       'pending_review',
      productType:  productType  || 'download',
      hostedFile:   hostedFile   || null,
      previewUrl:   previewUrl   || null,
      previewType:  previewType  || 'none',
      audioData:    audioData    || null,
      videoData:    videoData    || null,
      softwareData: softwareData || null,
      ebookData:    ebookData    || null,
      designData:   designData   || null,
      courseData:   (productType === 'course' && courseData)
                      ? processChaptersForDelivery(JSON.parse(JSON.stringify(courseData)))
                      : (courseData || null),
      // ── external media ──
      externalVideoUrl: externalVideoUrl ? externalVideoUrl.trim() : null,
      externalAudioUrl: externalAudioUrl ? externalAudioUrl.trim() : null,
      embedType:        parsedEmbed.embedType,
      embedUrl:         parsedEmbed.embedUrl,
      mediaType:        parsedEmbed.mediaType,
      submittedAt: new Date()
    });
 
    await creatorProduct.save();
    creator.totalProducts += 1;
    await creator.save();
 
    console.log(`📦 New product submitted by creator ${creator.storeName}: ${title} [${parsedEmbed.mediaType || 'file'}]`);
 
    res.status(201).json({
      success: true,
      message: 'Product submitted for review! We will notify you within 24 hours.',
      product: creatorProduct
    });
 
  } catch (error) {
    console.error('❌ Creator submit product error:', error);
    res.status(500).json({ success: false, message: 'Product submission failed' });
  }
});
 


// ── CREATOR: GET MY PRODUCTS ────────────────────────────────────
app.get('/api/creator/products', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator) {
      return res.status(404).json({ success: false, message: 'Creator account not found' });
    }

    const { status = 'all' } = req.query;
    let query = { creatorId: creator._id };
    if (status !== 'all') query.status = status;

    const products = await CreatorProduct.find(query)
      .populate('productId')
      .sort({ createdAt: -1 });

    res.json({ success: true, products, count: products.length });

  } catch (error) {
    console.error('❌ Get creator products error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch products' });
  }
});

// ── CREATOR: GET SINGLE PRODUCT ─────────────────────────────────────────────
app.get('/api/creator/products/:id', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator) return res.status(403).json({ success: false, message: 'Creator account required' });

    const product = await CreatorProduct.findOne({ _id: req.params.id, creatorId: creator._id })
      .populate('productId');
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });

    res.json({ success: true, product });
  } catch (error) {
    if (error.name === 'CastError') return res.status(400).json({ success: false, message: 'Invalid product ID' });
    console.error('❌ Get single creator product error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch product' });
  }
});

// ── GET /api/creator/products/:productId/students ─────────────────────────────
// For course creators only — shows enrolled students, progress, and completion rate
app.get('/api/creator/products/:productId/students', authenticateToken, async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator || creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Approved creator account required' });
    }

    // Verify this product belongs to this creator
    const creatorProduct = await CreatorProduct.findOne({
      _id:       req.params.productId,
      creatorId: creator._id,
      productType: 'course',
    });
    if (!creatorProduct) {
      return res.status(404).json({ success: false, message: 'Course not found or access denied' });
    }
    if (!creatorProduct.productId) {
      return res.status(400).json({ success: false, message: 'Course is not yet approved and live' });
    }

    const page  = Math.max(1, parseInt(req.query.page)  || 1);
    const limit = Math.min(100, parseInt(req.query.limit) || 30);
    const skip  = (page - 1) * limit;

    // Query both IDs: mirrored Product._id (canonical) and raw CreatorProduct._id
    // (legacy — present in progress records saved before checkout normalisation).
    const productIdFilter = {
      $or: [
        { productId: creatorProduct.productId },
        { productId: creatorProduct._id },
      ]
    };

    const [progressRecords, totalEnrolled] = await Promise.all([
      CourseProgress.find(productIdFilter)
        .sort({ lastAccessedAt: -1 })
        .skip(skip)
        .limit(limit)
        .populate('userId', 'fullName profileImage')
        .lean(),
      CourseProgress.countDocuments(productIdFilter)
    ]);

    // Count chapters live from the course structure so new/growing courses
    // are calculated correctly (avoids the stale || 1 fallback).
    const sections     = creatorProduct.courseData?.sections || [];
    const totalChapters = sections.reduce((sum, s) => sum + (s.chapters?.length || 0), 0) || 1;

    const completedCount = await CourseProgress.countDocuments({
      ...productIdFilter,
      completionPct: 100,
    });

    res.json({
      success: true,
      courseTitle:    creatorProduct.title,
      totalEnrolled,
      completedCount,
      completionRate: totalEnrolled > 0 ? Math.round((completedCount / totalEnrolled) * 100) : 0,
      totalChapters,
      students: progressRecords.map(p => ({
        userId:           p.userId?._id,
        fullName:         p.userId?.fullName     || 'Student',
        profileImage:     p.userId?.profileImage || null,
        completionPct:    p.completionPct,
        completedChapters: p.completedChapters?.length || 0,
        lastAccessedAt:   p.lastAccessedAt,
        startedAt:        p.startedAt,
        certificateIssued: p.certificateIssued,
        timeSpent:        p.timeSpent || 0,
      })),
      pagination: {
        page, limit, total: totalEnrolled,
        pages:   Math.ceil(totalEnrolled / limit),
        hasMore: skip + progressRecords.length < totalEnrolled,
      }
    });
  } catch (error) {
    console.error('❌ GET /api/creator/products/:productId/students error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch students' });
  }
});

// ── CREATOR: DELETE PRODUCT (pending or rejected only) ──────────────────────
app.delete('/api/creator/products/:id', authenticateToken, async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator) return res.status(403).json({ success: false, message: 'Creator account required' });

    const product = await CreatorProduct.findOne({ _id: req.params.id, creatorId: creator._id });
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });

    if (product.status === 'approved') {
      return res.status(403).json({ success: false, message: 'Approved products cannot be deleted. Contact support.' });
    }
     if (product) {
    setImmediate(() => deleteProductAssets(product).catch(() => {}));
   }
   await Product.findByIdAndDelete(req.params.id);
    await product.deleteOne();
    creator.totalProducts = Math.max(0, (creator.totalProducts || 1) - 1);
    await creator.save();

    console.log(`🗑️  Creator product deleted: ${product.title} by ${creator.storeName}`);
    res.json({ success: true, message: 'Product deleted successfully' });
  } catch (error) {
    if (error.name === 'CastError') return res.status(400).json({ success: false, message: 'Invalid product ID' });
    console.error('❌ Delete creator product error:', error);
    res.status(500).json({ success: false, message: 'Delete failed' });
  }
});

app.put('/api/creator/products/:id', authenticateToken, async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator) return res.status(403).json({ success: false, message: 'Creator account required' });
 
    const product = await CreatorProduct.findOne({ _id: req.params.id, creatorId: creator._id });
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });
 
  const allowedFields = [
      'title', 'description', 'category', 'suggestedPrice', 'tags',
      'images', 'downloadLink', 'fileSize', 'version', 'features', 'requirements',
      'hostedFile', 'previewUrl', 'previewType', 'notes',
      'audioData', 'softwareData', 'videoData', 'courseData', 'ebookData', 'designData',
      'externalVideoUrl', 'externalAudioUrl'
    ];
// productType locked once approved — changing it breaks delivery for buyers
if (product.status !== 'approved' && req.body.productType !== undefined) {
  product.productType = req.body.productType;
}

allowedFields.forEach(field => {
  if (req.body[field] !== undefined) product[field] = req.body[field];
});
 
    // Re-parse embed info if external URLs were updated
    if (req.body.externalVideoUrl !== undefined || req.body.externalAudioUrl !== undefined) {
      const videoUrl = product.externalVideoUrl;
      const audioUrl = product.externalAudioUrl;
 
      if (videoUrl && videoUrl.trim()) {
        const parsed = parseExternalMediaUrl(videoUrl.trim());
        product.embedType  = parsed.embedType;
        product.embedUrl   = parsed.embedUrl;
        product.mediaType  = 'video';
      } else if (audioUrl && audioUrl.trim()) {
        const parsed = parseExternalMediaUrl(audioUrl.trim());
        product.embedType  = parsed.embedType;
        product.embedUrl   = parsed.embedUrl;
        product.mediaType  = 'audio';
      } else {
        product.embedType  = null;
        product.embedUrl   = null;
        product.mediaType  = product.hostedFile?.publicId ? 'file' : null;
      }
    }
 
    // Re-process courseData chapters if updated
    if (req.body.courseData !== undefined) {
    product.courseData = product.courseData
      ? processChaptersForDelivery(JSON.parse(JSON.stringify(product.courseData)))
      : null;
    product.markModified('courseData');
  }
 
    // Always re-infer mediaType
    // Always re-infer mediaType — but never downgrade a course to 'video'
    if (product.productType === 'course') {
      product.mediaType = 'course';
    } else {
      product.mediaType = inferProductMediaType(product);
    }
 
    // If resubmitting a rejected product
    if (req.body.status === 'pending_review' && product.status === 'rejected') {
      product.status = 'pending_review';
      product.rejectionReason = '';
    }
 
    await product.save();
 
    // ── GAP 6 FIX: Sync changes to mirrored Product if approved ──────────
    // Only sync non-pricing fields — price is controlled by admin approval.
    // Only sync if product is approved (productId exists).
    if (product.status === 'approved' && product.productId) {
      try {
        const syncFields = {
          title:            product.title,
          description:      product.description,
          category:         product.category,
          image:            product.images?.[0] || '',
          images:           product.images || [],
          fileSize:         product.fileSize     || null,
          version:          product.version      || null,
          features:         product.features     || [],
          requirements:     product.requirements || [],
          tags:             product.tags         || [],
          productType:      product.productType,
          hostedFile:       product.hostedFile   || null,
          previewUrl:       product.previewUrl   || null,
          previewType:      product.previewType  || 'none',
          courseData:       product.courseData   || null,
          audioData:        product.audioData    || null,
          videoData:        product.videoData    || null,
          softwareData:     product.softwareData || null,
          externalVideoUrl: product.externalVideoUrl || null,
          externalAudioUrl: product.externalAudioUrl || null,
          embedType:        product.embedType    || null,
          embedUrl:         product.embedUrl     || null,
          mediaType:        product.mediaType    || null,
          downloadLink:     product.downloadLink || null,
        };
 
        await Product.findByIdAndUpdate(product.productId, { $set: syncFields });
        console.log(`🔄 Mirrored Product synced after creator edit: ${product.title}`);
      } catch (syncErr) {
        // Non-fatal — log but don't fail the creator's save
        console.error('⚠️  Mirror sync failed (non-fatal):', syncErr.message);
      }
    }
 
    res.json({ success: true, message: 'Product updated', product });
  } catch (error) {
    console.error('❌ Update creator product error:', error);
    res.status(500).json({ success: false, message: 'Update failed' });
  }
});
 
// ── Proxy download route ──────────────────────────────────────────────────
// Fetches the raw Cloudinary file server-side and streams it to the browser
// with the correct Content-Disposition filename.
// This avoids Cloudinary's fl_attachment re-wrapping which corrupts file size.
//
// GET /api/download/file?orderId=…&productId=…
// Auth: JWT Bearer token required
app.get('/api/download/file', authenticateToken, downloadLimiter, async (req, res) => {
  try {
    const { orderId, productId } = req.query;
    if (!orderId || !productId) {
      return res.status(400).json({ success: false, message: 'orderId and productId required' });
    }
 
    const order = await Order.findOne({ _id: orderId, userId: req.user.userId }).lean();
    if (!order) {
      return res.status(403).json({ success: false, message: 'Order not found or access denied' });
    }
 
    // ── E3: Refund blocks download access ────────────────────────────────
    if (order.status === 'refunded') {
      return res.status(403).json({
        success: false,
        message: 'This order has been refunded. Download access has been revoked.',
      });
    }
 
    // ── Per-item download limit check ────────────────────────────────────
    const orderItem = (order.items || []).find(
      i => String(i.productId || i.id) === String(productId)
    );
    if (orderItem) {
      // Check expiry
      if (orderItem.downloadExpiry && new Date(orderItem.downloadExpiry) < new Date()) {
        return res.status(403).json({ success: false, message: 'Download link has expired.' });
      }
      // Check count
      if (orderItem.downloadCount >= (orderItem.downloadLimit ?? 10)) {
        // A5: fire the download limit email
        setImmediate(async () => {
          try {
            const user = await User.findById(req.user.userId).select('fullName email notificationPreferences').lean();
            if (user && userWantsEmail(user, 'orders')) {
              let product = await Product.findById(productId).select('title').lean()
                         || await CreatorProduct.findById(productId).select('title').lean();
              if (global.sendDownloadLimitEmail) {
                await global.sendDownloadLimitEmail(user.email, {
                  fullName:      user.fullName,
                  productTitle:  product?.title || 'your product',
                  downloadLimit: orderItem.downloadLimit ?? 10,
                });
              }
            }
          } catch (_) {}
        });
        return res.status(429).json({
          success: false,
          message: `Download limit of ${orderItem.downloadLimit ?? 10} reached for this product. Contact support for help.`,
        });
      }
    }
 
    let product = await Product.findById(productId).select('title hostedFile productType').lean();
    if (!product) product = await CreatorProduct.findById(productId).select('title hostedFile productType').lean();
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });
    if (!product.hostedFile?.publicId) return res.status(404).json({ success: false, message: 'No file attached to this product' });
 
    const cloudinaryRawUrl = cloudinary.url(product.hostedFile.publicId, {
      resource_type: product.hostedFile.resourceType || 'raw',
      type:          'upload',
      secure:        true,
    });
 
    const rawOriginalName = product.hostedFile.originalName || product.hostedFile.publicId.split('/').pop();
    const ext             = require('path').extname(rawOriginalName);
    const fmt             = product.hostedFile.format || '';
    const nameWithExt     = ext ? rawOriginalName : (fmt ? `${rawOriginalName}.${fmt}` : rawOriginalName);
    const safeFilename    = nameWithExt.replace(/[^\w.\-\s]/g, '_');
 
    // Increment per-item downloadCount — try items.productId first, fall back to items.id
    const incResult = await Order.updateOne(
      { _id: orderId, 'items.productId': String(productId) },
      { $inc: { 'items.$.downloadCount': 1 } }
    );
    if (incResult.modifiedCount === 0) {
      await Order.updateOne(
        { _id: orderId, 'items.id': String(productId) },
        { $inc: { 'items.$.downloadCount': 1 } }
      );
    }
 
    // Track in Download collection + fire analytics event
    try {
      await Download.create({ userId: req.user.userId, productId: product._id, orderId: order._id });
      trackDownload();  // real-time analytics counter
    } catch (_) {}

    const upstream = await require('axios').get(cloudinaryRawUrl, { responseType: 'stream', timeout: 60000 });
    const contentType   = upstream.headers['content-type'] || 'application/octet-stream';
    const contentLength = upstream.headers['content-length'] || null;
 
    res.setHeader('Content-Type', contentType);
    res.setHeader('Content-Disposition', `attachment; filename="${safeFilename}"`);
    if (contentLength) res.setHeader('Content-Length', contentLength);
    res.setHeader('Cache-Control', 'no-store');
 
    upstream.data.pipe(res);
    upstream.data.on('error', (err) => {
      console.error('❌ Proxy download stream error:', err.message);
      if (!res.headersSent) res.status(500).end();
    });
 
  } catch (error) {
    console.error('❌ Proxy download error:', error.message);
    if (!res.headersSent) res.status(500).json({ success: false, message: 'Download failed' });
  }
});
 
// ══════════════════════════════════════════════════════════════════════════════
// COURSE STRUCTURE MANAGEMENT
// Save/replace the full section+chapter structure for a product (or creator product)
// ══════════════════════════════════════════════════════════════════════════════

// Admin: update course structure on a Product
app.put('/api/admin/products/:id/course-structure', authenticateAdmin, async (req, res) => {
  try {
    const product = await Product.findById(req.params.id);
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });
    if (product.productType !== 'course') {
      return res.status(400).json({ success: false, message: 'Product is not a course' });
    }

    const { sections, level, language, certificate } = req.body;

    // Compute totals from sections
    let totalChapters = 0;
    let totalDuration = 0;
    (sections || []).forEach(s => {
      (s.chapters || []).forEach(ch => {
        totalChapters++;
        totalDuration += ch.duration || 0;
      });
    });

    const existingCourse = product.courseData
      ? product.courseData.toJSON()
      : {};

    const rawCourseData = {
      totalDuration,
      totalChapters,
      totalSections:     (sections || []).length,
      sections:          sections || [],
      level:             (['beginner','intermediate','advanced','all'].includes(level)
                           ? level : (existingCourse.level || 'all')),
      language:          language    || existingCourse.language    || 'English',
      certificate:       certificate !== undefined
                           ? (certificate === true || certificate === 'true')
                           : (existingCourse.certificate || false),
      whatYouLearn:      Array.isArray(req.body.whatYouLearn)
                           ? req.body.whatYouLearn
                           : (existingCourse.whatYouLearn || []),
      targetAudience:    Array.isArray(req.body.targetAudience)
                           ? req.body.targetAudience
                           : (existingCourse.targetAudience || []),
      welcomeMessage:    req.body.welcomeMessage    !== undefined
                           ? req.body.welcomeMessage
                           : (existingCourse.welcomeMessage    || null),
      completionMessage: req.body.completionMessage !== undefined
                           ? req.body.completionMessage
                           : (existingCourse.completionMessage || null),
    };

  product.courseData = processChaptersForDelivery(rawCourseData);
  product.markModified('courseData');
  await product.save();

    // Sync the updated courseData back to the linked CreatorProduct so they stay in sync
    if (product.creatorProductId) {
      try {
        await CreatorProduct.findByIdAndUpdate(product.creatorProductId, {
          $set: { courseData: product.courseData }
        });
        console.log(`🔄 Admin course structure synced to CreatorProduct: ${product.title}`);
      } catch (syncErr) {
        console.error('⚠️  Sync to CreatorProduct failed (non-fatal):', syncErr.message);
      }
    }

    res.json({ success: true, message: 'Course structure saved', courseData: product.courseData });
  } catch (error) {
    console.error('❌ Course structure save error:', error);
    res.status(500).json({ success: false, message: 'Failed to save course structure' });
  }
});

// Creator: update course structure on a CreatorProduct
app.put('/api/creator/products/:id/course-structure', authenticateToken, async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator) return res.status(403).json({ success: false, message: 'Creator account required' });

    const product = await CreatorProduct.findOne({ _id: req.params.id, creatorId: creator._id });
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });
    if (product.productType !== 'course') {
      return res.status(400).json({ success: false, message: 'Product is not a course' });
    }

    const { sections, level, language, certificate } = req.body;

    let totalChapters = 0, totalDuration = 0;
    (sections || []).forEach(s => {
      (s.chapters || []).forEach(ch => {
        totalChapters++;
        totalDuration += ch.duration || 0;
      });
    });

    // Pull existing values safely — toJSON() gives a plain object without Mongoose internals
    const existingCourse = product.courseData
      ? product.courseData.toJSON()
      : {};

   const rawCourseData = {
      totalDuration,
      totalChapters,
      totalSections:     (sections || []).length,
      sections:          sections || [],
      level:             (['beginner','intermediate','advanced','all'].includes(level)
                           ? level : (existingCourse.level || 'all')),
      language:          language    || existingCourse.language    || 'English',
      certificate:       certificate !== undefined
                           ? (certificate === true || certificate === 'true')
                           : (existingCourse.certificate || false),
      whatYouLearn:      Array.isArray(req.body.whatYouLearn)
                           ? req.body.whatYouLearn
                           : (existingCourse.whatYouLearn || []),
      targetAudience:    Array.isArray(req.body.targetAudience)
                           ? req.body.targetAudience
                           : (existingCourse.targetAudience || []),
      welcomeMessage:    req.body.welcomeMessage    !== undefined
                           ? req.body.welcomeMessage
                           : (existingCourse.welcomeMessage    || null),
      completionMessage: req.body.completionMessage !== undefined
                           ? req.body.completionMessage
                           : (existingCourse.completionMessage || null),
    };

    product.courseData = processChaptersForDelivery(rawCourseData);
    product.markModified('courseData');
    await product.save();

    // Sync courseData to mirrored Product so buyers see the updated structure immediately
    if (product.status === 'approved' && product.productId) {
      try {
        await Product.findByIdAndUpdate(product.productId, {
          $set: { courseData: product.courseData }
        });
        console.log(`🔄 Course structure synced to Product: ${product.title}`);
      } catch (syncErr) {
        console.error('⚠️  Course structure sync to Product failed (non-fatal):', syncErr.message);
      }
    }

    res.json({ success: true, message: 'Course structure saved', courseData: product.courseData });
  } catch (error) {
    console.error('❌ Creator course structure error:', error);
    res.status(500).json({ success: false, message: 'Failed to save' });
  }
});

// Public: get course preview structure (only free chapters exposed, no URLs)
app.get('/api/products/:id/course-preview', async (req, res) => {
  try {
    const product = await Product.findById(req.params.id);
    if (!product || !product.isActive) return res.status(404).json({ success: false, message: 'Product not found' });
    if (product.productType !== 'course') return res.status(400).json({ success: false, message: 'Not a course' });

    const publicSections = (product.courseData?.sections || []).map(section => ({
      sectionTitle: section.sectionTitle,
      sectionOrder: section.sectionOrder,
      chapters: (section.chapters || []).map(ch => {
        let freeUrl    = null;
        let embedUrl   = null;
        let embedType  = null;
        let playerType = null;

        if (ch.isFree) {
          // Prefer resolved embedUrl (YouTube/Vimeo) → fall back to externalUrl
          if (ch.embedUrl) {
            embedUrl   = ch.embedUrl;
            embedType  = ch.embedType  || null;
            playerType = ch.playerType || 'iframe';
          } else if ((ch.externalUrl || ch.embedUrl) && typeof parseExternalMediaUrl === 'function') {
            const rawUrl = ch.externalUrl || ch.embedUrl;
            const parsed = parseExternalMediaUrl(rawUrl);
            if (parsed.embedType && parsed.embedType !== 'unknown') {
              embedUrl   = parsed.embedUrl;
              embedType  = parsed.embedType;
              playerType = ['youtube','vimeo','dailymotion','gdrive'].includes(parsed.embedType)
                ? 'iframe'
                : parsed.embedType === 'soundcloud' ? 'soundcloud_widget' : 'html5_video';
            } else {
              // Unrecognised host — pass raw URL through directly, never drop it
              freeUrl    = rawUrl;
              embedType  = 'direct';
              const AUDIO_EXT_CP = ['mp3','wav','ogg','aac','flac','m4a','opus'];
              const lUrlCp = rawUrl.toLowerCase().split('?')[0];
              playerType = AUDIO_EXT_CP.some(ext => lUrlCp.endsWith('.' + ext))
                ? 'html5_audio' : 'html5_video';
            }
          } else if (ch.hostedFile?.publicId) {
            const hfFmtFree   = (ch.hostedFile.format || '').toLowerCase();
            const isPdfFree   = hfFmtFree === 'pdf' || ch.chapterType === 'pdf';
            const AUDIO_FMT_CP = ['mp3','wav','ogg','aac','flac','m4a','wma','opus','aiff'];
            const isAudioFree  = ch.chapterType === 'audio'
              || ch.mediaType   === 'audio'
              || AUDIO_FMT_CP.includes(hfFmtFree);

            if (isPdfFree) {
              // PDF chapter: expose pdfUrl for inline viewer, never a video player
              freeUrl    = ch.hostedFile.secureUrl
                || generateSecureDeliveryUrl(ch.hostedFile.publicId, 'raw', 3600, false);
              playerType = 'pdf_viewer';
            } else {
              // Audio / video hosted file — original behaviour
              freeUrl    = ch.hostedFile.secureUrl
                || generateSecureDeliveryUrl(ch.hostedFile.publicId, ch.hostedFile.resourceType || 'raw', 3600, false);
              playerType = isAudioFree ? 'cloudinary_audio' : 'cloudinary';
            }
          }
        }

        return {
          chapterTitle: ch.chapterTitle,
          chapterOrder: ch.chapterOrder,
          duration:     ch.duration,
          isFree:       ch.isFree,
          chapterUrl:   playerType === 'pdf_viewer' ? null : freeUrl,
          pdfUrl:       playerType === 'pdf_viewer' ? freeUrl : null,
          embedUrl:     embedUrl,
          embedType:    embedType,
          playerType:   playerType,
          chapterType:  ch.chapterType || null,
        };
      })
    }));

    res.json({
      success: true,
      coursePreview: {
        totalChapters: product.courseData?.totalChapters,
        totalDuration: product.courseData?.totalDuration,
        totalSections: product.courseData?.totalSections,
        level:         product.courseData?.level,
        language:      product.courseData?.language,
        certificate:   product.courseData?.certificate,
        sections:      publicSections
      }
    });
  } catch (error) {
    res.status(500).json({ success: false, message: 'Failed to load course preview' });
  }
});

// ══════════════════════════════════════════════════════════════════════════════
// COURSE PROGRESS — Save & Resume
// ══════════════════════════════════════════════════════════════════════════════

// GET — load a user's current progress for a course
app.get('/api/orders/:orderId/course-progress', authenticateToken, async (req, res) => {
  try {
    const { orderId }   = req.params;
    const { productId } = req.query;

    if (!productId) {
      return res.status(400).json({ success: false, message: 'productId query parameter is required' });
    }

    // Verify order belongs to this user
  // CourseProgress is keyed on userId — JWT already authenticates who the user is.
    // No need to re-verify the order on every progress read (saves 1 DB round-trip).
    const progress = await CourseProgress.findOne({
      userId:    req.user.userId,
      productId,
    }).lean();

    res.json({
      success: true,
      progress: progress || {
        completedChapters:  [],
        lastSectionOrder:   0,
        lastChapterOrder:   0,
        completionPct:      0,
        certificateIssued:  false,
        completedAt:        null,
        startedAt:          null,
        lastAccessedAt:     null,
        timeSpent:          0,
      }
    });
  } catch (error) {
    console.error('❌ Get course progress error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch progress' });
  }
});


// POST — save / update a user's course progress
app.post('/api/orders/:orderId/course-progress', authenticateToken, async (req, res) => {
  try {
    const { orderId }                = req.params;
    const { productId, completedChapters, lastSectionOrder, lastChapterOrder } = req.body;

    if (!productId) {
      return res.status(400).json({ success: false, message: 'productId is required' });
    }

    // Verify order belongs to this user and is paid
    const order = await Order.findOne({
      _id: orderId,
      userId: req.user.userId,
      status: 'completed'
    }).lean();
    if (!order) {
      return res.status(403).json({ success: false, message: 'Order not found or not completed' });
    }

    // Load the product — count chapters LIVE from sections to avoid stale totalChapters.
    // FIX #4: productId may be a CreatorProduct _id (not a Product _id), so we use the
    // same multi-strategy lookup as media-access rather than a bare Product.findById.
    const isValidOid = (id) => id && String(id).match(/^[a-f\d]{24}$/i);
    let product = null;

    // Strategy A — productId is a main Product _id
    if (isValidOid(productId)) {
      product = await Product.findById(productId).select('courseData').lean();
    }

    // Strategy B — productId is a CreatorProduct _id; resolve to its mirrored Product
    if (!product && isValidOid(productId)) {
      const cp = await CreatorProduct.findById(productId).select('productId courseData').lean();
      if (cp) {
        if (cp.productId && isValidOid(cp.productId)) {
          product = await Product.findById(cp.productId).select('courseData').lean();
        }
        // If no mirrored Product exists yet, use the CreatorProduct's own courseData
        if (!product) product = cp;
      }
    }

    let totalChapters = 0;
    (product?.courseData?.sections || []).forEach(s =>
      (s.chapters || []).forEach(() => totalChapters++)
    );
    // Fallback to stored value if sections array is somehow empty
    if (totalChapters === 0) totalChapters = product?.courseData?.totalChapters || 0;

    const { timeSpent } = req.body; // optional: client sends seconds watched this session

    // Deduplicate keys so duplicate submissions don't inflate percentage
    const doneChapters = [...new Set(Array.isArray(completedChapters) ? completedChapters : [])];
    const completionPct = totalChapters > 0
      ? Math.min(100, Math.round((doneChapters.length / totalChapters) * 100))
      : 0;

    const isComplete = completionPct >= 100;
    const offersCert = product?.courseData?.certificate === true;

    // Upsert — create if first time, update if exists
    const existing = await CourseProgress.findOne({ userId: req.user.userId, productId }).lean();
    const alreadyCertified = existing?.certificateIssued === true;

    // Generate a certificate ID only once, when first earned
    let newCertId = null;
    if (isComplete && offersCert && !alreadyCertified) {
      newCertId = require('crypto').randomBytes(16).toString('hex');
    }

    const progress = await CourseProgress.findOneAndUpdate(
      { userId: req.user.userId, productId },
      {
        $set: {
          orderId,
          completedChapters:   doneChapters,
          lastSectionOrder:    lastSectionOrder || 0,
          lastChapterOrder:    lastChapterOrder || 0,
          completionPct,
          lastAccessedAt:      new Date(),
          ...(isComplete && !existing?.completedAt && { completedAt: new Date() }),
          ...(isComplete && offersCert && !alreadyCertified && {
            certificateIssued:   true,
            certificateIssuedAt: new Date(),
            certificateId:       newCertId,
          }),
        },
        // Increment total time spent — only if client sent a valid positive number
        ...(timeSpent > 0 && { $inc: { timeSpent: Math.min(timeSpent, 7200) } }),
        // Set startedAt only on first creation (upsert insert path)
        $setOnInsert: { startedAt: new Date() },
      },
      { upsert: true, new: true }
    );

    res.json({
      success: true,
      message: isComplete ? '🎉 Course completed!' : 'Progress saved',
      progress: {
        completedChapters:  progress.completedChapters,
        lastSectionOrder:   progress.lastSectionOrder,
        lastChapterOrder:   progress.lastChapterOrder,
        completionPct:      progress.completionPct,
        certificateIssued:  progress.certificateIssued,
        completedAt:        progress.completedAt,
        startedAt:          progress.startedAt,
        lastAccessedAt:     progress.lastAccessedAt,
        timeSpent:          progress.timeSpent,
      },
      certificateAvailable: progress.certificateIssued,
    });
  } catch (error) {
    console.error('❌ Save course progress error:', error);
    res.status(500).json({ success: false, message: 'Failed to save progress' });
  }
});


// GET — check / download certificate for a completed course
app.get('/api/orders/:orderId/certificate', authenticateToken, async (req, res) => {
  try {
    const { orderId }   = req.params;
    const { productId } = req.query;

    if (!productId) {
      return res.status(400).json({ success: false, message: 'productId query parameter is required' });
    }

    const order = await Order.findOne({ _id: orderId, userId: req.user.userId }).lean();
    if (!order) {
      return res.status(403).json({ success: false, message: 'Order not found or access denied' });
    }

    const progress = await CourseProgress.findOne({
      userId:    req.user.userId,
      productId
    }).lean();

    if (!progress || !progress.certificateIssued) {
      return res.status(403).json({
        success: false,
        message: 'Certificate not yet earned. Complete all chapters to unlock your certificate.',
        completionPct: progress?.completionPct || 0,
      });
    }

    // Load user + product for certificate data
    const [user, product] = await Promise.all([
      User.findById(req.user.userId).select('fullName email').lean(),
      Product.findById(productId).select('title courseData').lean(),
    ]);

    res.json({
      success: true,
      certificate: {
        certificateId:   progress.certificateId  || null,
        userName:        user?.fullName          || 'Student',
        userEmail:       user?.email             || '',
        courseTitle:     product?.title          || 'Course',
        completedAt:     progress.completedAt,
        issuedAt:        progress.certificateIssuedAt,
        completionPct:   progress.completionPct,
      }
    });
  } catch (error) {
    console.error('❌ Certificate fetch error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch certificate' });
  }
});

