// PRODUCT REVIEWS
// POST   /api/reviews                      — buyer submits a review
// GET    /api/products/:id/reviews         — public: list approved reviews
// GET    /api/products/:id/reviews/summary — public: rating summary (avg + counts)
// ══════════════════════════════════════════════════════════════════════════════

// POST — submit or update a review (one per buyer per product, enforced by DB index)
app.post('/api/reviews', authenticateToken, async (req, res) => {
  try {
    const { productId, orderId, rating, title, body } = req.body;

    // ── Validate inputs ───────────────────────────────────────────────────
    if (!productId) {
      return res.status(400).json({ success: false, message: 'productId is required' });
    }
    if (!orderId) {
      return res.status(400).json({ success: false, message: 'orderId is required' });
    }
    if (!rating || typeof rating !== 'number' || rating < 1 || rating > 5) {
      return res.status(400).json({ success: false, message: 'rating must be a number between 1 and 5' });
    }
    if (!body || String(body).trim().length < 5) {
      return res.status(400).json({ success: false, message: 'Review body must be at least 5 characters' });
    }

    // ── Verify the buyer actually purchased this product ──────────────────
    const order = await Order.findOne({
      _id:    orderId,
      userId: req.user.userId,
      status: 'completed',
    }).lean();
    if (!order) {
      return res.status(403).json({ success: false, message: 'Purchase not verified — order not found or not completed' });
    }

    // Confirm this product is in the order
    const orderItem = order.items.find(item =>
      String(item.id)        === String(productId) ||
      String(item.productId) === String(productId)
    );
    if (!orderItem) {
      return res.status(403).json({ success: false, message: 'This product was not part of your order' });
    }

    // ── Upsert the review (unique index: userId + productId) ──────────────
    const reviewData = {
      $set: {
        orderId,
        rating,
        title:            String(title || '').trim().slice(0, 120),
        body:             String(body).trim().slice(0, 2000),
        verifiedPurchase: true,
        status:           'approved',   // auto-approve verified purchases; set to 'pending' if you want manual moderation
        updatedAt:        new Date(),
      },
      $setOnInsert: {
        userId:    req.user.userId,
        productId,
        createdAt: new Date(),
      },
    };

    const review = await Review.findOneAndUpdate(
      { userId: req.user.userId, productId },
      reviewData,
      { upsert: true, new: true }
    );

    // ── Mark the order item as reviewed ──────────────────────────────────
    // Update both possible field names (id and productId) to cover all order formats
    await Order.updateOne(
      { _id: orderId },
      {
        $set: {
          'items.$[item].hasReviewed': true,
          'items.$[item].reviewId':    review._id,
        }
      },
      {
        arrayFilters: [
          {
            $or: [
              { 'item.id':        String(productId) },
              { 'item.productId': String(productId) },
            ]
          }
        ]
      }
    );

    console.log(`⭐ Review submitted: user ${req.user.userId} → product ${productId} [${rating}★]`);

    return res.json({
      success: true,
      message: 'Review submitted successfully',
      review: {
        _id:              review._id,
        rating:           review.rating,
        title:            review.title,
        body:             review.body,
        verifiedPurchase: review.verifiedPurchase,
        createdAt:        review.createdAt,
      },
    });

  } catch (error) {
    // Duplicate key — the unique index fired; user already reviewed this product
    if (error.code === 11000) {
      return res.status(409).json({
        success: false,
        message: 'You have already reviewed this product. Only one review per purchase is allowed.',
      });
    }
    console.error('❌ POST /api/reviews error:', error);
    return res.status(500).json({ success: false, message: 'Failed to submit review' });
  }
});

// ─────────────────────────────────────────────────────────────────────────────
// BLOCK 22 — PUBLIC CERTIFICATE VERIFICATION ENDPOINT (C13)
// ─────────────────────────────────────────────────────────────────────────────
 
app.get('/api/certificates/verify/:certificateId', async (req, res) => {
  try {
    const { certificateId } = req.params;
    if (!certificateId || certificateId.length < 8) {
      return res.status(400).json({ success: false, message: 'Invalid certificate ID' });
    }
 
    const progress = await CourseProgress.findOne({ certificateId }).lean();
    if (!progress || !progress.certificateIssued) {
      return res.status(404).json({
        success:  false,
        valid:    false,
        message:  'Certificate not found or not yet issued',
      });
    }
 
    const [user, product] = await Promise.all([
      User.findById(progress.userId).select('fullName').lean(),
      Product.findById(progress.productId).select('title courseData').lean()
        .then(p => p || CreatorProduct.findById(progress.productId).select('title').lean()),
    ]);
 
    // Check if the underlying order was refunded
    const refundedOrder = await Order.findOne({
      userId:  progress.userId,
      'items.productId': String(progress.productId),
      status:  'refunded',
    }).lean();
 
    const isValid = !refundedOrder;
 
    res.json({
      success:     true,
      valid:       isValid,
      certificate: {
        certificateId:  progress.certificateId,
        issuedTo:       user?.fullName || '—',
        courseTitle:    product?.title || '—',
        completedAt:    progress.completedAt,
        issuedAt:       progress.certificateIssuedAt,
        completionPct:  progress.completionPct,
        revoked:        !isValid,
        revokedReason:  !isValid ? 'Order was refunded' : null,
      },
    });
  } catch (err) {
    console.error('❌ Certificate verify error:', err.message);
    res.status(500).json({ success: false, message: 'Verification failed' });
  }
});
 
 
