// ── PATCH /api/creator/coupons/:id/products — opt products in/out ─────────────
// Body: { allowedProductIds: [productId, ...] }
// Empty array = coupon applies to ALL of creator's approved products.
// Non-empty = only those specific products.
// Creator can call this any time before the coupon is consumed (while still active).
app.patch('/api/creator/coupons/:id/products', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator || creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Approved creator account required' });
    }

    const coupon = await Coupon.findOne({ _id: req.params.id, ownerCreatorId: creator._id });
    if (!coupon) {
      return res.status(404).json({ success: false, message: 'Coupon not found or access denied' });
    }

    const { allowedProductIds } = req.body;
    if (!Array.isArray(allowedProductIds)) {
      return res.status(400).json({ success: false, message: 'allowedProductIds must be an array' });
    }

    // Validate every ID belongs to this creator
    if (allowedProductIds.length > 0) {
      const approvedProds = await CreatorProduct.find({
        creatorId: creator._id,
        status:    'approved',
      }).select('productId').lean();
      const validSet = new Set(approvedProds.map(p => p.productId?.toString()).filter(Boolean));
      const bad = allowedProductIds.filter(id => !validSet.has(id.toString()));
      if (bad.length > 0) {
        return res.status(400).json({
          success: false,
          message: 'Some product IDs do not belong to your approved products',
          invalid: bad,
        });
      }
    }

    // Update both fields in sync
    coupon.allowedProductIds  = allowedProductIds;
    coupon.applicableProducts = allowedProductIds.length > 0
      ? allowedProductIds
      : (await CreatorProduct.find({ creatorId: creator._id, status: 'approved' }).select('productId').lean())
          .map(p => p.productId).filter(Boolean);

    await coupon.save();

    return res.json({
      success: true,
      message: allowedProductIds.length > 0
        ? `Coupon restricted to ${allowedProductIds.length} product(s)`
        : 'Coupon now applies to all your approved products',
      allowedProductIds: coupon.allowedProductIds,
      applicableProducts: coupon.applicableProducts,
    });
  } catch (error) {
    console.error('❌ Coupon product opt error:', error);
    res.status(500).json({ success: false, message: 'Failed to update product scope' });
  }
});

// ── DELETE /api/creator/coupons/:id — deactivate a creator coupon ─────────────
// Only works on coupons that have NOT yet been paid. After payment the creator
// cannot delete — they must contact admin. (Protects admin review queue.)
app.delete('/api/creator/coupons/:id', authenticateToken, requireFeature('creatorEnabled'), async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator || creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Approved creator account required' });
    }

    const coupon = await Coupon.findOne({ _id: req.params.id, ownerCreatorId: creator._id });
    if (!coupon) {
      return res.status(404).json({ success: false, message: 'Coupon not found or access denied' });
    }

    if (coupon.paymentStatus === 'paid' && coupon.isActive) {
      return res.status(403).json({
        success: false,
        message: 'Active paid coupons cannot be deleted. Deactivation is handled by admin. Contact support.',
      });
    }

    // Unpaid coupons can be fully deleted; paid-but-pending ones just deactivated
    if (coupon.paymentStatus === 'unpaid') {
      await Coupon.deleteOne({ _id: coupon._id });
      return res.json({ success: true, message: 'Coupon deleted' });
    }

    coupon.isActive = false;
    await coupon.save();
    return res.json({ success: true, message: 'Coupon deactivated' });
  } catch (error) {
    console.error('❌ Delete creator coupon error:', error);
    res.status(500).json({ success: false, message: 'Failed to deactivate coupon' });
  }
});

// ── GET /api/creator/buyers — deduplicated list of customers who bought creator's products ──
app.get('/api/creator/buyers', authenticateToken, async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator || creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Approved creator account required' });
    }

    const page  = Math.max(1, parseInt(req.query.page)  || 1);
    const limit = Math.min(50, parseInt(req.query.limit) || 20);
    const skip  = (page - 1) * limit;

    const creatorProducts = await CreatorProduct.find({ creatorId: creator._id })
      .select('productId title _id').lean();

    // Collect every possible ID form for this creator's products in one flat array.
    // Covers: mirrored Product._id, raw CreatorProduct._id, and String duplicates.
    const allProductIds = [
      ...creatorProducts.map(p => p.productId?.toString()).filter(Boolean),
      ...creatorProducts.map(p => p._id?.toString()).filter(Boolean),
    ];
    const productTitles = creatorProducts.map(p => p.title).filter(Boolean);

    if (!allProductIds.length && !productTitles.length) {
      return res.json({ success: true, buyers: [], total: 0 });
    }

    // Build an expanded $or covering items.id, items.productId, and title fallback.
    const buyersMatchStage = {
      status: 'completed',
      $or: [
        { 'items.id':        { $in: allProductIds } },
        { 'items.productId': { $in: allProductIds } },
        { 'items.title':     { $in: productTitles } },
      ]
    };

    // Aggregate unique buyers with purchase count and last purchase date
    const buyerAgg = await Order.aggregate([
      { $match: buyersMatchStage },
      // Unwind items so we can sum only the items that belong to this creator.
      { $unwind: '$items' },
      {
        $match: {
          $or: [
            { 'items.id':        { $in: allProductIds } },
            { 'items.productId': { $in: allProductIds } },
            { 'items.title':     { $in: productTitles } },
          ]
        }
      },
      {
        $group: {
          _id:           '$userId',
          purchaseCount: { $sum: 1 },
          totalSpent:    { $sum: '$items.price' },   // only this creator's items
          lastPurchase:  { $max: '$createdAt' },
          customerEmail: { $first: '$customerInfo.email' },
          customerName:  { $first: '$customerInfo.name' },
        }
      },
      { $sort: { lastPurchase: -1 } },
      { $skip: skip },
      { $limit: limit },
      {
        $lookup: {
          from:         'users',
          localField:   '_id',
          foreignField: '_id',
          as:           'user',
          pipeline: [{ $project: { fullName: 1, email: 1, profileImage: 1 } }],
        }
      },
      { $unwind: { path: '$user', preserveNullAndEmptyArrays: true } }
    ]);

    const totalAgg = await Order.aggregate([
      { $match: buyersMatchStage },
      { $group: { _id: '$userId' } },
      { $count: 'total' }
    ]);

    const total = totalAgg[0]?.total || 0;

    res.json({
      success: true,
      buyers: buyerAgg.map(b => ({
        userId:        b._id,
        fullName:      b.user?.fullName    || b.customerName  || 'Customer',
        email:         b.user?.email       || null,   // only expose when a registered account exists
        profileImage:  b.user?.profileImage || null,
        purchaseCount: b.purchaseCount,
        totalSpent:    parseFloat((b.totalSpent || 0).toFixed(2)),
        lastPurchase:  b.lastPurchase,
        isRepeat:      b.purchaseCount > 1,
      })),
      total,
      pagination: {
        page, limit, total,
        pages:   Math.ceil(total / limit),
        hasMore: skip + buyerAgg.length < total,
      }
    });
  } catch (error) {
    console.error('❌ GET /api/creator/buyers error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch buyers' });
  }
});

