// ── LIST ALL CREATOR APPLICATIONS ──────────────────────────────
app.get('/api/admin/creators', authenticateAdmin, async (req, res) => {
  try {
    const { status = 'all', page = 1, limit = 20 } = req.query;
    
    let query = {};
    if (status !== 'all') query.applicationStatus = status;

    const cacheKey = `creators:${status}:${page}:${limit}`;
    const cached = _getCachedCreators(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });

    const [creators, total] = await Promise.all([
      Creator.find(query)
        .populate('userId', 'fullName email phone country emailVerified lastLogin createdAt profileImage')
        .sort({ createdAt: -1 })
        .limit(parseInt(limit))
        .skip((parseInt(page) - 1) * parseInt(limit)),
      Creator.countDocuments(query)
    ]);

    const payload = { creators, pagination: { total, page: parseInt(page), limit: parseInt(limit) } };
    _setCachedCreators(cacheKey, payload);
    res.json({ success: true, ...payload, fromCache: false });

  } catch (error) {
    console.error('❌ Get creators error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch creators' });
  }
});


// ── APPROVE OR REJECT CREATOR APPLICATION ──────────────────────
app.put('/api/admin/creators/:creatorId/review', authenticateAdmin, async (req, res) => {
  try {
    const { action, rejectionReason, platformCommissionRate, affiliateCommissionRate } = req.body;
    
    if (!['approve', 'reject'].includes(action)) {
      return res.status(400).json({ success: false, message: 'Action must be approve or reject' });
    }

    const creator = await Creator.findById(req.params.creatorId)
      .populate('userId', 'fullName email');

    if (!creator) {
      return res.status(404).json({ success: false, message: 'Creator not found' });
    }

    if (creator.applicationStatus !== 'pending') {
      return res.status(400).json({ success: false, message: 'Application already reviewed' });
    }

    creator.applicationStatus = action === 'approve' ? 'approved' : 'rejected';
    creator.reviewedBy = req.adminUser._id;
    creator.reviewedAt = new Date();

    if (action === 'approve') {
      creator.approvedAt = new Date();
      // Admin can set custom commission rates or use defaults
      if (platformCommissionRate !== undefined) creator.platformCommissionRate = platformCommissionRate;
      if (affiliateCommissionRate !== undefined) creator.affiliateCommissionRate = affiliateCommissionRate;

      // Update user to have creator role
      await User.findByIdAndUpdate(creator.userId._id, { isCreator: true });

    } else {
      creator.rejectionReason = rejectionReason || 'Application did not meet our requirements';
    }

    await creator.save();
    // Sync commission rates to all creator products when approving
    if (action === 'approve') {
      try {
        await CreatorProduct.updateMany(
          { creatorId: creator._id },
          {
            $set: {
              platformCommission:  creator.platformCommissionRate,
              affiliateCommission: creator.affiliateCommissionRate,
            }
          }
        );
        console.log(`🔄 Commission rates synced to products for creator: ${creator.storeName}`);
      } catch (e) {
        console.error('⚠️  Commission sync to products failed (non-fatal):', e.message);
      }
    }
     if (status === 'approved' || status === 'rejected') {
          setImmediate(async () => {
            try {
              const notifType = status === 'approved' ? 'creator_approved' : 'creator_rejected';
              const notifTitle = status === 'approved'
                ? '🎉 Creator Application Approved!'
                : '❌ Creator Application Update';
              const notifMsg = status === 'approved'
                ? `Welcome to the marketplace! Your store "${creator.storeName}" is now live.`
                : `Your application was not approved. Reason: ${creator.rejectionReason || 'See admin notes'}`;
              await createNotification(
                creator.userId, 'creator', notifType, notifTitle, notifMsg,
                { url: '/marketplace/creator-dashboard.html' }
              );
            } catch (_) {}
          });
        }
    // Email notification to creator
    setImmediate(async () => {
      try {
        const user = creator.userId; // already populated: fullName, email
        if (!user?.email) return;

        if (action === 'approve') {
          await sendCreatorApplicationApprovedEmail(user.email, {
            fullName:               user.fullName,
            storeName:              creator.storeName,
            storeSlug:              creator.storeSlug,
            platformCommissionRate: creator.platformCommissionRate,
            affiliateCommissionRate: creator.affiliateCommissionRate
          });
        } else {
          await sendCreatorApplicationRejectedEmail(user.email, {
            fullName:        user.fullName,
            rejectionReason: creator.rejectionReason
          });
        }
      } catch (e) {
        console.error('⚠️ Creator review email failed:', e.message);
      }
    });

    console.log(`${action === 'approve' ? '✅' : '❌'} Creator ${action}d: ${creator.storeName}`);
    invalidateCreatorsCache();
    res.json({
      success: true,
      message: `Creator application ${action}d successfully`,
      creator: {
        id: creator._id,
        storeName: creator.storeName,
        applicationStatus: creator.applicationStatus,
        platformCommissionRate: creator.platformCommissionRate,
        affiliateCommissionRate: creator.affiliateCommissionRate
      }
    });

  } catch (error) {
    console.error('❌ Review creator error:', error);
    res.status(500).json({ success: false, message: 'Review failed' });
  }
});


