// GET /api/admin/creator-products/:id
app.get('/api/admin/creator-products/:id', authenticateAdmin, async (req, res) => {
  try {
    const product = await CreatorProduct.findById(req.params.id)
      .populate('creatorId', 'storeName userId applicationStatus platformCommissionRate affiliateCommissionRate totalSales totalRevenue createdAt')
      .lean();

    if (!product) {
      return res.status(404).json({ success: false, message: 'Product not found' });
    }

    // Attach creator user info (email, name) for admin context
    let creatorUser = null;
    if (product.creatorId?.userId) {
      creatorUser = await User.findById(product.creatorId.userId)
        .select('fullName email createdAt')
        .lean();
    }

    // Sales history for this specific product
    const orders = await Order.find({ productId: product._id })
      .select('amount status createdAt userId')
      .sort({ createdAt: -1 })
      .limit(10)
      .lean();

    // Enrich hosted file with admin-accessible download URL (direct Cloudinary URL,
    // not fl_attachment — avoids file corruption on raw resources).
    if (product.hostedFile?.publicId) {
      // secureUrl already stored from upload — use it directly.
      // For PDF/raw files: Cloudinary secureUrl is the raw bytes URL, safe to use.
      product.hostedFile._adminDownloadUrl = product.hostedFile.secureUrl || null;
    }

    // For course chapters, enrich embed URLs so the drawer can render them inline
    if (product.productType === 'course' && product.courseData?.sections) {
      const AUDIO_EMBED_TYPES = ['soundcloud','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer'];
      product.courseData.sections = product.courseData.sections.map(sec => ({
        ...sec,
        chapters: (sec.chapters || []).map(ch => {
          // Derive embedVideoUrl / embedAudioUrl if not stored
          const rawUrl = ch.externalUrl || ch.embedUrl || null;
          let embedVideoUrl = ch.embedVideoUrl || null;
          let embedAudioUrl = ch.embedAudioUrl || null;
          if (!embedVideoUrl && !embedAudioUrl && rawUrl && typeof parseExternalMediaUrl === 'function') {
            const parsed = parseExternalMediaUrl(rawUrl);
            if (parsed.embedType && parsed.embedType !== 'unknown') {
              if (AUDIO_EMBED_TYPES.includes(parsed.embedType)) {
                embedAudioUrl = parsed.embedUrl;
              } else {
                embedVideoUrl = parsed.embedUrl;
              }
            }
          }
          return {
            ...ch,
            embedVideoUrl: embedVideoUrl || ch.embedVideoUrl,
            embedAudioUrl: embedAudioUrl || ch.embedAudioUrl,
          };
        }),
      }));
    }

    res.json({
      success: true,
      product,
      creatorUser,
      recentOrders: orders,
    });

  } catch (error) {
    console.error('❌ Get creator product detail error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch product detail' });
  }
});
// ── ADMIN: APPROVE / REJECT CREATOR PRODUCT ────────────────────
app.put('/api/admin/creator-products/:productId/review', authenticateAdmin, async (req, res) => {
  try {
    const { action, approvedPrice, adminNotes, rejectionReason } = req.body;

    // ── 1. Validate action ────────────────────────────────────────────────────
    if (!['approve', 'reject'].includes(action)) {
      return res.status(400).json({ success: false, message: 'Action must be approve or reject' });
    }
    // ── 2. Load CreatorProduct (with creator populated) ───────────────────────
    const creatorProduct = await CreatorProduct.findById(req.params.productId)
      .populate('creatorId');

  if (!creatorProduct) {
      return res.status(404).json({ success: false, message: 'Product not found' });
    }

    // ── Resolve creator FIRST before any guard checks ─────────────────────
    const creator    = creatorProduct.creatorId;
    const finalPrice = parseFloat(approvedPrice ?? creatorProduct.suggestedPrice) || 0;
if (isNaN(finalPrice) || finalPrice < 0) {
  return res.status(400).json({ success: false, message: 'Invalid price. Provide a valid approvedPrice.' });
}
      
      if (!creator || typeof creator !== 'object' || !creator._id) {
      return res.status(400).json({
        success: false,
        message: 'Creator account not found. The creator may have been deleted. Cannot approve this product.'
      });
    }



    // ── 4. REJECT path ────────────────────────────────────────────────────────
    if (action === 'reject') {
      creatorProduct.status          = 'rejected';
      creatorProduct.rejectionReason = rejectionReason || 'Product did not meet our quality standards';
      creatorProduct.adminNotes      = adminNotes || '';
      await creatorProduct.save();

      console.log(`❌ Product rejected: ${creatorProduct.title}`);

      // Notify creator of rejection
      try {
        const creatorUser = await User.findById(creator.userId).select('fullName email');
        if (creatorUser?.email) {
          await sendProductRejectedEmail(creatorUser.email, {
            storeName:       creator.storeName,
            productTitle:    creatorProduct.title,
            productType:     creatorProduct.productType,
            rejectionReason: creatorProduct.rejectionReason
          });
        }
      } catch (emailErr) {
        console.error('⚠️ Product rejection email failed:', emailErr.message);
      }

      return res.json({ success: true, message: 'Product rejected', product: creatorProduct });
    }

      // ── 5. APPROVE path ───────────────────────────────────────────────────────
    // Non-course types must never mirror courseData to the live Product
    if (creatorProduct.productType !== 'course') {
      creatorProduct.courseData = undefined;
    }

    // ── Video product validation ───────────────────────────────────────────
    if (creatorProduct.productType === 'video') {
      const hasHostedVideo   = !!creatorProduct.hostedFile?.publicId;
      const hasExternalVideo = !!(creatorProduct.externalVideoUrl?.trim() || creatorProduct.embedUrl?.trim());
      if (!hasHostedVideo && !hasExternalVideo) {
        return res.status(400).json({
          success: false,
          message: 'Cannot approve a video product with no uploaded video file or external video URL.'
        });
      }
    }

    if (creatorProduct.productType === 'course') {
      const sections = creatorProduct.courseData?.sections || [];
      const sectionCount = sections.length;
      const chapterCount = sections.reduce((acc, s) => acc + (s.chapters?.length || 0), 0);
      const chaptersWithContent = sections.reduce((acc, s) =>
        acc + (s.chapters || []).filter(ch => ch.externalUrl || ch.embedUrl || ch.hostedFile?.publicId).length, 0
      );

      if (sectionCount === 0 || chapterCount === 0) {
        return res.status(400).json({
          success: false,
          message: 'Cannot approve a course with no sections or chapters. Ask the creator to build the course structure first.'
        });
      }

      if (chaptersWithContent === 0) {
        return res.status(400).json({
          success: false,
          message: `Course has ${chapterCount} chapter(s) but none have a video URL or uploaded file. Ask the creator to add content to their chapters.`
        });
      }

      // Normalise totals if missing
      if (!creatorProduct.courseData.totalSections) creatorProduct.courseData.totalSections = sectionCount;
      if (!creatorProduct.courseData.totalChapters) creatorProduct.courseData.totalChapters = chapterCount;
    }

    const platformCom  = creator.platformCommissionRate  || 20;
    const affiliateCom = creator.affiliateCommissionRate || 10;

    // Serialize courseData safely
    let processedCourseData = null;
    if (creatorProduct.productType === 'course' && creatorProduct.courseData) {
      try {
        // .toObject() correctly unwraps Mongoose subdocuments without circular refs.// toJSON() is safe on subdocuments — strips Mongoose internals cleanly
        const rawCourse = creatorProduct.courseData.toJSON
          ? creatorProduct.courseData.toJSON()
          : JSON.parse(JSON.stringify(creatorProduct.courseData));

        // Guarantee enum fields are valid before passing to Product schema
        if (rawCourse) {
          rawCourse.level = (['beginner','intermediate','advanced','all'].includes(rawCourse.level)
            ? rawCourse.level : 'all');
          rawCourse.language    = rawCourse.language    || 'English';
          rawCourse.certificate = rawCourse.certificate === true || rawCourse.certificate === 'true';
          if (!Array.isArray(rawCourse.sections)) rawCourse.sections = [];
        }

      processedCourseData = rawCourse ? processChaptersForDelivery(rawCourse) : null;
      } catch (e) {
        console.error('❌ courseData serialization failed:', e.message);
        return res.status(500).json({
          success: false,
          message: `Course data could not be processed: ${e.message}. Ask the creator to re-save the course structure and resubmit.`
        });
      }
    }
    // Resolve top-level embed fields (handles products submitted before
    // parseExternalMediaUrl was wired up)
    let resolvedEmbedUrl  = creatorProduct.embedUrl  || null;
    let resolvedEmbedType = creatorProduct.embedType || null;
    let resolvedMediaType = inferProductMediaType(creatorProduct);

    if (!resolvedEmbedUrl) {
      const rawUrl = creatorProduct.externalVideoUrl || creatorProduct.externalAudioUrl || null;
      if (rawUrl && typeof parseExternalMediaUrl === 'function') {
        const parsed = parseExternalMediaUrl(rawUrl);
        if (parsed.embedType && parsed.embedType !== 'unknown') {
          resolvedEmbedUrl  = parsed.embedUrl;
          resolvedEmbedType = parsed.embedType;
        }
      }
    }

    // Warn if hostedFile is missing publicId — delivery will fall back to downloadLink
    const hostedFile = creatorProduct.hostedFile || null;
    if (hostedFile && !hostedFile.publicId) {
      console.warn(`⚠️  Product "${creatorProduct.title}" has hostedFile without publicId — delivery will use downloadLink fallback`);
    }

    // ── 6. Mirror to main Product collection ──────────────────────────────────
    // Re-approval after rejection reuses the existing mirrored product if present
    let mainProduct = creatorProduct.productId
      ? await Product.findById(creatorProduct.productId)
      : null;

    const productFields = {
      title:            creatorProduct.title,
      description:      creatorProduct.description,
      category:         creatorProduct.category        || 'General',
      price:            finalPrice,
      icon:             '📦',
      image:            creatorProduct.images?.[0]     || '',
      images:           creatorProduct.images           || [],
      downloadLink:     creatorProduct.downloadLink     || null,
      fileSize:         creatorProduct.fileSize         || null,
      version:          creatorProduct.version          || null,
      features:         creatorProduct.features         || [],
      requirements:     creatorProduct.requirements     || [],
      tags:             creatorProduct.tags             || [],
      productType:      creatorProduct.productType      || 'download',
      hostedFile:       hostedFile?.publicId ? hostedFile : undefined,
      previewUrl:       creatorProduct.previewUrl       || null,
      previewType:      creatorProduct.previewType      || 'none',
      courseData:       (creatorProduct.productType === 'course')
                          ? (processedCourseData || null)
                          : undefined,
    notes:            creatorProduct.notes            || null,
      audioData:        creatorProduct.audioData        || null,
      softwareData:     creatorProduct.softwareData     || null,
      videoData:        creatorProduct.videoData        || null,
      externalVideoUrl: creatorProduct.externalVideoUrl || null,
      externalAudioUrl: creatorProduct.externalAudioUrl || null,
      embedType:        (!resolvedEmbedType  || resolvedEmbedType  === 'unknown') ? null : resolvedEmbedType,
      embedUrl:         resolvedEmbedUrl,
      mediaType:        (!resolvedMediaType  || resolvedMediaType  === 'unknown') ? null : resolvedMediaType,
      isActive:         true,
      creatorProductId: creatorProduct._id,
      creatorId:        creator._id,
      isCreatorProduct: true,
      isAdminProduct:   false,
    };

   // ── Sanitise productFields before save — prevent ValidationError 500s ────
    // category and description are required on the Product schema
    if (!productFields.category || typeof productFields.category !== 'string') {
      productFields.category = 'General';
    }
    if (!productFields.description || typeof productFields.description !== 'string') {
      productFields.description = creatorProduct.title || 'Creator product';
    }
    // null mediaType/embedType stored as the string "null" or "unknown" will
    // fail the enum check — coerce them to an actual null
    if (!productFields.mediaType  || productFields.mediaType  === 'unknown' || productFields.mediaType  === 'null')  productFields.mediaType  = null;
    if (!productFields.embedType  || productFields.embedType  === 'unknown' || productFields.embedType  === 'null')  productFields.embedType  = null;
    if (!productFields.previewType || !['video','audio','image','iframe','none'].includes(productFields.previewType)) productFields.previewType = 'none';

    // ── Save to Product collection ────────────────────────────────────────────
    try {
      if (mainProduct) {
        Object.assign(mainProduct, productFields);
        mainProduct.markModified('courseData');
        mainProduct.markModified('audioData');
        mainProduct.markModified('softwareData');
        mainProduct.markModified('videoData');
        await mainProduct.save();
        console.log(`🔄 Re-approved product updated: ${creatorProduct.title}`);
      } else {
        mainProduct = new Product(productFields);
        await mainProduct.save();
        console.log(`✅ Product approved & mirrored: ${creatorProduct.title}`);
      }
    } catch (saveErr) {
      // Surface the exact Mongoose validation error back to admin
      const detail = saveErr?.errors
        ? Object.values(saveErr.errors).map(e => e.message).join('; ')
        : saveErr.message;
      console.error('❌ Product mirror save failed:', detail);
      return res.status(500).json({
        success: false,
        message: `Product could not be saved to the store: ${detail}`
      });
    }

    // ── 7. Update CreatorProduct approval fields ──────────────────────────────
    creatorProduct.status                = 'approved';
    creatorProduct.approvedPrice         = finalPrice;
    creatorProduct.platformCommission    = platformCom;
    creatorProduct.affiliateCommission   = affiliateCom;
    creatorProduct.creatorEarningPerSale = finalPrice * (1 - platformCom / 100);
    creatorProduct.approvedAt            = new Date();
    creatorProduct.approvedBy            = req.adminUser._id;
    creatorProduct.adminNotes            = adminNotes || '';
    creatorProduct.productId             = mainProduct._id;
    creatorProduct.embedUrl              = resolvedEmbedUrl;
    creatorProduct.embedType             = (!resolvedEmbedType || resolvedEmbedType === 'unknown' || resolvedEmbedType === 'null') ? null : resolvedEmbedType;
    creatorProduct.mediaType             = (!resolvedMediaType || resolvedMediaType === 'unknown' || resolvedMediaType === 'null') ? null : resolvedMediaType;
    if (processedCourseData) {
      creatorProduct.courseData = processedCourseData;
      creatorProduct.markModified('courseData');
    }

    try {
      await creatorProduct.save();
    } catch (cpSaveErr) {
      const detail = cpSaveErr?.errors
        ? Object.values(cpSaveErr.errors).map(e => e.message).join('; ')
        : cpSaveErr.message;
      console.error('❌ CreatorProduct status update failed:', detail);
      // Product was already saved — log and continue, don't fail the whole request
      console.warn('⚠️  Product is live in store but CreatorProduct status may still show pending_review. Run sync-all to fix.');
    }
  setImmediate(async () => {
    try {
      const notifType  = creatorProduct.status === 'approved' ? 'product_approved' : 'product_rejected';
      const notifTitle = creatorProduct.status === 'approved' ? '✅ Product Approved' : '❌ Product Not Approved';
      const notifMsg   = creatorProduct.status === 'approved'
        ? `"${creatorProduct.title}" is now live on the marketplace.`
        : `"${creatorProduct.title}" was not approved. ${creatorProduct.rejectionReason || 'See admin notes.'}`;
      await createNotification(
        creator.userId, 'creator', notifType, notifTitle, notifMsg,
        { url: '/marketplace/creator-dashboard.html', productId: mainProduct._id }
      );
    } catch (notifErr) {
      console.error('⚠️ Approval notification failed:', notifErr.message);
    }
  });
    // ── 8. Notify creator of approval ─────────────────────────────────────────
  // ── 8. Respond to admin immediately, then notify creator in background ────
        await logProductAction(req, status === 'approved' ? 'product_approved' : 'product_rejected', creatorProduct);
    res.json({
      success: true,
      message: 'Product approved and mirrored to store successfully',
      product: creatorProduct,
      mainProductId: mainProduct._id
    });

    setImmediate(async () => {
      try {
        const creatorUser = await User.findById(creator.userId).select('fullName email');
        if (creatorUser?.email) {
          await sendProductApprovedEmail(creatorUser.email, {
            storeName:    creator.storeName,
            productTitle: creatorProduct.title,
            productType:  creatorProduct.productType,
            approvedPrice: finalPrice,
            productId:    mainProduct._id
          });
        }
      } catch (emailErr) {
        console.error('⚠️ Product approval email failed:', emailErr.message);
      }
    });

  } catch (error) {
    console.error('❌ Review product error:', error);
    res.status(500).json({ success: false, message: 'Review failed', error: error.message });
  }
});




