// AFFILIATE ENDPOINTS
// ═══════════════════════════════════════════════════════════════
app.post('/api/affiliate/register', authenticateToken, requireFeature('affiliatesEnabled'), async (req, res) => {
  try {
    // ── 0. Sanitize inputs (NoSQL injection guard) ───────────────────────────
    const rawCode = req.body.referredByCode;
    if (rawCode !== null && rawCode !== undefined && typeof rawCode !== 'string') {
      return res.status(400).json({ success: false, message: 'Invalid referral code format' });
    }

    // ── 1. Already registered? ───────────────────────────────────────────────
    const existing = await Affiliate.findOne({ userId: toObjectId(req.user.userId) });
    if (existing) {
      return res.status(400).json({
        success: false,
        message: `Already registered — your code is ${existing.affiliateCode}`
      });
    }

    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    // ── 2. Email-verified check — blocks disposable/unverified accounts ──────
    if (user.isEmailVerified === false) {
      return res.status(403).json({
        success: false,
        message: 'Please verify your email address before joining the affiliate program.'
      });
    }

    // ── 3. IP-based multi-account cap (max 2 affiliate accounts per IP) ──────
    const registrationIp = (req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.ip || '').slice(0, 45);
    if (registrationIp) {
      const sameIpCount = await Affiliate.countDocuments({ registrationIp });
      if (sameIpCount >= 2) {
        console.warn(`⚠️  Affiliate IP cap hit: ${registrationIp} already has ${sameIpCount} accounts`);
        return res.status(429).json({
          success: false,
          message: 'Maximum affiliate accounts from this network reached. Contact support if this is a mistake.'
        });
      }
    }

    // ── 4. Build unique affiliate code ────────────────────────────────────────
    const base = user.fullName.replace(/[^a-zA-Z0-9]/g, '').toUpperCase().substring(0, 6) || 'AFF';
    let affiliateCode = base + Math.random().toString(36).substring(2, 6).toUpperCase();
    if (await Affiliate.findOne({ affiliateCode })) {
      affiliateCode = base + Date.now().toString(36).toUpperCase().slice(-4);
    }

    // ── 5. Referral code validation (with self-referral guard) ────────────────
    const referredByCode = (typeof rawCode === 'string') ? rawCode.toUpperCase().trim() : null;
    let referredByAffiliate = null;
    if (referredByCode) {
      // Self-referral block
      const selfCheck = await Affiliate.findOne({ userId: toObjectId(req.user.userId) });
      if (selfCheck && selfCheck.affiliateCode === referredByCode) {
        return res.status(400).json({ success: false, message: 'You cannot refer yourself.' });
      }
      // Resolve the referrer (must be active, strip any non-alphanum to sanitize)
      const safeCode = referredByCode.replace(/[^A-Z0-9]/g, '');
      referredByAffiliate = await Affiliate.findOne({
        $or: [
          { affiliateCode: safeCode },
          { customSlug: safeCode.toLowerCase() }
        ],
        status: 'active'
      });
      if (referredByCode && !referredByAffiliate) {
        // Code was provided but invalid — reject rather than silently ignore
        return res.status(400).json({ success: false, message: 'Referral code not found or inactive.' });
      }
    }

    // ── 6. Create affiliate record ─────────────────────────────────────────────
    const affiliate = new Affiliate({
      userId:         req.user.userId,
      affiliateCode,
      status:         'active',
      tier:           'starter',
      referredBy:     referredByAffiliate?._id || null,
      cookieDays:     30,
      registrationIp: registrationIp || null,
    });
    await affiliate.save();
    // ── 7. Register referral & run 4-tier promotion check ────────────────────
    if (referredByAffiliate) {
      await Affiliate.findByIdAndUpdate(referredByAffiliate._id, {
        $addToSet: { referrals: affiliate._id },
        $inc:      { totalReferrals: 1 }
      });

      const freshReferrer = await Affiliate.findById(referredByAffiliate._id);
      if (freshReferrer) {
        const promoted = _checkAndPromoteAffiliateTier(freshReferrer);
        if (promoted) {
          await freshReferrer.save();
          console.log(`🏆 Affiliate ${freshReferrer.affiliateCode} promoted to ${freshReferrer.tier} (${freshReferrer.totalReferrals} referrals)`);
        }
      }
    }
 
    // Auto-create a storewide homepage link for them
    await AffiliateLink.create({
      affiliateId:     affiliate._id,
      affiliateCode,
      userId:          req.user.userId,
      isStorewideLink: true,
      url: `${global.FRONTEND_URL}/marketplace/?ref=${affiliateCode}`,
    });
 
    console.log(`🔗 New affiliate: ${user.fullName} — ${affiliateCode}`);

    // Send welcome email — fire-and-forget, never delays the HTTP response
    setImmediate(async () => {
      try {
        const welcomeHtml = _shell('🔗 Affiliate Program', `
          <h2 class="title">Welcome — you're in! 🎉</h2>
          <p>Hi <strong style="color:#00ff88;">${user.fullName}</strong>,</p>
          <p>Your affiliate account is active. Start sharing and earning immediately.</p>
          <div class="info-card">
            ${_row('Your Code',       `<strong style="color:#00ff88;font-family:monospace;font-size:18px;">${affiliateCode}</strong>`)}
            ${_row('Your Link',       `<a href="${global.FRONTEND_URL}/marketplace/?ref=${affiliateCode}" style="color:#00ff88;">${global.FRONTEND_URL}/marketplace/?ref=${affiliateCode}</a>`)}
            ${_row('Your Tier',        'Starter — build your referrals to unlock earnings')}
            ${_row('Earn Commission',   'Refer 10 people → Regular (5%) | 50 → Pro (7%) | 150 → Elite (10%)')}
            ${_row('Starter Rate',     '2% — unlocks after your 10th confirmed referral')}
            ${_row('Payout Threshold', '$20 minimum')}
          </div>
          ${_alert('💡 Tip: Generate per-product links from your dashboard for higher conversion rates.')}
          ${_btn(`${global.FRONTEND_URL}/marketplace/affiliate`, '📊 Open My Affiliate Dashboard')}
          <p>Happy promoting!<br><strong style="color:#00ff88;">The UYEH TECH Team</strong></p>
        `);
        await _sendEmail(
          user.email,
          '🔗 Welcome to the UYEH TECH Affiliate Program!',
          welcomeHtml,
          'affiliate-welcome'
        );
      } catch (_) {}
    });

    res.status(201).json({
      success: true,
      message: 'Welcome to the UYEH TECH Affiliate Program!',
      affiliate: {
        affiliateCode,
        tier: 'starter',
        affiliateLink: `${global.FRONTEND_URL}/marketplace/?ref=${affiliateCode}`,
        cookieDays: 30,
      }
    });
 
  } catch (err) {
    console.error('❌ Affiliate register error:', err);
    res.status(500).json({ success: false, message: 'Registration failed' });
  }
});
 
 
// ── C2. DASHBOARD ─────────────────────────────────────────────────────────────
app.get('/api/affiliate/dashboard', authenticateToken, requireFeature('affiliatesEnabled'), async (req, res) => {
  try {
    const affiliate = await Affiliate.findOne({ userId: toObjectId(req.user.userId) });
    if (!affiliate) {
      return res.status(404).json({ success: false, message: 'Affiliate account not found' });
    }
 
    const uid = new mongoose.Types.ObjectId(req.user.userId);
 
    const [earningsAgg, myLinks, recentEvents, payoutHistory, topLinks] = await Promise.all([
 
      // Earnings breakdown by status
      EarningsLedger.aggregate([
        { $match: { recipientId: uid, recipientType: 'affiliate' } },
        { $group: { _id: '$status', total: { $sum: '$earningAmount' }, count: { $sum: 1 } } }
      ]),
 
      // All active product links this affiliate has created
      AffiliateLink.find({ affiliateId: affiliate._id, isActive: true })
        .populate('productId', 'title price category image productType')
        .populate('creatorProductId', 'title approvedPrice affiliateCommission image')
        .sort({ createdAt: -1 })
        .limit(50),
 
      // Recent funnel events
      AffiliateEvent.find({ affiliateId: affiliate._id })
        .sort({ createdAt: -1 })
        .limit(30),
 
      // Payout history
      PayoutRequest.find({ requesterId: uid, requesterType: 'affiliate' })
        .sort({ requestedAt: -1 }).limit(10),
 
      // Top 5 links by earnings
      AffiliateLink.find({ affiliateId: affiliate._id })
        .sort({ earnings: -1 })
        .limit(5),
    ]);
 
    // Map earnings
    const em = {};
    earningsAgg.forEach(e => { em[e._id] = { total: e.total, count: e.count }; });
 
    // Build available products list — creator products with confirmed mirror only.
    // productId must exist (mirror step completed) and creatorId must exist.
    // Admin products never appear here — this query only touches CreatorProduct.
    const availableProducts = await CreatorProduct.find({
      status:    'approved',
      productId: { $exists: true, $ne: null }, // mirror must be complete
      creatorId: { $exists: true, $ne: null }  // creator must be attached
    })
      .populate('productId', 'title price category productType image icon isActive')
      .populate('creatorId', 'storeName storeSlug storeLogo')
      .sort({ totalSales: -1 })
      .limit(100);
 
    // Tier progress — 4-tier ladder
    const tierProgress = _buildTierProgress(affiliate);
 
    // 30-day click/conversion trend (group by day)
    const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
    const dailyTrend = await AffiliateEvent.aggregate([
      { $match: { affiliateId: affiliate._id, createdAt: { $gte: thirtyDaysAgo } } },
      { $group: {
        _id: { $dateToString: { format: '%Y-%m-%d', date: '$createdAt' } },
        clicks:      { $sum: { $cond: [{ $eq: ['$eventType', 'click'] }, 1, 0] } },
        conversions: { $sum: { $cond: [{ $eq: ['$converted', true] }, 1, 0] } },
      }},
      { $sort: { _id: 1 } }
    ]);
 
    res.json({
      success: true,
 
      affiliate: {
        affiliateCode:    affiliate.affiliateCode,
        customSlug:       affiliate.customSlug,
        // Product/shopping link — earns commissions on purchases
        affiliateLink:    `${global.FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`,
        vanityLink:       affiliate.customSlug ? `${global.FRONTEND_URL}/ref/${affiliate.customSlug}` : null,
        // Invite/signup link — counts toward referral total & tier progression
        // Frontend must read localStorage('uyeh_ref') at signup time and send it as `ref` in the body
        inviteLink:       `${global.FRONTEND_URL}/marketplace/signup?ref=${affiliate.affiliateCode}`,
        vanityInviteLink: affiliate.customSlug
          ? `${global.FRONTEND_URL}/marketplace/signup?ref=${affiliate.customSlug}`
          : null,
        status:           affiliate.status,
        tier:             affiliate.tier || 'starter',
        commissionRate:   AFFILIATE_COMMISSION_RATE[affiliate.tier || 'starter'],
        earningsLocked:   (affiliate.tier === 'starter') && (affiliate.totalReferrals || 0) < AFFILIATE_MIN_REFERRALS_TO_EARN,
        referralsToUnlock: Math.max(0, AFFILIATE_MIN_REFERRALS_TO_EARN - (affiliate.totalReferrals || 0)),
        tierProgress,
        totalClicks:        affiliate.totalClicks,
        totalConversions:   affiliate.totalConversions,
        totalEarnings:      affiliate.totalEarnings,
        pendingEarnings:    affiliate.pendingEarnings,
        paidEarnings:       affiliate.paidEarnings,
        totalReferrals:     affiliate.totalReferrals   || 0,
        referralCount:      affiliate.totalReferrals   || 0, // alias for frontend
        cookieDays:         affiliate.cookieDays       || 30,
        commissionOverride: affiliate.commissionOverride,
        conversionRate:     affiliate.totalClicks > 0
          ? ((affiliate.totalConversions / affiliate.totalClicks) * 100).toFixed(1) + '%'
          : '0%',
        payoutMethod:    affiliate.payoutMethod  || null,
        payoutDetails:   affiliate.payoutDetails || null,
        payoutThreshold: affiliate.payoutThreshold || 20,
        bestProduct: affiliate.bestProductTitle ? {
          productId: affiliate.bestProductId,
          title:     affiliate.bestProductTitle,
          revenue:   affiliate.bestProductRevenue,
        } : null,
      },
 
      earnings: {
        pending:   em['pending']?.total   || 0,
        confirmed: em['confirmed']?.total || 0,
        paid:      em['paid']?.total      || 0,
        total:     affiliate.totalEarnings,
      },
 
      myLinks: myLinks.map(l => ({
        _id:         l._id,
        url:         l.url,
        campaign:    l.campaign,
        productId:   l.productId?._id || null,
        title:       l.productId?.title || l.creatorProductId?.title || 'Storewide Link',
        price:       l.productId?.price || l.creatorProductId?.approvedPrice || 0,
        image:       l.productId?.image || null,
        commission:  l.creatorProductId?.affiliateCommission || 10,
        clicks:      l.clicks,
        uniqueClicks:l.uniqueClicks,
        conversions: l.conversions,
        revenue:     l.revenue,
        earnings:    l.earnings,
        isStorewideLink: l.isStorewideLink,
      })),
 
      topLinks,
      recentEvents,
      payoutHistory,
      dailyTrend,
 
      // All promotable products
      availableProducts: availableProducts
        // Final safety filter: exclude if mirrored product is inactive
        .filter(p => p.productId?.isActive !== false)
        .map(p => {
        // Commission rate = affiliate's direct % of the creator pool (80% of sale)
        const tierRate      = AFFILIATE_COMMISSION_RATE[affiliate.tier || 'starter'];
        const commissionRate = Math.min(
          AFFILIATE_COMMISSION_CAP,
          p.affiliateCommission ?? tierRate
        );
        const price       = p.approvedPrice || p.productId?.price || 0;
        const creatorPool = parseFloat((price * 0.80).toFixed(2));
        const youEarn     = parseFloat((creatorPool * commissionRate / 100).toFixed(2));
        return {
          productId:        p.productId?._id || null,
          creatorProductId: p._id,
          title:            p.title || p.productId?.title || 'Untitled',
          price,
          category:         p.productId?.category   || null,
          productType:      p.productId?.productType || null,
          image:            p.image || p.productId?.image || null,
          icon:             p.icon  || p.productId?.icon  || null,
          commissionRate,
          commissionAmount: youEarn,
          commissionBreakdown: {
            salePrice:    price,
            platformCut:  parseFloat((price * 0.20).toFixed(2)),
            creatorPool,
            yourRate:     commissionRate,
            youEarn,
          },
          storeSlug:        p.creatorId?.storeSlug || null,
          storeName:        p.creatorId?.storeName || null,
          storeLogo:        p.creatorId?.storeLogo || null,
          totalSales:       p.totalSales || 0,
          affiliateLink: p.creatorId?.storeSlug
           ? `${global.FRONTEND_URL}/marketplace/${p.creatorId.storeSlug}/${p.productId?._id}/?ref=${affiliate.affiliateCode}`
            : `${global.FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`,
        };
      }),
    });
 
  } catch (err) {
    console.error('❌ Affiliate dashboard error:', err);
    res.status(500).json({ success: false, message: 'Failed to load dashboard' });
  }
});
 
 
// ── C3. GENERATE A PRODUCT LINK ───────────────────────────────────────────────
// Affiliate calls this to create a tracked link for a specific product.
// Returns a shortlink they can copy and share anywhere.
app.post('/api/affiliate/links/generate', authenticateToken, requireFeature('affiliatesEnabled'), async (req, res) => {
  try {
    const { productId, campaign, utm_source, utm_medium } = req.body;
 
    const affiliate = await Affiliate.findOne({ userId: toObjectId(req.user.userId), status: 'active' });
    if (!affiliate) return res.status(403).json({ success: false, message: 'Active affiliate account required' });
 
    let creatorProduct = null;
    let productDoc     = null;
    let url            = '';
 
    if (productId) {
      creatorProduct = await CreatorProduct.findOne({
        $or: [{ productId: toObjectId(productId) }, { _id: toObjectId(productId) }],
        status: 'approved'
      }).populate('productId', 'title price').populate('creatorId', 'storeSlug storeName');
 
      if (!creatorProduct) {
        return res.status(404).json({ success: false, message: 'Product not found or not approved' });
      }
 
      productDoc = creatorProduct.productId;
      url = creatorProduct.creatorId?.storeSlug
       ? `${global.FRONTEND_URL}/marketplace/${creatorProduct.creatorId.storeSlug}/${productDoc._id}/?ref=${affiliate.affiliateCode}`
        : `${global.FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`;
      url = `${global.FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`;
 
    } else {
      // Storewide link
      url = `${global.FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`;
    }
 
    // Append campaign UTM if provided
    if (campaign) {
      url += `&utm_campaign=${encodeURIComponent(campaign)}`;
    }
    if (utm_source) url += `&utm_source=${encodeURIComponent(utm_source)}`;
    if (utm_medium) url += `&utm_medium=${encodeURIComponent(utm_medium)}`;
 
    // Check if link for this product+campaign already exists
    const existingQuery = {
      affiliateId: affiliate._id,
      campaign:    campaign || null,
      ...(productId ? { productId: toObjectId(productId) } : { isStorewideLink: true })
    };
    let link = await AffiliateLink.findOne(existingQuery);
 
    if (!link) {
      link = await AffiliateLink.create({
        affiliateId:      affiliate._id,
        affiliateCode:    affiliate.affiliateCode,
        userId:           req.user.userId,
        productId:        productDoc?._id || null,
        creatorProductId: creatorProduct?._id || null,
        isStorewideLink:  !productId,
        url,
        campaign:   campaign   || null,
        utm_source: utm_source || null,
        utm_medium: utm_medium || null,
      });
    }
 
    const tierRate       = AFFILIATE_COMMISSION_RATE[affiliate.tier || 'starter'];
    const commissionRate = Math.min(
      AFFILIATE_COMMISSION_CAP,
      creatorProduct?.affiliateCommission ?? tierRate
    );
    const price       = productDoc?.price || creatorProduct?.approvedPrice || 0;
    const creatorPool = parseFloat((price * 0.80).toFixed(2));
    const youEarn     = parseFloat((creatorPool * commissionRate / 100).toFixed(2));

    res.status(201).json({
      success:  true,
      message:  'Affiliate link ready',
      link: {
        _id:          link._id,
        url:          link.url,
        productTitle: productDoc?.title || 'Storewide',
        tier:         affiliate.tier || 'starter',
        price,
        commissionRate,
        commissionAmount: youEarn,
        commissionBreakdown: {
          salePrice:   price,
          platformCut: parseFloat((price * 0.20).toFixed(2)),
          creatorPool,
          yourRate:    commissionRate,
          youEarn,
        },
        campaign,
        clicks:      link.clicks,
        conversions: link.conversions,
        earnings:    link.earnings,
      }
    });
 
  } catch (err) {
    console.error('❌ Generate link error:', err);
    res.status(500).json({ success: false, message: 'Failed to generate link' });
  }
});
 
 
