// ── C5. TRACK A CLICK (called by frontend on page load when ?ref= is present) ─
app.post('/api/affiliate/track-click', affiliateClickLimiter, async (req, res) => {
  try {
    const { affiliateCode, productId, eventType = 'click', sessionToken, campaign, utm_source, utm_medium } = req.body;
    if (!affiliateCode) return res.json({ success: false });
 
    const affiliate = await Affiliate.findOne({
      $or: [
        { affiliateCode: affiliateCode.toUpperCase() },
        { customSlug: affiliateCode.toLowerCase() }
      ],
      status: 'active'
    });
 
    if (!affiliate) return res.json({ success: false, message: 'Invalid code' });
 
    const vHash  = visitorHash(req);
    const ip     = req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.ip;
 
    // Unique-click detection: has this visitor clicked this code in the last 24h?
    const recentClick = await AffiliateEvent.findOne({
      affiliateCode: affiliate.affiliateCode,
      visitorHash:   vHash,
      eventType:     'click',
      createdAt:     { $gte: new Date(Date.now() - 24 * 60 * 60 * 1000) }
    });
    const isUnique = !recentClick;
 
    // ── Guard: productId must belong to a creator product ──────────────────
    // Admin products are not part of the affiliate program. If the productId
    // resolves to a non-creator product, reject the click silently.
    if (productId) {
      const isCreatorProd = await Product.findById(productId)
        .select('isCreatorProduct isAdminProduct').lean();

      // Also check via CreatorProduct directly (handles CP._id being passed)
      const isDirectCP = !isCreatorProd
        ? await CreatorProduct.exists({ _id: toObjectId(productId), status: 'approved' })
        : null;

      const confirmed = (isCreatorProd?.isCreatorProduct === true && isCreatorProd?.isAdminProduct === false)
        || !!isDirectCP;

      if (!confirmed) {
        console.log(`ℹ️  track-click: productId "${productId}" is not a creator product — ignored`);
        return res.json({ success: true, affiliateCode: affiliate.affiliateCode, cookieDays: affiliate.cookieDays || 30, isUnique: false });
      }
    }

    // Resolve which product link this belongs to
    let linkDoc = null;
    if (productId) {
      linkDoc = await AffiliateLink.findOne({
        affiliateId: affiliate._id,
        productId:   toObjectId(productId)
      });
    } else {
      linkDoc = await AffiliateLink.findOne({ affiliateId: affiliate._id, isStorewideLink: true });
    }
 
    // Record the event
    await AffiliateEvent.create({
      affiliateId:     affiliate._id,
      affiliateLinkId: linkDoc?._id || null,
      affiliateCode:   affiliate.affiliateCode,
      eventType:       eventType || 'click',
      productId:       productId ? toObjectId(productId) : null,
      visitorHash:     vHash,
      ipAddress:       ip,
      userAgent:       req.headers['user-agent'],
      referrer:        req.headers.referer || null,
      isUnique,
      sessionToken:    sessionToken || null,
      campaign:        campaign    || linkDoc?.campaign    || null,
      utm_source:      utm_source  || linkDoc?.utm_source  || null,
      utm_medium:      utm_medium  || linkDoc?.utm_medium  || null,
    });
 
    // Update counters
    await Affiliate.findByIdAndUpdate(affiliate._id, {
      $inc: {
        totalClicks:                        1,
        ...(isUnique ? { uniqueClicks: 1 } : {}) // uniqueClicks field — add to schema if not present
      }
    });
 
    if (linkDoc) {
      await AffiliateLink.findByIdAndUpdate(linkDoc._id, {
        $inc: {
          clicks:      1,
          ...(isUnique ? { uniqueClicks: 1 } : {})
        }
      });
    }
 
    res.json({
      success:      true,
      affiliateCode: affiliate.affiliateCode,
      cookieDays:   affiliate.cookieDays || 30,
      isUnique,
    });
 
  } catch (err) {
    console.error('❌ Track click error:', err.message);
    res.json({ success: false });
  }
});
 
 
// ── C6. TRACK FUNNEL EVENT (add-to-cart, checkout-start — called by frontend) ─
app.post('/api/affiliate/track-event', affiliateClickLimiter, async (req, res) => {
  try {
    const { affiliateCode, eventType, productId, sessionToken } = req.body;
    if (!affiliateCode || !eventType) return res.json({ success: false });
 
    const allowed = ['view', 'add_to_cart', 'checkout_start'];
    if (!allowed.includes(eventType)) return res.json({ success: false, message: 'Unknown event type' });
 
    const affiliate = await Affiliate.findOne({ affiliateCode: affiliateCode.toUpperCase(), status: 'active' });
    if (!affiliate) return res.json({ success: false });
 
    // ── Guard: if a productId is supplied, only record event for creator products ──
    let resolvedProductId = null;
    if (productId) {
      const isCreatorProd = await Product.findById(productId)
        .select('isCreatorProduct isAdminProduct').lean();
      const isDirectCP = !isCreatorProd
        ? await CreatorProduct.exists({ _id: toObjectId(productId), status: 'approved' })
        : null;
      const confirmed = (isCreatorProd?.isCreatorProduct === true && isCreatorProd?.isAdminProduct === false)
        || !!isDirectCP;

      if (!confirmed) {
        // Admin product in the event — don't record, don't pollute funnel
        console.log(`ℹ️  track-event (${eventType}): productId "${productId}" is not a creator product — ignored`);
        return res.json({ success: true });
      }
      resolvedProductId = toObjectId(productId);
    }

    await AffiliateEvent.create({
      affiliateId:   affiliate._id,
      affiliateCode: affiliate.affiliateCode,
      eventType,
      productId:     resolvedProductId,
      visitorHash:   visitorHash(req),
      ipAddress:     req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.ip,
      userAgent:     req.headers['user-agent'],
      referrer:      req.headers.referer || null,
      sessionToken:  sessionToken || null,
    });
 
    res.json({ success: true });
  } catch (err) {
    res.json({ success: false });
  }
});
 
// ── C7. SET CUSTOM SLUG (vanity link: /ref/myname) ───────────────────────────
app.put('/api/affiliate/slug', authenticateToken, requireFeature('affiliatesEnabled'), async (req, res) => {
  try {
    const { slug } = req.body;
    if (!slug || slug.length < 3 || slug.length > 30) {
      return res.status(400).json({ success: false, message: 'Slug must be 3–30 characters' });
    }
    const clean = slug.toLowerCase().replace(/[^a-z0-9-_]/g, '');
    if (clean !== slug.toLowerCase()) {
      return res.status(400).json({ success: false, message: 'Only letters, numbers, hyphens and underscores allowed' });
    }
 
    const taken = await Affiliate.findOne({ customSlug: clean });
    if (taken) return res.status(409).json({ success: false, message: 'Slug already taken' });
 
    const affiliate = await Affiliate.findOne({ userId: toObjectId(req.user.userId) });
    if (!affiliate) return res.status(404).json({ success: false, message: 'Not registered' });
 
    affiliate.customSlug = clean;
    await affiliate.save();
 
    res.json({
      success: true,
      message: 'Custom slug set',
      vanityLink: `${global.FRONTEND_URL}/ref/${clean}`,
    });
  } catch (err) {
    res.status(500).json({ success: false, message: 'Failed to set slug' });
  }
});
 
 
