// ── C10. ANALYTICS — DETAILED STATS ──────────────────────────────────────────
app.get('/api/affiliate/analytics', authenticateToken, requireFeature('affiliatesEnabled'), async (req, res) => {
  try {
    const { period = '30d' } = req.query;
    const periodMap = { '7d': 7, '30d': 30, '90d': 90, 'all': 3650 };
    const days      = periodMap[period] || 30;
    const since     = new Date(Date.now() - days * 24 * 60 * 60 * 1000);
 
    const affiliate = await Affiliate.findOne({ userId: toObjectId(req.user.userId) });
    if (!affiliate) return res.status(404).json({ success: false, message: 'Not registered' });
 
    const [
      funnelStats,
      topProducts,
      dailyBreakdown,
      earningsByProduct,
      subAffiliateStats,
    ] = await Promise.all([
 
      // Full funnel counts
      AffiliateEvent.aggregate([
        { $match: { affiliateId: affiliate._id, createdAt: { $gte: since } } },
        { $group: {
          _id:         '$eventType',
          count:       { $sum: 1 },
          unique:      { $sum: { $cond: ['$isUnique', 1, 0] } },
          conversions: { $sum: { $cond: ['$converted', 1, 0] } },
        }},
        { $sort: { _id: 1 } }
      ]),
 
      // Top 10 products by earnings
      AffiliateLink.find({ affiliateId: affiliate._id, earnings: { $gt: 0 } })
        .populate('productId', 'title image category')
        .sort({ earnings: -1 })
        .limit(10),
 
      // Daily click+conversion trend
      AffiliateEvent.aggregate([
        { $match: { affiliateId: affiliate._id, createdAt: { $gte: since } } },
        { $group: {
          _id: { $dateToString: { format: '%Y-%m-%d', date: '$createdAt' } },
          clicks:      { $sum: { $cond: [{ $eq: ['$eventType', 'click'] }, 1, 0] } },
          uClicks:     { $sum: { $cond: [{ $and: [{ $eq: ['$eventType', 'click'] }, '$isUnique'] }, 1, 0] } },
          conversions: { $sum: { $cond: ['$converted', 1, 0] } },
        }},
        { $sort: { _id: 1 } }
      ]),
 
      // Earnings per product
      EarningsLedger.aggregate([
        { $match: { recipientId: new mongoose.Types.ObjectId(req.user.userId), recipientType: 'affiliate', createdAt: { $gte: since } } },
        { $group: { _id: '$productId', total: { $sum: '$earningAmount' }, count: { $sum: 1 } } },
        { $sort: { total: -1 } },
        { $limit: 10 },
      ]),
 
      // (sub-affiliate system removed — replaced by referral-count tier ladder)
      Promise.resolve([]),
    ]);
 
    // Build funnel map
    const funnel = {};
    funnelStats.forEach(f => { funnel[f._id] = f; });
 
    const clickCount      = funnel['click']?.count       || 0;
    const uniqueClicks    = funnel['click']?.unique       || 0;
    const atcCount        = funnel['add_to_cart']?.count  || 0;
    const purchaseCount   = funnel['purchase']?.conversions || affiliate.totalConversions;
 
    res.json({
      success: true,
      period,
      since,
      funnel: {
        clicks:         clickCount,
        uniqueClicks,
        addToCart:      atcCount,
        checkoutStart:  funnel['checkout_start']?.count || 0,
        purchases:      purchaseCount,
        clickToCart:    clickCount   > 0 ? ((atcCount      / clickCount)    * 100).toFixed(1) + '%' : '0%',
        cartToPurchase: atcCount     > 0 ? ((purchaseCount / atcCount)      * 100).toFixed(1) + '%' : '0%',
        overallCvr:     clickCount   > 0 ? ((purchaseCount / clickCount)    * 100).toFixed(1) + '%' : '0%',
      },
      topProducts,
      dailyBreakdown,
      earningsByProduct,
      tier: _buildTierProgress(affiliate),
    });
 
  } catch (err) {
    console.error('❌ Affiliate analytics error:', err);
    res.status(500).json({ success: false, message: 'Analytics failed' });
  }
});
 
// GET /api/affiliate/referrals  — users who signed up via this affiliate's link
// GET /api/affiliate/referrals  — users who signed up via this affiliate's invite link
// These are the referrals that count toward tier progression.
app.get('/api/affiliate/referrals', authenticateToken, requireFeature('affiliatesEnabled'), async (req, res) => {
  try {
    const affiliate = await Affiliate.findOne({ userId: req.user.userId, status: 'active' }).lean();
    if (!affiliate) return res.status(404).json({ success: false, message: 'Affiliate account not found' });

    const { page = 1, limit = 20 } = req.query;
    const pg   = Math.max(1, parseInt(page)  || 1);
    const lim  = Math.min(50, parseInt(limit) || 20);
    const skip = (pg - 1) * lim;

    // Find users who signed up through this affiliate's invite link
    const [users, total] = await Promise.all([
      User.find({ referredByAffiliateCode: affiliate.affiliateCode })
        .select('fullName createdAt country') // never expose email to affiliates
        .sort({ createdAt: -1 })
        .skip(skip)
        .limit(lim)
        .lean(),
      User.countDocuments({ referredByAffiliateCode: affiliate.affiliateCode }),
    ]);

    // Tier progress snapshot
    const tierInfo = _buildTierProgress(affiliate);

    res.json({
      success:  true,
      total,
      page:     pg,
      pages:    Math.ceil(total / lim),
      // What counts toward tier promotion
      tierProgress: tierInfo,
      referrals: users.map(u => ({
        joinedAt: u.createdAt,
        country:  u.country || '—',
        // fullName is first-name only for privacy (affiliates don't need to know who exactly)
        firstName: u.fullName?.split(' ')[0] || 'Member',
      })),
    });
  } catch (err) {
    console.error('❌ GET /api/affiliate/referrals error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch referrals' });
  }
});

// ── C11. EARNINGS LEDGER ──────────────────────────────────────────────────────
app.get('/api/affiliate/earnings', authenticateToken, async (req, res) => {
  try {
    const { page = 1, limit = 50, status } = req.query;
    const filter = {
      recipientId:   toObjectId(req.user.userId),
      recipientType: 'affiliate',
      ...(status ? { status } : {}),
    };
    const [ledger, total] = await Promise.all([
      EarningsLedger.find(filter)
        .sort({ createdAt: -1 })
        .skip((parseInt(page) - 1) * parseInt(limit))
        .limit(parseInt(limit))
        .populate('orderId',   'orderReference createdAt')
        .populate('productId', 'title price'),
      EarningsLedger.countDocuments(filter),
    ]);
 
    res.json({
      success: true,
      total,
      page: parseInt(page),
      pages: Math.ceil(total / parseInt(limit)),
      ledger: ledger.map(e => ({
        _id:            e._id,
        createdAt:      e.createdAt,
        status:         e.status,
        earningAmount:  e.earningAmount,
        commissionRate: e.commissionRate,
        saleAmount:     e.saleAmount,
        productTitle:   e.productId?.title || '—',
        orderRef:       e.orderId?.orderReference || '—',
        description:    e.description,
      }))
    });
  } catch (err) {
    res.status(500).json({ success: false, message: 'Failed to fetch earnings' });
  }
});
 
 
// ── C12. REQUEST PAYOUT ───────────────────────────────────────────────────────
app.post('/api/affiliate/payout/request', authenticateToken, async (req, res) => {
  try {
    const { payoutMethod, payoutDetails } = req.body;
    const affiliate = await Affiliate.findOne({ userId: toObjectId(req.user.userId) });
    if (!affiliate || affiliate.status !== 'active') {
      return res.status(403).json({ success: false, message: 'Active affiliate account required' });
    }
 
    const result = await EarningsLedger.aggregate([
      { $match: { recipientId: new mongoose.Types.ObjectId(req.user.userId), recipientType: 'affiliate', status: 'confirmed' } },
      { $group: { _id: null, total: { $sum: '$earningAmount' } } }
    ]);
    const available = result[0]?.total || 0;
 
    if (available < (affiliate.payoutThreshold || 20)) {
      return res.status(400).json({
        success: false,
        message: `Minimum payout is $${affiliate.payoutThreshold || 20}. Available: $${available.toFixed(2)}`
      });
    }
 
    // Block duplicate pending payout
    const pendingPayout = await PayoutRequest.findOne({
      requesterId: toObjectId(req.user.userId),
      requesterType: 'affiliate',
      status: 'pending'
    });
    if (pendingPayout) {
      return res.status(400).json({ success: false, message: 'You already have a pending payout request' });
    }
 
    const payout = await PayoutRequest.create({
      requesterId:   toObjectId(req.user.userId),
      requesterType: 'affiliate',
      amount:        available,
      payoutMethod:  payoutMethod || affiliate.payoutMethod,
      payoutDetails: payoutDetails || affiliate.payoutDetails,
    });
 
    await EarningsLedger.updateMany(
      { recipientId: toObjectId(req.user.userId), recipientType: 'affiliate', status: 'confirmed' },
      { status: 'pending', payoutRequestId: payout._id }
    );
 
    // Save payout details to affiliate profile
    if (payoutMethod)  { affiliate.payoutMethod  = payoutMethod; }
    if (payoutDetails) { affiliate.payoutDetails = payoutDetails; }
    await affiliate.save();
    await logAffiliateAction(req, 'affiliate_payout_requested', affiliate, { amount: available });
    res.json({
      success: true,
      message: `Payout of $${available.toFixed(2)} requested. Processing in 3–5 business days.`,
      payoutId: payout._id,
    });
  } catch (err) {
    console.error('❌ Affiliate payout error:', err);
    res.status(500).json({ success: false, message: 'Payout request failed' });
  }
});
 
 
