// ── C15. PUBLIC VANITY REDIRECT — GET /ref/:slug ──────────────────────────────
// Put this BEFORE any catch-all route in your server.
// Redirects /ref/john → /marketplace?ref=JOHN1234 and tracks the click.
app.get('/ref/:slug', async (req, res) => {
  try {
    const slug = req.params.slug?.toLowerCase();
    const affiliate = await Affiliate.findOne({
      $or: [
        { customSlug: slug },
        { affiliateCode: slug.toUpperCase() }
      ],
      status: 'active'
    });
 
    if (!affiliate) {
      return res.redirect(`${global.FRONTEND_URL}/marketplace/`);
    }
 
    // Fire-and-forget click track
    setImmediate(async () => {
      try {
        const vHash = visitorHash(req);
        const recentClick = await AffiliateEvent.findOne({
          affiliateId: affiliate._id, visitorHash: vHash, eventType: 'click',
          createdAt: { $gte: new Date(Date.now() - 24 * 60 * 60 * 1000) }
        });
        await AffiliateEvent.create({
          affiliateId:   affiliate._id,
          affiliateCode: affiliate.affiliateCode,
          eventType:     'click',
          visitorHash:   vHash,
          ipAddress:     req.headers['x-forwarded-for']?.split(',')[0]?.trim() || req.ip,
          userAgent:     req.headers['user-agent'],
          referrer:      req.headers.referer || null,
          isUnique:      !recentClick,
        });
        await Affiliate.findByIdAndUpdate(affiliate._id, { $inc: { totalClicks: 1 } });
      } catch (e) { /* silent */ }
    });
 
    const dest = `${global.FRONTEND_URL}/marketplace/?ref=${affiliate.affiliateCode}`;
    res.redirect(302, dest);
  } catch (err) {
    res.redirect(`${global.FRONTEND_URL}/marketplace/`);
  }
});
 
 // GET /api/wishlist  — fetch user wishlist with product details
app.get('/api/wishlist', authenticateToken, async (req, res) => {
  try {
    const items = await Wishlist.find({ userId: req.user.userId }).sort({ addedAt: -1 }).lean();
    if (!items.length) return res.json({ success: true, wishlist: [], count: 0 });
 
    // Enrich each item with product info
    const enriched = await Promise.all(items.map(async item => {
      let product = null;
      if (item.productCollection === 'CreatorProduct') {
        product = await CreatorProduct.findById(item.productId)
          .select('title coverImage suggestedPrice productType category status creatorId')
          .lean();
      } else {
        product = await Product.findById(item.productId)
          .select('title coverImage price productType category isPublished slug')
          .lean();
      }
      return { ...item, product: product || null, available: !!product };
    }));
 
    res.json({ success: true, wishlist: enriched, count: enriched.length });
  } catch (err) {
    console.error('❌ GET /api/wishlist error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch wishlist' });
  }
});
 
