// POST /api/wishlist/:productId  — add item
app.post('/api/wishlist/:productId', authenticateToken, async (req, res) => {
  try {
    const { productId } = req.params;
    const { productCollection = 'Product' } = req.body;
 
    // Verify product exists
    const product = productCollection === 'CreatorProduct'
      ? await CreatorProduct.findById(productId).select('_id').lean()
      : await Product.findById(productId).select('_id').lean();
    if (!product) return res.status(404).json({ success: false, message: 'Product not found' });
 
    await Wishlist.create({ userId: req.user.userId, productId, productCollection });
    const count = await Wishlist.countDocuments({ userId: req.user.userId });
    res.json({ success: true, message: 'Added to wishlist', count });
  } catch (err) {
    if (err.code === 11000) return res.json({ success: true, message: 'Already in wishlist' });
    console.error('❌ POST /api/wishlist error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to add to wishlist' });
  }
});
 
