app.post('/api/chat/:chatId/message',authenticateToken, async (req, res) => {
  try {
    const { chatId } = req.params;
    const { message, sender, senderId, senderName } = req.body;

    console.log(`📨 API message received for chat ${chatId} from ${sender}`);

    // Validate basic inputs first
    if (!message || !sender) {
      return res.status(400).json({
        success: false,
        message: 'Message and sender required'
      });
    }

    if (message.length > 5000) {
      return res.status(400).json({ success: false, message: 'Message too long (max 5000 characters).' });
    }

    // Find chat BEFORE checking chat-specific limits
    const chat = await Chat.findOne({ chatId });
    if (!chat) {
      return res.status(404).json({
        success: false,
        message: 'Chat session not found'
      });
    }

    // Now safe to check chat properties
    if (chat.messages.length >= (chat.messageLimit || 500)) {
      return res.status(400).json({
        success: false,
        message: 'This chat has reached its message limit. Please open a new support chat.'
      });
    }

    // Create message object
    const messageObj = {
      messageId: `MSG-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      sender,
      senderId: senderId || 'system',
      senderName: senderName || (sender === 'agent' ? 'Agent' : 'Customer'),
      message: message.trim(),
      timestamp: new Date(),
      read: false
    };

    // Add to chat
    chat.messages.push(messageObj);
    chat.updatedAt = new Date();
    
    // Update status if needed
    if (chat.status === 'assigned') {
      chat.status = 'in-progress';
    }

    await chat.save();
 setImmediate(async () => {
          try {
            await createNotification(
              agentUserId, 'agent',
              'chat_assigned',
              '💬 Chat Assigned',
              `You have been assigned a chat with ${chat.customerName || 'a customer'}.`,
              { url: '/super-admin/agent-dashboard.html', chatId: chat.chatId }
            );
          } catch (_) {}
        });
    console.log(`✅ Message saved: ${messageObj.messageId}`);

    // ✅ INSTANT WebSocket broadcast
    const broadcastData = {
      type: 'chat_message',
      chatId,
      message: messageObj
    };

    let broadcastCount = 0;

    wss.clients.forEach((client) => {
      if (client.readyState === 1 && 
          (client.chatId === chatId || client.agentId)) {
        try {
          client.send(JSON.stringify(broadcastData));
          broadcastCount++;
        } catch (error) {
          console.error('Error broadcasting:', error);
        }
      }
    });

    console.log(`📢 Broadcasted to ${broadcastCount} clients`);

    // Send success response
    res.json({
      success: true,
      message: messageObj,
      broadcastCount
    });

  } catch (error) {
    console.error('❌ Send message error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to send message',
      error: error.message
    });
  }
});


function getFromCache(key) {
  const cached = cache.get(key);
  if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
    return cached.data;
  }
  cache.delete(key);
  return null;
}

function setCache(key, data) {
  cache.set(key, { data, timestamp: Date.now() });
}

// Auto-clear stale cache entries every 90 seconds
// Cache TTL is 1 minute — running cleanup at 5 min held stale data 4x longer than needed
setInterval(() => {
  const now = Date.now();
  let evicted = 0;
  for (const [key, value] of cache.entries()) {
    if (now - value.timestamp > CACHE_TTL) {
      cache.delete(key);
      evicted++;
    }
  }
  if (evicted > 0) console.log(`🧹 cache: evicted ${evicted} stale entries`);
}, 90 * 1000);

function cacheMessage(chatId, message) {
  if (!messageCache.has(chatId)) {
    messageCache.set(chatId, []);
  }
  
  const messages = messageCache.get(chatId);
  messages.push({
    message,
    timestamp: Date.now()
  });
  
  // Keep only last 50 messages
  if (messages.length > 50) {
    messages.shift();
  }
  
// Auto-clear: only set one timer per chatId, not one per message
  if (!messageCache._timers) messageCache._timers = new Map();
  if (!messageCache._timers.has(chatId)) {
    const timer = setTimeout(() => {
      messageCache.delete(chatId);
      messageCache._timers.delete(chatId);
    }, CACHE_TTL);
    messageCache._timers.set(chatId, timer);
  }
}

function getCachedMessages(chatId) {
  const cached = messageCache.get(chatId);
  if (!cached) return null;
  
  const now = Date.now();
  return cached
    .filter(item => (now - item.timestamp) < CACHE_TTL)
    .map(item => item.message);
}


