// Replaces the old live-aggregation route with pre-computed data from the
// Analytics collection, with live fallback for today.
app.get('/api/admin/analytics', authenticateAdmin, async (req, res) => {
  try {
    const { period = '30d' } = req.query;
    const cacheKey = `analytics:main:${period}`;
    const cached   = _getCachedAnalytics(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });
 
    const days = period === '7d' ? 7 : period === '90d' ? 90 : period === '365d' ? 365 : 30;
    const startDate = new Date(Date.now() - days * 86400000);
    startDate.setUTCHours(0, 0, 0, 0);
 
    // Pull from Analytics collection first (fast)
    const historicalDocs = await Analytics.find({ date: { $gte: startDate } })
      .sort({ date: 1 }).lean();
 
    // Build daily time series for charts
    const dailySeries = historicalDocs.map(d => ({
      date:            d.dateStr,
      revenue:         d.revenue         || 0,
      orders:          d.completedOrders || 0,
      newUsers:        d.newUsers        || 0,
      pageViews:       d.pageViews       || 0,
      uniqueVisitors:  d.uniqueVisitors  || 0,
      downloads:       d.downloads       || 0,
      chatsStarted:    d.chatsStarted    || 0,
      chatsResolved:   d.chatsResolved   || 0,
      affiliateClicks: d.affiliateClicks || 0,
    }));
 
    // Summary totals over the period
    const totals = historicalDocs.reduce((acc, d) => {
      acc.revenue         += d.revenue         || 0;
      acc.orders          += d.completedOrders || 0;
      acc.newUsers        += d.newUsers        || 0;
      acc.pageViews       += d.pageViews       || 0;
      acc.uniqueVisitors  += d.uniqueVisitors  || 0;
      acc.downloads       += d.downloads       || 0;
      acc.chatsStarted    += d.chatsStarted    || 0;
      acc.chatsResolved   += d.chatsResolved   || 0;
      acc.creatorRevenue  += d.creatorRevenue  || 0;
      acc.affiliateRevenue+= d.affiliateRevenue|| 0;
      acc.affiliateClicks += d.affiliateClicks || 0;
      acc.ticketsCreated  += d.ticketsCreated  || 0;
      return acc;
    }, {
      revenue:0, orders:0, newUsers:0, pageViews:0, uniqueVisitors:0,
      downloads:0, chatsStarted:0, chatsResolved:0, creatorRevenue:0,
      affiliateRevenue:0, affiliateClicks:0, ticketsCreated:0,
    });
 
    totals.avgOrderValue      = totals.orders > 0 ? totals.revenue / totals.orders : 0;
    totals.chatResolutionRate = totals.chatsStarted > 0
      ? Math.round((totals.chatsResolved / totals.chatsStarted) * 100) : 0;
 
    // Aggregate top products across the period
    const productMap = {};
    historicalDocs.forEach(d => {
      (d.topProducts || []).forEach(p => {
        const key = p.productId?.toString() || p.productName;
        if (!productMap[key]) productMap[key] = { productName: p.productName, productType: p.productType, sales: 0, revenue: 0 };
        productMap[key].sales   += p.sales   || 0;
        productMap[key].revenue += p.revenue || 0;
      });
    });
    const topProducts = Object.values(productMap).sort((a,b) => b.revenue - a.revenue).slice(0,10);
 
    // Aggregate category revenue
    const catMap = {};
    historicalDocs.forEach(d => {
      (d.revenueByCategory || []).forEach(c => {
        if (!catMap[c.category]) catMap[c.category] = { category: c.category, revenue: 0, sales: 0 };
        catMap[c.category].revenue += c.revenue || 0;
        catMap[c.category].sales   += c.sales   || 0;
      });
    });
    const revenueByCategory = Object.values(catMap).sort((a,b) => b.revenue - a.revenue);
 
    // Live data for comparison (all time totals — from live DB for accuracy)
    const [allTimeRevenue, totalUsers, totalOrders] = await Promise.all([
      Order.aggregate([{ $match: { status: 'completed' } }, { $group: { _id: null, total: { $sum: '$total' } } }]),
      User.countDocuments(),
      Order.countDocuments({ status: 'completed' }),
    ]);
 
    const payload = {
      period,
      days,
      summary: {
        ...totals,
        revenue:       parseFloat(totals.revenue.toFixed(2)),
        avgOrderValue: parseFloat(totals.avgOrderValue.toFixed(2)),
      },
      allTime: {
        revenue:     allTimeRevenue[0]?.total || 0,
        totalUsers,
        totalOrders,
      },
      charts: {
        daily:              dailySeries,
        topProducts,
        revenueByCategory,
      },
    };
 
    _setCachedAnalytics(cacheKey, payload);
    res.json({ success: true, ...payload, fromCache: false });
 
  } catch (err) {
    console.error('❌ GET /api/admin/analytics:', err);
    res.status(500).json({ success: false, message: 'Analytics fetch failed' });
  }
});
 
 
// ── ADMIN: Revenue deep-dive ──────────────────────────────────────────────
app.get('/api/admin/analytics/revenue', authenticateAdmin, async (req, res) => {
  try {
    const { period = '30d', groupBy = 'day' } = req.query;
    const cacheKey = `analytics:revenue:${period}:${groupBy}`;
    const cached   = _getCachedAnalytics(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });
 
    const days      = parseInt(period) || 30;
    const startDate = new Date(Date.now() - days * 86400000);
 
    const format = groupBy === 'month' ? '%Y-%m' : groupBy === 'week' ? '%Y-W%V' : '%Y-%m-%d';
 
    const [revenueSeries, topEarners, revenueByType, mrr] = await Promise.all([
      // Daily/weekly/monthly revenue breakdown
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: startDate } } },
        { $group: {
          _id:     { $dateToString: { format, date: '$createdAt' } },
          revenue: { $sum: '$total' },
          orders:  { $sum: 1 },
          aov:     { $avg: '$total' },
        }},
        { $sort: { _id: 1 } },
      ]),
      // Top earning products (all time)
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: startDate } } },
        { $unwind: '$items' },
        { $group: {
          _id:         '$items.title',
          revenue:     { $sum: '$items.price' },
          unitsSold:   { $sum: 1 },
          avgPrice:    { $avg: '$items.price' },
        }},
        { $sort: { revenue: -1 } },
        { $limit: 10 },
      ]),
      // Revenue by product type
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: startDate } } },
        { $unwind: '$items' },
        { $group: {
          _id:     '$items.productType',
          revenue: { $sum: '$items.price' },
          sales:   { $sum: 1 },
        }},
        { $sort: { revenue: -1 } },
      ]),
      // MRR (Monthly Recurring Revenue) — current month
      Order.aggregate([
        {
          $match: {
            status: 'completed',
            createdAt: {
              $gte: new Date(new Date().getFullYear(), new Date().getMonth(), 1),
              $lt:  new Date(new Date().getFullYear(), new Date().getMonth() + 1, 1),
            },
          },
        },
        { $group: { _id: null, mrr: { $sum: '$total' }, count: { $sum: 1 } } },
      ]),
    ]);
 
    const payload = {
      period: `${days}d`,
      revenueSeries: revenueSeries.map(r => ({
        period:  r._id,
        revenue: parseFloat((r.revenue || 0).toFixed(2)),
        orders:  r.orders,
        aov:     parseFloat((r.aov || 0).toFixed(2)),
      })),
      topEarners,
      revenueByType,
      mrr: {
        amount: parseFloat((mrr[0]?.mrr || 0).toFixed(2)),
        orders: mrr[0]?.count || 0,
      },
    };
 
    _setCachedAnalytics(cacheKey, payload);
    res.json({ success: true, ...payload, fromCache: false });
 
  } catch (err) {
    console.error('❌ Revenue analytics:', err);
    res.status(500).json({ success: false, message: 'Revenue analytics failed' });
  }
});
 
 
// ── ADMIN: User analytics ─────────────────────────────────────────────────
app.get('/api/admin/analytics/users', authenticateAdmin, async (req, res) => {
  try {
    const { period = '30d' } = req.query;
    const cacheKey = `analytics:users:${period}`;
    const cached   = _getCachedAnalytics(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });
 
    const days      = parseInt(period) || 30;
    const startDate = new Date(Date.now() - days * 86400000);
 
    const [
      growthSeries,
      topSpenders,
      geoBreakdown,
      conversionFunnel,
      retentionData,
    ] = await Promise.all([
      // Daily signups
      User.aggregate([
        { $match: { createdAt: { $gte: startDate } } },
        { $group: {
          _id:       { $dateToString: { format: '%Y-%m-%d', date: '$createdAt' } },
          signups:   { $sum: 1 },
          verified:  { $sum: { $cond: [{ $eq: ['$emailVerified', true] }, 1, 0] } },
        }},
        { $sort: { _id: 1 } },
      ]),
      // Top spenders
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: startDate } } },
        { $group: { _id: '$userId', totalSpent: { $sum: '$total' }, orderCount: { $sum: 1 } } },
        { $sort: { totalSpent: -1 } },
        { $limit: 10 },
        { $lookup: { from: 'users', localField: '_id', foreignField: '_id', as: 'user' } },
        { $unwind: '$user' },
        { $project: { fullName: '$user.fullName', email: '$user.email', totalSpent: 1, orderCount: 1 } },
      ]),
      // Geography breakdown
      User.aggregate([
        { $match: { country: { $ne: null, $ne: '' } } },
        { $group: { _id: '$country', count: { $sum: 1 } } },
        { $sort: { count: -1 } },
        { $limit: 15 },
      ]),
      // Conversion funnel: signups → verified → purchased
      (async () => {
        const [signups, verified, purchased] = await Promise.all([
          User.countDocuments({ createdAt: { $gte: startDate } }),
          User.countDocuments({ createdAt: { $gte: startDate }, emailVerified: true }),
          Order.aggregate([
            { $match: { status: 'completed', createdAt: { $gte: startDate } } },
            { $group: { _id: '$userId' } },
            { $count: 'n' },
          ]),
        ]);
        return {
          signups,
          verified,
          verificationRate: signups > 0 ? Math.round(verified / signups * 100) : 0,
          purchased: purchased[0]?.n || 0,
          purchaseRate: verified > 0 ? Math.round((purchased[0]?.n || 0) / verified * 100) : 0,
        };
      })(),
      // Repeat buyers
      Order.aggregate([
        { $match: { status: 'completed' } },
        { $group: { _id: '$userId', orders: { $sum: 1 } } },
        { $bucket: {
          groupBy: '$orders',
          boundaries: [1, 2, 3, 5, 10, 100],
          default: '10+',
          output: { count: { $sum: 1 } },
        }},
      ]),
    ]);
 
    const payload = {
      period: `${days}d`,
      growthSeries,
      topSpenders,
      geoBreakdown: geoBreakdown.map(g => ({ country: g._id, users: g.count })),
      conversionFunnel,
      retentionBuckets: retentionData,
    };
 
    _setCachedAnalytics(cacheKey, payload);
    res.json({ success: true, ...payload, fromCache: false });
 
  } catch (err) {
    console.error('❌ User analytics:', err);
    res.status(500).json({ success: false, message: 'User analytics failed' });
  }
});
 
 
