app.get('/api/admin/analytics/products', authenticateAdmin, async (req, res) => {
  try {
    const { period = '30d' } = req.query;
    const cacheKey = `analytics:products:${period}`;
    const cached   = _getCachedAnalytics(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });
 
    const days      = parseInt(period) || 30;
    const startDate = new Date(Date.now() - days * 86400000);
 
    const [topSellers, topEarning, byCategory, byType, lowStock] = await Promise.all([
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: startDate } } },
        { $unwind: '$items' },
        { $group: { _id: '$items.title', sales: { $sum: 1 }, revenue: { $sum: '$items.price' }, productType: { $first: '$items.productType' } } },
        { $sort: { sales: -1 } },
        { $limit: 15 },
      ]),
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: startDate } } },
        { $unwind: '$items' },
        { $group: { _id: '$items.title', revenue: { $sum: '$items.price' }, sales: { $sum: 1 } } },
        { $sort: { revenue: -1 } },
        { $limit: 15 },
      ]),
      Order.aggregate([
        { $match: { status: 'completed', createdAt: { $gte: startDate } } },
        { $unwind: '$items' },
        { $group: { _id: '$items.category', revenue: { $sum: '$items.price' }, sales: { $sum: 1 } } },
        { $sort: { revenue: -1 } },
      ]),
      Product.aggregate([
        { $group: { _id: '$productType', count: { $sum: 1 }, totalSold: { $sum: '$soldCount' } } },
        { $sort: { totalSold: -1 } },
      ]),
      // Software products running low on license keys
      Product.find({
        productType: 'software',
        'softwareData.licenseKeys.0': { $exists: true },
      })
      .select('title softwareData.licenseKeys')
      .lean()
      .then(prods => prods
        .filter(p => (p.softwareData?.licenseKeys?.length || 0) < 5)
        .map(p => ({ title: p.title, keysRemaining: p.softwareData?.licenseKeys?.length || 0 }))
      ),
    ]);
 
    const payload = { period: `${days}d`, topSellers, topEarning, byCategory, byType, lowStock };
    _setCachedAnalytics(cacheKey, payload);
    res.json({ success: true, ...payload, fromCache: false });
 
  } catch (err) {
    console.error('❌ Product analytics:', err);
    res.status(500).json({ success: false, message: 'Product analytics failed' });
  }
});
 
 
