app.get('/api/admin/analytics/creators', authenticateAdmin, async (req, res) => {
  try {
    const { period = '30d' } = req.query;
    const cacheKey = `analytics:creators:${period}`;
    const cached   = _getCachedAnalytics(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });
 
    const days      = parseInt(period) || 30;
    const startDate = new Date(Date.now() - days * 86400000);
 
    const [topCreators, applicationFunnel, payoutStats, topAffiliates, affiliateConversion] = await Promise.all([
      EarningsLedger.aggregate([
        { $match: { recipientType: 'creator', createdAt: { $gte: startDate } } },
        { $group: { _id: '$recipientId', totalEarned: { $sum: '$earningAmount' }, saleCount: { $sum: 1 } } },
        { $sort: { totalEarned: -1 } },
        { $limit: 10 },
        { $lookup: { from: 'users', localField: '_id', foreignField: '_id', as: 'user' } },
        { $unwind: '$user' },
        { $lookup: { from: 'creators', localField: '_id', foreignField: 'userId', as: 'creator' } },
        { $unwind: { path: '$creator', preserveNullAndEmptyArrays: true } },
        { $project: { fullName: '$user.fullName', storeName: '$creator.storeName', totalEarned: 1, saleCount: 1 } },
      ]),
      (async () => {
        const [applied, approved, rejected, suspended] = await Promise.all([
          Creator.countDocuments({ createdAt: { $gte: startDate } }),
          Creator.countDocuments({ applicationStatus: 'approved', updatedAt: { $gte: startDate } }),
          Creator.countDocuments({ applicationStatus: 'rejected', updatedAt: { $gte: startDate } }),
          Creator.countDocuments({ applicationStatus: 'suspended' }),
        ]);
        return { applied, approved, rejected, suspended, approvalRate: applied > 0 ? Math.round(approved/applied*100) : 0 };
      })(),
      PayoutRequest.aggregate([
        { $match: { createdAt: { $gte: startDate } } },
        { $group: {
          _id: { requesterType: '$requesterType', status: '$status' },
          count:  { $sum: 1 },
          amount: { $sum: '$amount' },
        }},
      ]),
      EarningsLedger.aggregate([
        { $match: { recipientType: 'affiliate', createdAt: { $gte: startDate } } },
        { $group: { _id: '$recipientId', totalEarned: { $sum: '$earningAmount' }, saleCount: { $sum: 1 } } },
        { $sort: { totalEarned: -1 } },
        { $limit: 10 },
        { $lookup: { from: 'users', localField: '_id', foreignField: '_id', as: 'user' } },
        { $unwind: '$user' },
        { $project: { fullName: '$user.fullName', email: '$user.email', totalEarned: 1, saleCount: 1 } },
      ]),
      AffiliateClick.aggregate([
        { $match: { clickedAt: { $gte: startDate } } },
        { $group: { _id: '$affiliateId', clicks: { $sum: 1 } } },
        { $lookup: { from: 'affiliates', localField: '_id', foreignField: '_id', as: 'aff' } },
        { $unwind: '$aff' },
        { $lookup: { from: 'earningsLedgers', localField: 'aff.userId', foreignField: 'recipientId', as: 'earnings' } },
        { $project: { clicks: 1, conversions: { $size: '$earnings' }, conversionRate: {
          $multiply: [{ $divide: [{ $size: '$earnings' }, { $max: ['$clicks', 1] }] }, 100]
        }}},
        { $sort: { clicks: -1 } },
        { $limit: 10 },
      ]),
    ]);
 
    const payload = { period: `${days}d`, topCreators, applicationFunnel, payoutStats, topAffiliates, affiliateConversion };
    _setCachedAnalytics(cacheKey, payload);
    res.json({ success: true, ...payload, fromCache: false });
 
  } catch (err) {
    console.error('❌ Creator analytics:', err);
    res.status(500).json({ success: false, message: 'Creator analytics failed' });
  }
});
 
 
