app.get('/api/admin/analytics/support', authenticateAdmin, async (req, res) => {
  try {
    const { period = '30d' } = req.query;
    const cacheKey = `analytics:support:${period}`;
    const cached   = _getCachedAnalytics(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });
 
    const days      = parseInt(period) || 30;
    const startDate = new Date(Date.now() - days * 86400000);
 
    const [agentLeaderboard, dailySupport, ticketCategories, slaBreakdown] = await Promise.all([
      Chat.aggregate([
        { $match: { assignedAgent: { $ne: null }, createdAt: { $gte: startDate } } },
        { $group: {
          _id:             '$assignedAgent',
          totalChats:      { $sum: 1 },
          resolved:        { $sum: { $cond: [{ $eq: ['$status', 'resolved'] }, 1, 0] } },
          avgResponseTime: { $avg: '$firstResponseTime' },
          totalMessages:   { $sum: { $size: '$messages' } },
        }},
        { $sort: { resolved: -1 } },
        { $limit: 10 },
        { $lookup: { from: 'users', localField: '_id', foreignField: '_id', as: 'agent' } },
        { $unwind: '$agent' },
        { $project: {
          agentName:       '$agent.fullName',
          totalChats:      1,
          resolved:        1,
          resolutionRate:  { $multiply: [{ $divide: ['$resolved', { $max: ['$totalChats', 1] }] }, 100] },
          avgResponseTime: 1,
          totalMessages:   1,
        }},
      ]),
      Analytics.find({ date: { $gte: startDate } })
        .select('dateStr chatsStarted chatsResolved ticketsCreated ticketsResolved avgChatResponseTime')
        .sort({ date: 1 })
        .lean(),
      SupportTicket.aggregate([
        { $match: { createdAt: { $gte: startDate } } },
        { $group: { _id: '$category', count: { $sum: 1 }, avgResolutionTime: { $avg: '$firstResponseTime' } } },
        { $sort: { count: -1 } },
      ]),
      // SLA: % chats responded within 5 minutes
      Chat.aggregate([
        { $match: { firstResponseTime: { $exists: true }, createdAt: { $gte: startDate } } },
        { $group: {
          _id: null,
          total:    { $sum: 1 },
          within5:  { $sum: { $cond: [{ $lte: ['$firstResponseTime', 5] },  1, 0] } },
          within15: { $sum: { $cond: [{ $lte: ['$firstResponseTime', 15] }, 1, 0] } },
          within30: { $sum: { $cond: [{ $lte: ['$firstResponseTime', 30] }, 1, 0] } },
        }},
      ]),
    ]);
 
    const sla = slaBreakdown[0] || { total: 0, within5: 0, within15: 0, within30: 0 };
    const payload = {
      period: `${days}d`,
      agentLeaderboard,
      dailySupport,
      ticketCategories,
      sla: {
        totalMeasured: sla.total,
        within5min:  sla.total > 0 ? Math.round(sla.within5  / sla.total * 100) : 0,
        within15min: sla.total > 0 ? Math.round(sla.within15 / sla.total * 100) : 0,
        within30min: sla.total > 0 ? Math.round(sla.within30 / sla.total * 100) : 0,
      },
    };
 
    _setCachedAnalytics(cacheKey, payload);
    res.json({ success: true, ...payload, fromCache: false });
 
  } catch (err) {
    console.error('❌ Support analytics:', err);
    res.status(500).json({ success: false, message: 'Support analytics failed' });
  }
});
 
 
