// ── AGENT: analytics route — upgraded from in-memory loop to DB aggregation ─
app.get('/api/agent/analytics', authenticateAgent, async (req, res) => {
  try {
    const agentId   = req.agentUser._id;
    const { period = '7d' } = req.query;
    const cacheKey  = `analytics:agent:${agentId}:${period}`;
    const cached    = _getCachedAnalytics(cacheKey);
    if (cached) return res.json({ success: true, ...cached, fromCache: true });
 
    const days      = period === 'today' ? 1 : period === 'month' ? 30 : 7;
    const startDate = new Date();
    if (period === 'today') startDate.setHours(0, 0, 0, 0);
    else startDate.setTime(Date.now() - days * 86400000);
 
    const [summary, dailySeries, ticketStats] = await Promise.all([
      Chat.aggregate([
        { $match: { assignedAgent: agentId, createdAt: { $gte: startDate } } },
        { $group: {
          _id:             null,
          totalChats:      { $sum: 1 },
          resolved:        { $sum: { $cond: [{ $eq: ['$status', 'resolved'] }, 1, 0] } },
          avgResponseTime: { $avg: '$firstResponseTime' },
          totalMessages:   { $sum: {
            $size: { $filter: { input: '$messages', as: 'm', cond: { $eq: ['$$m.sender', 'agent'] } } }
          }},
        }},
      ]),
      Chat.aggregate([
        { $match: { assignedAgent: agentId, createdAt: { $gte: startDate } } },
        { $group: {
          _id:      { $dateToString: { format: '%Y-%m-%d', date: '$createdAt' } },
          total:    { $sum: 1 },
          resolved: { $sum: { $cond: [{ $eq: ['$status', 'resolved'] }, 1, 0] } },
        }},
        { $sort: { _id: 1 } },
      ]),
      SupportTicket.aggregate([
        { $match: { assignedAgent: agentId, createdAt: { $gte: startDate } } },
        { $group: {
          _id:      null,
          total:    { $sum: 1 },
          resolved: { $sum: { $cond: [{ $eq: ['$status', 'closed'] }, 1, 0] } },
          avgFirst: { $avg: '$firstResponseTime' },
        }},
      ]),
    ]);
 
    const s = summary[0] || { totalChats: 0, resolved: 0, avgResponseTime: 0, totalMessages: 0 };
    const t = ticketStats[0] || { total: 0, resolved: 0, avgFirst: 0 };
 
    const payload = {
      period,
      chats: {
        total:          s.totalChats,
        resolved:       s.resolved,
        resolutionRate: s.totalChats > 0 ? Math.round(s.resolved / s.totalChats * 100) : 0,
        avgResponseTime: Math.round(s.avgResponseTime || 0),
        agentMessages:  s.totalMessages,
      },
      tickets: {
        total:          t.total,
        resolved:       t.resolved,
        avgFirstResponse: Math.round(t.avgFirst || 0),
      },
      dailySeries,
    };
 
    _setCachedAnalytics(cacheKey, payload);
    res.json({ success: true, analytics: payload, fromCache: false });
 
  } catch (err) {
    console.error('❌ Agent analytics:', err);
    res.status(500).json({ success: false, message: 'Agent analytics failed' });
  }
});


// ========== USER MANAGEMENT ==========
// Get All Users (with pagination and search)
app.get('/api/admin/users', authenticateAdmin, async (req, res) => {
  try {
    const { page = 1, limit = 20, search = '', status = 'all', role = 'all' } = req.query;
    
    let query = {};
    
    // Search by name or email
    if (search) {
      query.$or = [
        { fullName: { $regex: search, $options: 'i' } },
        { email: { $regex: search, $options: 'i' } }
      ];
    }
    
    // Filter by status
    if (status === 'banned') {
      query.isBanned = true;
    } else if (status === 'active') {
      query.isBanned = false;
    }

    // Filter by role 
    if (role === 'admin') {
      query.isAdmin = true;
    } else if (role === 'agent') {
      query.isAgent = true;
    } else if (role === 'user') {
      query.isAdmin = false;
      query.isAgent = false;
    }

    const skip = (parseInt(page) - 1) * parseInt(limit);
    
    const users = await User.find(query)
      .select('-password -twoFactorSecret')
      .sort({ createdAt: -1 })
      .limit(parseInt(limit))
      .skip(skip);

    const total = await User.countDocuments(query);

    // Add statistics for each user
    const usersWithStats = await Promise.all(
      users.map(async (user) => {
        const orderCount = await Order.countDocuments({ userId: user._id });
        const downloadCount = await Download.countDocuments({ userId: user._id });
        const chatCount = await Chat.countDocuments({ customerId: user.email }); 
        const totalSpent = await Order.aggregate([
          { $match: { userId: user._id, status: 'completed' } },
          { $group: { _id: null, total: { $sum: '$total' } } }
        ]);
        return {
          ...user.toObject(),
          orderCount,
          downloadCount,
          chatCount, 
          totalSpent: totalSpent[0]?.total || 0
        };
      })
    );

    res.json({
      success: true,
      users: usersWithStats,
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        pages: Math.ceil(total / parseInt(limit))
      }
    });
  } catch (error) {
    console.error('❌ Get users error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch users' });
  }
});

// Get Single User Details
// Get Single User — Full Detail for admin drawer
app.get('/api/admin/users/:userId', authenticateAdmin, async (req, res) => {
  try {
    const user = await User.findById(req.params.userId)
      .select('-password -twoFactorSecret -emailVerificationToken -passwordResetToken');

    if (!user) {
      return res.status(404).json({ success: false, message: 'User not found' });
    }

    const uid = user._id;

    const [
      orderCount,
      downloadCount,
      chatCount,
      pendingOrderCount,
      totalSpentAgg,
      recentOrders,
      recentChats,
      recentDownloads,
      creatorProfile,
      affiliateProfile,
      supportTickets,
      reviewCount,
    ] = await Promise.all([
      Order.countDocuments({ userId: uid }),
      Download.countDocuments({ userId: uid }),
      Chat.countDocuments({ customerId: user.email }),
      Order.countDocuments({ userId: uid, status: 'pending' }),

      // Total completed spend
      Order.aggregate([
        { $match: { userId: uid, status: 'completed' } },
        { $group: { _id: null, total: { $sum: '$total' }, count: { $sum: 1 } } }
      ]),

      // Last 15 orders
      Order.find({ userId: uid })
        .sort({ createdAt: -1 })
        .limit(15)
        .select('orderReference total status createdAt paymentInfo productId')
        .lean(),

      // Last 10 support chats
      Chat.find({ customerId: user.email })
        .sort({ createdAt: -1 })
        .limit(10)
        .select('chatId status subject createdAt resolvedAt assignedAgent')
        .lean(),

      // Last 10 downloads
      Download.find({ userId: uid })
        .sort({ downloadedAt: -1 })
        .limit(10)
        .populate('productId', 'title productType')
        .lean(),

      // Creator profile if they are a creator
      user.isCreator
        ? Creator.findOne({ userId: uid })
            .select('storeName storeSlug applicationStatus totalProducts totalSales totalRevenue totalEarnings pendingPayout createdAt')
            .lean()
        : Promise.resolve(null),

      // Affiliate profile if they have one
      Affiliate
        ? Affiliate.findOne({ userId: uid })
            .select('status totalEarnings pendingEarnings totalClicks totalConversions createdAt')
            .lean()
        : Promise.resolve(null),

      // Support tickets
      SupportTicket
        ? SupportTicket.find({ userId: uid })
            .sort({ createdAt: -1 })
            .limit(10)
            .select('ticketId subject status priority createdAt resolvedAt')
            .lean()
        : Promise.resolve([]),

      // Total reviews written
      Review.countDocuments({ userId: uid }),
    ]);

    const spent = totalSpentAgg[0] || { total: 0, count: 0 };

    res.json({
      success: true,
      user: {
        ...user.toObject(),
        // Stats
        orderCount,
        pendingOrderCount,
        downloadCount,
        chatCount,
        totalSpent:     spent.total,
        completedOrders: spent.count,
        reviewCount,
        // Related data
        recentOrders,
        recentChats,
        recentDownloads,
        creatorProfile,
        affiliateProfile,
        supportTickets,
      }
    });
  } catch (error) {
    console.error('❌ Get user detail error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch user details' });
  }
});

// Ban/Unban User
app.put('/api/admin/users/:userId/ban', authenticateAdmin, async (req, res) => {
  try {
    const { isBanned, banReason } = req.body;
    
    const user = await User.findById(req.params.userId);
    if (!user) {
      return res.status(404).json({ success: false, message: 'User not found' });
    }

    // Cannot ban admin users
    if (user.isAdmin) {
      return res.status(400).json({ success: false, message: 'Cannot ban administrator accounts' });
    }

    user.isBanned = isBanned;
    user.banReason = isBanned ? (banReason || 'Violated terms of service') : '';
    await user.save();

    console.log(`${isBanned ? '🚫 User banned' : '✅ User unbanned'}: ${user.email}`);
    await logAdminAction(req, isBanned ? 'user_banned' : 'user_unbanned', user, { reason: banReason });
    if (isBanned && global.sendAccountBannedEmail) {
      setImmediate(() =>
        global.sendAccountBannedEmail(user.email, {
          fullName:  user.fullName,
          banReason: user.banReason,
        }).catch(() => {})
      );
    }
    res.json({
      success: true,
      message: isBanned ? 'User has been banned' : 'User has been unbanned',
      user: {
        id: user._id,
        name: user.fullName,
        email: user.email,
        isBanned: user.isBanned,
        banReason: user.banReason
      }
    });
  } catch (error) {
    console.error('❌ Ban user error:', error);
    res.status(500).json({ success: false, message: 'Failed to update user status' });
  }
});

// GET /api/admin/users/:userId/orders  — view all orders for a specific user
app.get('/api/admin/users/:userId/orders', authenticateAdmin, async (req, res) => {
  try {
    const { page = 1, limit = 20 } = req.query;
    const skip = (parseInt(page) - 1) * parseInt(limit);

    const user = await User.findById(req.params.userId).select('fullName email').lean();
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    const [orders, total] = await Promise.all([
      Order.find({ userId: req.params.userId })
        .sort({ createdAt: -1 })
        .skip(skip)
        .limit(parseInt(limit))
        .lean(),
      Order.countDocuments({ userId: req.params.userId }),
    ]);

    res.json({
      success: true,
      user:   { id: user._id, fullName: user.fullName, email: user.email },
      orders,
      total,
      page:   parseInt(page),
      pages:  Math.ceil(total / parseInt(limit)),
    });
  } catch (err) {
    console.error('❌ GET /api/admin/users/:userId/orders error:', err.message);
    res.status(500).json({ success: false, message: 'Failed to fetch user orders' });
  }
});

// Delete User
app.delete('/api/admin/users/:userId', authenticateAdmin, async (req, res) => {
  try {
    const userId = req.params.userId;

    // Cannot delete own account
    if (userId === req.user.userId) {
      return res.status(400).json({ success: false, message: 'Cannot delete your own account' });
    }

    const user = await User.findById(userId);
    if (!user) {
      return res.status(404).json({ success: false, message: 'User not found' });
    }

    // Cannot delete admin users
    if (user.isAdmin) {
      return res.status(400).json({ success: false, message: 'Cannot delete administrator accounts' });
    }

   const uid = user._id;
    await Promise.all([
      Order.deleteMany({ userId: uid }),
      Download.deleteMany({ userId: uid }),
      PaymentMethod.deleteMany({ userId: uid }),
      // Anonymise chats rather than delete (keeps support history)
      Chat.updateMany(
        { customerId: user.email },
        { $set: { customerName: 'Deleted User', customerEmail: 'deleted@example.com' } }
      ),
      // Affiliate cleanup
      global.Affiliate        ? global.Affiliate.deleteOne({ userId: uid })                    : Promise.resolve(),
      global.AffiliateLink    ? global.AffiliateLink.deleteMany({ affiliateId: uid })          : Promise.resolve(),
      global.AffiliateEvent   ? global.AffiliateEvent.deleteMany({ affiliateId: uid })         : Promise.resolve(),
      global.AffiliateCampaign? global.AffiliateCampaign.deleteMany({ userId: uid })           : Promise.resolve(),
      global.EarningsLedger   ? global.EarningsLedger.deleteMany({ recipientId: uid })         : Promise.resolve(),
      // Creator cleanup — unpublish products, then remove profile
      global.Creator          ? (async () => {
                                  const cr = await global.Creator.findOne({ userId: uid });
                                  if (cr) {
                                    await global.CreatorProduct.updateMany({ creatorId: cr._id }, { $set: { status: 'archived' } });
                                    await global.Creator.deleteOne({ _id: cr._id });
                                  }
                                })()                                                            : Promise.resolve(),
      // Social / content cleanup
      global.Follow           ? global.Follow.deleteMany({ $or: [{ followerId: uid }, { creatorId: uid }] }) : Promise.resolve(),
      global.Review           ? global.Review.deleteMany({ userId: uid })                      : Promise.resolve(),
      global.CourseProgress   ? global.CourseProgress.deleteMany({ userId: uid })              : Promise.resolve(),
      global.StudentNote      ? global.StudentNote.deleteMany({ userId: uid })                 : Promise.resolve(),
      global.Notification     ? global.Notification.deleteMany({ recipientId: uid })           : Promise.resolve(),
      global.SupportTicket    ? global.SupportTicket.updateMany({ userId: uid }, { $set: { userId: null, customerEmail: 'deleted@example.com', customerName: 'Deleted User' } }) : Promise.resolve(),
      global.CouponUsage      ? global.CouponUsage.deleteMany({ userId: uid })                 : Promise.resolve(),
    ]);
    await User.findByIdAndDelete(userId);


    console.log(`🗑️  User deleted: ${user.email}`);

    res.json({
      success: true,
      message: 'User and associated data have been deleted'
    });
  } catch (error) {
    console.error('❌ Delete user error:', error);
    res.status(500).json({ success: false, message: 'Failed to delete user' });
  }
});

