// 2FA ADMIN RESET — emergency: admin can clear 2FA for a locked-out user
// Sends email confirmation to the user so they know it happened
// ─────────────────────────────────────────────────────────────────────────
app.post('/api/admin/users/:userId/reset-2fa', authenticateAdmin, async (req, res) => {
  try {
    const user = await User.findById(req.params.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
 
    user.twoFactorEnabled     = false;
    user.twoFactorSecret      = undefined;
    user.twoFactorPending     = undefined;
    user.twoFactorBackupCodes = [];
    user.twoFactorEnabledAt   = undefined;
    user.twoFactorAttempts    = 0;
    user.twoFactorLockedUntil = undefined;
    await user.save();
 
    console.log(`🔓 2FA reset by admin (${req.adminUser.email}) for user: ${user.email}`);
 
    setImmediate(() => {
      _send2FAAdminResetEmail(user.email, user.fullName, req.adminUser.email).catch(() => {});
    });
 
    res.json({
      success: true,
      message: `2FA cleared for ${user.email}. They have been notified by email.`
    });
 
  } catch (error) {
    console.error('❌ Admin 2FA reset error:', error);
    res.status(500).json({ success: false, message: 'Admin 2FA reset failed' });
  }
});
 
// Promote User to Agent 
app.put('/api/admin/users/:userId/promote-agent', authenticateAdmin, async (req, res) => {
  try {
    const { department = 'General', maxChats = 5 } = req.body;
    
    const user = await User.findById(req.params.userId);
    if (!user) {
      return res.status(404).json({ success: false, message: 'User not found' });
    }

    if (user.isAgent) {
      return res.status(400).json({ success: false, message: 'User is already an agent' });
    }

    user.isAgent = true;
    user.agentInfo = {
      department,
      status: 'offline',
      activeChats: 0,
      maxChats,
      rating: 0,
      totalChats: 0,
      resolvedChats: 0
    };
    await user.save();

    console.log(`👨‍💼 User promoted to agent: ${user.email}`);

    res.json({
      success: true,
      message: 'User has been promoted to agent',
      user: {
        id: user._id,
        name: user.fullName,
        email: user.email,
        isAgent: user.isAgent,
        agentInfo: user.agentInfo
      }
    });
  } catch (error) {
    console.error('❌ Promote agent error:', error);
    res.status(500).json({ success: false, message: 'Failed to promote user' });
  }
});

// Demote Agent to User 
app.put('/api/admin/users/:userId/demote-agent', authenticateAdmin, async (req, res) => {
  try {
    const user = await User.findById(req.params.userId);
    if (!user) {
      return res.status(404).json({ success: false, message: 'User not found' });
    }

    if (!user.isAgent) {
      return res.status(400).json({ success: false, message: 'User is not an agent' });
    }

    // Unassign all chats
    await Chat.updateMany(
      { assignedAgent: user._id, status: { $ne: 'closed' } },
      { $set: { assignedAgent: null, status: 'open' } }
    );

    user.isAgent = false;
    user.agentInfo = undefined;
    await user.save();

    console.log(`👤 Agent demoted to user: ${user.email}`);

    res.json({
      success: true,
      message: 'Agent has been demoted to regular user',
      user: {
        id: user._id,
        name: user.fullName,
        email: user.email,
        isAgent: user.isAgent
      }
    });
  } catch (error) {
    console.error('❌ Demote agent error:', error);
    res.status(500).json({ success: false, message: 'Failed to demote agent' });
  }
});

