// GET — full settings for admin dashboard
// NOTE: maintenanceBypassToken is intentionally EXCLUDED from the response
//       to prevent it being leaked to compromised admin accounts.
app.get('/api/admin/settings', authenticateAdmin, async (req, res) => {
  try {
    const settings = await getSettings();

    // Strip the bypass token before sending — write-only field
    const safe = { ...settings };
    delete safe.maintenanceBypassToken;
    safe.hasMaintenanceBypassToken = !!(settings.maintenanceBypassToken);

    res.json({ success: true, settings: safe });
  } catch (err) {
    console.error('❌ GET /api/admin/settings:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch settings' });
  }
});


// PUT — save full or partial settings payload
app.put('/api/admin/settings', authenticateAdmin, async (req, res) => {
  try {
    let doc = await SystemSettings.findOne();
    if (!doc) doc = new SystemSettings();

    const allowed = [
      // Identity
      'siteName', 'siteDescription', 'siteUrl', 'contactEmail', 'supportEmail',
      'phone', 'address', 'logo', 'favicon', 'socialMedia',
      // Maintenance
      'maintenanceMode', 'maintenanceMessage', 'maintenanceTitle',
      'maintenanceETA', 'maintenanceBypassToken', 'maintenancePages',
      // Auth & registration
      'allowRegistration', 'requireEmailVerification', 'allowGuestCheckout',
      // Feature flags
      'storeEnabled', 'blogEnabled', 'chatEnabled', 'creatorEnabled', 'affiliatesEnabled',
      // Banner
      'bannerEnabled', 'bannerText', 'bannerType', 'bannerLink', 'bannerLinkText', 'bannerDismissible',
      // Payments
      'paymentSettings',
      // Custom code
      'customCSS', 'customJS', 'customHead',
      // SEO
      'seoTitle', 'seoDescription', 'seoKeywords',
      'googleAnalyticsId', 'facebookPixelId',
    ];

    allowed.forEach(field => {
      if (req.body[field] !== undefined) {
        doc[field] = req.body[field];
      }
    });

    doc.updatedAt = new Date();
    doc.updatedBy = req.adminUser.email;
    await doc.save();

    // Invalidate cache immediately
    invalidateSettings();

    // Broadcast to all connected WebSocket clients so the frontend can
    // react without waiting for the next poll.
    _broadcastSettingsUpdate(doc);

    console.log(`⚙️  Settings updated by ${req.adminUser.email}`);

    // Return safe copy (no bypass token)
    const safe = doc.toObject();
    delete safe.maintenanceBypassToken;
    safe.hasMaintenanceBypassToken = !!(doc.maintenanceBypassToken);
    // ── Audit log for sensitive code injection fields ──────────────────────
    const sensitiveChanged = ['customJS', 'customHead', 'customCSS'].some(
      f => req.body[f] !== undefined
    );
    if (sensitiveChanged) {
      console.warn(`⚠️  SECURITY: Admin ${req.adminUser.email} modified customJS/customHead/customCSS settings`);
      await adminLog({
        actor:    resolveActor(req),
        category: 'admin',
        action:   'settings_code_injection_fields_modified',
        severity: 'warning',
        detail:   {
          modifiedFields: ['customJS', 'customHead', 'customCSS'].filter(f => req.body[f] !== undefined),
          ip: req.ip,
        },
        success: true,
      });
    }
    res.json({ success: true, message: 'Settings saved', settings: safe });

  } catch (err) {
    console.error('❌ PUT /api/admin/settings:', err);
    res.status(500).json({ success: false, message: 'Failed to save settings' });
  }
});


// POST — toggle maintenance mode on/off with one call
app.post('/api/admin/settings/maintenance/toggle', authenticateAdmin, async (req, res) => {
  try {
    let doc = await SystemSettings.findOne();
    if (!doc) doc = new SystemSettings();

    doc.maintenanceMode = !doc.maintenanceMode;
    doc.updatedAt = new Date();
    doc.updatedBy = req.adminUser.email;
    await doc.save();

    invalidateSettings();
    _broadcastSettingsUpdate(doc);

    const state = doc.maintenanceMode ? 'ENABLED' : 'DISABLED';
    console.log(`🔧 Maintenance ${state} by ${req.adminUser.email}`);

    res.json({
      success:         true,
      maintenanceMode: doc.maintenanceMode,
      message:         `Maintenance mode ${doc.maintenanceMode ? 'enabled' : 'disabled'}`,
    });
  } catch (err) {
    console.error('❌ Maintenance toggle:', err);
    res.status(500).json({ success: false, message: 'Toggle failed' });
  }
});


// PATCH — toggle a single feature flag by name
// Body: { value: true|false }   (omit value to flip current state)
app.patch('/api/admin/settings/feature/:key', authenticateAdmin, async (req, res) => {
  const ALLOWED_FLAGS = [
    'storeEnabled', 'blogEnabled', 'chatEnabled',
    'creatorEnabled', 'affiliatesEnabled',
    'allowRegistration', 'requireEmailVerification', 'allowGuestCheckout',
    'bannerEnabled', 'maintenanceMode',
  ];

  const { key } = req.params;
  if (!ALLOWED_FLAGS.includes(key)) {
    return res.status(400).json({ success: false, message: `Unknown feature flag: ${key}` });
  }

  try {
    let doc = await SystemSettings.findOne();
    if (!doc) doc = new SystemSettings();

    // If body contains an explicit value use it, otherwise flip
    doc[key] = req.body.value !== undefined ? !!req.body.value : !doc[key];
    doc.updatedAt = new Date();
    doc.updatedBy = req.adminUser.email;
    await doc.save();

    invalidateSettings();
    _broadcastSettingsUpdate(doc);

    console.log(`⚙️  Feature flag '${key}' set to ${doc[key]} by ${req.adminUser.email}`);

    res.json({ success: true, key, value: doc[key], message: `${key} is now ${doc[key] ? 'enabled' : 'disabled'}` });
  } catch (err) {
    console.error(`❌ PATCH /api/admin/settings/feature/${key}:`, err);
    res.status(500).json({ success: false, message: 'Flag update failed' });
  }
});


// PATCH — quick banner update (text + enable/disable in one call)
app.patch('/api/admin/settings/banner', authenticateAdmin, async (req, res) => {
  try {
    let doc = await SystemSettings.findOne();
    if (!doc) doc = new SystemSettings();

    const { enabled, text, type, link, linkText, dismissible } = req.body;
    if (enabled    !== undefined) doc.bannerEnabled    = !!enabled;
    if (text       !== undefined) doc.bannerText       = String(text).substring(0, 500);
    if (type       !== undefined) doc.bannerType       = ['info','success','warning','urgent'].includes(type) ? type : 'info';
    if (link       !== undefined) doc.bannerLink       = String(link);
    if (linkText   !== undefined) doc.bannerLinkText   = String(linkText);
    if (dismissible !== undefined) doc.bannerDismissible = !!dismissible;

    doc.updatedAt = new Date();
    doc.updatedBy = req.adminUser.email;
    await doc.save();

    invalidateSettings();
    _broadcastSettingsUpdate(doc);

    res.json({
      success: true,
      message: `Banner ${doc.bannerEnabled ? 'enabled' : 'disabled'}`,
      banner: {
        enabled:     doc.bannerEnabled,
        text:        doc.bannerText,
        type:        doc.bannerType,
        link:        doc.bannerLink,
        linkText:    doc.bannerLinkText,
        dismissible: doc.bannerDismissible,
      },
    });
  } catch (err) {
    console.error('❌ PATCH /api/admin/settings/banner:', err);
    res.status(500).json({ success: false, message: 'Banner update failed' });
  }
});


// POST — upload site logo to Cloudinary and save URL to settings
app.post('/api/admin/settings/logo', authenticateAdmin, upload.single('logo'), async (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ success: false, message: 'No file uploaded' });
    }

    const allowed = ['image/png', 'image/jpeg', 'image/jpg', 'image/webp', 'image/svg+xml'];
    if (!allowed.includes(req.file.mimetype)) {
      return res.status(400).json({ success: false, message: 'Logo must be PNG, JPG, WEBP, or SVG' });
    }

    if (req.file.size > 2 * 1024 * 1024) {
      return res.status(400).json({ success: false, message: 'Logo must be under 2 MB' });
    }

    const result = await uploadToCloudinary(req.file.buffer, req.file.mimetype, 'uyehtech/branding', {
      public_id:      'site-logo',
      overwrite:      true,
      unique_filename: false,
      invalidate:     true,
    });

    let doc = await SystemSettings.findOne();
    if (!doc) doc = new SystemSettings();
    doc.logo = result.secureUrl;
    doc.updatedAt = new Date();
    doc.updatedBy = req.adminUser.email;
    await doc.save();

    invalidateSettings();
    _broadcastSettingsUpdate(doc);

    console.log(`🖼️  Site logo updated by ${req.adminUser.email}: ${result.secureUrl}`);
    res.json({ success: true, message: 'Logo updated', logoUrl: result.secureUrl });

  } catch (err) {
    console.error('❌ POST /api/admin/settings/logo:', err);
    res.status(500).json({ success: false, message: 'Logo upload failed' });
  }
});


// POST — upload site favicon to Cloudinary and save URL to settings
app.post('/api/admin/settings/favicon', authenticateAdmin, upload.single('favicon'), async (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ success: false, message: 'No file uploaded' });
    }

    const allowed = ['image/png', 'image/x-icon', 'image/vnd.microsoft.icon', 'image/svg+xml'];
    if (!allowed.includes(req.file.mimetype)) {
      return res.status(400).json({ success: false, message: 'Favicon must be PNG, ICO, or SVG' });
    }

    if (req.file.size > 512 * 1024) {
      return res.status(400).json({ success: false, message: 'Favicon must be under 512 KB' });
    }

    const result = await uploadToCloudinary(req.file.buffer, req.file.mimetype, 'uyehtech/branding', {
      public_id:      'site-favicon',
      overwrite:      true,
      unique_filename: false,
      invalidate:     true,
    });

    let doc = await SystemSettings.findOne();
    if (!doc) doc = new SystemSettings();
    doc.favicon = result.secureUrl;
    doc.updatedAt = new Date();
    doc.updatedBy = req.adminUser.email;
    await doc.save();

    invalidateSettings();
    _broadcastSettingsUpdate(doc);

    console.log(`🖼️  Favicon updated by ${req.adminUser.email}: ${result.secureUrl}`);
    res.json({ success: true, message: 'Favicon updated', faviconUrl: result.secureUrl });

  } catch (err) {
    console.error('❌ POST /api/admin/settings/favicon:', err);
    res.status(500).json({ success: false, message: 'Favicon upload failed' });
  }
});


