// POST — import settings from a JSON backup
app.post('/api/admin/settings/import', authenticateAdmin, async (req, res) => {
  try {
    const { settings: imported } = req.body;
    if (!imported || typeof imported !== 'object') {
      return res.status(400).json({ success: false, message: 'Send { settings: {...} } in the request body' });
    }

    let doc = await SystemSettings.findOne();
    if (!doc) doc = new SystemSettings();

    // Same allowed list as the PUT — never import _id, __v, or bypassToken
    const allowed = [
      'siteName', 'siteDescription', 'siteUrl', 'contactEmail', 'supportEmail',
      'phone', 'address', 'logo', 'favicon', 'socialMedia',
      'maintenanceMode', 'maintenanceMessage', 'maintenanceTitle',
      'maintenanceETA', 'maintenancePages',
      'allowRegistration', 'requireEmailVerification', 'allowGuestCheckout',
      'storeEnabled', 'blogEnabled', 'chatEnabled', 'creatorEnabled', 'affiliatesEnabled',
      'bannerEnabled', 'bannerText', 'bannerType', 'bannerLink', 'bannerLinkText', 'bannerDismissible',
      'paymentSettings', 'customCSS', 'customJS', 'customHead',
      'seoTitle', 'seoDescription', 'seoKeywords', 'googleAnalyticsId', 'facebookPixelId',
    ];

    allowed.forEach(field => {
      if (imported[field] !== undefined) doc[field] = imported[field];
    });

    doc.updatedAt = new Date();
    doc.updatedBy = req.adminUser.email + ' (import)';
    await doc.save();

    invalidateSettings();
    _broadcastSettingsUpdate(doc);

    console.log(`📥 Settings IMPORTED by ${req.adminUser.email}`);

    const safe = doc.toObject();
    delete safe.maintenanceBypassToken;
    res.json({ success: true, message: 'Settings imported successfully', settings: safe });

  } catch (err) {
    console.error('❌ POST /api/admin/settings/import:', err);
    res.status(500).json({ success: false, message: 'Import failed' });
  }
});


// ── Internal broadcast helper ─────────────────────────────────────────────
// Notifies every connected WebSocket client that settings changed so the
// frontend can react immediately without waiting for the next poll.
function _broadcastSettingsUpdate(doc) {
  if (!global.wss || !global.wss.clients) return;

  const payload = JSON.stringify({
    type:            'settings_updated',
    maintenanceMode: doc.maintenanceMode || false,
    bannerEnabled:   doc.bannerEnabled   || false,
    storeEnabled:    doc.storeEnabled    !== false,
    blogEnabled:     doc.blogEnabled     !== false,
    chatEnabled:     doc.chatEnabled     !== false,
    creatorEnabled:  doc.creatorEnabled  !== false,
    affiliatesEnabled: doc.affiliatesEnabled !== false,
    timestamp:       new Date(),
  });

  let sent = 0;
  global.wss.clients.forEach(client => {
    if (client.readyState === 1) {
      try { client.send(payload); sent++; } catch (_) {}
    }
  });

  console.log(`📡 Settings broadcast sent to ${sent} WebSocket client(s)`);
}

// ========== ORDER MANAGEMENT ==========
app.get('/api/admin/orders', authenticateAdmin, async (req, res) => {
  try {
    const { page = 1, limit = 20, status = 'all', search = '' } = req.query;
    
    let query = {};
    
    if (status && status !== 'all') {
      query.status = status;
    }
    
    if (search) {
      query.$or = [
        { orderReference: { $regex: search, $options: 'i' } },
        { 'customerInfo.email': { $regex: search, $options: 'i' } },
        { 'customerInfo.name': { $regex: search, $options: 'i' } }
      ];
    }

    const skip = (parseInt(page) - 1) * parseInt(limit);

    const orders = await Order.find(query)
      .populate('userId', 'fullName email')
      .sort({ createdAt: -1 })
      .limit(parseInt(limit))
      .skip(skip);

    const total = await Order.countDocuments(query);

    res.json({
      success: true,
      orders: orders,
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        pages: Math.ceil(total / parseInt(limit))
      }
    });
  } catch (error) {
    console.error('❌ Get orders error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch orders' });
  }
});

