app.put('/api/admin/orders/:orderId/status', authenticateAdmin, async (req, res) => {
  try {
    const { status } = req.body;

    if (!['pending', 'completed', 'failed', 'refunded', 'cancelled'].includes(status)) {
      return res.status(400).json({ success: false, message: 'Invalid status. Use: pending, completed, failed, refunded, cancelled' });
    }

    const order = await Order.findById(req.params.orderId);
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }

    order.status = status;
    await order.save();
    // ── Handle cancellation — reverse any pending commissions ──────────
    if (status === 'cancelled') {
      if (order.commissionsProcessed) {
        try {
          await EarningsLedger.updateMany(
            { orderId: order._id, status: 'confirmed' },
            { status: 'reversed', reversedAt: new Date(), reversedReason: 'order_cancelled' }
          );
          console.log(`🔄 Commissions reversed for cancelled order ${order.orderReference}`);
        } catch (e) {
          console.error('⚠️  Commission reversal error on cancel:', e.message);
        }
      }
    }

    if (status === 'refunded') {
      // ── Log the admin action ──────────────────────────────────────────
      await logRefund(req, order, req.adminUser);

      // ── Send refund email to customer ─────────────────────────────────
      const customerEmail = order.customerInfo?.email || null;
      if (customerEmail && global.sendRefundEmail) {
        // Fetch user's full name if we have userId
        let fullName = order.customerInfo?.name || 'Customer';
        if (order.userId) {
          try {
            const buyer = await User.findById(order.userId).select('fullName email');
            if (buyer) {
              fullName       = buyer.fullName || fullName;
            }
          } catch (_) {}
        }

        setImmediate(() => global.sendRefundEmail(customerEmail, {
          fullName,
          orderReference: order.orderReference,
          refundAmount:   req.body.refundAmount || order.total,
          refundReason:   req.body.refundReason || req.body.notes || 'Processed by support',
          items:          order.items || [],
          total:          order.total,
        }));
      }

      // ── Reverse affiliate commission if order had one ─────────────────
      if (order.affiliateCode && order.commissionsProcessed) {
        try {
          await EarningsLedger.updateMany(
            { orderId: order._id, recipientType: 'affiliate', status: 'confirmed' },
            { status: 'reversed', reversedAt: new Date(), reversedReason: 'order_refunded' }
          );
          console.log(`↩️  Affiliate commission reversed for order ${order.orderReference}`);
        } catch (e) {
          console.error('❌ Affiliate commission reversal error:', e.message);
        }
      }

      // ── Reverse creator earnings for this order ───────────────────────
      if (order.commissionsProcessed) {
        try {
          // Get all confirmed creator ledger entries for this order
          const creatorEntries = await EarningsLedger.find({
            orderId:       order._id,
            recipientType: 'creator',
            status:        { $in: ['confirmed', 'pending'] },
          }).lean();

          if (creatorEntries.length) {
            await EarningsLedger.updateMany(
              { orderId: order._id, recipientType: 'creator', status: { $in: ['confirmed', 'pending'] } },
              { status: 'reversed', reversedAt: new Date(), reversedReason: 'order_refunded' }
            );

            // Aggregate reversal amounts per creator
            const byCreator = {};
            creatorEntries.forEach(e => {
              const key = e.recipientId.toString();
              if (!byCreator[key]) byCreator[key] = { earned: 0, sales: 0, revenue: 0 };
              byCreator[key].earned  += e.earningAmount;
              byCreator[key].sales   += 1;
              byCreator[key].revenue += e.saleAmount;
            });

            // Decrement cached totals on each Creator document
            await Promise.all(
              Object.entries(byCreator).map(([recipientId, vals]) =>
                Creator.findOneAndUpdate(
                  { userId: new mongoose.Types.ObjectId(recipientId) },
                  {
                    $inc: {
                      totalSales:    -vals.sales,
                      totalRevenue:  -vals.revenue,
                      totalEarnings: -vals.earned,
                      pendingPayout: -vals.earned,
                    }
                  }
                )
              )
            );

            // Decrement CreatorProduct sales counts
            for (const entry of creatorEntries) {
              if (entry.creatorProductId) {
                await CreatorProduct.findByIdAndUpdate(entry.creatorProductId, {
                  $inc: { totalSales: -1, totalRevenue: -entry.saleAmount }
                });
              }
            }

            console.log(`↩️  Creator earnings reversed for order ${order.orderReference} (${creatorEntries.length} entries)`);
          }
        } catch (e) {
          console.error('❌ Creator earnings reversal error:', e.message);
        }
      }

    } else {
      await logAdminAction(req, `order_status_changed_to_${status}`, null, {
        orderId:  order._id,
        orderRef: order.orderReference
      });
    }

    res.json({
      success: true,
      message: status === 'refunded' ? 'Order refunded and customer notified' : 'Order status updated',
      order
    });
  } catch (error) {
    console.error('❌ Update order error:', error);
    res.status(500).json({ success: false, message: 'Update failed' });
  }
});

