        artist:           ad.artist           || null,
        album:            ad.album            || null,
        releaseYear:      ad.releaseYear      || null,
        genre:            ad.genre            || null,
        bpm:              ad.bpm              || null,
        key:              ad.key              || null,
        mood:             ad.mood             || null,
        duration:         ad.duration         || null,
        license:          ad.license          || null,
        stems:            ad.stems            || false,
        hasVocals:        ad.hasVocals        || false,
        loopable:         ad.loopable         || false,
        instruments:      ad.instruments      || [],
        allowedUses:      ad.allowedUses      || [],
        isrc:             ad.isrc             || null,
