        duration:      vd.duration      || null,
        resolution:    vd.resolution    || null,
        genre:         vd.genre         || null,
        language:      vd.language      || 'English',
        subtitles:     vd.subtitles     || [],
        hasCaption:    vd.hasCaption    || false,
        director:      vd.director      || null,
        cast:          vd.cast          || [],
        releaseYear:   vd.releaseYear   || null,
