// Get All Customers (Agent/Admin)
app.get('/api/customers', authenticateAgent, async (req, res) => {
  try {
    const { search = '', page = 1, limit = 20 } = req.query;
    
    let query = {};
    
    if (search) {
      query.$or = [
        { fullName: { $regex: search, $options: 'i' } },
        { email: { $regex: search, $options: 'i' } }
      ];
    }
    
    const skip = (parseInt(page) - 1) * parseInt(limit);
    
    const [customers, total] = await Promise.all([
      User.find(query)
        .select('-password -twoFactorSecret')
        .sort({ createdAt: -1 })
        .limit(parseInt(limit))
        .skip(skip),
      User.countDocuments(query)
    ]);
    
    // Add chat statistics for each customer
    const customersWithStats = await Promise.all(
      customers.map(async (customer) => {
        const chatCount = await Chat.countDocuments({ 
          customerEmail: customer.email 
        });
        
        const lastChat = await Chat.findOne({ 
          customerEmail: customer.email 
        }).sort({ createdAt: -1 });
        
        return {
          ...customer.toObject(),
          totalChats: chatCount,
          lastContactDate: lastChat?.createdAt || null,
          status: chatCount > 0 ? 'active' : 'inactive'
        };
      })
    );
    
    res.json({
      success: true,
      customers: customersWithStats,
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        pages: Math.ceil(total / parseInt(limit))
      }
    });
    
  } catch (error) {
    console.error('âŒ Get customers error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch customers' });
  }
});

// Get Customer Details
app.get('/api/customers/:customerId', authenticateAgent, async (req, res) => {
  try {
    const customer = await User.findById(req.params.customerId)
      .select('-password -twoFactorSecret');
    
    if (!customer) {
      return res.status(404).json({ success: false, message: 'Customer not found' });
    }
    
    // Get customer's chat history
    const chats = await Chat.find({ customerEmail: customer.email })
      .sort({ createdAt: -1 })
      .limit(10);
    
    // Get customer's orders
    const orders = await Order.find({ userId: customer._id })
      .sort({ createdAt: -1 })
      .limit(5);
    
    // Get customer's tickets
    const tickets = await SupportTicket.find({ userId: customer._id })
      .sort({ createdAt: -1 })
      .limit(5);
    
    res.json({
      success: true,
      customer: {
        ...customer.toObject(),
        recentChats: chats,
        recentOrders: orders,
        recentTickets: tickets,
        totalChats: chats.length,
        totalOrders: orders.length,
        totalTickets: tickets.length
      }
    });
    
  } catch (error) {
    console.error('âŒ Get customer details error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch customer details' });
  }
});

// ── GET notifications for any authenticated user ──────────────────────────
// Works for users, agents, admins, and creators — same endpoint.
// Query params:
//   ?page=1&limit=20        — pagination
//   ?unread=true            — only unread
//   ?type=order_completed   — filter by type
app.get('/api/notifications', authenticateToken, async (req, res) => {
  try {
    const page    = Math.max(1, parseInt(req.query.page)  || 1);
    const limit   = Math.min(50, parseInt(req.query.limit) || 20);
    const skip    = (page - 1) * limit;
 
    const filter  = {
      recipientId: req.user.userId,
      dismissed:   false,
    };
 
    if (req.query.unread === 'true') filter.read = false;
    if (req.query.type)              filter.type = req.query.type;
 
    const [notifications, total, unreadCount] = await Promise.all([
      Notification.find(filter)
                  .sort({ createdAt: -1 })
                  .skip(skip)
                  .limit(limit)
                  .lean(),
      Notification.countDocuments(filter),
      Notification.countDocuments({ recipientId: req.user.userId, read: false, dismissed: false }),
    ]);
 
    res.json({
      success: true,
      notifications,
      unreadCount,
      pagination: {
        page,
        limit,
        total,
        pages: Math.ceil(total / limit),
        hasMore: skip + notifications.length < total,
      },
    });
  } catch (err) {
    console.error('❌ GET /api/notifications:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch notifications' });
  }
});
 
 
