// ── NOTIFICATION PREFERENCES (replaces both old pref routes) ──────────────
// Kept here so the old /api/profile/notifications and
// /api/user/notifications/update callers don't break.
app.put('/api/notifications/preferences', authenticateToken, async (req, res) => {
  try {
    const { email, orders, marketing } = req.body;
    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });
 
    if (email     !== undefined) user.notificationPreferences.email     = !!email;
    if (orders    !== undefined) user.notificationPreferences.orders    = !!orders;
    if (marketing !== undefined) user.notificationPreferences.marketing = !!marketing;
    await user.save();
 
    res.json({ success: true, preferences: user.notificationPreferences });
  } catch (err) {
    res.status(500).json({ success: false, message: 'Failed to update preferences' });
  }
});

// ── PUT /api/creator/notifications/preferences — save creator-specific notification prefs ──
app.put('/api/creator/notifications/preferences', authenticateToken, async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator) {
      return res.status(404).json({ success: false, message: 'Creator profile not found' });
    }

    const { newSale, newReview, newFollower, payoutUpdate, productUpdate, weeklySummary } = req.body;

    if (!creator.creatorNotifPrefs) {
      creator.creatorNotifPrefs = {
        newSale: true, newReview: true, newFollower: true,
        payoutUpdate: true, productUpdate: true, weeklySummary: false,
      };
    }

    if (newSale       !== undefined) creator.creatorNotifPrefs.newSale       = !!newSale;
    if (newReview     !== undefined) creator.creatorNotifPrefs.newReview     = !!newReview;
    if (newFollower   !== undefined) creator.creatorNotifPrefs.newFollower   = !!newFollower;
    if (payoutUpdate  !== undefined) creator.creatorNotifPrefs.payoutUpdate  = !!payoutUpdate;
    if (productUpdate !== undefined) creator.creatorNotifPrefs.productUpdate = !!productUpdate;
    if (weeklySummary !== undefined) creator.creatorNotifPrefs.weeklySummary = !!weeklySummary;

    creator.markModified('creatorNotifPrefs');
    await creator.save();

    res.json({ success: true, preferences: creator.creatorNotifPrefs });
  } catch (error) {
    console.error('❌ Creator notification preferences error:', error);
    res.status(500).json({ success: false, message: 'Failed to update preferences' });
  }
});

// Alias routes — forward body and user context directly to the real handler
// (res._router does not exist; 307 redirect changes PUT to GET on some clients)
async function _handleNotificationPreferences(req, res) {
  try {
    const { email, orders, marketing } = req.body;
    const user = await User.findById(req.user.userId);
    if (!user) return res.status(404).json({ success: false, message: 'User not found' });

    if (email     !== undefined) user.notificationPreferences.email     = !!email;
    if (orders    !== undefined) user.notificationPreferences.orders    = !!orders;
    if (marketing !== undefined) user.notificationPreferences.marketing = !!marketing;
    await user.save();

    res.json({ success: true, preferences: user.notificationPreferences });
  } catch (err) {
    res.status(500).json({ success: false, message: 'Failed to update preferences' });
  }
}

app.put('/api/profile/notifications',     authenticateToken, _handleNotificationPreferences);
app.put('/api/user/notifications/update', authenticateToken, _handleNotificationPreferences);
 
 
// ── ADMIN — send a system broadcast to all users / staff ──────────────────
app.post('/api/admin/notifications/broadcast', authenticateAdmin, async (req, res) => {
  try {
    const { title, message, targetRole, url } = req.body;
    if (!title || !message) {
      return res.status(400).json({ success: false, message: 'title and message are required' });
    }
 
    const validRoles = ['user', 'agent', 'admin', 'creator', 'affiliate', 'all'];
    if (targetRole && !validRoles.includes(targetRole)) {
      return res.status(400).json({ success: false, message: `targetRole must be one of: ${validRoles.join(', ')}` });
    }
 
    // Build user query
    const query = {};
    if (!targetRole || targetRole === 'all') {
      // Everyone — no filter
    } else if (targetRole === 'admin')  { query.isAdmin = true; }
    else if (targetRole === 'agent')    { query.isAgent = true; }
    else if (targetRole === 'creator')  { query.isCreator = true; }
 
    const users = await User.find(query).select('_id isAdmin isAgent isCreator').lean();
    let created = 0;
 
    for (const u of users) {
      const role = u.isAdmin ? 'admin' : u.isAgent ? 'agent' : u.isCreator ? 'creator' : 'user';
      await createNotification(u._id, role, 'system', title, message, { url: url || '/' });
      created++;
    }
 
    console.log(`📣 Broadcast by ${req.adminUser.email}: "${title}" → ${created} recipients`);
    res.json({ success: true, message: `Broadcast sent to ${created} user(s)`, recipientCount: created });
 
  } catch (err) {
    console.error('❌ Broadcast notification:', err);
    res.status(500).json({ success: false, message: 'Broadcast failed' });
  }
});
 
 
// ── ADMIN — get all notifications (admin view with filters) ───────────────
app.get('/api/admin/notifications', authenticateAdmin, async (req, res) => {
  try {
    const page  = Math.max(1, parseInt(req.query.page) || 1);
    const limit = Math.min(50, parseInt(req.query.limit) || 30);
    const skip  = (page - 1) * limit;
 
    // Admin sees their own notifications; for oversight of all, use the
    // broadcast route or the admin dashboard aggregations
    const filter = { recipientId: req.adminUser._id, dismissed: false };
    if (req.query.unread === 'true') filter.read = false;
 
    const [notifications, total, unreadCount] = await Promise.all([
      Notification.find(filter).sort({ createdAt: -1 }).skip(skip).limit(limit).lean(),
      Notification.countDocuments(filter),
      Notification.countDocuments({ recipientId: req.adminUser._id, read: false, dismissed: false }),
    ]);
 
    res.json({ success: true, notifications, unreadCount, pagination: {
      page, limit, total, pages: Math.ceil(total / limit)
    }});
  } catch (err) {
    console.error('❌ Admin notifications:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch admin notifications' });
  }
});
 
