// Get orders with full product details including download links
app.get('/api/orders/detailed', authenticateToken, async (req, res) => {
  try {
    const orders = await Order.find({ userId: req.user.userId })
      .sort({ createdAt: -1 });

    // Enhance orders with full product details including download links
    const enhancedOrders = await Promise.all(
      orders.map(async (order) => {
        const enhancedItems = await Promise.all(
          order.items.map(async (item) => {
            // Try to find product by MongoDB ID first, then by title
            let product = null;
            if (mongoose.Types.ObjectId.isValid(item.id)) {
              product = await Product.findById(item.id);
            }
            if (!product) {
              product = await Product.findOne({ title: item.title });
            }
            
            return {
              ...item.toObject(),
              downloadLink: product?.downloadLink || '',
              image: product?.image || item.icon || '',
              description: product?.description || '',
              fileSize: product?.fileSize || '',
              version: product?.version || '',
              productId: product?._id || null
            };
          })
        );

        return {
          ...order.toObject(),
          items: enhancedItems,
          canDownload: order.status === 'completed'
        };
      })
    );

    res.json({
      success: true,
      orders: enhancedOrders,
      count: enhancedOrders.length
    });
  } catch (error) {
    console.error('❌ Get detailed orders error:', error);
    res.status(500).json({ 
      success: false, 
      message: 'Failed to fetch orders' 
    });
  }
});

// Track downloads
app.post('/api/orders/track-download', authenticateToken, async (req, res) => {
  try {
    const { productId, orderId } = req.body;

    if (!productId || !orderId) {
      return res.status(400).json({
        success: false,
        message: 'Product ID and Order ID required'
      });
    }

    // Verify user owns this order
    const order = await Order.findOne({ _id: orderId, userId: req.user.userId });
    if (!order) {
      return res.status(403).json({
        success: false,
        message: 'Order not found or access denied'
      });
    }

    if (order.status !== 'completed') {
      return res.status(403).json({
        success: false,
        message: 'Order must be completed to download'
      });
    }

    const download = new Download({
      userId: req.user.userId,
      productId,
      orderId,
      ipAddress: req.ip,
      userAgent: req.headers['user-agent']
    });

    await download.save();
   trackDownload();
    res.json({
      success: true,
      message: 'Download tracked successfully'
    });
  } catch (error) {
    console.error('❌ Track download error:', error);
    res.status(500).json({ 
      success: false, 
      message: 'Failed to track download' 
    });
  }
});

// ══════════════════════════════════════════════════════════════════════════════
// SECURE PRODUCT DELIVERY — generates a time-limited signed URL
// Called after payment verified. Never exposes raw Cloudinary publicId to client.
// ══════════════════════════════════════════════════════════════════════════════
app.post('/api/orders/get-delivery', authenticateToken, async (req, res) => {
  try {
    const { orderId, productId } = req.body;

    if (!orderId || !productId) {
      return res.status(400).json({ success: false, message: 'orderId and productId required' });
    }

    // Verify ownership
    const order = await Order.findOne({ _id: orderId, userId: req.user.userId });
    if (!order) return res.status(403).json({ success: false, message: 'Order not found or access denied' });
    if (order.status !== 'completed' || order.paymentInfo?.status !== 'successful') {
      return res.status(403).json({ success: false, message: 'Payment not yet verified' });
    }

    // Find the product
    let product = null;
    if (mongoose.Types.ObjectId.isValid(productId)) {
      product = await Product.findById(productId);
    }
    if (!product) {
      return res.status(404).json({ success: false, message: 'Product not found' });
    }

    const delivery = { productId: product._id, title: product.title, productType: product.productType };

    if (product.productType === 'course') {
      // For courses: return the section/chapter structure with
      // per-chapter signed URLs (1hr expiry each)
      const sections = (product.courseData?.sections || []).map(section => ({
        sectionTitle: section.sectionTitle,
        sectionOrder: section.sectionOrder,
        chapters: (section.chapters || []).map(ch => {
          const AUDIO_FMTS        = ['mp3','wav','ogg','aac','flac','m4a','wma','opus','aiff'];
          const VIDEO_EMBED_TYPES = ['youtube','vimeo','dailymotion','gdrive'];
          const AUDIO_EMBED_TYPES = ['soundcloud','spotify','audiomack','youtube_music','mixcloud','bandcamp','apple_music','deezer'];

          let chapterUrl = null;
          let pdfUrl     = null;
          let playerType = ch.playerType || null;

          // ── STEP 1: Hosted Cloudinary file (PDF / audio / video) ────────────
          if (ch.hostedFile?.publicId) {
            const hfFmt  = (ch.hostedFile.format || '').toLowerCase();
            const hfUrl  = (ch.hostedFile.secureUrl   || '').toLowerCase().split('?')[0];
            const hfName = (ch.hostedFile.originalName || ch.hostedFile.publicId || '').toLowerCase();
            const isPdf  = hfFmt === 'pdf' || hfUrl.endsWith('.pdf') || hfName.endsWith('.pdf') || ch.chapterType === 'pdf';

            if (isPdf) {
              pdfUrl     = `${BACKEND_URL}/api/orders/${orderId}/pdf-chapter?productId=${productId}&publicId=${encodeURIComponent(ch.hostedFile.publicId)}`;
              chapterUrl = null;
              playerType = 'pdf_viewer';
            } else {
              chapterUrl = ch.hostedFile.secureUrl
                || generateSecureDeliveryUrl(ch.hostedFile.publicId, ch.hostedFile.resourceType || 'raw', 3600, false);
              if (!playerType) {
                const hfId = (ch.hostedFile.publicId || '').toLowerCase();
                const isAudio = ch.chapterType === 'audio'
                  || ch.mediaType === 'audio'
                  || AUDIO_FMTS.includes(hfFmt)
                  || AUDIO_FMTS.some(ext => hfId.endsWith('.' + ext));
                playerType = isAudio ? 'cloudinary_audio' : 'cloudinary';
              }
            }
          }

          // ── STEP 2: Embedded media — use split fields first ──────────────────
          // ch.embedVideoUrl and ch.embedAudioUrl are already the final embed URLs
          // set by processChaptersForDelivery. Trust them directly.
          // Only re-parse ch.externalUrl when split fields are completely absent
          // (handles chapters saved before split-field logic existed).
          let retEmbedVideoUrl  = ch.embedVideoUrl  || null;
          let retEmbedVideoType = ch.embedVideoType || null;
          let retEmbedAudioUrl  = ch.embedAudioUrl  || null;
          let retEmbedAudioType = ch.embedAudioType || null;

          if (!retEmbedVideoUrl && !retEmbedAudioUrl && !chapterUrl && playerType !== 'pdf_viewer') {
            const isAudioChapter = ch.chapterType === 'audio' || ch.mediaType === 'audio';
            const rawSrc = ch.externalUrl || null;
            if (rawSrc) {
              const parsed = parseExternalMediaUrl(rawSrc);
              const isKnown = parsed.embedType && parsed.embedType !== 'unknown';
              if (parsed.mediaCategory === 'audio' || isAudioChapter) {
                retEmbedAudioUrl  = isKnown ? parsed.embedUrl  : rawSrc;
                retEmbedAudioType = isKnown ? parsed.embedType : 'direct';
              } else {
                retEmbedVideoUrl  = isKnown ? parsed.embedUrl  : rawSrc;
                retEmbedVideoType = isKnown ? parsed.embedType : 'direct';
              }
            }
          }

          // ── STEP 3: Derive playerType from split embed fields ────────────────
          if (!playerType) {
            if (retEmbedVideoUrl) {
              const et = retEmbedVideoType || '';
              playerType = VIDEO_EMBED_TYPES.includes(et) ? 'iframe'
                : et === 'direct' ? 'html5_video' : 'iframe';
            } else if (retEmbedAudioUrl) {
              const et = retEmbedAudioType || '';
              playerType = AUDIO_EMBED_TYPES.includes(et) ? 'soundcloud_widget'
                : et === 'direct' ? 'html5_audio' : 'soundcloud_widget';
            }
          }

          // ── STEP 4: Correct stale playerType mismatches ──────────────────────
          // If stored playerType is 'iframe' but this is an audio-only chapter, fix it
          if (playerType === 'iframe' && retEmbedAudioUrl && !retEmbedVideoUrl) {
            const et = retEmbedAudioType || '';
            playerType = AUDIO_EMBED_TYPES.includes(et) ? 'soundcloud_widget'
              : et === 'direct' ? 'html5_audio' : 'soundcloud_widget';
          }
          // If stored playerType is 'soundcloud_widget' but this is a video embed, fix it
          if (playerType === 'soundcloud_widget' && retEmbedVideoUrl && !retEmbedAudioUrl) {
            const et = retEmbedVideoType || '';
            playerType = VIDEO_EMBED_TYPES.includes(et) ? 'iframe' : 'html5_video';
          }

          // ── STEP 5: Build legacy embedUrl/embedType for older frontend code ──
          const legacyEmbedUrl  = retEmbedVideoUrl  || retEmbedAudioUrl  || null;
          const legacyEmbedType = retEmbedVideoType || retEmbedAudioType || null;

          // ── STEP 6: Final chapterType ────────────────────────────────────────
          const retChapterType = ch.chapterType
            || (playerType === 'pdf_viewer'                    ? 'pdf'
              : (retEmbedAudioUrl && !retEmbedVideoUrl)        ? 'audio'
              : 'video');

          return {
            chapterTitle:   ch.chapterTitle || 'Chapter',
            chapterOrder:   ch.chapterOrder ?? 0,
            chapterType:    retChapterType,
            mediaType:      ch.mediaType || (retChapterType === 'audio' ? 'audio' : null),
            duration:       ch.duration   || null,
            notes:          ch.notes      || null,
            transcript:     ch.transcript || null,
            isFree:         true,
            isUnlocked:     true,
            cloudinaryUrl:  chapterUrl    || null,
            chapterUrl:     chapterUrl    || null,
            pdfUrl:         pdfUrl        || null,
            embedVideoUrl:  retEmbedVideoUrl,
            embedVideoType: retEmbedVideoType,
            embedAudioUrl:  retEmbedAudioUrl,
            embedAudioType: retEmbedAudioType,
            embedUrl:       legacyEmbedUrl,
            embedType:      legacyEmbedType,
            playerType,
          };
        })
      }));

      delivery.type = 'course';
      delivery.courseData = {
        totalDuration: product.courseData?.totalDuration,
        totalChapters: product.courseData?.totalChapters,
        level:         product.courseData?.level,
        certificate:   product.courseData?.certificate,
        sections
      };

  } else {
      // For all other types: generate delivery URL
      let fileUrl = null;

      if (product.hostedFile?.publicId) {
        const _rt          = product.hostedFile.resourceType || 'raw';
        const _isStreamable = _rt === 'video' || _rt === 'image'
          || product.productType === 'music'
          || product.productType === 'video';

        if (_isStreamable) {
          // Stream directly — public Cloudinary URL, plays instantly
          fileUrl = product.hostedFile.secureUrl
            || generateSecureDeliveryUrl(product.hostedFile.publicId, _rt, 7200, false);
        } else {
          // Raw download (ZIP, PDF, software, ebook, template, script, component).
          // Point at the proxy route — it streams raw bytes and sets the correct
          // Content-Disposition with the real original filename.
          // This eliminates the filename corruption and file-size mismatch.
          fileUrl = `/api/download/file?orderId=${orderId}&productId=${productId}`;
        }
      } else if (product.externalVideoUrl || product.externalAudioUrl) {
        // Music, audio, and video embed products delivered via external URL
        const rawUrl = product.externalVideoUrl || product.externalAudioUrl;
        let resolvedEmbedUrl  = product.embedUrl  || null;
        let resolvedEmbedType = product.embedType || null;

        if (!resolvedEmbedUrl && typeof parseExternalMediaUrl === 'function') {
          const parsed = parseExternalMediaUrl(rawUrl);
          if (parsed.embedType && parsed.embedType !== 'unknown') {
            resolvedEmbedUrl  = parsed.embedUrl;
            resolvedEmbedType = parsed.embedType;
          }
        }

        delivery.type      = 'embed';
        delivery.embedUrl  = resolvedEmbedUrl  || rawUrl;
        delivery.embedType = resolvedEmbedType || null;
        delivery.mediaType = product.externalVideoUrl ? 'video' : 'audio';

        if (resolvedEmbedType === 'soundcloud') {
          delivery.playerType = 'soundcloud_widget';
        } else if (['youtube','vimeo','dailymotion','gdrive'].includes(resolvedEmbedType)) {
          delivery.playerType = 'iframe';
        } else if (resolvedEmbedType === 'direct') {
          // FIX: use externalAudioUrl presence AND extension check, not just externalVideoUrl
          const AUDIO_EXT = ['mp3','wav','ogg','aac','flac','m4a','wma','opus','aiff'];
          const lUrl = (resolvedEmbedUrl || '').toLowerCase().split('?')[0];
          const isDirectAudio =
            !!product.externalAudioUrl && !product.externalVideoUrl ||
            AUDIO_EXT.some(ext => lUrl.endsWith('.' + ext)) ||
            product.productType === 'music' ||
            product.mediaType   === 'audio';
          delivery.playerType = isDirectAudio ? 'html5_audio' : 'html5_video';
        } else {
          // FIX: null/unknown resolvedEmbedType — don't default to iframe which breaks audio.
          // Use mediaType / productType as the final signal.
          const isAudioFallback =
            product.productType === 'music'  ||
            product.mediaType   === 'audio'  ||
            (!!product.externalAudioUrl && !product.externalVideoUrl);
          delivery.playerType = isAudioFallback ? 'html5_audio' : 'iframe';
        }

        delivery.fileUrl = null;
      } else if (product.downloadLink) {
        // Fallback: still support external links for older products
        fileUrl = product.downloadLink;
      }

      if (delivery.type !== 'embed') {
        delivery.type    = 'file';
        delivery.fileUrl = fileUrl;
      }
      delivery.fileSize = product.fileSize || formatBytes(product.hostedFile?.bytes);
      delivery.version  = product.version;
      delivery.format   = product.hostedFile?.format;

      // Specific extras per type
      if (product.productType === 'music' && product.audioData) {
        delivery.audioData = {
          bpm:      product.audioData.bpm,
          key:      product.audioData.key,
          genre:    product.audioData.genre,
          license:  product.audioData.license,
          stems:    product.audioData.stems,
        };
      }
      if (product.productType === 'video' && product.videoData) {
        delivery.videoData = {
          duration:      product.videoData.duration      || null,
          resolution:    product.videoData.resolution    || null,
          genre:         product.videoData.genre         || null,
          language:      product.videoData.language      || 'English',
          subtitles:     product.videoData.subtitles     || [],
          license:       product.videoData.license       || 'personal',
          allowDownload: product.videoData.allowDownload || false,
        };
      }
      if (product.productType === 'software' && product.softwareData) {
        delivery.softwareData = {
          platform:      product.softwareData.platform,
          licenseType:   product.softwareData.licenseType,
          licenseKey:    product.softwareData.licenseKey,
          supportPeriod: product.softwareData.supportPeriod,
        };
      }if (product.productType === 'software' && product.softwareData) {
        // Issue one key from the pool per order (pop atomically)
        let issuedKey = null;
        if (product.softwareData.licenseKeys?.length > 0) {
          const updated = await Product.findByIdAndUpdate(
            product._id,
            { $pop: { 'softwareData.licenseKeys': -1 } }, // -1 pops from front of array
            { new: false }  // return doc BEFORE update to get the key we just popped
          ).lean();
          issuedKey = updated?.softwareData?.licenseKeys?.[0] || null;
        }
        delivery.softwareData = {
          platform:       product.softwareData.platform      || [],
          licenseType:    product.softwareData.licenseType   || 'single',
          licenseKey:     issuedKey,                          // null if pool empty
          maxDevices:     product.softwareData.maxDevices    || 1,
          supportPeriod:  product.softwareData.supportPeriod || null,
          updatePeriod:   product.softwareData.updatePeriod  || null,
          activationUrl:  product.softwareData.activationUrl || null,
          demoUrl:        product.softwareData.demoUrl       || null,
          changelog:      product.softwareData.changelog     || null,
        };
      }
    }

    // Log the access
    setImmediate(async () => {
      try {
        const dl = new Download({ userId: req.user.userId, productId: product._id, orderId });
        await dl.save();
      } catch (_) {}
    });

    res.json({ success: true, delivery });

  } catch (error) {
    console.error('❌ Secure delivery error:', error);
    res.status(500).json({ success: false, message: 'Failed to generate delivery' });
  }
});

// Admin: View download statistics
app.get('/api/admin/downloads/stats', authenticateAdmin, async (req, res) => {
  try {
    const totalDownloads = await Download.countDocuments();
    
    const popularProducts = await Download.aggregate([
      { 
        $group: { 
          _id: '$productId', 
          count: { $sum: 1 } 
        } 
      },
      { $sort: { count: -1 } },
      { $limit: 10 },
      {
        $lookup: {
          from: 'products',
          localField: '_id',
          foreignField: '_id',
          as: 'product'
        }
      },
      { $unwind: { path: '$product', preserveNullAndEmptyArrays: true } }
    ]);

    const recentDownloads = await Download.find()
      .populate('userId', 'fullName email')
      .populate('productId', 'title category')
      .sort({ downloadedAt: -1 })
      .limit(20);

    // Downloads by date (last 30 days)
    const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
    const downloadsByDate = await Download.aggregate([
      { $match: { downloadedAt: { $gte: thirtyDaysAgo } } },
      {
        $group: {
          _id: { $dateToString: { format: '%Y-%m-%d', date: '$downloadedAt' } },
          count: { $sum: 1 }
        }
      },
      { $sort: { _id: 1 } }
    ]);

    res.json({
      success: true,
      stats: {
        totalDownloads,
        popularProducts,
        recentDownloads,
        downloadsByDate
      }
    });
  } catch (error) {
    console.error('❌ Download stats error:', error);
    res.status(500).json({ 
      success: false, 
      message: 'Failed to fetch stats' 
    });
  }
});

// ========== PRODUCT MANAGEMENT ==========
app.get('/api/admin/products', authenticateAdmin, async (req, res) => {
  try {
    const { page = 1, limit = 20, category = 'all', status = 'all', search = '' } = req.query;
    
    let query = {};
    
    if (category && category !== 'all') {
      query.category = category;
    }
    
    if (status === 'active') {
      query.isActive = true;
    } else if (status === 'inactive') {
      query.isActive = false;
    } else if (status === 'featured') {
      query.isFeatured = true;
    }
    
    if (search) {
      query.$or = [
        { title: { $regex: search, $options: 'i' } },
        { description: { $regex: search, $options: 'i' } }
      ];
    }

    const skip = (parseInt(page) - 1) * parseInt(limit);

   const products = await Product.find(query)
      .sort({ createdAt: -1 })
      .limit(parseInt(limit))
      .skip(parseInt(skip))
      .select('-hostedFile.secureUrl -hostedFile.publicId -courseData.sections.chapters.hostedFile');
      // ↑ Never send raw Cloudinary credentials to the public listing

    const total = await Product.countDocuments(query);

    res.json({
      success: true,
      products: products,
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        pages: Math.ceil(total / parseInt(limit))
      }
    });
  } catch (error) {
    console.error('❌ Get products error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch products' });
  }
});

