// ── PUT /api/admin/coupons/:id/review — approve or reject a creator coupon ────
// Body: { action: 'approve' | 'reject', adminNote (optional) }
//
// approve → isActive = true, adminApprovalStatus = 'approved'
// reject  → isActive = false, adminApprovalStatus = 'rejected', paymentStatus = 'refunded'
//           (admin must manually process the refund outside the system)
app.put('/api/admin/coupons/:id/review', authenticateAdmin, async (req, res) => {
  try {
    const { action, adminNote } = req.body;
    if (!['approve', 'reject'].includes(action)) {
      return res.status(400).json({ success: false, message: 'action must be "approve" or "reject"' });
    }

    const coupon = await Coupon.findOne({
      _id:            req.params.id,
      ownerCreatorId: { $ne: null },
      paymentStatus:  'paid',
    });

    if (!coupon) {
      return res.status(404).json({
        success: false,
        message: 'Coupon not found, not creator-owned, or not yet paid',
      });
    }

    if (coupon.adminApprovalStatus === 'approved') {
      return res.status(400).json({ success: false, message: 'Coupon is already approved' });
    }

    coupon.adminNote  = adminNote || null;
    coupon.approvedBy = req.user?.userId || null;
    coupon.approvedAt = new Date();

    if (action === 'approve') {
      coupon.isActive             = true;
      coupon.adminApprovalStatus  = 'approved';
      console.log(`✅ Admin approved coupon: ${coupon.code}`);
    } else {
      coupon.isActive             = false;
      coupon.adminApprovalStatus  = 'rejected';
      coupon.paymentStatus        = 'refunded'; // flag for manual refund
      console.log(`❌ Admin rejected coupon: ${coupon.code} — note: ${adminNote}`);
    }

    await coupon.save();

    // ── Notify creator by email ───────────────────────────────────────────
    try {
      const creatorUser = await User.findById(coupon.createdBy).select('email name').lean();
      if (creatorUser?.email) {
        queueEmail(async () => {
          const resend = new Resend(process.env.RESEND_API_KEY);
          const subject = action === 'approve'
            ? `✅ Your coupon "${coupon.code}" has been approved!`
            : `❌ Your coupon "${coupon.code}" was not approved`;
          const body = action === 'approve'
            ? `<p>Good news! Your coupon <strong>${coupon.code}</strong> has been approved and is now active. Buyers can start using it immediately.</p>`
            : `<p>Your coupon <strong>${coupon.code}</strong> was not approved.</p>${adminNote ? `<p><strong>Reason:</strong> ${adminNote}</p>` : ''}<p>Please contact support for a refund of your platform fee.</p>`;
          await resend.emails.send({
            from:    'UYEH TECH <noreply@uyehtech.com>',
            to:      creatorUser.email,
            subject,
            html:    `<div style="font-family:sans-serif;max-width:500px;">${body}</div>`,
          });
        });
      }
    } catch (notifyErr) {
      console.warn('Coupon review notification failed (non-fatal):', notifyErr.message);
    }
    // Write AdminLog
    try {
      if (typeof logCouponAction === 'function') {
        await logCouponAction({ user: req.user }, action === 'approve' ? 'approve' : 'reject', coupon);
      }
    } catch (_) {}

    return res.json({
      success: true,
      message: action === 'approve' ? 'Coupon approved and activated' : 'Coupon rejected. Please process refund manually.',
      coupon: {
        _id:                 coupon._id,
        code:                coupon.code,
        isActive:            coupon.isActive,
        adminApprovalStatus: coupon.adminApprovalStatus,
        paymentStatus:       coupon.paymentStatus,
        adminNote:           coupon.adminNote,
        approvedAt:          coupon.approvedAt,
      },
    });
  } catch (error) {
    console.error('❌ Admin coupon review error:', error);
    res.status(500).json({ success: false, message: 'Review failed' });
  }
});

// ── POST /api/coupons/validate — validate coupon & enforce creator scope ───────
// Body: { code, orderTotal, items (array of { productId or id }) }
//
// For creator coupons: every item in the cart must belong to the coupon's creator.
// Items that don't belong are reported so the frontend can warn the user.
app.post('/api/coupons/validate', authenticateToken, async (req, res) => {
  try {
    const { code, orderTotal, items } = req.body;
    if (!code) {
      return res.status(400).json({ success: false, message: 'Coupon code required' });
    }

    const cleanCode  = code.trim().toUpperCase();
    const coupon     = await Coupon.findOne({ code: cleanCode });

    if (!coupon) {
      return res.status(404).json({ success: false, message: `Invalid coupon "${cleanCode}"` });
    }
    if (!coupon.isActive) {
      return res.status(400).json({ success: false, message: 'This coupon is not active' });
    }
    if (coupon.expiresAt && new Date() > coupon.expiresAt) {
      return res.status(400).json({ success: false, message: 'Coupon has expired' });
    }

    // ── Per-user usage check ──────────────────────────────────────────────
    const alreadyUsed = await CouponUsage.findOne({ couponCode: cleanCode, userId: req.user.userId });
    if (alreadyUsed) {
      return res.status(400).json({ success: false, message: 'You have already used this coupon' });
    }

    if (coupon.usageLimit && coupon.usageCount >= coupon.usageLimit) {
      return res.status(400).json({ success: false, message: 'Coupon usage limit reached' });
    }

    // minPurchaseAmount is checked after scope resolution for creator coupons (see below).
    // For platform coupons check it immediately.
    if (!coupon.ownerCreatorId && orderTotal < coupon.minPurchaseAmount) {
      return res.status(400).json({
        success: false,
        message: `Minimum purchase of ₦${coupon.minPurchaseAmount} required`,
      });
    }

    // ── Creator-scope enforcement ─────────────────────────────────────────
    // Only runs when this is a creator-issued coupon (ownerCreatorId is set).
    if (coupon.ownerCreatorId) {
      const cartItems = Array.isArray(items) ? items : [];

      if (cartItems.length === 0) {
        return res.status(400).json({
          success: false,
          message: 'Cart items are required to validate a creator coupon',
        });
      }

      // Resolve each cart item to its owning creator
      const itemProductIds = cartItems.map(i => i.productId || i.id).filter(Boolean);

      // Look up via Product (has creatorId after approval pipeline)
      const products = await Product.find({ _id: { $in: itemProductIds } })
        .select('_id creatorId').lean();

      // Also check CreatorProduct table (for items where productId = CreatorProduct._id)
      const creatorProds = await CreatorProduct.find({ _id: { $in: itemProductIds } })
        .select('_id creatorId').lean();

      const ownerIdStr = coupon.ownerCreatorId.toString();

      // Build a map of productId → belongs to coupon's creator
      const productOwnership = {};
      for (const p of products) {
        productOwnership[p._id.toString()] = p.creatorId?.toString() === ownerIdStr;
      }
      for (const cp of creatorProds) {
        productOwnership[cp._id.toString()] = cp.creatorId?.toString() === ownerIdStr;
      }

        // Check minimum purchase against the eligible subtotal
        if (coupon.minPurchaseAmount && eligibleSubtotal < coupon.minPurchaseAmount) {
          return res.status(400).json({
            success: false,
            message: `Minimum purchase of ₦${coupon.minPurchaseAmount} from this creator's products is required`,
          });
        }

      const outsideItems = itemProductIds.filter(id => !productOwnership[id.toString()]);
      const eligibleItems = itemProductIds.filter(id => productOwnership[id.toString()] === true);

      if (eligibleItems.length === 0) {
        return res.status(400).json({
          success: false,
          message: 'This coupon only works on products from the issuing creator. None of your cart items qualify.',
        });
      }

      // ── Specific product opt-in restriction ────────────────────────────
      // If the creator has set allowedProductIds, further restrict.
      if (coupon.allowedProductIds && coupon.allowedProductIds.length > 0) {
        const allowedSet = new Set(coupon.allowedProductIds.map(id => id.toString()));
        const finalEligible = eligibleItems.filter(id => allowedSet.has(id.toString()));
        if (finalEligible.length === 0) {
          return res.status(400).json({
            success: false,
            message: 'This coupon is restricted to specific products from the creator and none of your cart items match.',
          });
        }
      }

      // Warn but allow if some items are from other sellers (discount only on eligible ones)
     if (outsideItems.length > 0) {
        // Compute discount on only the eligible subtotal
        const eligibleSubtotal = cartItems
          .filter(i => eligibleItems.includes((i.productId || i.id)?.toString()))
          .reduce((sum, i) => sum + (Number(i.price) || 0), 0);

        let partialDiscount;
        if (coupon.type === 'percentage') {
          partialDiscount = (eligibleSubtotal * coupon.discount) / 100;
          if (coupon.maxDiscountAmount) partialDiscount = Math.min(partialDiscount, coupon.maxDiscountAmount);
        } else {
          partialDiscount = coupon.discount;
        }
        partialDiscount = Math.min(partialDiscount, eligibleSubtotal);

        return res.json({
          success:            true,
          partialScope:       true,
          eligibleProductIds: eligibleItems,
          outsideProductIds:  outsideItems,
          eligibleSubtotal,
          discountAmount:     partialDiscount,
          finalAmount:        Math.max(0, orderTotal - partialDiscount),
          warning:            `This coupon only applies to ${eligibleItems.length} of your ${cartItems.length} cart item(s). The discount will apply to those items only.`,
          coupon: {
            code:          coupon.code,
            discount:      coupon.discount,
            type:          coupon.type,
            discountAmount: partialDiscount,
          },
        });
      }
    }

    // ── Compute discount ──────────────────────────────────────────────────
    let discountAmount;
    if (coupon.type === 'percentage') {
      discountAmount = (orderTotal * coupon.discount) / 100;
      if (coupon.maxDiscountAmount) discountAmount = Math.min(discountAmount, coupon.maxDiscountAmount);
    } else {
      discountAmount = coupon.discount;
    }
    discountAmount    = Math.min(discountAmount, orderTotal);
    const finalAmount = Math.max(0, orderTotal - discountAmount);
    const isFree      = finalAmount === 0;

    return res.json({
      success: true,
      coupon: {
        code:           coupon.code,
        discount:       coupon.discount,
        type:           coupon.type,
        discountAmount,
        finalAmount,
        isFree,
      },
      message: isFree ? '🎉 Order is FREE!' : `✅ Saved ₦${discountAmount.toFixed(2)}`,
    });
  } catch (error) {
    console.error('❌ Validate coupon error:', error);
    res.status(500).json({ success: false, message: 'Validation failed' });
  }
});

