// ── GLOBAL SEARCH ROUTE ───────────────────────────────────────────────────
// GET /api/search?q=keyword&scope=all&page=1&limit=10
//
// scope options: 'all' | 'products' | 'blog' | 'creators' | 'users' (admin only)
// Returns results grouped by type, with relevance scores and match snippets.
app.get('/api/search', async (req, res) => {
  try {
    const raw   = (req.query.q || '').trim();
    const scope = req.query.scope || 'all';
    const page  = Math.max(1, parseInt(req.query.page)  || 1);
    const limit = Math.min(20, parseInt(req.query.limit) || 10);
    const skip  = (page - 1) * limit;
 
    if (!raw || raw.length < 2) {
      return res.status(400).json({
        success: false,
        message: 'Search query must be at least 2 characters'
      });
    }
 
    // Sanitise query — strip regex chars to prevent injection
    const q      = raw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const textQ  = { $search: raw };   // for $text index queries
    const regexQ = new RegExp(q, 'i'); // for fallback regex on fields without text index
 
    // Detect if the caller is an authenticated admin (optional — adds user search)
    let isAdmin = false;
    const authHeader = req.headers['authorization'];
    if (authHeader && authHeader.startsWith('Bearer ')) {
      try {
        const decoded = require('jsonwebtoken').verify(authHeader.slice(7), JWT_SECRET);
        if (decoded?.userId) {
          const caller = await User.findById(decoded.userId).select('isAdmin').lean();
          isAdmin = !!(caller?.isAdmin);
        }
      } catch (_) {}
    }
 
    const results = {};
    const promises = [];
 
    // ── Products (admin & creator products merged) ────────────────────
    if (scope === 'all' || scope === 'products') {
      // Admin products
      promises.push(
        Product.find(
          { $text: textQ, isPublished: true },
          { score: { $meta: 'textScore' } }
        )
        .sort({ score: { $meta: 'textScore' } })
        .limit(limit)
        .select('title description category productType price coverImage slug tags rating soldCount')
        .lean()
        .then(docs => {
          results.products = docs.map(d => ({
            _id:         d._id,
            type:        'product',
            title:       d.title,
            description: _snippet(d.description, raw, 120),
            category:    d.category,
            productType: d.productType,
            price:       d.price,
            image:       d.coverImage,
            url:         `/marketplace/?product=${d.slug || d._id}`,
            meta:        { rating: d.rating, sold: d.soldCount, tags: d.tags },
            score:       d.score,
          }));
        })
        .catch(() => { results.products = []; })
      );
 
      // Creator marketplace products
      promises.push(
        CreatorProduct.find(
          { $text: textQ, status: 'approved' },
          { score: { $meta: 'textScore' } }
        )
        .sort({ score: { $meta: 'textScore' } })
        .limit(limit)
        .select('title description category productType suggestedPrice coverImage creatorId tags rating')
        .lean()
        .then(docs => {
          results.creatorProducts = docs.map(d => ({
            _id:         d._id,
            type:        'creator_product',
            title:       d.title,
            description: _snippet(d.description, raw, 120),
            category:    d.category,
            productType: d.productType,
            price:       d.suggestedPrice,
            image:       d.coverImage,
            url:         `/marketplace/?id=${d._id}`,
            meta:        { rating: d.rating, tags: d.tags },
            score:       d.score,
          }));
        })
        .catch(() => { results.creatorProducts = []; })
      );
    }
 
    // ── Blog posts ────────────────────────────────────────────────────
    if (scope === 'all' || scope === 'blog') {
      promises.push(
        BlogPost.find(
          { $text: textQ, status: 'published' },
          { score: { $meta: 'textScore' } }
        )
        .sort({ score: { $meta: 'textScore' } })
        .limit(limit)
        .select('title excerpt content category tags slug coverImage publishedAt author')
        .lean()
        .then(docs => {
          results.blog = docs.map(d => ({
            _id:       d._id,
            type:      'blog',
            title:     d.title,
            excerpt:   d.excerpt || _snippet(d.content, raw, 140),
            category:  d.category,
            image:     d.coverImage,
            url:       `/blog/${d.slug || d._id}`,
            meta:      { tags: d.tags, publishedAt: d.publishedAt },
            score:     d.score,
          }));
        })
        .catch(() => { results.blog = []; })
      );
    }
 
    // ── Creators / stores ────────────────────────────────────────────
    if (scope === 'all' || scope === 'creators') {
      promises.push(
        Creator.find(
          { $text: textQ, applicationStatus: 'approved' },
          { score: { $meta: 'textScore' } }
        )
        .sort({ score: { $meta: 'textScore' } })
        .limit(limit)
        .select('storeName bio logo storeSlug skills rating totalSales')
        .lean()
        .then(docs => {
          results.creators = docs.map(d => ({
            _id:    d._id,
            type:   'creator',
            title:  d.storeName,
            description: _snippet(d.bio, raw, 120),
            image:  d.logo,
            url:    `/store/${d.storeSlug || d._id}`,
            meta:   { rating: d.rating, sales: d.totalSales, skills: d.skills },
            score:  d.score,
          }));
        })
        .catch(() => { results.creators = []; })
      );
    }
 
    // ── Users (admin only) ────────────────────────────────────────────
    if (isAdmin && (scope === 'all' || scope === 'users')) {
      promises.push(
        User.find({
          $or: [
            { fullName: regexQ },
            { email:    regexQ },
          ],
        })
        .limit(10)
        .select('fullName email profileImage isAdmin isAgent isCreator isBanned createdAt')
        .lean()
        .then(docs => {
          results.users = docs.map(d => ({
            _id:   d._id,
            type:  'user',
            title: d.fullName,
            email: d.email,
            image: d.profileImage,
            url:   `/marketplace/admin-dashboard#users/${d._id}`,
            meta:  { isAdmin: d.isAdmin, isAgent: d.isAgent, isBanned: d.isBanned, joined: d.createdAt },
          }));
        })
        .catch(() => { results.users = []; })
      );
    }
 
    // ── Run all searches in parallel ──────────────────────────────────
    await Promise.all(promises);
 
    // ── Merge and sort all results by relevance score ─────────────────
    const all = [
      ...(results.products       || []),
      ...(results.creatorProducts || []),
      ...(results.blog           || []),
      ...(results.creators       || []),
      ...(results.users          || []),
    ].sort((a, b) => (b.score || 0) - (a.score || 0));
 
    // Total unique results count (approximate across types)
    const totalCount =
      (results.products?.length       || 0) +
      (results.creatorProducts?.length || 0) +
      (results.blog?.length           || 0) +
      (results.creators?.length       || 0) +
      (results.users?.length          || 0);
 
    res.json({
      success: true,
      query:   raw,
      scope,
      total:   totalCount,
      // By type — for tabs on the search results page
      results: {
        products:        [...(results.products || []), ...(results.creatorProducts || [])],
        blog:            results.blog        || [],
        creators:        results.creators    || [],
        users:           results.users       || [],   // empty for non-admins
      },
      // Combined flat list for "All Results" tab
      all: all.slice(skip, skip + limit),
      pagination: {
        page,
        limit,
        hasMore: all.length > skip + limit,
      },
    });
 
  } catch (err) {
    console.error('❌ GET /api/search:', err);
    res.status(500).json({ success: false, message: 'Search failed' });
  }
});

// ── Autocomplete endpoint (fast, lightweight, used for search-as-you-type) ─
// GET /api/search/suggest?q=web
// Returns up to 5 quick title matches from products and blog — no full content
app.get('/api/search/suggest', async (req, res) => {
  try {
    const raw = (req.query.q || '').trim();
    if (!raw || raw.length < 2) return res.json({ success: true, suggestions: [] });
 
    const regexQ = new RegExp(raw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i');
 
    const [products, blogs, creators] = await Promise.all([
      Product.find({ title: regexQ, isPublished: true })
             .limit(4).select('title productType price slug').lean(),
      BlogPost.find({ title: regexQ, status: 'published' })
              .limit(3).select('title category slug').lean(),
      Creator.find({ storeName: regexQ, applicationStatus: 'approved' })
             .limit(2).select('storeName storeSlug').lean(),
    ]);
 
    const suggestions = [
      ...products.map(p => ({
        label:    p.title,
        type:     'product',
        sublabel: `${p.productType} · $${p.price}`,
        url:      `/marketplace/?id=${p.slug || p._id}`,
      })),
      ...blogs.map(b => ({
        label:    b.title,
        type:     'blog',
        sublabel: b.category,
        url:      `/blog/${b.slug || b._id}`,
      })),
      ...creators.map(c => ({
        label:    c.storeName,
        type:     'creator',
        sublabel: 'Creator Store',
        url:      `/store/${c.storeSlug || c._id}`,
      })),
    ];
 
    res.json({ success: true, query: raw, suggestions });
 
  } catch (err) {
    console.error('❌ GET /api/search/suggest:', err);
    res.status(500).json({ success: false, message: 'Suggestions failed' });
  }
});
 
 
// ── _snippet() — extract a keyword-containing text excerpt ────────────────
function _snippet(text, keyword, maxLen) {
  if (!text) return '';
  const clean  = text.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
  const lower  = clean.toLowerCase();
  const kLower = keyword.toLowerCase();
  const idx    = lower.indexOf(kLower);
  if (idx === -1) return clean.substring(0, maxLen) + (clean.length > maxLen ? '…' : '');
  const start  = Math.max(0, idx - 40);
  const end    = Math.min(clean.length, idx + keyword.length + 80);
  return (start > 0 ? '…' : '') + clean.substring(start, end) + (end < clean.length ? '…' : '');
}
 
