app.get('/api/admin/tickets', authenticateAdmin, async (req, res) => {
  try {
    const { status = 'all', priority = 'all', page = 1, limit = 20, search = '', assigned = 'all' } = req.query;

    let query = {};

    if (status !== 'all')   query.status   = status;
    if (priority !== 'all') query.priority = priority;
    if (assigned === 'unassigned') query.assignedAgent = null;
    else if (assigned === 'assigned') query.assignedAgent = { $ne: null };

    if (search && search.trim()) {
      const s = search.trim();
      query.$or = [
        { ticketId:    { $regex: s, $options: 'i' } },
        { subject:     { $regex: s, $options: 'i' } },
        { guestEmail:  { $regex: s, $options: 'i' } },
        { description: { $regex: s, $options: 'i' } }
      ];
    }

    const skip = (parseInt(page) - 1) * parseInt(limit);

    const [tickets, total] = await Promise.all([
      SupportTicket.find(query)
        .populate('userId', 'fullName email')
        .populate('assignedAgent', 'fullName email')
        .sort({ createdAt: -1 })
        .limit(parseInt(limit))
        .skip(skip),
      SupportTicket.countDocuments(query)
    ]);
    
    res.json({
      success: true,
      tickets,
      pagination: {
        total,
        page: parseInt(page),
        limit: parseInt(limit),
        pages: Math.ceil(total / parseInt(limit))
      }
    });
    
  } catch (error) {
    console.error('âŒ Get all tickets error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch tickets' });
  }
});

// Update Ticket
app.put('/api/tickets/:ticketId', authenticateAgent, async (req, res) => {
  try {
    const { ticketId } = req.params;
    const { status, priority, assignedAgent, response } = req.body;
    
    const ticket = await SupportTicket.findOne({ ticketId });
    
    if (!ticket) {
      return res.status(404).json({ success: false, message: 'Ticket not found' });
    }
    
    if (status) ticket.status = status;
    if (priority) ticket.priority = priority;
    if (assignedAgent) ticket.assignedAgent = assignedAgent;
    
    if (response) {
      ticket.messages.push({
        sender: 'agent',
        senderId: req.agentUser._id,
        senderName: req.agentUser.fullName || 'Agent',
        message: response,
        timestamp: new Date()
      });
    }
    
    if (status === 'resolved') {
      ticket.resolvedAt = new Date();
    }

    await ticket.save();

    // ── Notify the user by email ──────────────────────────────────────────
    // Get customer email from ticket submitter info
    const submitterMsg = ticket.messages.find(m => m.sender === 'customer');
    const customerEmail = ticket.userEmail
      || (submitterMsg?.senderId?.includes('@') ? submitterMsg.senderId : null)
      || null;

    // Also try to get email from userId if stored
    let resolvedUserEmail = customerEmail;
    if (!resolvedUserEmail && ticket.userId) {
      try {
        const ticketUser = await User.findById(ticket.userId).select('email fullName');
        if (ticketUser) resolvedUserEmail = ticketUser.email;
      } catch (_) {}
    }

    if (resolvedUserEmail) {
      const agentFullName = req.agentUser?.fullName || 'Support Team';

      if (status === 'resolved' && global.sendTicketResolvedEmail) {
        // Resolved — send resolved email
        setImmediate(() => global.sendTicketResolvedEmail(resolvedUserEmail, {
          ticketId:   ticket.ticketId,
          subject:    ticket.subject,
          agentName:  agentFullName,
          fullName:   ticket.name || submitterMsg?.senderName || 'Customer',
          summary:    response || null,
        }));
      } else if (response && global.sendTicketReplyEmail) {
        // Agent replied but not yet resolved — send reply email
        setImmediate(() => global.sendTicketReplyEmail(resolvedUserEmail, {
          ticketId:  ticket.ticketId,
          subject:   ticket.subject,
          message:   response,
          agentName: agentFullName,
          status:    ticket.status,
        }));
      }
    }

    console.log(`✅ Ticket updated: ${ticketId} [${ticket.status}]`);

    res.json({
      success: true,
      message: 'Ticket updated successfully',
      ticket
    });
    
  } catch (error) {
    console.error('âŒ Update ticket error:', error);
    res.status(500).json({ success: false, message: 'Failed to update ticket' });
  }
});

// Assign Ticket to Agent
app.post('/api/tickets/:ticketId/assign', authenticateAdmin, async (req, res) => {
  try {
    const { ticketId } = req.params;
    const { agentId } = req.body;
    
    if (!agentId) {
      return res.status(400).json({ success: false, message: 'Agent ID required' });
    }
    
    const ticket = await SupportTicket.findOne({ ticketId });
    
    if (!ticket) {
      return res.status(404).json({ success: false, message: 'Ticket not found' });
    }
    
    const agent = await User.findById(agentId);
    
    if (!agent || (!agent.isAgent && !agent.isAdmin)) {
      return res.status(400).json({ success: false, message: 'Invalid agent ID' });
    }
    
    ticket.assignedAgent = agentId;
    ticket.status = 'in-progress';
    
    ticket.messages.push({
      sender: 'system',
      message: `Ticket assigned to ${agent.fullName}`,
      timestamp: new Date()
    });
    
    await ticket.save();
    
    console.log(`âœ… Ticket ${ticketId} assigned to ${agent.fullName}`);
    
    res.json({
      success: true,
      message: 'Ticket assigned successfully',
      ticket
    });
    
  } catch (error) {
    console.error('âŒ Assign ticket error:', error);
    res.status(500).json({ success: false, message: 'Failed to assign ticket' });
  }
});
