// ── ADMIN: Delete a specific Cloudinary asset ─────────────────────────────
// Used by the admin dashboard when replacing a product file or avatar.
// DELETE /api/admin/cloudinary/:publicId?resourceType=raw
app.delete('/api/admin/cloudinary/:publicId', authenticateAdmin, async (req, res) => {
  try {
    const publicId     = decodeURIComponent(req.params.publicId);
    const resourceType = req.query.resourceType || 'raw';
 
    if (!publicId || publicId === 'undefined') {
      return res.status(400).json({ success: false, message: 'publicId is required' });
    }
 
    const result = await deleteFromCloudinary(publicId, resourceType);
    if (result.success) {
      res.json({ success: true, message: `Asset deleted: ${publicId}`, result: result.result });
    } else {
      res.status(500).json({ success: false, message: result.error || 'Delete failed' });
    }
  } catch (err) {
    console.error('❌ Admin Cloudinary delete:', err);
    res.status(500).json({ success: false, message: 'Delete failed' });
  }
});
 
// GET /api/admin/cloudinary/list  — Browse stored assets
app.get('/api/admin/cloudinary/list', authenticateAdmin, async (req, res) => {
  try {
    const { folder = '', max_results = 50, next_cursor, resource_type = 'image' } = req.query;
    const ALLOWED_TYPES = ['image', 'video', 'raw'];
    const rtype = ALLOWED_TYPES.includes(resource_type) ? resource_type : 'image';
    const opts = {
      type:          'upload',
      max_results:   Math.min(parseInt(max_results) || 50, 200),
      resource_type: rtype,
    };
    if (folder)      opts.prefix      = folder;
    if (next_cursor) opts.next_cursor = next_cursor;

    const result = await cloudinary.api.resources(opts);


    // ✅ FIX: Build a lookup map of all known publicIds from the DB
    // so each asset can show which product/user it belongs to
    const allPublicIds = new Map();
    try {
      const [products, creatorProducts, users, blogPosts] = await Promise.all([
        Product.find({}).select('title hostedFile coverImage previewUrl').lean(),
        CreatorProduct.find({}).select('title hostedFile coverImage').lean(),
        User.find({ profileImage: { $exists: true, $ne: '' } }).select('fullName profileImage').lean(),
        BlogPost ? BlogPost.find({}).select('title featuredImage').lean() : Promise.resolve([]),
      ]);

      const register = (publicIdOrUrl, label, type) => {
        if (!publicIdOrUrl) return;
        // Handle full URLs — extract the publicId segment after /upload/
        const match = String(publicIdOrUrl).match(/\/upload\/(?:v\d+\/)?(.+?)(?:\.[a-z0-9]+)?$/i);
        const key = match ? match[1] : publicIdOrUrl;
        if (key) allPublicIds.set(key, { label, type });
      };

      products.forEach(p => {
        register(p.hostedFile?.publicId, `Product: ${p.title}`, 'product');
        register(p.coverImage,           `Product cover: ${p.title}`, 'product');
        register(p.previewUrl,           `Product preview: ${p.title}`, 'product');
      });
      creatorProducts.forEach(p => {
        register(p.hostedFile?.publicId, `Creator product: ${p.title}`, 'creator-product');
        register(p.coverImage,           `Creator cover: ${p.title}`, 'creator-product');
      });
      users.forEach(u => register(u.profileImage, `User avatar: ${u.fullName}`, 'user'));
      blogPosts.forEach(b => register(b.featuredImage, `Blog image: ${b.title}`, 'blog'));
    } catch(_) { /* non-fatal — proceed without context */ }

    res.json({
      success:     true,
      resources:   result.resources.map(r => {
        const ctx = allPublicIds.get(r.public_id);
        return {
          publicId:    r.public_id,
          url:         r.secure_url,
          format:      r.format,
          bytes:       r.bytes,
          width:       r.width,
          height:      r.height,
          createdAt:   r.created_at,
          folder:      r.folder || '',
          linkedTo:    ctx ? ctx.label : null,   // ✅ NEW — context label
          linkedType:  ctx ? ctx.type  : null,   // ✅ NEW — 'product' | 'user' | etc.
        };
      }),
      nextCursor:  result.next_cursor || null,
      totalCount:  result.total_count || result.resources.length,
    });
  } catch (error) {
    console.error('❌ Cloudinary list error:', error.message);
    res.status(500).json({ success: false, message: error.message });
  }
});
// ── ADMIN: Delete product + all its Cloudinary assets ─────────────────────
// Extend your existing DELETE /api/admin/products/:id route to call this.
// Paste this function, then call it from the product delete route.
async function deleteProductAssets(product) {
  if (!product) return;
  const toDelete = [];
 
  // Hosted file (the actual product download)
  if (product.hostedFile?.publicId) {
    toDelete.push({ publicId: product.hostedFile.publicId, type: product.hostedFile.resourceType || 'raw' });
  }
 
  // Cover / thumbnail image
  if (product.coverImage) {
    const publicId = _extractCloudinaryPublicId(product.coverImage);
    if (publicId) toDelete.push({ publicId, type: 'image' });
  }
 
  // Preview image/video
  if (product.previewUrl) {
    const publicId = _extractCloudinaryPublicId(product.previewUrl);
    if (publicId) toDelete.push({ publicId, type: product.previewType === 'video' ? 'video' : 'image' });
  }
 
  // Course chapter files
  if (product.courseData?.chapters) {
    for (const chapter of product.courseData.chapters) {
      if (chapter.hostedFile?.publicId) {
        toDelete.push({ publicId: chapter.hostedFile.publicId, type: chapter.hostedFile.resourceType || 'raw' });
      }
    }
  }
 
  if (toDelete.length === 0) return;
 
  console.log(`🗑️  Deleting ${toDelete.length} Cloudinary asset(s) for product "${product.title}"…`);
  const results = await Promise.allSettled(
    toDelete.map(a => deleteFromCloudinary(a.publicId, a.type))
  );
  const deleted = results.filter(r => r.status === 'fulfilled' && r.value.success).length;
  console.log(`   ✅ ${deleted}/${toDelete.length} assets deleted from Cloudinary`);
}
 
global.deleteProductAssets = deleteProductAssets;

app.post('/api/admin/cloudinary/cleanup-orphans', authenticateAdmin, async (req, res) => {
  try {
    const { dryRun = true, folder = 'uyehtech' } = req.body;
 
    // Collect all known publicIds from DB
    const [products, creatorProducts, users, creators, blogPosts] = await Promise.all([
      Product.find({}).select('hostedFile coverImage courseData.chapters').lean(),
      CreatorProduct.find({}).select('hostedFile coverImage courseData.chapters').lean(),
      User.find({ profileImage: { $ne: '' } }).select('profileImage').lean(),
      Creator.find({ logo: { $ne: '' } }).select('logo').lean(),
      BlogPost.find({ featuredImage: { $ne: '' } }).select('featuredImage coverImage').lean(),
    ]);
 
    const knownPublicIds = new Set();
 
    const _addKnown = (url) => {
      const pid = _extractCloudinaryPublicId(url);
      if (pid) knownPublicIds.add(pid);
    };
 
    products.forEach(p => {
      if (p.hostedFile?.publicId) knownPublicIds.add(p.hostedFile.publicId);
      _addKnown(p.coverImage);
      (p.courseData?.chapters || []).forEach(c => {
        if (c.hostedFile?.publicId) knownPublicIds.add(c.hostedFile.publicId);
      });
    });
    creatorProducts.forEach(p => {
      if (p.hostedFile?.publicId) knownPublicIds.add(p.hostedFile.publicId);
      _addKnown(p.coverImage);
    });
    users.forEach(u => _addKnown(u.profileImage));
    creators.forEach(c => _addKnown(c.logo));
    blogPosts.forEach(b => { _addKnown(b.featuredImage); _addKnown(b.coverImage); });
 
    // Fetch all assets from Cloudinary (paginated)
    let cloudinaryAssets = [];
    let nextCursor       = null;
 
    do {
      const opts = { type: 'upload', max_results: 500, prefix: folder };
      if (nextCursor) opts.next_cursor = nextCursor;
 
      const page = await cloudinary.api.resources(opts);
      cloudinaryAssets = cloudinaryAssets.concat(page.resources || []);
      nextCursor = page.next_cursor || null;
    } while (nextCursor);
 
    // Find orphans
    const orphans = cloudinaryAssets.filter(asset => !knownPublicIds.has(asset.public_id));
 
    const totalSize = orphans.reduce((s, a) => s + (a.bytes || 0), 0);
 
    console.log(`🔍 Cloudinary orphan scan: ${cloudinaryAssets.length} total, ${orphans.length} orphans (${(totalSize / 1024 / 1024).toFixed(1)} MB)`);
 
    res.json({
      success:     true,
      scanned:     cloudinaryAssets.length,
      known:       knownPublicIds.size,
      orphanCount: orphans.length,
      orphanSizeMB: parseFloat((totalSize / 1024 / 1024).toFixed(2)),
      dryRun,
      orphans: orphans.map(a => ({
        publicId:    a.public_id,
        url:         a.secure_url,
        bytes:       a.bytes,
        createdAt:   a.created_at,
        resourceType: a.resource_type,
      })),
      message: dryRun
        ? `Dry run — ${orphans.length} orphan(s) found. Call DELETE /api/admin/cloudinary/:publicId to remove each.`
        : `Found ${orphans.length} orphan(s). Remove each via DELETE /api/admin/cloudinary/:publicId.`,
    });
 
  } catch (err) {
    console.error('❌ Cloudinary orphan scan:', err);
    res.status(500).json({ success: false, message: 'Orphan scan failed: ' + err.message });
  }
});
 
// Helper: extract publicId from a Cloudinary URL
function _extractCloudinaryPublicId(url) {
  if (!url || !url.includes('cloudinary.com')) return null;
  try {
    // URL format: https://res.cloudinary.com/CLOUD_NAME/image/upload/v123/folder/filename.ext
    const match = url.match(/\/upload\/(?:v\d+\/)?(.+?)(?:\.[a-z0-9]+)?$/i);
    return match ? match[1] : null;
  } catch { return null; }
}
 async function generateInvoicePDF(order, docType = 'invoice') {
  return new Promise((resolve, reject) => {
    try {
      const doc    = new PDFDocument({ size: 'A4', margin: 50, compress: true });
      const chunks = [];
 
      doc.on('data', chunk => chunks.push(chunk));
      doc.on('end',  ()    => resolve(Buffer.concat(chunks)));
      doc.on('error', reject);
 
      // ── Brand colours & fonts ───────────────────────────────────────────
      const GREEN  = '#00ff88';
      const DARK   = '#0a0a0a';
      const GRAY   = '#6b7280';
      const WHITE  = '#ffffff';
      const TEXT   = '#e5e7eb';
 
      const items    = order.items         || [];
      const info     = order.customerInfo  || {};
      const payment  = order.paymentInfo   || {};
      const ref      = order.orderReference || String(order._id || '').slice(-8).toUpperCase();
      const isReceipt = docType === 'receipt';
 
      const paidAt = payment.paidAt
        ? new Date(payment.paidAt).toLocaleDateString('en-GB', { day:'2-digit', month:'long', year:'numeric' })
        : new Date(order.createdAt || Date.now()).toLocaleDateString('en-GB', { day:'2-digit', month:'long', year:'numeric' });
 
      const currency  = payment.currency || 'USD';
      const symbol    = currency === 'NGN' ? '₦' : currency === 'GBP' ? '£' : currency === 'EUR' ? '€' : '$';
 
      const fmt = (n) => `${symbol}${Number(n || 0).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
 
      // ── Page background ─────────────────────────────────────────────────
      doc.rect(0, 0, doc.page.width, doc.page.height).fill(DARK);
 
      // ── Header band ─────────────────────────────────────────────────────
      doc.rect(0, 0, doc.page.width, 120).fill('#0f0f0f');
 
      // Brand name
      doc.font('Helvetica-Bold').fontSize(28).fillColor(GREEN)
         .text('UYEH TECH', 50, 35);
 
      doc.font('Helvetica').fontSize(11).fillColor(GRAY)
         .text('uyehtech.com  ·  support@uyehtech.com', 50, 68);
 
      // Document type badge (top right)
      const badgeLabel = isReceipt ? 'RECEIPT' : 'INVOICE';
      const badgeW     = 120;
      const badgeX     = doc.page.width - 50 - badgeW;
      doc.roundedRect(badgeX, 30, badgeW, 38, 6).fill(GREEN);
      doc.font('Helvetica-Bold').fontSize(16).fillColor(DARK)
         .text(badgeLabel, badgeX, 42, { width: badgeW, align: 'center' });
 
      // ── Reference info block ─────────────────────────────────────────────
      let y = 145;
 
      doc.font('Helvetica-Bold').fontSize(10).fillColor(GRAY)
         .text('REFERENCE', 50, y);
      doc.font('Helvetica-Bold').fontSize(14).fillColor(WHITE)
         .text(ref, 50, y + 16);
 
      doc.font('Helvetica-Bold').fontSize(10).fillColor(GRAY)
         .text('DATE', 200, y);
      doc.font('Helvetica').fontSize(12).fillColor(WHITE)
         .text(paidAt, 200, y + 16);
 
      doc.font('Helvetica-Bold').fontSize(10).fillColor(GRAY)
         .text('STATUS', 350, y);
      doc.font('Helvetica-Bold').fontSize(12).fillColor(GREEN)
         .text(isReceipt ? '✓ PAID' : (order.status === 'completed' ? '✓ PAID' : order.status.toUpperCase()), 350, y + 16);
 
      if (payment.method) {
        doc.font('Helvetica-Bold').fontSize(10).fillColor(GRAY)
           .text('PAYMENT', 460, y);
        doc.font('Helvetica').fontSize(11).fillColor(WHITE)
           .text((payment.method || 'Card').toUpperCase(), 460, y + 16);
      }
 
      // ── Divider ──────────────────────────────────────────────────────────
      y += 55;
      doc.moveTo(50, y).lineTo(doc.page.width - 50, y).strokeColor(GREEN).lineWidth(1.5).stroke();
 
      // ── Bill to ──────────────────────────────────────────────────────────
      y += 20;
      doc.font('Helvetica-Bold').fontSize(10).fillColor(GRAY).text('BILL TO', 50, y);
      y += 16;
      doc.font('Helvetica-Bold').fontSize(13).fillColor(WHITE)
         .text(info.name || info.fullName || 'Customer', 50, y);
      y += 16;
      doc.font('Helvetica').fontSize(11).fillColor(GRAY);
      if (info.email)   { doc.text(info.email,   50, y); y += 14; }
      if (info.phone)   { doc.text(info.phone,   50, y); y += 14; }
      if (info.country) { doc.text(info.country, 50, y); y += 14; }
 
      // ── Items table header ───────────────────────────────────────────────
      y += 20;
      doc.rect(50, y, doc.page.width - 100, 28).fill('#1a1a1a');
      doc.font('Helvetica-Bold').fontSize(10).fillColor(GRAY);
      doc.text('ITEM',     60,  y + 9);
      doc.text('TYPE',     300, y + 9);
      doc.text('QTY',      400, y + 9, { width: 50, align: 'right' });
      doc.text('PRICE',    460, y + 9, { width: 80, align: 'right' });
      y += 28;
 
      // ── Items rows ────────────────────────────────────────────────────────
      items.forEach((item, idx) => {
        const rowBg = idx % 2 === 0 ? '#0f0f0f' : '#111111';
        const rowH  = 34;
 
        // Check if we need a new page
        if (y + rowH > doc.page.height - 120) {
          doc.addPage();
          doc.rect(0, 0, doc.page.width, doc.page.height).fill(DARK);
          y = 60;
        }
 
        doc.rect(50, y, doc.page.width - 100, rowH).fill(rowBg);
 
        // Title — truncate if too long
        const title = (item.title || item.name || 'Product').substring(0, 38);
        doc.font('Helvetica').fontSize(11).fillColor(WHITE)
           .text(title, 60, y + 11, { width: 235, ellipsis: true });
 
        // Product type
        const ptype = (item.productType || item.category || '').toLowerCase();
        doc.font('Helvetica').fontSize(10).fillColor(GRAY)
           .text(ptype, 300, y + 12, { width: 95 });
 
        // Qty
        doc.font('Helvetica').fontSize(11).fillColor(WHITE)
           .text(String(item.quantity || 1), 400, y + 11, { width: 50, align: 'right' });
 
        // Price
        doc.font('Helvetica-Bold').fontSize(11).fillColor(GREEN)
           .text(fmt(item.price), 460, y + 11, { width: 80, align: 'right' });
 
        y += rowH;
      });
 
      // ── Totals block ──────────────────────────────────────────────────────
      y += 16;
      const totalsX = doc.page.width - 250;
 
      const _totRow = (label, value, highlight = false, bold = false) => {
        if (y + 22 > doc.page.height - 80) {
          doc.addPage();
          doc.rect(0, 0, doc.page.width, doc.page.height).fill(DARK);
          y = 60;
        }
        doc.font(bold ? 'Helvetica-Bold' : 'Helvetica').fontSize(bold ? 13 : 11)
           .fillColor(highlight ? GREEN : (bold ? WHITE : GRAY))
           .text(label, totalsX, y, { width: 110 });
        doc.font(bold ? 'Helvetica-Bold' : 'Helvetica').fontSize(bold ? 14 : 11)
           .fillColor(highlight ? GREEN : (bold ? WHITE : GRAY))
           .text(value, totalsX + 110, y, { width: 90, align: 'right' });
        y += bold ? 24 : 20;
      };
 
      _totRow('Subtotal',   fmt(order.subtotal || order.total));
      if (order.discount && order.discount > 0) {
        _totRow(`Discount${order.couponCode ? ` (${order.couponCode})` : ''}`, `-${fmt(order.discount)}`);
      }
 
      // Separator line before total
      doc.moveTo(totalsX, y).lineTo(totalsX + 200, y).strokeColor(GREEN).lineWidth(1).stroke();
      y += 10;
      _totRow('Total Paid', fmt(order.total), true, true);
 
      // ── Transaction reference ─────────────────────────────────────────────
      if (payment.transactionId || payment.transactionRef) {
        y += 10;
        doc.font('Helvetica').fontSize(9).fillColor(GRAY)
           .text(`Transaction: ${payment.transactionRef || payment.transactionId}`, totalsX, y);
        y += 14;
      }
 
      // ── Footer bar ────────────────────────────────────────────────────────
      const footerY = doc.page.height - 70;
      doc.rect(0, footerY, doc.page.width, 70).fill('#0f0f0f');
 
      doc.font('Helvetica').fontSize(9).fillColor(GRAY)
         .text(
           `UYEH TECH · uyehtech.com · ${ADMIN_EMAIL}  —  Thank you for your purchase!`,
           50, footerY + 14,
           { width: doc.page.width - 100, align: 'center' }
         );
      doc.font('Helvetica').fontSize(8).fillColor('#374151')
         .text(
           `Generated: ${new Date().toLocaleString('en-GB')}  ·  This document serves as your official ${docType}.`,
           50, footerY + 32,
           { width: doc.page.width - 100, align: 'center' }
         );
 
      doc.end();
 
    } catch (err) {
      reject(err);
    }
  });
}
 
global.generateInvoicePDF = generateInvoicePDF;
 
// ── GET /api/orders/:orderId/invoice — download the invoice PDF ───────────
app.get('/api/orders/:orderId/invoice', authenticateToken, async (req, res) => {
  try {
    const order = await Order.findOne({
      _id:    req.params.orderId,
      userId: req.user.userId,
    }).lean();
 
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }
 
    if (!['completed', 'refunded'].includes(order.status)) {
      return res.status(400).json({
        success: false,
        message: 'Invoice is only available for completed or refunded orders'
      });
    }
 
    const docType = req.query.type === 'receipt' ? 'receipt' : 'invoice';
    const pdfBuf  = await generateInvoicePDF(order, docType);
    const filename = `UYEH-TECH-${docType.toUpperCase()}-${order.orderReference}.pdf`;
 
    res.set({
      'Content-Type':        'application/pdf',
      'Content-Disposition': `inline; filename="${filename}"`,
      'Content-Length':      pdfBuf.length,
      'Cache-Control':       'private, max-age=3600',
    });
    res.send(pdfBuf);
 
  } catch (err) {
    console.error('❌ Invoice PDF error:', err);
    res.status(500).json({ success: false, message: 'Failed to generate invoice' });
  }
});
 
