app.get('/api/orders/:orderId/receipt', authenticateToken, async (req, res) => {
  req.query.type = 'receipt';
  // Re-use the invoice route logic by forwarding to the same handler
  try {
    const order = await Order.findOne({
      _id:    req.params.orderId,
      userId: req.user.userId,
    }).lean();
 
    if (!order) {
      return res.status(404).json({ success: false, message: 'Order not found' });
    }
    if (!['completed', 'refunded'].includes(order.status)) {
      return res.status(400).json({ success: false, message: 'Receipt is only available for completed orders' });
    }
 
    const pdfBuf  = await generateInvoicePDF(order, 'receipt');
    const filename = `UYEH-TECH-RECEIPT-${order.orderReference}.pdf`;
 
    res.set({
      'Content-Type':        'application/pdf',
      'Content-Disposition': `inline; filename="${filename}"`,
      'Content-Length':      pdfBuf.length,
      'Cache-Control':       'private, max-age=3600',
    });
    res.send(pdfBuf);
 
  } catch (err) {
    console.error('❌ Receipt PDF error:', err);
    res.status(500).json({ success: false, message: 'Failed to generate receipt' });
  }
});
 
// ── ADMIN: generate invoice for any order ─────────────────────────────────
app.get('/api/admin/orders/:orderId/invoice', authenticateAdmin, async (req, res) => {
  try {
    const order = await Order.findById(req.params.orderId).lean();
    if (!order) return res.status(404).json({ success: false, message: 'Order not found' });
 
    const docType = req.query.type === 'receipt' ? 'receipt' : 'invoice';
    const pdfBuf  = await generateInvoicePDF(order, docType);
    const filename = `UYEH-TECH-ADMIN-${docType.toUpperCase()}-${order.orderReference}.pdf`;
 
    res.set({
      'Content-Type':        'application/pdf',
      'Content-Disposition': `attachment; filename="${filename}"`,
      'Content-Length':      pdfBuf.length,
    });
    res.send(pdfBuf);
 
  } catch (err) {
    console.error('❌ Admin invoice PDF error:', err);
    res.status(500).json({ success: false, message: 'Failed to generate invoice' });
  }
});
 
// ── POST /api/orders/:orderId/email-invoice — send PDF as email attachment ─
app.post('/api/orders/:orderId/email-invoice', authenticateToken, async (req, res) => {
  try {
    const order = await Order.findOne({
      _id:    req.params.orderId,
      userId: req.user.userId,
    }).lean();
 
    if (!order) return res.status(404).json({ success: false, message: 'Order not found' });
    if (order.status !== 'completed') {
      return res.status(400).json({ success: false, message: 'Invoice only available for completed orders' });
    }
 
    const pdfBuf  = await generateInvoicePDF(order, 'invoice');
    const filename = `UYEH-TECH-INVOICE-${order.orderReference}.pdf`;
    const email    = order.customerInfo?.email || req.body.email;
 
    if (!email) {
      return res.status(400).json({ success: false, message: 'No email address on order' });
    }
 
    if (!resend || !RESEND_API_KEY) {
      return res.json({ success: true, message: 'Email service not configured — download the PDF instead' });
    }
 
    const { data, error } = await resend.emails.send({
      from:        `${RESEND_SENDER_NAME} <${RESEND_SENDER_EMAIL}>`,
      to:          [email],
      subject:     `🧾 Your Invoice — Order ${order.orderReference} | UYEH TECH`,
      html: _shell('🧾 Your Invoice', `
        <h2 class="title">Your Invoice is Attached</h2>
        <p>Hi <strong style="color:#00ff88;">${order.customerInfo?.name || 'there'}</strong>,</p>
        <p>Your invoice for Order <strong style="color:#00ff88;">${order.orderReference}</strong> is attached to this email as a PDF.</p>
        <div class="info-card">
          ${_row('Order Reference', order.orderReference)}
          ${_row('Total Paid',      `$${Number(order.total).toFixed(2)}`)}
          ${_row('Payment Status',  '✅ Confirmed')}
        </div>
        <p style="color:#6b7280;font-size:13px;">
          This is your official invoice from UYEH TECH. Keep it for your records.
        </p>
        ${_btn(`${FRONTEND_URL}/marketplace/orders`, '📦 View My Orders')}
      `),
      attachments: [{
        filename:    filename,
        content:     pdfBuf.toString('base64'),
        contentType: 'application/pdf',
      }],
    });
 
    if (error) {
      console.error('❌ Invoice email error:', error);
      return res.status(500).json({ success: false, message: 'Failed to send invoice email' });
    }
 
    console.log(`✅ Invoice emailed to ${email} for order ${order.orderReference}`);
    res.json({ success: true, message: `Invoice sent to ${email}` });
 
  } catch (err) {
    console.error('❌ Email invoice error:', err);
    res.status(500).json({ success: false, message: 'Failed to send invoice' });
  }
});
