// GET /api/admin/email-preview/:template  — render HTML in browser (no send)
app.get('/api/admin/email-preview/:template', authenticateAdmin, async (req, res) => {
  const key = req.params.template;
  const sampleFn = EMAIL_PREVIEW_SAMPLES[key];
  if (!sampleFn) {
    return res.status(404).send(`<h3>Template "${key}" not found. <a href="/api/admin/email-preview">← Back</a></h3>`);
  }
 
  try {
    // Temporarily monkey-patch _sendEmail to capture the HTML
    let capturedHtml  = null;
    let capturedSubject = null;
    const _origSend = global._sendEmail || _sendEmail;
 
    // Override for this call only via a local wrapper
    async function _captureSend(to, subject, html) {
      capturedHtml    = html;
      capturedSubject = subject;
    }
 
    // We can't easily intercept _sendEmail without patching global,
    // so instead we rebuild the email using the same _shell helper approach.
    // For preview: call the function but override Resend to not actually send.
    const origResend = global._resend;
    if (global._resend) {
      global._resend = { emails: { send: async () => ({ id: 'preview' }) } };
    }
 
    const args = sampleFn();
    const emailFn = EMAIL_FN_MAP[key];
    if (!emailFn) return res.status(404).send(`<h3>No function mapped for "${key}"</h3>`);
 
    // Call the function — Resend is mocked so no real email is sent
    await emailFn(...args).catch(() => {});
 
    // Restore Resend
    if (origResend) global._resend = origResend;
 
    // Since we can't easily capture HTML without refactoring _shell,
    // we use an alternative: send a note and direct to Send Test.
    res.send(`
      <!DOCTYPE html>
      <html>
      <head>
        <title>Preview: ${key}</title>
        <style>
          body { font-family: sans-serif; background: #0d1117; color: #e5e7eb; padding: 40px; }
          .notice { background: #161b22; border: 1px solid rgba(0,255,136,.3); border-radius: 10px; padding: 24px 28px; max-width: 600px; margin: 0 auto; }
          h2 { color: #00ff88; margin-bottom: 12px; }
          p { color: #9ca3af; line-height: 1.6; }
          a { color: #00ff88; }
          .actions { display: flex; gap: 12px; margin-top: 20px; flex-wrap: wrap; }
          .btn { padding: 10px 20px; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: .875rem; }
          .send-btn { background: rgba(0,255,136,.12); border: 1px solid rgba(0,255,136,.3); color: #00ff88; }
          .back-btn { background: rgba(255,255,255,.06); border: 1px solid rgba(255,255,255,.12); color: #9ca3af; }
        </style>
      </head>
      <body>
        <div class="notice">
          <h2>📧 Template: ${key}</h2>
          <p>To see the full rendered HTML, use <strong>Send Test</strong> — this will send the email to
             <strong>${ADMIN_EMAIL}</strong> using real sample data so you see exactly what recipients see,
             including fonts, colours, and responsive layout.</p>
          <p style="margin-top:12px;">The template function called is: <code style="color:#00ff88;background:rgba(0,255,136,.08);padding:2px 8px;border-radius:4px;">${EMAIL_FN_MAP[key]?.name || key}</code></p>
          <div class="actions">
            <a class="btn send-btn" href="/api/admin/email-preview/${key}/send" target="_blank">📤 Send Test Email to ${ADMIN_EMAIL}</a>
            <a class="btn back-btn" href="/api/admin/email-preview">← All Templates</a>
          </div>
        </div>
      </body>
      </html>`);
  } catch (err) {
    res.status(500).send(`<h3 style="color:red;">Error rendering preview: ${err.message}</h3>`);
  }
});
 
