// ── GET /api/admin/logs ───────────────────────────────────────────────────────
// Master query endpoint. Supports every filter the admin panel needs.
//
// Query params:
//   page      — integer, default 1
//   limit     — integer, default 50, max 200
//   category  — filter by category (auth, order, server, ...)
//   action    — exact action string
//   severity  — info | warning | error | critical
//   role      — actor role filter
//   userId    — filter by actor.id
//   ip        — filter by actor.ip
//   targetId  — filter by target.id
//   targetType— filter by target.type
//   success   — 'true' | 'false'
//   from      — ISO date string, start of range
//   to        — ISO date string, end of range
//   search    — text search in actor.email, actor.name, http.path, action
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/admin/logs', authenticateAdmin, async (req, res) => {
  try {
    const {
      page = 1, limit = 50,
      category, action, severity, role,
      userId, ip, targetId, targetType,
      success, from, to, search,
    } = req.query;
 
    const filter = {};
 
    if (category)   filter.category         = category;
    if (action)     filter.action           = action;
    if (severity)   filter.severity         = severity;
    if (role)       filter['actor.role']    = role;
    if (userId)     filter['actor.id']      = userId;
    if (ip)         filter['actor.ip']      = ip;
    if (targetId)   filter['target.id']     = targetId;
    if (targetType) filter['target.type']   = targetType;
    if (success !== undefined) filter.success = success === 'true';
 
    if (from || to) {
      filter.timestamp = {};
      if (from) filter.timestamp.$gte = new Date(from);
      if (to)   filter.timestamp.$lte = new Date(to);
    }
 
    if (search) {
      filter.$or = [
        { 'actor.email': { $regex: search, $options: 'i' } },
        { 'actor.name':  { $regex: search, $options: 'i' } },
        { 'http.path':   { $regex: search, $options: 'i' } },
        { action:        { $regex: search, $options: 'i' } },
        { 'target.label':{ $regex: search, $options: 'i' } },
      ];
    }
 
    const pageNum  = Math.max(1, parseInt(page));
    const limitNum = Math.min(200, Math.max(1, parseInt(limit)));
    const skip     = (pageNum - 1) * limitNum;
 
    const [logs, total] = await Promise.all([
      AdminLog.find(filter)
        .sort({ timestamp: -1 })
        .skip(skip)
        .limit(limitNum)
        .lean(),
      AdminLog.countDocuments(filter),
    ]);
 
    res.json({
      success: true,
      total,
      page: pageNum,
      pages: Math.ceil(total / limitNum),
      count: logs.length,
      logs,
    });
  } catch (err) {
    console.error('❌ AdminLog GET error:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch logs' });
  }
});
 
 
// ── GET /api/admin/logs/stats ─────────────────────────────────────────────────
// Dashboard summary: totals by category, severity, top actors, top IPs.
// Query params: period — '24h' | '7d' | '30d' (default '24h')
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/admin/logs/stats', authenticateAdmin, async (req, res) => {
  try {
    const { period = '24h' } = req.query;
    const periodMap = { '1h': 1, '24h': 24, '7d': 168, '30d': 720 };
    const hours     = periodMap[period] || 24;
    const since     = new Date(Date.now() - hours * 60 * 60 * 1000);
    const filter    = { timestamp: { $gte: since } };
 
    const [
      totalLogs,
      byCategory,
      bySeverity,
      failedRequests,
      topActors,
      topIPs,
      recentErrors,
      hourlyVolume,
    ] = await Promise.all([
 
      AdminLog.countDocuments(filter),
 
      AdminLog.aggregate([
        { $match: filter },
        { $group: { _id: '$category', count: { $sum: 1 } } },
        { $sort: { count: -1 } },
      ]),
 
      AdminLog.aggregate([
        { $match: filter },
        { $group: { _id: '$severity', count: { $sum: 1 } } },
        { $sort: { count: -1 } },
      ]),
 
      AdminLog.countDocuments({ ...filter, success: false }),
 
      AdminLog.aggregate([
        { $match: { ...filter, 'actor.id': { $ne: null } } },
        { $group: {
          _id:   '$actor.id',
          email: { $first: '$actor.email' },
          name:  { $first: '$actor.name' },
          role:  { $first: '$actor.role' },
          count: { $sum: 1 },
        }},
        { $sort: { count: -1 } },
        { $limit: 10 },
      ]),
 
      AdminLog.aggregate([
        { $match: { ...filter, 'actor.ip': { $ne: null } } },
        { $group: { _id: '$actor.ip', count: { $sum: 1 }, roles: { $addToSet: '$actor.role' } } },
        { $sort: { count: -1 } },
        { $limit: 10 },
      ]),
 
      AdminLog.find({ ...filter, severity: { $in: ['error', 'critical'] } })
        .sort({ timestamp: -1 })
        .limit(20)
        .lean(),
 
      AdminLog.aggregate([
        { $match: filter },
        { $group: {
          _id: {
            $dateToString: {
              format: hours <= 24 ? '%Y-%m-%dT%H:00' : '%Y-%m-%d',
              date: '$timestamp',
            }
          },
          count: { $sum: 1 },
          errors: { $sum: { $cond: [{ $eq: ['$success', false] }, 1, 0] } },
        }},
        { $sort: { _id: 1 } },
      ]),
 
    ]);
 
    res.json({
      success: true,
      period,
      since,
      totalLogs,
      failedRequests,
      failureRate: totalLogs > 0 ? ((failedRequests / totalLogs) * 100).toFixed(1) + '%' : '0%',
      byCategory,
      bySeverity,
      topActors,
      topIPs,
      recentErrors,
      hourlyVolume,
    });
  } catch (err) {
    console.error('❌ AdminLog stats error:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch log stats' });
  }
});
 
 
// ── GET /api/admin/logs/user/:userId ──────────────────────────────────────────
// Full activity timeline for one user.
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/admin/logs/user/:userId', authenticateAdmin, async (req, res) => {
  try {
    const { userId } = req.params;
    const { page = 1, limit = 50 } = req.query;
    const pageNum  = Math.max(1, parseInt(page));
    const limitNum = Math.min(200, parseInt(limit));
    const skip     = (pageNum - 1) * limitNum;
 
    const filter = { 'actor.id': userId };
 
    const [logs, total, summary] = await Promise.all([
      AdminLog.find(filter).sort({ timestamp: -1 }).skip(skip).limit(limitNum).lean(),
      AdminLog.countDocuments(filter),
      AdminLog.aggregate([
        { $match: filter },
        { $group: {
          _id:          '$category',
          count:        { $sum: 1 },
          lastAction:   { $max: '$timestamp' },
          failures:     { $sum: { $cond: [{ $eq: ['$success', false] }, 1, 0] } },
        }},
        { $sort: { count: -1 } },
      ]),
    ]);
 
    res.json({
      success: true,
      userId,
      total,
      page: pageNum,
      pages: Math.ceil(total / limitNum),
      summary,
      logs,
    });
  } catch (err) {
    console.error('❌ AdminLog user query error:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch user logs' });
  }
});
 
 
// ── GET /api/admin/logs/server ────────────────────────────────────────────────
// Only server, error, and health events — the operations view.
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/admin/logs/server', authenticateAdmin, async (req, res) => {
  try {
    const { limit = 100, from, to } = req.query;
 
    const filter = { category: { $in: ['server', 'error', 'health', 'websocket'] } };
    if (from || to) {
      filter.timestamp = {};
      if (from) filter.timestamp.$gte = new Date(from);
      if (to)   filter.timestamp.$lte = new Date(to);
    }
 
    const [logs, criticalCount, dbEvents, memEvents] = await Promise.all([
      AdminLog.find(filter).sort({ timestamp: -1 }).limit(parseInt(limit)).lean(),
      AdminLog.countDocuments({ ...filter, severity: 'critical' }),
      AdminLog.find({ category: 'server', action: { $in: ['db_disconnected', 'db_reconnected', 'db_error'] } })
        .sort({ timestamp: -1 }).limit(20).lean(),
      AdminLog.find({ category: 'server', action: 'memory_high' })
        .sort({ timestamp: -1 }).limit(10).lean(),
    ]);
 
    res.json({
      success: true,
      criticalCount,
      dbEventCount:  dbEvents.length,
      memEventCount: memEvents.length,
      serverHealth: {
        uptime:    process.uptime(),
        memoryMB:  Math.round(process.memoryUsage().heapUsed / 1024 / 1024),
        wsClients: global.wss?.clients?.size || 0,
        dbState:   mongoose.connection.readyState === 1 ? 'connected' : 'disconnected',
      },
      dbEvents,
      memEvents,
      logs,
    });
  } catch (err) {
    console.error('❌ AdminLog server query error:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch server logs' });
  }
});
 
 
// ── GET /api/admin/logs/security ──────────────────────────────────────────────
// Security-focused view: failed logins, access attempts, blocked IPs.
// ─────────────────────────────────────────────────────────────────────────────
app.get('/api/admin/logs/security', authenticateAdmin, async (req, res) => {
  try {
    const { hours = 24 } = req.query;
    const since = new Date(Date.now() - parseInt(hours) * 60 * 60 * 1000);
 
    const filter = {
      timestamp: { $gte: since },
      $or: [
        { category: 'security' },
        { category: 'auth', success: false },
        { category: 'access' },
      ],
    };
 
    const [events, failedByIP, failedByEmail] = await Promise.all([
      AdminLog.find(filter).sort({ timestamp: -1 }).limit(200).lean(),
 
      AdminLog.aggregate([
        { $match: { ...filter, 'actor.ip': { $ne: null } } },
        { $group: {
          _id:      '$actor.ip',
          count:    { $sum: 1 },
          actions:  { $addToSet: '$action' },
          lastSeen: { $max: '$timestamp' },
        }},
        { $sort: { count: -1 } },
        { $limit: 20 },
      ]),
 
      AdminLog.aggregate([
        { $match: { category: 'auth', success: false, timestamp: { $gte: since } } },
        { $group: {
          _id:   '$actor.email',
          count: { $sum: 1 },
          ips:   { $addToSet: '$actor.ip' },
          last:  { $max: '$timestamp' },
        }},
        { $sort: { count: -1 } },
        { $limit: 20 },
      ]),
    ]);
 
    res.json({
      success: true,
      period:  `${hours}h`,
      since,
      totalEvents:  events.length,
      failedByIP,
      failedByEmail,
      events,
    });
  } catch (err) {
    console.error('❌ AdminLog security query error:', err);
    res.status(500).json({ success: false, message: 'Failed to fetch security logs' });
  }
});
 
 
