// ── DELETE /api/admin/logs/purge ──────────────────────────────────────────────
// Manual purge of logs older than N days. Separate from TTL auto-expiry.
// Admin-only. Requires confirmation body: { confirm: 'PURGE', olderThanDays: 90 }
// ─────────────────────────────────────────────────────────────────────────────
app.delete('/api/admin/logs/purge', authenticateAdmin, async (req, res) => {
  try {
    const { confirm, olderThanDays = 90 } = req.body;
 
    if (confirm !== 'PURGE') {
      return res.status(400).json({
        success: false,
        message: 'Send { confirm: "PURGE", olderThanDays: 90 } to confirm',
      });
    }
 
    const cutoff = new Date(Date.now() - parseInt(olderThanDays) * 24 * 60 * 60 * 1000);
    const result = await AdminLog.deleteMany({ timestamp: { $lt: cutoff } });
 
    // Log the purge itself
    await adminLog({
      actor:    resolveActor(req),
      category: 'admin',
      action:   'logs_purged',
      severity: 'warning',
      detail:   { deletedCount: result.deletedCount, olderThanDays, cutoff },
      success:  true,
    });
 
    res.json({
      success: true,
      deletedCount: result.deletedCount,
      cutoff,
    });
  } catch (err) {
    console.error('❌ AdminLog purge error:', err);
    res.status(500).json({ success: false, message: 'Purge failed' });
  }
});
 
