// GET — public settings (called by every frontend page on load)
// Uses the cache so this never causes a DB hit per page load.
app.get('/api/settings/public', async (req, res) => {
  try {
    const settings = await getSettings();

    const bypassToken = req.query.bypass || req.headers['x-bypass-token'];
    const bypassGranted = bypassToken &&
      settings.maintenanceBypassToken &&
      bypassToken === settings.maintenanceBypassToken;

    res.json({
      success: true,
      settings: {
        // Identity
        siteName:        settings.siteName        || 'UYEH TECH',
        siteDescription: settings.siteDescription || '',
        siteUrl:         settings.siteUrl         || '',
        contactEmail:    settings.contactEmail    || '',
        supportEmail:    settings.supportEmail    || '',
        phone:           settings.phone           || '',
        address:         settings.address         || '',
        logo:            settings.logo            || '',
        favicon:         settings.favicon         || '',
        socialMedia:     settings.socialMedia     || {},

        // Maintenance — bypassGranted suppresses maintenanceMode for that client
        maintenanceMode:    bypassGranted ? false : (settings.maintenanceMode || false),
        maintenanceMessage: settings.maintenanceMessage || "We'll be back shortly!",
        maintenanceTitle:   settings.maintenanceTitle   || 'Under Maintenance',
        maintenanceETA:     settings.maintenanceETA     || '',
        maintenancePages:   settings.maintenancePages   || 'all',
        // NOTE: maintenanceBypassToken is NEVER returned — write-only

        // Auth & registration
        allowRegistration:        settings.allowRegistration        !== false,
        requireEmailVerification: settings.requireEmailVerification !== false,
        allowGuestCheckout:       settings.allowGuestCheckout       !== false,

        // Feature flags
        storeEnabled:      settings.storeEnabled      !== false,
        blogEnabled:       settings.blogEnabled        !== false,
        chatEnabled:       settings.chatEnabled        !== false,
        creatorEnabled:    settings.creatorEnabled     !== false,
        affiliatesEnabled: settings.affiliatesEnabled  !== false,

        // Announcement banner
        banner: {
          enabled:     settings.bannerEnabled     || false,
          text:        settings.bannerText        || '',
          type:        settings.bannerType        || 'info',
          link:        settings.bannerLink        || '',
          linkText:    settings.bannerLinkText    || '',
          dismissible: settings.bannerDismissible !== false,
        },

        // Custom code (CSS only — JS is never served publicly)
        customCSS: settings.customCSS || '',

        // Analytics IDs
        googleAnalyticsId: settings.googleAnalyticsId || '',
        facebookPixelId:   settings.facebookPixelId   || '',

        // Payment gateway — public key is SAFE to expose (it's a publishable key)
        // Secret key is NEVER included here.
        flutterwavePublicKey: FLUTTERWAVE_PUBLIC_KEY || '',

        // Feature flags for paid features
        couponFeeEnabled: settings.couponFeeEnabled !== false,

        // Meta
        lastUpdated: settings.updatedAt,
      },
    });

  } catch (err) {
    console.error('❌ GET /api/settings/public:', err);
    // Never fail on this endpoint — always return safe defaults
    res.json({
      success: true,
      settings: {
        siteName: 'UYEH TECH', logo: '', favicon: '',
        maintenanceMode: false,
        allowRegistration: true, requireEmailVerification: true, allowGuestCheckout: true,
        storeEnabled: true, blogEnabled: true, chatEnabled: true,
        creatorEnabled: true, affiliatesEnabled: true, flutterwavePublicKey: '', couponFeeEnabled: true,
        banner: { enabled: false, text: '', type: 'info', link: '', linkText: '', dismissible: true },
        customCSS: '', googleAnalyticsId: '', facebookPixelId: '',
      },
    });
  }
});

