// ── GET /api/creator/followers — creator's own paginated follower list ────────
app.get('/api/creator/followers', authenticateToken, async (req, res) => {
  try {
    const creator = await Creator.findOne({ userId: req.user.userId });
    if (!creator || creator.applicationStatus !== 'approved') {
      return res.status(403).json({ success: false, message: 'Approved creator account required' });
    }

    const page  = Math.max(1, parseInt(req.query.page)  || 1);
    const limit = Math.min(50, parseInt(req.query.limit) || 20);
    const skip  = (page - 1) * limit;

    const [followers, total] = await Promise.all([
      Follow.find({ creatorId: creator._id })
        .sort({ followedAt: -1 })
        .skip(skip)
        .limit(limit)
        .populate('followerId', 'fullName profileImage')
        .lean(),
      Follow.countDocuments({ creatorId: creator._id })
    ]);

    res.json({
      success: true,
      followers: followers.map(f => ({
        userId:       f.followerId?._id,
        fullName:     f.followerId?.fullName || 'Marketplace User',
        profileImage: f.followerId?.profileImage || null,
        followedAt:   f.followedAt,
      })),
      total,
      pagination: {
        page, limit, total,
        pages:   Math.ceil(total / limit),
        hasMore: skip + followers.length < total,
      }
    });
  } catch (error) {
    console.error('❌ GET /api/creator/followers error:', error);
    res.status(500).json({ success: false, message: 'Failed to fetch followers' });
  }
});

