// ── ONE-TIME MIGRATION: normalise order items to canonical Product._id ─────
// Run once via POST /api/admin/migrations/normalise-order-items
// Remove this route after the migration report shows 0 remaining.
app.post('/api/admin/migrations/normalise-order-items', authenticateAdmin, async (req, res) => {
  const dryRun = req.query.dry !== 'false'; // default: dry run; pass ?dry=false to commit
  try {
    // Find all orders that have at least one item where id !== productId,
    // or where productId looks like it might be a CreatorProduct._id.
    const orders = await Order.find({
      'items.0': { $exists: true }
    }).select('items').lean();

    let checked = 0, needsFix = 0, fixed = 0, errors = 0;
    const report = [];

    for (const order of orders) {
      checked++;
      let dirty = false;
      const updatedItems = [];

      for (const item of order.items) {
        const pid = item.id || item.productId;
        if (!pid) { updatedItems.push(item); continue; }

        // If both fields match and look like a valid Product, skip.
        if (item.id && item.productId && String(item.id) === String(item.productId)) {
          // Verify it IS a Product (not a CreatorProduct masquerading as one)
          const isProduct = await Product.exists({ _id: pid });
          if (isProduct) { updatedItems.push(item); continue; }
        }

        // Try to resolve to the canonical Product._id
        let canonicalId = null;

        // Case 1: pid is already a Product._id
        const product = await Product.findById(pid).select('_id').lean();
        if (product) { canonicalId = String(product._id); }

        // Case 2: pid is a CreatorProduct._id
        if (!canonicalId) {
          const cp = await CreatorProduct.findById(pid).select('productId').lean();
          if (cp?.productId) { canonicalId = String(cp.productId); }
        }

        if (canonicalId && (String(item.id) !== canonicalId || String(item.productId) !== canonicalId)) {
          dirty = true;
          updatedItems.push({ ...item, id: canonicalId, productId: canonicalId });
          report.push({ orderId: order._id, from: pid, to: canonicalId });
        } else {
          updatedItems.push(item);
        }
      }

      if (dirty) {
        needsFix++;
        if (!dryRun) {
          try {
            await Order.updateOne({ _id: order._id }, { $set: { items: updatedItems } });
            fixed++;
          } catch (e) {
            errors++;
            console.error(`Migration error on order ${order._id}:`, e.message);
          }
        }
      }
    }

    res.json({
      success: true,
      dryRun,
      checked,
      needsFix,
      fixed: dryRun ? 0 : fixed,
      errors,
      sample: report.slice(0, 20),   // first 20 changes for review
      message: dryRun
        ? `Dry run complete. ${needsFix} orders would be updated. Run with ?dry=false to commit.`
        : `Migration complete. ${fixed} orders updated, ${errors} errors.`,
    });
  } catch (err) {
    console.error('Migration error:', err.message);
    res.status(500).json({ success: false, message: err.message });
  }
});
