// ─────────────────────────────────────────────────────────────────────────────
// Uncaught Exception Handler
// ─────────────────────────────────────────────────────────────────────────────
process.on('uncaughtException', (err) => {
  uncaughtExceptionCount++;

  console.error('\n╔═══════════════════════════════════════════════════════════════╗');
  console.error('║              ❌ UNCAUGHT EXCEPTION DETECTED                   ║');
  console.error('╚═══════════════════════════════════════════════════════════════╝');
  console.error(`📊 Exception #${uncaughtExceptionCount} of ${ERROR_HANDLING_CONFIG.maxUncaughtExceptions}`);
  console.error(`⏰ Time: ${new Date().toISOString()}`);
  console.error(`🔍 Error: ${err.message}`);
  console.error(`📍 Stack Trace:\n${err.stack}\n`);

  // ✅ FIXED: AdminLog DB write moved here from deleted prependListener.
  // Using setImmediate so the log attempt never blocks or re-throws into this handler.
  setImmediate(async () => {
    try {
      await AdminLog.create({
        actor:        { role: 'system', name: 'Process', email: 'system', ip: null, device: null },
        category:     'error',
        action:       'uncaught_exception',
        severity:     'critical',
        detail:       { message: err.message, stack: err.stack?.slice(0, 1000) },
        success:      false,
        errorMessage: err.message,
      });
    } catch (_) { /* never let a log write crash the crash handler */ }
  });

  if (ERROR_HANDLING_CONFIG.forceShutdown ||
      uncaughtExceptionCount >= ERROR_HANDLING_CONFIG.maxUncaughtExceptions) {

    console.error('🚨 CRITICAL: Maximum exceptions reached or force shutdown enabled');
    console.error('⚠️  Initiating graceful shutdown...\n');

    initiateGracefulShutdown(1, 'Too many uncaught exceptions');
  } else {
    const remaining = ERROR_HANDLING_CONFIG.maxUncaughtExceptions - uncaughtExceptionCount;
    console.log(`⚠️  Exception logged - server continuing`);
    console.log(`   ${remaining} exception(s) remaining before shutdown\n`);
    console.log('═══════════════════════════════════════════════════════════════\n');
  }
});

// ─────────────────────────────────────────────────────────────────────────────
// Unhandled Promise Rejection Handler
// ─────────────────────────────────────────────────────────────────────────────
process.on('unhandledRejection', (reason, promise) => {
  unhandledRejectionCount++;

  // ✅ FIXED: reason can be a string, number, or null — not always an Error object.
  // Accessing reason.stack directly on a non-Error causes a secondary crash on Render.
  const message = reason instanceof Error ? reason.message : String(reason ?? 'Unknown rejection');
  const stack   = reason instanceof Error ? reason.stack   : '(no stack — rejection was not an Error object)';

  console.error('\n╔═══════════════════════════════════════════════════════════════╗');
  console.error('║           ⚠️  UNHANDLED PROMISE REJECTION                     ║');
  console.error('╚═══════════════════════════════════════════════════════════════╝');
  console.error(`📊 Rejection #${unhandledRejectionCount}`);
  console.error(`⏰ Time: ${new Date().toISOString()}`);
  console.error(`🔍 Reason: ${message}`);
  console.error(`📍 Stack Trace:\n${stack}`);

  // ✅ Also write to AdminLog DB (non-blocking — never throws outward)
  setImmediate(async () => {
    try {
      await AdminLog.create({
        actor:        { role: 'system', name: 'Process', email: 'system', ip: null, device: null },
        category:     'error',
        action:       'unhandled_rejection',
        severity:     'critical',
        detail:       { message, stack: stack?.slice(0, 1000) },
        success:      false,
        errorMessage: message,
      });
    } catch (_) { /* never let a log write crash the rejection handler */ }
  });

  console.log('\n⚠️  Promise rejection logged - server continuing');
  console.log('💡 Tip: Add .catch() handlers to promises to prevent this\n');
  console.log('═══════════════════════════════════════════════════════════════\n');
});


// ─────────────────────────────────────────────────────────────────────────────
// Warning Handler
// ─────────────────────────────────────────────────────────────────────────────

process.on('warning', (warning) => {
  console.warn('\n⚠️  Node.js Warning:');
  console.warn(`   Name: ${warning.name}`);
  console.warn(`   Message: ${warning.message}`);
  if (warning.stack) {
    console.warn(`   Stack: ${warning.stack}`);
  }
  console.warn('');
});

// ─────────────────────────────────────────────────────────────────────────────
// Graceful Shutdown System
// ─────────────────────────────────────────────────────────────────────────────

async function initiateGracefulShutdown(exitCode = 0, reason = 'Unknown') {
  if (isShuttingDown) {
    console.log('⏳ Shutdown already in progress...');
    return;
  }
  
  isShuttingDown = true;
  
  console.log('\n╔═══════════════════════════════════════════════════════════════╗');
  console.log('║              🛑 INITIATING GRACEFUL SHUTDOWN                  ║');
  console.log('╚═══════════════════════════════════════════════════════════════╝');
  console.log(`📋 Reason: ${reason}`);
  console.log(`⏰ Time: ${new Date().toISOString()}\n`);
  
  // Force shutdown after timeout
  const forceShutdownTimer = setTimeout(() => {
    console.error('⚠️  Graceful shutdown timeout - forcing exit');
    process.exit(exitCode);
  }, ERROR_HANDLING_CONFIG.shutdownTimeout);
  
  try {
    // 1. Stop accepting new connections
    console.log('1️⃣  Stopping HTTP server...');
    await new Promise((resolve) => {
      server.close((err) => {
        if (err) {
          console.error('   ❌ Error closing HTTP server:', err.message);
        } else {
          console.log('   ✅ HTTP server closed');
        }
        resolve();
      });
    });
    
    // 2. Stop monitoring system
    console.log('2️⃣  Stopping monitoring system...');
    if (typeof stopMonitoring === 'function') {
      stopMonitoring();
      console.log('   ✅ Monitoring stopped');
    }
    // 2b. Clear WebSocket heartbeat interval
    if (typeof heartbeatInterval !== 'undefined' && heartbeatInterval) {
      clearInterval(heartbeatInterval);
      console.log('   ✅ WebSocket heartbeat cleared');
    }
    
    // 3. Close WebSocket connections
    console.log('3️⃣  Closing WebSocket connections...');
    let wsCount = 0;
    if (wss && wss.clients) {
      wss.clients.forEach((client) => {
        try {
          client.send(JSON.stringify({
            type: 'server_shutdown',
            message: 'Server is shutting down. Please reconnect in a moment.'
          }));
          client.close();
          wsCount++;
        } catch (err) {
          // Ignore errors during shutdown
        }
      });
    }
    console.log(`   ✅ Closed ${wsCount} WebSocket connections`);
    
    // 4. Close database connection
    console.log('4️⃣  Closing MongoDB connection...');
    try {
      await mongoose.connection.close(false);
      console.log('   ✅ MongoDB connection closed');
    } catch (error) {
      console.error('   ❌ Error closing MongoDB:', error.message);
    }
    
    // 5. Clear all intervals/timeouts
    console.log('5️⃣  Clearing all timers...');
    // Node.js will handle this automatically
    console.log('   ✅ Timers cleared');
    
    console.log('\n✅ Graceful shutdown complete');
    console.log('👋 UYEH TECH Server - Goodbye\n');
    
    clearTimeout(forceShutdownTimer);
    process.exit(exitCode);
    
  } catch (error) {
    console.error('\n❌ Error during graceful shutdown:', error);
    clearTimeout(forceShutdownTimer);
    process.exit(1);
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// System Signal Handlers
// ─────────────────────────────────────────────────────────────────────────────

process.on('SIGTERM', () => {
  console.log('\n📡 SIGTERM signal received');
  initiateGracefulShutdown(0, 'SIGTERM signal (deployment/restart)');
});

process.on('SIGINT', () => {
  console.log('\n📡 SIGINT signal received (Ctrl+C)');
  initiateGracefulShutdown(0, 'SIGINT signal (manual stop)');
});

process.on('SIGHUP', () => {
  console.log('\n📡 SIGHUP signal received');
  initiateGracefulShutdown(0, 'SIGHUP signal (terminal closed)');
});

// ── Memory watcher — fires every 5 minutes ────────────────────────────────────
const MEMORY_LOG_INTERVAL       = 5 * 60 * 1000;   // 5 minutes
const MEMORY_WARNING_THRESHOLD  = 0.80;             // 80% heap used → warning
const MEMORY_CRITICAL_THRESHOLD = 0.95;             // 95% heap used → critical
const MEMORY_CHECK_INTERVAL = 5 * 60 * 1000; // 5 minutes
// ─────────────────────────────────────────────────────────────────────────────
// Memory & Performance Monitoring
// ─────────────────────────────────────────────────────────────────────────────

setInterval(() => {
  const memUsage = process.memoryUsage();
  const heapUsedPercent = memUsage.heapUsed / memUsage.heapTotal;
  
  if (heapUsedPercent > MEMORY_WARNING_THRESHOLD) {
    console.warn('\n⚠️  HIGH MEMORY USAGE WARNING');
    console.warn(`   Heap Used: ${Math.round(memUsage.heapUsed / 1024 / 1024)}MB`);
    console.warn(`   Heap Total: ${Math.round(memUsage.heapTotal / 1024 / 1024)}MB`);
    console.warn(`   Usage: ${Math.round(heapUsedPercent * 100)}%`);
    console.warn('   Consider investigating memory leaks\n');
  }
}, MEMORY_CHECK_INTERVAL);

// ── Memory pressure response ──────────────────────────────────────────────
// When heap exceeds 85% — proactively free whatever we can before hitting 95%
setInterval(() => {
  const mem      = process.memoryUsage();
  const heapPct  = mem.heapUsed / mem.heapTotal;

  if (heapPct > 0.85) {
    const beforeMB = Math.round(mem.heapUsed / 1024 / 1024);

    // 1. Clear the query cache
    cache.clear();

    // 2. Clear the analytics cache
    if (typeof invalidateAnalyticsCache === 'function') invalidateAnalyticsCache();

    // 3. Clear message cache for chats idle > 5 minutes
    const now = Date.now();
    let msgCleared = 0;
    for (const [chatId, messages] of messageCache.entries()) {
      const lastMsg = messages[messages.length - 1];
      if (!lastMsg || now - lastMsg.timestamp > 5 * 60 * 1000) {
        messageCache.delete(chatId);
        msgCleared++;
      }
    }

    // 4. Clear expired OTP entries immediately
    for (const [key, entry] of otpStore.entries()) {
      if (entry.expiresAt && Date.now() > new Date(entry.expiresAt).getTime()) {
        otpStore.delete(key);
      }
    }

    // 5. Suggest GC if available (only works with --expose-gc flag)
    if (typeof global.gc === 'function') {
      global.gc();
    }

    const afterMem  = process.memoryUsage();
    const afterMB   = Math.round(afterMem.heapUsed / 1024 / 1024);
    console.warn(`🧹 Memory pressure response: ${beforeMB}MB → ${afterMB}MB (freed ~${beforeMB - afterMB}MB)`);
    console.warn(`   Cleared: query cache, analytics cache, ${msgCleared} message caches, expired OTPs`);
  }
}, 2 * 60 * 1000); // check every 2 minutes

